const ENGINEERING_SCENARIO_TEMPLATE_BY_ID = new Map(
  ENGINEERING_SCENARIO_TEMPLATES.map((template) => [template.id, template]),
);

const SHOW_ENGINEERING_DELIVERY_WORKFLOWS = false;
const ASYNC_INDOOR_ADJUSTMENT_SAMPLE_SIZE = 200;
const ENGINEERING_RESULT_TABLE_VISIBLE_ROW_LIMIT = 200;

function cloneEngineeringJson<T>(value: T): T {
  return JSON.parse(JSON.stringify(value)) as T;
}

export function getEngineeringScenarioTemplate(
  templateId: EngineeringScenarioTemplateId | string | null | undefined,
): EngineeringScenarioTemplate | null {
  if (!templateId) return null;
  return ENGINEERING_SCENARIO_TEMPLATE_BY_ID.get(templateId as EngineeringScenarioTemplateId) ?? null;
}

function uniqueNonEmptyStrings(values: unknown[]): string[] {
  return Array.from(new Set(values.map((value) => textFrom(value, "")).filter(Boolean)));
}

function projectToleranceValueFromCell(value: unknown): unknown {
  const text = textFrom(value, "");
  if (!text) return "";
  const numeric = Number(text);
  if (Number.isFinite(numeric)) return numeric;
  if (/^(true|false)$/i.test(text)) return text.toLowerCase() === "true";
  return text;
}

function projectToleranceToolId(value: unknown): EngineeringToolId | null {
  const toolId = textFrom(value, "");
  return ENGINEERING_TOOL_IDS.includes(toolId as EngineeringToolId) ? (toolId as EngineeringToolId) : null;
}

function projectToleranceTemplateId(value: unknown): EngineeringScenarioTemplateId | null {
  const templateId = textFrom(value, "");
  return getEngineeringScenarioTemplate(templateId)?.id ?? null;
}

function normalizedProjectToleranceParameters(
  value: unknown,
  warnings: string[],
): Partial<Record<EngineeringToolId, Record<string, unknown>>> {
  const parameters: Partial<Record<EngineeringToolId, Record<string, unknown>>> = {};
  for (const [rawToolId, rawParameters] of Object.entries(objectFrom(value))) {
    const toolId = projectToleranceToolId(rawToolId);
    if (!toolId) {
      warnings.push(`未知工具 ${rawToolId} 已忽略`);
      continue;
    }
    const parameterRows = objectFrom(rawParameters);
    parameters[toolId] = {};
    for (const [key, parameterValue] of Object.entries(parameterRows)) {
      if (!key) continue;
      parameters[toolId]![key] = cloneEngineeringJson(parameterValue);
    }
  }
  return parameters;
}

export function parseEngineeringProjectToleranceLibrary(
  text: string,
  options: EngineeringProjectToleranceLibraryParseOptions = {},
): EngineeringProjectToleranceLibrary {
  const importedAt = options.importedAt ?? new Date().toISOString();
  const sourceName = textFrom(options.sourceName, "") || null;
  const format = options.format ?? (text.trim().startsWith("{") ? "json" : "csv");
  const warnings: string[] = [];
  let templateId: EngineeringScenarioTemplateId | null = null;
  let templateVersion = "";
  let projectName: string | null = null;
  let sourceNote = "";
  let rowCount = 0;
  const defaultParameters: Partial<Record<EngineeringToolId, Record<string, unknown>>> = {};
  const requiredDeliverables: string[] = [];
  const archiveChecklist: string[] = [];
  const qualityNotes: string[] = [];

  if (format === "json") {
    const raw = objectFrom(JSON.parse(text));
    templateId = projectToleranceTemplateId(raw.templateId);
    templateVersion = textFrom(raw.templateVersion ?? raw.version, "");
    projectName = textFrom(raw.projectName, "") || null;
    sourceNote = textFrom(raw.sourceNote, "");
    Object.assign(defaultParameters, normalizedProjectToleranceParameters(raw.defaultParameters, warnings));
    requiredDeliverables.push(...uniqueNonEmptyStrings(arrayFrom(raw.requiredDeliverables)));
    archiveChecklist.push(...uniqueNonEmptyStrings(arrayFrom(raw.archiveChecklist)));
    qualityNotes.push(...uniqueNonEmptyStrings(arrayFrom(raw.qualityNotes)));
    rowCount = Object.keys(defaultParameters).length || 1;
  } else {
    const rows = parseDelimitedRows(text, format === "csv" ? "," : "\t");
    const headers = rows[0] ?? [];
    const bodyRows = rows.slice(1);
    const headerIndex = new Map(headers.map((header, index) => [normalizeHeader(header), index]));
    const cell = (row: string[], ...aliases: string[]) => {
      for (const alias of aliases) {
        const index = headerIndex.get(normalizeHeader(alias));
        if (index !== undefined) return row[index] ?? "";
      }
      return "";
    };
    for (const row of bodyRows) {
      const rowTemplateId = projectToleranceTemplateId(cell(row, "templateId", "template", "场景模板"));
      if (rowTemplateId && !templateId) templateId = rowTemplateId;
      const toolId = projectToleranceToolId(cell(row, "toolId", "tool", "工具ID"));
      const parameterName = textFrom(cell(row, "parameter", "key", "参数"), "");
      if (!toolId || !parameterName) {
        warnings.push(`第 ${rowCount + 2} 行缺少有效工具或参数名`);
      } else {
        defaultParameters[toolId] = defaultParameters[toolId] ?? {};
        defaultParameters[toolId]![parameterName] = projectToleranceValueFromCell(cell(row, "value", "参数值", "值"));
      }
      if (!templateVersion) templateVersion = textFrom(cell(row, "templateVersion", "version", "模板版本"), "");
      if (!projectName) projectName = textFrom(cell(row, "projectName", "project", "项目名称"), "") || null;
      const rowSourceNote = textFrom(cell(row, "sourceNote", "source", "来源说明"), "");
      if (rowSourceNote && !sourceNote) sourceNote = rowSourceNote;
      requiredDeliverables.push(textFrom(cell(row, "requiredDeliverable", "deliverable", "成果"), ""));
      archiveChecklist.push(textFrom(cell(row, "archiveChecklist", "archiveItem", "归档清单"), ""));
      qualityNotes.push(textFrom(cell(row, "qualityNote", "qualityNotes", "质量说明"), ""));
      rowCount += 1;
    }
  }

  const template = getEngineeringScenarioTemplate(templateId);
  if (!template) throw new Error("项目限差库缺少有效场景模板 templateId");
  const mergedRequiredDeliverables = uniqueNonEmptyStrings([
    ...template.requiredDeliverables,
    ...requiredDeliverables,
  ]);
  const mergedArchiveChecklist = uniqueNonEmptyStrings([...template.archiveChecklist, ...archiveChecklist]);
  const mergedQualityNotes = uniqueNonEmptyStrings([...template.qualityNotes, ...qualityNotes]);
  const payload = {
    schema: "railwise.engineering.projectToleranceLibrary.v1" as const,
    projectName,
    templateId: template.id,
    templateTitle: template.title,
    templateVersion: templateVersion || "project-default",
    importedAt,
    sourceName,
    defaultParameters,
    requiredDeliverables: mergedRequiredDeliverables,
    archiveChecklist: mergedArchiveChecklist,
    qualityNotes: mergedQualityNotes,
    sourceNote: sourceNote || template.sourceNote,
    rowCount,
    warnings,
  };
  return {
    ...payload,
    libraryFingerprint: fnv1a32Fingerprint(JSON.stringify(payload)),
  };
}

export function inferEngineeringProjectToleranceLibraryFormat(
  fileName: string,
  text: string,
): EngineeringProjectToleranceLibraryInputFormat {
  const lower = fileName.toLowerCase();
  if (lower.endsWith(".json")) return "json";
  if (lower.endsWith(".tsv")) return "tsv";
  if (lower.endsWith(".xlsx")) return "xlsx";
  if (lower.endsWith(".csv")) return "csv";
  if (text.trim().startsWith("{")) return "json";
  return text.includes("\t") ? "tsv" : "csv";
}

function primitiveToleranceValue(value: unknown): Primitive {
  if (value === null || typeof value === "string" || typeof value === "number" || typeof value === "boolean") return value;
  if (value === undefined) return null;
  return JSON.stringify(value);
}

function toleranceParameterKey(toolId: EngineeringToolId, parameter: string): string {
  return `${toolId}:${parameter}`;
}

function flattenProjectToleranceParameters(
  library: EngineeringProjectToleranceLibrary,
): Map<string, { toolId: EngineeringToolId; parameter: string; value: Primitive }> {
  const entries = new Map<string, { toolId: EngineeringToolId; parameter: string; value: Primitive }>();
  for (const toolId of ENGINEERING_TOOL_IDS) {
    const parameters = library.defaultParameters[toolId];
    if (!parameters) continue;
    for (const [parameter, rawValue] of Object.entries(parameters)) {
      entries.set(toleranceParameterKey(toolId, parameter), {
        toolId,
        parameter,
        value: primitiveToleranceValue(rawValue),
      });
    }
  }
  return entries;
}

function toleranceChangeImpact(
  previousValue: Primitive,
  currentValue: Primitive,
  changeType: EngineeringProjectToleranceLibraryChangeType,
): EngineeringProjectToleranceLibraryChangeImpact {
  if (changeType === "added") return "added";
  if (changeType === "removed") return "removed";
  if (changeType === "unchanged") return "unchanged";
  if (typeof previousValue === "number" && typeof currentValue === "number") {
    if (currentValue < previousValue) return "tightened";
    if (currentValue > previousValue) return "loosened";
  }
  return "changed";
}

function projectToleranceChecklistChangeCount(
  previousLibrary: EngineeringProjectToleranceLibrary,
  currentLibrary: EngineeringProjectToleranceLibrary,
): number {
  const previousItems = new Set(previousLibrary.archiveChecklist);
  const currentItems = new Set(currentLibrary.archiveChecklist);
  let count = 0;
  for (const item of currentItems) if (!previousItems.has(item)) count += 1;
  for (const item of previousItems) if (!currentItems.has(item)) count += 1;
  return count;
}

export function compareEngineeringProjectToleranceLibraries(
  previousLibrary: EngineeringProjectToleranceLibrary,
  currentLibrary: EngineeringProjectToleranceLibrary,
  context: { comparedAt?: string } = {},
): EngineeringProjectToleranceLibraryComparison {
  const comparedAt = context.comparedAt ?? new Date().toISOString();
  const previousParameters = flattenProjectToleranceParameters(previousLibrary);
  const currentParameters = flattenProjectToleranceParameters(currentLibrary);
  const keys = Array.from(new Set([...previousParameters.keys(), ...currentParameters.keys()])).sort();
  const rows = keys.map((key): EngineeringProjectToleranceLibraryComparisonRow => {
    const previous = previousParameters.get(key);
    const current = currentParameters.get(key);
    const toolId = (current?.toolId ?? previous?.toolId) as EngineeringToolId;
    const parameter = current?.parameter ?? previous?.parameter ?? key;
    const previousValue = previous?.value ?? null;
    const currentValue = current?.value ?? null;
    const changeType: EngineeringProjectToleranceLibraryChangeType =
      previous && !current
        ? "removed"
        : !previous && current
          ? "added"
          : JSON.stringify(previousValue) === JSON.stringify(currentValue)
            ? "unchanged"
            : "changed";
    const impact = toleranceChangeImpact(previousValue, currentValue, changeType);
    return {
      changeType,
      toolId,
      parameter,
      previousValue,
      currentValue,
      impact,
      requiresApproval: changeType !== "unchanged",
    };
  });
  const archiveChecklistChangeCount = projectToleranceChecklistChangeCount(previousLibrary, currentLibrary);
  const addedParameterCount = rows.filter((row) => row.changeType === "added").length;
  const removedParameterCount = rows.filter((row) => row.changeType === "removed").length;
  const changedParameterCount = rows.filter((row) => row.changeType === "changed").length;
  const unchangedParameterCount = rows.filter((row) => row.changeType === "unchanged").length;
  const approvalRequired = addedParameterCount + removedParameterCount + changedParameterCount + archiveChecklistChangeCount > 0;
  const csvRows = rows.map((row) => ({
    change_type: row.changeType,
    tool_id: row.toolId,
    parameter: row.parameter,
    previous_value: row.previousValue,
    current_value: row.currentValue,
    impact: row.impact,
    requires_approval: row.requiresApproval,
  }));
  const comparisonBody = {
    schema: "railwise.engineering.projectToleranceLibrary.comparison.v1" as const,
    comparedAt,
    projectName: currentLibrary.projectName ?? previousLibrary.projectName,
    templateId: currentLibrary.templateId,
    templateTitle: currentLibrary.templateTitle,
    previousVersion: previousLibrary.templateVersion,
    currentVersion: currentLibrary.templateVersion,
    previousFingerprint: previousLibrary.libraryFingerprint,
    currentFingerprint: currentLibrary.libraryFingerprint,
    addedParameterCount,
    removedParameterCount,
    changedParameterCount,
    unchangedParameterCount,
    archiveChecklistChangeCount,
    approvalRequired,
    recommendation: approvalRequired
      ? "限差库参数或归档清单已变化，归档前应完成项目限差变更审批。"
      : "限差库参数和归档清单未变化，可沿用既有审批记录。",
    rows,
    csv: csvFromRows(
      ["change_type", "tool_id", "parameter", "previous_value", "current_value", "impact", "requires_approval"],
      csvRows,
    ),
  };
  return {
    ...comparisonBody,
    comparisonFingerprint: fnv1a32Fingerprint(JSON.stringify(comparisonBody)),
  };
}

export function buildEngineeringProjectToleranceApprovalRecord(
  comparison: EngineeringProjectToleranceLibraryComparison,
  input: EngineeringProjectToleranceApprovalInput = {},
): EngineeringProjectToleranceApprovalRecord {
  const approvedAt = input.approvedAt ?? new Date().toISOString();
  const approvalBody = {
    schema: "railwise.engineering.projectToleranceApproval.v1" as const,
    approvedAt,
    approver: textFrom(input.approver, "").trim() || null,
    conclusion: input.conclusion ?? "pending_review",
    remarks: textFrom(input.remarks, ""),
    projectName: comparison.projectName,
    previousVersion: comparison.previousVersion,
    currentVersion: comparison.currentVersion,
    comparisonFingerprint: comparison.comparisonFingerprint,
  };
  return {
    ...approvalBody,
    approvalFingerprint: fnv1a32Fingerprint(JSON.stringify(approvalBody)),
  };
}

function applyMissingObjectDefaults(target: Record<string, unknown>, defaults: Record<string, unknown>): void {
  for (const [key, value] of Object.entries(defaults)) {
    if (target[key] === undefined || target[key] === null || target[key] === "") {
      target[key] = cloneEngineeringJson(value);
    }
  }
}

export function applyEngineeringScenarioTemplateToInput(
  toolId: EngineeringToolId,
  input: unknown,
  templateId: EngineeringScenarioTemplateId | string | null | undefined,
  projectToleranceLibrary?: EngineeringProjectToleranceLibrary | null,
): unknown {
  const template = getEngineeringScenarioTemplate(templateId);
  const libraryMatches = projectToleranceLibrary?.templateId === template?.id;
  const defaults = {
    ...(template?.defaultParameters[toolId] ?? {}),
    ...(libraryMatches ? (projectToleranceLibrary?.defaultParameters[toolId] ?? {}) : {}),
  };
  if (!template || Object.keys(defaults).length === 0) return input;
  const cloned = cloneEngineeringJson(input);
  const root = objectFrom(cloned);
  applyMissingObjectDefaults(root, defaults);

  if (toolId === "alignment_station_offset") {
    const observations = arrayFrom(root.observations);
    for (const observation of observations) {
      const row = objectFrom(observation);
      for (const key of ["toleranceMm", "verticalToleranceMm"]) {
        if (defaults[key] !== undefined && (row[key] === undefined || row[key] === null || row[key] === "")) {
          row[key] = cloneEngineeringJson(defaults[key]);
        }
      }
    }
  }

  return root;
}

export function buildEngineeringScenarioTemplateApplication(
  toolId: EngineeringToolId,
  templateId: EngineeringScenarioTemplateId | string | null | undefined,
  appliedAt = new Date().toISOString(),
  projectToleranceLibrary?: EngineeringProjectToleranceLibrary | null,
): EngineeringScenarioTemplateApplication | null {
  const template = getEngineeringScenarioTemplate(templateId);
  if (!template) return null;
  const libraryMatches = projectToleranceLibrary?.templateId === template.id;
  const defaultParameters = cloneEngineeringJson({
    ...(template.defaultParameters[toolId] ?? {}),
    ...(libraryMatches ? (projectToleranceLibrary?.defaultParameters[toolId] ?? {}) : {}),
  });
  const payload = {
    templateId: template.id,
    templateTitle: template.title,
    templateVersion: libraryMatches ? projectToleranceLibrary.templateVersion : "project-default",
    projectName: libraryMatches ? projectToleranceLibrary.projectName : null,
    toolId,
    defaultParameters,
    requiredDeliverables: libraryMatches ? projectToleranceLibrary.requiredDeliverables : template.requiredDeliverables,
    archiveChecklist: libraryMatches ? projectToleranceLibrary.archiveChecklist : template.archiveChecklist,
    qualityNotes: libraryMatches ? projectToleranceLibrary.qualityNotes : template.qualityNotes,
    sourceNote: libraryMatches ? projectToleranceLibrary.sourceNote : template.sourceNote,
    projectToleranceLibraryFingerprint: libraryMatches ? projectToleranceLibrary.libraryFingerprint : null,
    projectToleranceLibrarySourceName: libraryMatches ? projectToleranceLibrary.sourceName : null,
  };
  return {
    schema: "railwise.engineering.scenarioTemplateApplication.v1",
    ...payload,
    appliedAt,
    parameterFingerprint: fnv1a32Fingerprint(JSON.stringify(payload)),
  };
}

