const ENGINEERING_VECTOR_OUTPUT_FORMAT_OPTIONS = ["GeoJSON", "GPKG", "DXF", "ESRI Shapefile"] as const;
const ENGINEERING_VECTOR_OUTPUT_FORMATS = new Set<string>(ENGINEERING_VECTOR_OUTPUT_FORMAT_OPTIONS);

function requiredPlanText(params: Record<string, unknown>, key: string): string {
  const value = textFrom(params[key], "").trim();
  if (!value) throw new Error(`${key} is required`);
  return value;
}

function requiredPlanNumber(params: Record<string, unknown>, key: string): number {
  const value = Number(requiredPlanText(params, key));
  if (!Number.isFinite(value) || value <= 0) throw new Error(`${key} must be a positive number`);
  return value;
}

function pdalPipelinePlan(
  workflow: EngineeringEngineWorkflow,
  workflowId: EngineeringEngineWorkflowId,
  pipeline: unknown[],
  options: Partial<EngineeringEngineCommandPlan> = {},
): EngineeringEngineCommandPlan {
  return {
    ...workflow,
    workflowId,
    args: ["pipeline", "--stdin", ...(options.metadataPath ? ["--metadata", options.metadataPath] : [])],
    stdin: JSON.stringify({ pipeline }, null, 2),
    ...options,
  };
}

export function buildEngineeringEngineCommandPlan(
  workflowId: EngineeringEngineWorkflowId,
  params: Record<string, unknown>,
): EngineeringEngineCommandPlan {
  const workflow = ENGINEERING_ENGINE_WORKFLOWS.find((item) => item.id === workflowId);
  if (!workflow) throw new Error(`Unknown engine workflow: ${workflowId}`);
  if (workflowId === "proj_crs_pipeline") {
    return {
      ...workflow,
      workflowId,
      args: [
        "-s",
        requiredPlanText(params, "sourceCrs"),
        "-t",
        requiredPlanText(params, "targetCrs"),
        "-o",
        "PROJJSON",
      ],
    };
  }
  if (workflowId === "proj_transform_points") {
    const operationArgs = requiredPlanText(params, "operation").split(/\s+/).filter(Boolean);
    return {
      ...workflow,
      workflowId,
      args: operationArgs,
      stdin: requiredPlanText(params, "pointsText"),
      parseOutput: "proj-cct",
    };
  }
  if (workflowId === "gdal_vector_info") {
    return {
      ...workflow,
      workflowId,
      args: ["-json", "-so", "-al", requiredPlanText(params, "inputPath")],
    };
  }
  if (workflowId === "gdal_vector_convert") {
    const outputFormat = requiredPlanText(params, "outputFormat");
    if (!ENGINEERING_VECTOR_OUTPUT_FORMATS.has(outputFormat)) {
      throw new Error(`Unsupported outputFormat: ${outputFormat}`);
    }
    const selectFields = textFrom(params.selectFields, "");
    const whereClause = textFrom(params.whereClause, "");
    const layerName = textFrom(params.layerName, "");
    const args = [
      "-f",
      outputFormat,
      ...(selectFields ? ["-select", selectFields] : []),
      ...(whereClause ? ["-where", whereClause] : []),
      requiredPlanText(params, "outputPath"),
      requiredPlanText(params, "inputPath"),
      ...(layerName ? [layerName] : []),
    ];
    return {
      ...workflow,
      workflowId,
      args,
      outputPath: requiredPlanText(params, "outputPath"),
      reloadOutput: true,
    };
  }
  if (workflowId === "pdal_pointcloud_info") {
    return {
      ...workflow,
      workflowId,
      args: ["info", "--metadata", requiredPlanText(params, "inputPath")],
    };
  }
  if (workflowId === "pdal_icp_registration") {
    const outputPath = requiredPlanText(params, "outputPath");
    return pdalPipelinePlan(
      workflow,
      workflowId,
      [
        requiredPlanText(params, "fixedInputPath"),
        requiredPlanText(params, "movingInputPath"),
        { type: "filters.icp", max_iter: requiredPlanNumber(params, "maxIterations") },
        outputPath,
      ],
      {
        outputPath,
        metadataPath: textFrom(params.metadataPath, "").trim() || `${outputPath}.icp-metadata.json`,
      },
    );
  }
  if (workflowId === "pdal_crop_bounds") {
    const outputPath = requiredPlanText(params, "outputPath");
    return pdalPipelinePlan(
      workflow,
      workflowId,
      [
        requiredPlanText(params, "inputPath"),
        { type: "filters.crop", bounds: requiredPlanText(params, "bounds") },
        outputPath,
      ],
      { outputPath },
    );
  }
  if (workflowId === "pdal_decimation") {
    const outputPath = requiredPlanText(params, "outputPath");
    return pdalPipelinePlan(
      workflow,
      workflowId,
      [
        requiredPlanText(params, "inputPath"),
        { type: "filters.decimation", step: requiredPlanNumber(params, "step") },
        outputPath,
      ],
      { outputPath },
    );
  }
  const outputPath = requiredPlanText(params, "outputPath");
  return pdalPipelinePlan(
    workflow,
    workflowId,
    [
      requiredPlanText(params, "inputPath"),
      { type: "filters.voxelcenternearestneighbor", cell: requiredPlanNumber(params, "cell") },
      outputPath,
    ],
    { outputPath },
  );
}

function shellQuote(value: string): string {
  if (/^[A-Za-z0-9_./:@%+=,-]+$/.test(value)) return value;
  return `'${value.replace(/'/g, "'\\''")}'`;
}

export function summarizeEngineeringPdalMetadata(metadataText: string): string {
  let metadata: unknown;
  try {
    metadata = JSON.parse(metadataText);
  } catch {
    return "PDAL metadata 摘要\nmetadata: 非 JSON 文本";
  }

  const wanted = new Map<string, string>();
  const visit = (value: unknown) => {
    if (!value || typeof value !== "object") return;
    if (Array.isArray(value)) {
      for (const item of value) visit(item);
      return;
    }
    for (const [key, item] of Object.entries(value)) {
      const normalized = key.toLowerCase();
      if (
        ["transform", "transformation", "matrix", "fitness", "converged", "rmse", "rms"].includes(normalized) &&
        (typeof item === "string" || typeof item === "number" || typeof item === "boolean")
      ) {
        wanted.set(normalized, `${key}: ${String(item)}`);
      }
      visit(item);
    }
  };
  visit(metadata);

  return ["PDAL metadata 摘要", ...Array.from(wanted.values())].join("\n");
}

export type EngineeringProjCctOutput = EngineeringImportResult & {
  csv: string;
  rows: Array<Record<string, string>>;
};

export function parseEngineeringProjCctOutput(outputText: string): EngineeringProjCctOutput {
  const columnNames = ["id", "x", "y", "z", "t", "auxiliary"];
  const rows: Array<Record<string, string>> = [];
  const warnings: string[] = [];
  for (const [index, line] of outputText.split(/\r?\n/).entries()) {
    const trimmed = line.trim();
    if (!trimmed) continue;
    const tokens = trimmed.split(/\s+/);
    if (tokens.length < 2) {
      warnings.push(`第 ${index + 1} 行少于 2 个坐标列，已跳过`);
      continue;
    }
    const extra = tokens.slice(4);
    const id = extra[0] || `P${rows.length + 1}`;
    rows.push({
      id,
      x: tokens[0] ?? "",
      y: tokens[1] ?? "",
      z: tokens[2] ?? "",
      t: tokens[3] ?? "",
      auxiliary: extra.slice(extra[0] ? 1 : 0).join(" "),
    });
  }
  const csv = [
    columnNames.map((column) => csvCell(column)).join(","),
    ...rows.map((row) => columnNames.map((column) => csvCell(row[column] ?? "")).join(",")),
  ].join("\n");
  return {
    format: "csv",
    input: rows,
    rowCount: rows.length,
    columnNames,
    previewRows: rows.slice(0, 5).map((row) => ({ ...row })),
    warnings,
    csv,
    rows,
  };
}

function primitiveFromEngineValue(value: unknown): Primitive {
  if (value === null || typeof value === "string" || typeof value === "number" || typeof value === "boolean") return value;
  return JSON.stringify(value);
}

function engineReviewCsv(rows: EngineeringEngineReviewRow[], metrics: Record<string, Primitive>): string {
  if (rows.length === 0) {
    const metricColumns = Object.keys(metrics);
    return [
      ["type", ...metricColumns].map(csvCell).join(","),
      ["metric", ...metricColumns.map((column) => metrics[column] ?? null)].map(csvCell).join(","),
    ].join("\n");
  }
  const columns = Array.from(new Set(rows.flatMap((row) => Object.keys(row))));
  return [
    columns.map(csvCell).join(","),
    ...rows.map((row) => columns.map((column) => csvCell(row[column] ?? null)).join(",")),
  ].join("\n");
}

function engineExtentText(extent: unknown): string {
  if (Array.isArray(extent)) return extent.map((value) => String(value)).join(",");
  const obj = objectFrom(extent);
  const keys = ["minX", "minY", "maxX", "maxY", "minx", "miny", "maxx", "maxy"];
  const values = keys.map((key) => obj[key]).filter((value) => value !== undefined);
  return values.length > 0 ? values.map(String).join(",") : "";
}

function gdalLayerFields(layer: Record<string, unknown>): Array<Record<string, unknown>> {
  const fields = layer.fields;
  if (Array.isArray(fields)) return fields.map(objectFrom);
  const fieldsObject = objectFrom(fields);
  return Object.entries(fieldsObject).map(([name, value]) => ({ name, ...objectFrom(value) }));
}

function collectPdalMetricRows(metadataText: string): EngineeringEngineReviewRow[] {
  let metadata: unknown;
  try {
    metadata = JSON.parse(metadataText);
  } catch {
    return [
      {
        row_type: "engine_pdal_metadata_error",
        metric_key: "metadata",
        metric_value: "非 JSON 文本",
        quality_use: "点云配准/处理质量复核",
      },
    ];
  }

  const wanted = new Set(["transform", "transformation", "matrix", "fitness", "converged", "rmse", "rms"]);
  const rows: EngineeringEngineReviewRow[] = [];
  const visit = (value: unknown, path: string[]) => {
    if (!value || typeof value !== "object") return;
    if (Array.isArray(value)) {
      value.forEach((item, index) => visit(item, [...path, String(index)]));
      return;
    }
    for (const [key, item] of Object.entries(value)) {
      const normalized = key.toLowerCase();
      if (wanted.has(normalized)) {
        rows.push({
          row_type: "engine_pdal_metric",
          metric_key: normalized,
          metric_path: [...path, key].join("."),
          metric_value: primitiveFromEngineValue(item),
          quality_use: "点云配准/处理质量复核",
        });
      }
      visit(item, [...path, key]);
    }
  };
  visit(metadata, []);
  return rows;
}

function engineReviewMarkdown(review: Omit<EngineeringEngineReview, "markdown" | "csv" | "json">): string {
  const lines = [`# 专业引擎结构化审查`, "", `## ${review.title}`, ""];
  lines.push(`- 状态：${review.status}`);
  lines.push(`- 摘要：${review.summary}`);
  lines.push(`- 工作流：${review.workflowId}`);
  lines.push(`- 引擎：${review.engine}`);
  lines.push("");
  lines.push("## 指标");
  lines.push("");
  lines.push("| 指标 | 值 |");
  lines.push("| --- | ---: |");
  for (const [key, value] of Object.entries(review.metrics)) {
    lines.push(`| ${key} | ${formatPrimitive(value)} |`);
  }
  if (review.rows.length > 0) {
    const columns = Array.from(new Set(review.rows.flatMap((row) => Object.keys(row))));
    lines.push("");
    lines.push("## 结构化成果表");
    lines.push("");
    lines.push(`| ${columns.join(" | ")} |`);
    lines.push(`| ${columns.map(() => "---").join(" | ")} |`);
    for (const row of review.rows) {
      lines.push(`| ${columns.map((column) => formatPrimitive(row[column] ?? null)).join(" | ")} |`);
    }
  }
  if (review.workflowId === "gdal_vector_info") {
    lines.push("");
    lines.push("## GDAL/OGR 图层字段审查");
    lines.push("");
    lines.push("- 图层、要素数、范围和字段类型可进入导入前质量检查。");
  }
  if (review.engine === "pdal") {
    lines.push("");
    lines.push("## PDAL metadata 结构化审查");
    lines.push("");
    lines.push("- ICP 变换矩阵、fitness、收敛状态和 RMSE/RMS 可进入点云处理质量复核。");
  }
  return lines.join("\n");
}

export function buildEngineeringEngineReview(
  plan: EngineeringEngineCommandPlan,
  output: EngineeringEngineCommandResult & { metadataText?: string; generatedAt?: string },
): EngineeringEngineReview {
  const rows: EngineeringEngineReviewRow[] = [];
  const metrics: Record<string, Primitive> = {
    exit_code: output.exit_code,
    stdout_bytes: output.stdout.length,
    stderr_bytes: output.stderr.length,
  };
  const warnings: string[] = [];

  if (plan.parseOutput === "proj-cct") {
    const parsed = parseEngineeringProjCctOutput(output.stdout);
    rows.push(
      ...parsed.rows.map((row) => ({
        row_type: "engine_proj_point",
        point_id: row.id,
        x: numberFrom(row.x, Number.NaN),
        y: numberFrom(row.y, Number.NaN),
        z: numberFrom(row.z, Number.NaN),
        t: numberFrom(row.t, Number.NaN),
        auxiliary: row.auxiliary,
      })),
    );
    metrics.point_count = parsed.rowCount;
    metrics.warning_count = parsed.warnings.length;
    warnings.push(...parsed.warnings);
  } else if (plan.workflowId === "gdal_vector_info") {
    let parsed: unknown;
    try {
      parsed = JSON.parse(output.stdout);
    } catch {
      warnings.push("GDAL/OGR stdout 不是可解析 JSON；请确认 ogrinfo 使用 -json 输出。");
    }
    const root = objectFrom(parsed);
    const layers = arrayFrom(root.layers).map(objectFrom);
    let fieldCount = 0;
    let featureCount = 0;
    layers.forEach((layer, layerIndex) => {
      const fields = gdalLayerFields(layer);
      const layerFeatureCount = numberFrom(layer.featureCount ?? layer.feature_count, 0);
      featureCount += layerFeatureCount;
      fieldCount += fields.length;
      const layerName = textFrom(layer.name, `layer-${layerIndex + 1}`);
      rows.push({
        row_type: "engine_gdal_layer_summary",
        layer_name: layerName,
        geometry_type: textFrom(layer.geometryType ?? layer.geometry_type, ""),
        feature_count: layerFeatureCount,
        field_count: fields.length,
        extent: engineExtentText(layer.extent),
        quality_use: "矢量导入前图层、字段、范围和要素数复核",
      });
      fields.forEach((field, fieldIndex) => {
        rows.push({
          row_type: "engine_gdal_field",
          layer_name: layerName,
          field_index: fieldIndex + 1,
          field_name: textFrom(field.name, `field_${fieldIndex + 1}`),
          field_type: textFrom(field.type ?? field.fieldType ?? field.field_type, ""),
          width: numberFrom(field.width, 0),
          precision: numberFrom(field.precision, 0),
          quality_use: "矢量字段映射和成果导入复核",
        });
      });
    });
    metrics.layer_count = layers.length;
    metrics.field_count = fieldCount;
    metrics.feature_count = featureCount;
    if (layers.length === 0 && output.success) warnings.push("GDAL/OGR JSON 中未发现 layers。");
  } else if (plan.engine === "pdal") {
    const metadataText = textFrom(output.metadataText, "") || output.stdout;
    const pdalRows = metadataText ? collectPdalMetricRows(metadataText) : [];
    rows.push(...pdalRows);
    metrics.pdal_metric_count = rows.filter((row) => row.row_type === "engine_pdal_metric").length;
    if (pdalRows.length === 0 && output.success) warnings.push("PDAL metadata 中未发现可审查的 transform/fitness/converged/RMSE 指标。");
  }

  const status: EngineeringStatus = !output.success ? "error" : warnings.length > 0 ? "warn" : "ok";
  const summary =
    status === "error"
      ? `${plan.title} 执行失败，退出码 ${formatPrimitive(output.exit_code)}。`
      : `${plan.title} 结构化审查完成，生成 ${rows.length} 条成果行。`;
  const body = {
    schema: "railwise.engineering.engineReview.v1" as const,
    generatedAt: output.generatedAt ?? new Date().toISOString(),
    workflowId: plan.workflowId,
    engine: plan.engine,
    title: plan.title,
    status,
    summary,
    metrics: {
      ...metrics,
      row_count: rows.length,
      warning_count: numberFrom(metrics.warning_count, 0) + warnings.length,
    },
    rows,
  };
  const markdown = engineReviewMarkdown(body);
  const csv = engineReviewCsv(rows, body.metrics);
  const json = JSON.stringify({ ...body, markdown, csv }, null, 2);
  return { ...body, markdown, csv, json };
}

function engineReviewQualityUse(review: EngineeringEngineReview): string {
  if (review.workflowId === "proj_transform_points") return "PROJ 坐标转换点表、点号和坐标输出复核";
  if (review.workflowId === "gdal_vector_info") return "GDAL/OGR 图层、字段、范围和要素数导入前复核";
  if (review.engine === "pdal") return "PDAL 点云处理 metadata、配准矩阵、收敛和精度指标复核";
  return "专业引擎执行结果归档和质量复核";
}

function buildEngineeringEngineReviewCatalog(
  engineReviews: EngineeringEngineReview[],
  options: { generatedAt?: string } = {},
): EngineeringEngineReviewCatalog {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const rows = engineReviews.map((review, index) => ({
    reviewIndex: index + 1,
    workflowId: review.workflowId,
    engine: review.engine,
    title: review.title,
    status: review.status,
    rowCount: review.rows.length,
    metricCount: Object.keys(review.metrics).length,
    reviewFingerprint: fnv1a32Fingerprint(review.json),
    markdownFingerprint: fnv1a32Fingerprint(review.markdown),
    csvFingerprint: fnv1a32Fingerprint(review.csv),
    qualityUse: engineReviewQualityUse(review),
  }));
  const totalRowCount = rows.reduce((sum, row) => sum + row.rowCount, 0);
  const csv = [
    "review_index,workflow_id,engine,title,status,row_count,metric_count,review_fingerprint,markdown_fingerprint,csv_fingerprint,quality_use",
    ...rows.map((row) =>
      [
        row.reviewIndex,
        row.workflowId,
        row.engine,
        row.title,
        row.status,
        row.rowCount,
        row.metricCount,
        row.reviewFingerprint,
        row.markdownFingerprint,
        row.csvFingerprint,
        row.qualityUse,
      ]
        .map(csvCell)
        .join(","),
    ),
  ].join("\n");
  const withoutFingerprints = {
    schema: "railwise.engineering.engineReviewCatalog.v1" as const,
    generatedAt,
    reviewCount: rows.length,
    totalRowCount,
    rows,
  };
  const catalogFingerprint = fnv1a32Fingerprint(JSON.stringify(withoutFingerprints));
  const markdown = [
    "# 专业引擎审查成果目录",
    "",
    `- 生成时间：${generatedAt}`,
    `- 审查数量：${rows.length}`,
    `- 审查成果行：${totalRowCount}`,
    "",
    "| 序号 | 工作流 | 引擎 | 状态 | 成果行 | 用途 |",
    "| ---: | --- | --- | --- | ---: | --- |",
    ...rows.map((row) => `| ${row.reviewIndex} | ${row.workflowId} | ${row.engine} | ${row.status} | ${row.rowCount} | ${row.qualityUse} |`),
    "",
    `目录指纹：${catalogFingerprint}`,
  ].join("\n");
  const body = { ...withoutFingerprints, catalogFingerprint, markdown, csv };
  return { ...body, json: JSON.stringify(body, null, 2) };
}

function buildEngineeringBatchEngineReviewCatalog(
  packages: Array<Record<string, unknown>>,
  items: EngineeringBatchPackageItem[],
  options: { batchName: string; generatedAt: string },
): EngineeringBatchEngineReviewCatalog {
  const rows: EngineeringBatchEngineReviewCatalogRow[] = [];
  packages.forEach((projectPackage, packageIndex) => {
    const runId = items[packageIndex]?.id ?? `run-${packageIndex + 1}`;
    const sourceName = textFrom(objectFrom(projectPackage.input).sourceName, "") || null;
    const tool = objectFrom(projectPackage.tool);
    const catalog = objectFrom(projectPackage.engineReviewCatalog);
    const catalogRows = arrayFrom(catalog.rows).map(objectFrom);
    catalogRows.forEach((row, rowIndex) => {
      rows.push({
        reviewIndex: numberFrom(row.reviewIndex, rowIndex + 1),
        runId,
        sourceName,
        toolId: textFrom(tool.id, ""),
        toolTitle: textFrom(tool.title, ""),
        workflowId: textFrom(row.workflowId, "proj_crs_pipeline") as EngineeringEngineWorkflowId,
        engine: textFrom(row.engine, "proj") as EngineeringEngineId,
        title: textFrom(row.title, ""),
        status: textFrom(row.status, "error") as EngineeringStatus,
        rowCount: numberFrom(row.rowCount),
        metricCount: numberFrom(row.metricCount),
        reviewFingerprint: textFrom(row.reviewFingerprint, ""),
        markdownFingerprint: textFrom(row.markdownFingerprint, ""),
        csvFingerprint: textFrom(row.csvFingerprint, ""),
        qualityUse: textFrom(row.qualityUse, ""),
      });
    });
  });
  const totalRowCount = rows.reduce((sum, row) => sum + row.rowCount, 0);
  const csv = [
    "run_id,source_name,tool_id,tool_title,review_index,workflow_id,engine,title,status,row_count,metric_count,review_fingerprint,markdown_fingerprint,csv_fingerprint,quality_use",
    ...rows.map((row) =>
      [
        row.runId,
        row.sourceName ?? "",
        row.toolId,
        row.toolTitle,
        row.reviewIndex,
        row.workflowId,
        row.engine,
        row.title,
        row.status,
        row.rowCount,
        row.metricCount,
        row.reviewFingerprint,
        row.markdownFingerprint,
        row.csvFingerprint,
        row.qualityUse,
      ]
        .map(csvCell)
        .join(","),
    ),
  ].join("\n");
  const withoutFingerprints = {
    schema: "railwise.engineering.batch.engineReviewCatalog.v1" as const,
    generatedAt: options.generatedAt,
    batchName: options.batchName,
    runCount: packages.length,
    reviewCount: rows.length,
    totalRowCount,
    rows,
  };
  const catalogFingerprint = fnv1a32Fingerprint(JSON.stringify(withoutFingerprints));
  const markdown = [
    "# 批处理专业引擎审查成果目录",
    "",
    `- 批次：${options.batchName}`,
    `- 生成时间：${options.generatedAt}`,
    `- 审查数量：${rows.length}`,
    `- 审查成果行：${totalRowCount}`,
    "",
    "| 运行 | 源文件 | 工作流 | 引擎 | 状态 | 成果行 | 用途 |",
    "| --- | --- | --- | --- | --- | ---: | --- |",
    ...rows.map((row) => `| ${row.runId} | ${row.sourceName ?? ""} | ${row.workflowId} | ${row.engine} | ${row.status} | ${row.rowCount} | ${row.qualityUse} |`),
    "",
    `目录指纹：${catalogFingerprint}`,
  ].join("\n");
  const body = { ...withoutFingerprints, catalogFingerprint, markdown, csv };
  return { ...body, json: JSON.stringify(body, null, 2) };
}

function engineWorkflowCoverage(engine: EngineeringEngineId, binary: string): string {
  const workflows = ENGINEERING_ENGINE_WORKFLOWS.filter(
    (workflow) => workflow.engine === engine && workflow.binary === binary,
  );
  return workflows.length > 0 ? workflows.map((workflow) => workflow.title).join("；") : "引擎版本/连通性预检";
}

export function buildEngineeringEnginePreflightReport(
  statuses: EngineeringEngineStatus[],
  options: EngineeringEnginePreflightOptions = {},
): EngineeringEnginePreflightReport {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const batchName = options.batchName ?? "工程分析批处理";
  const rows: EngineeringEnginePreflightRow[] = statuses.flatMap((engine) =>
    engine.binaries.map((binary) => ({
      engine: engine.id,
      label: engine.label,
      binary: binary.name,
      available: binary.available,
      path: binary.path ?? null,
      version: binary.version ?? null,
      workflowCoverage: engineWorkflowCoverage(engine.id, binary.name),
      installHint: engine.installHint,
    })),
  );
  const engineCount = statuses.length;
  const availableEngineCount = statuses.filter((engine) => engine.available).length;
  const missingEngineCount = engineCount - availableEngineCount;
  const binaryCount = rows.length;
  const availableBinaryCount = rows.filter((row) => row.available).length;
  const missingBinaryCount = binaryCount - availableBinaryCount;
  const status: EngineeringStatus = missingBinaryCount > 0 || missingEngineCount > 0 ? "warn" : "ok";
  const csv = [
    "engine,label,binary,available,path,version,workflow_coverage,install_hint",
    ...rows.map((row) =>
      [
        row.engine,
        row.label,
        row.binary,
        row.available,
        row.path ?? "",
        row.version ?? "",
        row.workflowCoverage,
        row.installHint,
      ]
        .map(csvCell)
        .join(","),
    ),
  ].join("\n");
  const withoutArtifacts = {
    schema: "railwise.engineering.enginePreflight.v1" as const,
    generatedAt,
    batchName,
    status,
    engineCount,
    availableEngineCount,
    missingEngineCount,
    binaryCount,
    availableBinaryCount,
    missingBinaryCount,
    rows,
  };
  const preflightFingerprint = fnv1a32Fingerprint(JSON.stringify(withoutArtifacts));
  const markdown = [
    "# 专业引擎环境预检报告",
    "",
    `- 批次：${batchName}`,
    `- 生成时间：${generatedAt}`,
    `- 状态：${status}`,
    `- 引擎：${availableEngineCount}/${engineCount} 可用`,
    `- 二进制：${availableBinaryCount}/${binaryCount} 可用`,
    "",
    "| 引擎 | 二进制 | 状态 | 版本 | 覆盖工作流 | 安装提示 |",
    "| --- | --- | --- | --- | --- | --- |",
    ...rows.map(
      (row) =>
        `| ${row.label} | ${row.binary} | ${row.available ? "可用" : "缺失"} | ${row.version ?? ""} | ${row.workflowCoverage} | ${row.installHint} |`,
    ),
    "",
    `预检指纹：${preflightFingerprint}`,
  ].join("\n");
  const body = { ...withoutArtifacts, preflightFingerprint, markdown, csv };
  return { ...body, json: JSON.stringify(body, null, 2) };
}

function engineeringEngineAcceptanceStatusLabel(status: EngineeringEngineAcceptanceStatus): string {
  if (status === "accepted") return "已通过";
  if (status === "pending_review") return "待执行审查";
  return "阻断";
}

export function buildEngineeringEngineAcceptancePackage(
  preflight: EngineeringEnginePreflightReport,
  reviews: EngineeringEngineReview[],
  options: EngineeringEngineAcceptanceOptions = {},
): EngineeringEngineAcceptancePackage {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const batchName = options.batchName ?? preflight.batchName;
  const plannedWorkflowCount = options.plannedWorkflowCount ?? ENGINEERING_ENGINE_WORKFLOWS.length;
  const reviewIssueCount = reviews.filter((review) => review.status !== "ok").length;
  const acceptanceStatus: EngineeringEngineAcceptanceStatus =
    preflight.missingBinaryCount > 0 || reviewIssueCount > 0
      ? "blocked"
      : reviews.length < plannedWorkflowCount
        ? "pending_review"
        : "accepted";
  const acceptanceStatusLabel = engineeringEngineAcceptanceStatusLabel(acceptanceStatus);
  const reviewFingerprints = reviews.map((review) => fnv1a32Fingerprint(review.json));
  const csv = [
    "section,item,status,details,action",
    ...preflight.rows.map((row) =>
      [
        "preflight",
        `${row.label}/${row.binary}`,
        row.available ? "ok" : "missing",
        row.version || row.path || row.workflowCoverage,
        row.available ? "可用于专业工作流" : row.installHint,
      ]
        .map(csvCell)
        .join(","),
    ),
    ...reviews.map((review) =>
      [
        "review",
        review.title,
        review.status,
        `rows=${review.rows.length}; fingerprint=${fnv1a32Fingerprint(review.json)}`,
        review.status === "ok" ? "审查通过，可纳入归档" : review.summary,
      ]
        .map(csvCell)
        .join(","),
    ),
  ].join("\n");
  const withoutArtifacts = {
    schema: "railwise.engineering.engineAcceptance.v1" as const,
    generatedAt,
    batchName,
    acceptanceStatus,
    acceptanceStatusLabel,
    binaryCount: preflight.binaryCount,
    availableBinaryCount: preflight.availableBinaryCount,
    missingBinaryCount: preflight.missingBinaryCount,
    plannedWorkflowCount,
    reviewCount: reviews.length,
    reviewIssueCount,
    preflightFingerprint: preflight.preflightFingerprint,
    reviewFingerprints,
  };
  const packageFingerprint = fnv1a32Fingerprint(JSON.stringify(withoutArtifacts));
  const missingRows = preflight.rows.filter((row) => !row.available);
  const markdown = [
    "# Railwise 工程专业引擎工作台验收",
    "",
    `Schema：railwise.engineering.engineAcceptance.v1`,
    `批次：${batchName}`,
    `生成时间：${generatedAt}`,
    `验收结论：${acceptanceStatus}`,
    `验收状态：${acceptanceStatusLabel}`,
    `二进制：${preflight.availableBinaryCount}/${preflight.binaryCount}`,
    `执行审查：${reviews.length}/${plannedWorkflowCount}`,
    `异常审查：${reviewIssueCount}`,
    "",
    "## 环境预检",
    "",
    "| 引擎 | 二进制 | 状态 | 版本/路径 | 处理建议 |",
    "| --- | --- | --- | --- | --- |",
    ...preflight.rows.map(
      (row) =>
        `| ${row.label} | ${row.binary} | ${row.available ? "ok" : "missing"} | ${
          row.version || row.path || ""
        } | ${row.available ? row.workflowCoverage : row.installHint} |`,
    ),
    "",
    "## 执行审查",
    "",
    reviews.length > 0
      ? reviews
          .map(
            (review) =>
              `- ${review.title}：${review.status}，成果行 ${review.rows.length}，指纹 ${fnv1a32Fingerprint(
                review.json,
              )}`,
          )
          .join("\n")
      : "- 尚未执行专业工作流审查。",
    "",
    "## 整改提示",
    "",
    missingRows.length > 0
      ? missingRows.map((row) => `- ${row.label}/${row.binary}：${row.installHint}`).join("\n")
      : "- 专业引擎二进制预检通过。",
    reviews.length < plannedWorkflowCount
      ? `- 尚有 ${plannedWorkflowCount - reviews.length} 个专业工作流未形成结构化审查。`
      : "- 专业工作流审查覆盖完整。",
    "",
    `预检指纹：${preflight.preflightFingerprint}`,
    `验收包指纹：${packageFingerprint}`,
  ].join("\n");
  const body = { ...withoutArtifacts, packageFingerprint, markdown, csv };
  return { ...body, json: JSON.stringify(body, null, 2) };
}

function appendEngineeringEngineReviewHistory(
  current: EngineeringEngineReview[],
  review: EngineeringEngineReview,
): EngineeringEngineReview[] {
  const withoutSameWorkflow = current.filter((item) => item.workflowId !== review.workflowId);
  return [...withoutSameWorkflow, review].slice(-ENGINEERING_ENGINE_WORKFLOWS.length);
}

export function buildEngineeringEngineShellCommand(plan: EngineeringEngineCommandPlan): string {
  const command = [plan.binary, ...plan.args].map(shellQuote).join(" ");
  if (!plan.stdin) return command;
  return `printf '%s\\n' ${shellQuote(plan.stdin)} | ${command}`;
}

function round(value: number, digits = 6): number {
  if (!Number.isFinite(value)) return value;
  const factor = 10 ** digits;
  return Math.round(value * factor) / factor;
}

function normalizeFullWidthAscii(value: string): string {
  return value
    .replace(/[\uFF01-\uFF5E]/g, (char) => String.fromCharCode(char.charCodeAt(0) - 0xfee0))
    .replace(/\u3000/g, " ");
}

function chainageFromText(value: unknown): number | null {
  if (typeof value !== "string") return null;
  const compact = normalizeFullWidthAscii(value)
    .trim()
    .replace(/[−–—]/g, "-")
    .replace(/,/g, "")
    .replace(/\s+/g, "")
    .replace(/(?:公尺|米|m)$/i, "");
  const match = compact.match(/^[A-Za-z\u4e00-\u9fa5]*(-?\d+(?:\.\d+)?)\+(-?\d+(?:\.\d+)?)$/);
  if (!match) return null;
  const kilometers = Number(match[1]);
  const meters = Number(match[2]);
  if (!Number.isFinite(kilometers) || !Number.isFinite(meters)) return null;
  return kilometers * 1000 + meters;
}

const NUMERIC_CELL_PATTERN =
  /^([+-]?(?:\d+(?:\.\d*)?|\.\d+))(?:mm\/d|毫米\/天|毫米\/d|mm|毫米|cm|厘米|km|千米|公里|m|米|公尺|kn|千牛|n|牛|mpa|gpa|pa|ppm|%|‰|°|度|秒|s|d|天|με|µε|μm|um)?$/i;

function numericCellFromText(value: unknown): number | null {
  if (typeof value === "number") return Number.isFinite(value) ? value : null;
  if (typeof value !== "string") return null;
  const compact = normalizeFullWidthAscii(value)
    .trim()
    .replace(/[−–—]/g, "-")
    .replace(/,/g, "")
    .replace(/\s+/g, "");
  if (!compact) return null;
  const match = compact.match(NUMERIC_CELL_PATTERN);
  if (!match) return null;
  const numeric = Number(match[1]);
  return Number.isFinite(numeric) ? numeric : null;
}

function isoDateFromParts(year: number, month: number, day: number): string | null {
  if (!Number.isInteger(year) || !Number.isInteger(month) || !Number.isInteger(day)) return null;
  if (year < 1900 || year > 2200 || month < 1 || month > 12 || day < 1 || day > 31) return null;
  const date = new Date(Date.UTC(year, month - 1, day));
  if (date.getUTCFullYear() !== year || date.getUTCMonth() !== month - 1 || date.getUTCDate() !== day) return null;
  return date.toISOString().slice(0, 10);
}

function fieldDateFromText(value: unknown): string | null {
  const numeric = numericCellFromText(value);
  if (numeric !== null && numeric >= 30000 && numeric <= 80000) {
    const excelEpoch = Date.UTC(1899, 11, 30);
    return new Date(excelEpoch + Math.floor(numeric) * 86_400_000).toISOString().slice(0, 10);
  }
  if (typeof value !== "string") return null;
  const raw = normalizeFullWidthAscii(value).trim();
  if (!raw) return null;
  const compact = raw.replace(/\s+/g, "");
  const chinese = compact.match(/^(\d{4})年(\d{1,2})月(\d{1,2})日?$/);
  if (chinese) {
    return isoDateFromParts(Number(chinese[1]), Number(chinese[2]), Number(chinese[3]));
  }
  const normalized = raw
    .replace(/[年月]/g, "-")
    .replace(/日/g, "")
    .replace(/[/.]/g, "-")
    .trim();
  const separated = normalized.match(/^(\d{4})-(\d{1,2})-(\d{1,2})(?:[T\s].*)?$/);
  if (separated) {
    return isoDateFromParts(Number(separated[1]), Number(separated[2]), Number(separated[3]));
  }
  const compactDate = compact.match(/^(\d{4})(\d{1,2})(\d{2})$/);
  if (compactDate) {
    return isoDateFromParts(Number(compactDate[1]), Number(compactDate[2]), Number(compactDate[3]));
  }
  return null;
}

function decimalDegreesFromDmsText(value: unknown): number | null {
  if (typeof value !== "string") return null;
  const raw = value.trim().replace(/,/g, "").replace(/[−–—]/g, "-");
  if (!raw) return null;
  const compact = raw.replace(/\s+/g, "");
  const dashed = compact.match(/^([+-]?)(\d+(?:\.\d+)?)-(\d+(?:\.\d+)?)(?:-(\d+(?:\.\d+)?))?$/);
  if (dashed) {
    const sign = dashed[1] === "-" ? -1 : 1;
    const degrees = Number(dashed[2]);
    const minutes = Number(dashed[3] ?? 0);
    const seconds = Number(dashed[4] ?? 0);
    if (![degrees, minutes, seconds].every(Number.isFinite) || Math.abs(minutes) >= 60 || Math.abs(seconds) >= 60) return null;
    return sign * (degrees + Math.abs(minutes) / 60 + Math.abs(seconds) / 3600);
  }
  if (!/[°º度′’'分″”"秒]/.test(raw)) return null;
  const parts = raw
    .replace(/[°º度]/g, " ")
    .replace(/[′’'分]/g, " ")
    .replace(/[″”"秒]/g, " ")
    .replace(/[：:]/g, " ")
    .trim()
    .split(/\s+/)
    .filter(Boolean)
    .map(Number);
  if (parts.length === 0 || parts.length > 3 || parts.some((part) => !Number.isFinite(part))) return null;
  const [degrees = 0, minutes = 0, seconds = 0] = parts;
  if (Math.abs(minutes) >= 60 || Math.abs(seconds) >= 60) return null;
  const sign = degrees < 0 ? -1 : 1;
  return degrees + sign * (Math.abs(minutes) / 60 + Math.abs(seconds) / 3600);
}

function bearingComponentDegreesFromText(value: string): number | null {
  const parsed = decimalDegreesFromDmsText(value) ?? numericCellFromText(value);
  if (parsed === null || !Number.isFinite(parsed)) return null;
  const abs = Math.abs(parsed);
  return abs <= 90 ? abs : null;
}

function quadrantBearingDegreesFromText(value: unknown): number | null {
  if (typeof value !== "string") return null;
  const compact = normalizeFullWidthAscii(value)
    .trim()
    .replace(/[−–—]/g, "-")
    .replace(/,/g, "")
    .replace(/\s+/g, "")
    .toUpperCase();
  if (!compact) return null;

  const english = compact.match(/^([NS])(.+)([EW])$/);
  if (english) {
    const angle = bearingComponentDegreesFromText(english[2] ?? "");
    if (angle === null) return null;
    const ns = english[1];
    const ew = english[3];
    if (ns === "N" && ew === "E") return angle;
    if (ns === "N" && ew === "W") return normalizeDegrees(360 - angle);
    if (ns === "S" && ew === "E") return normalizeDegrees(180 - angle);
    if (ns === "S" && ew === "W") return normalizeDegrees(180 + angle);
  }

  const chinesePrefix = compact.match(/^([北南])偏?([东西])(.+)$/);
  const chineseWrapped = compact.match(/^([北南])(.+)偏?([东西])$/);
  const chinese = chinesePrefix
    ? { ns: chinesePrefix[1], ew: chinesePrefix[2], angleText: chinesePrefix[3] }
    : chineseWrapped
      ? { ns: chineseWrapped[1], ew: chineseWrapped[3], angleText: chineseWrapped[2] }
      : null;
  if (!chinese) return null;
  const angle = bearingComponentDegreesFromText(chinese.angleText ?? "");
  if (angle === null) return null;
  if (chinese.ns === "北" && chinese.ew === "东") return angle;
  if (chinese.ns === "北" && chinese.ew === "西") return normalizeDegrees(360 - angle);
  if (chinese.ns === "南" && chinese.ew === "东") return normalizeDegrees(180 - angle);
  if (chinese.ns === "南" && chinese.ew === "西") return normalizeDegrees(180 + angle);
  return null;
}

function numberFrom(value: unknown, fallback = 0): number {
  const chainage = chainageFromText(value);
  if (chainage !== null) return chainage;
  const quadrantBearingDegrees = quadrantBearingDegreesFromText(value);
  if (quadrantBearingDegrees !== null) return quadrantBearingDegrees;
  const dmsDegrees = decimalDegreesFromDmsText(value);
  if (dmsDegrees !== null) return dmsDegrees;
  const numeric = numericCellFromText(value);
  return numeric !== null ? numeric : fallback;
}

function textFrom(value: unknown, fallback: string): string {
  return typeof value === "string" && value.trim() ? value.trim() : fallback;
}

function objectFrom(value: unknown): Record<string, unknown> {
  return value && typeof value === "object" && !Array.isArray(value)
    ? (value as Record<string, unknown>)
    : {};
}

function arrayFrom(value: unknown): unknown[] {
  return Array.isArray(value) ? value : [];
}

type SurveyAdjustmentWorkbenchToolId = Extract<EngineeringToolId, "traverse_adjustment" | "level_adjustment">;

type SurveyAdjustmentIpcRequest = {
  tool: "traverse_adjust" | "level_adjust";
  input: Record<string, unknown>;
};

function primitiveFromUnknown(value: unknown): Primitive {
  if (typeof value === "string" || typeof value === "number" || typeof value === "boolean" || value === null) {
    return value;
  }
  if (value === undefined) return null;
  return JSON.stringify(value);
}

function primitiveRecordFromUnknown(value: unknown): Record<string, Primitive> {
  const obj = objectFrom(value);
  return Object.fromEntries(Object.entries(obj).map(([key, item]) => [key, primitiveFromUnknown(item)]));
}

function buildSurveyTraverseAdjustmentInput(input: unknown): SurveyAdjustmentIpcRequest {
  const obj = objectFrom(input);
  const params = objectFrom(obj.params);
  const knownPoints = arrayFrom(obj.knownPoints ?? obj.known_points ?? obj.fixedPoints)
    .map((item, index) => {
      const point = objectFrom(item);
      return {
        name: traversePointName(point, `P${index + 1}`),
        x: numberFrom(point.x, Number.NaN),
        y: numberFrom(point.y, Number.NaN),
        fixed: point.fixed !== false,
      };
    })
    .filter((point) => point.name && Number.isFinite(point.x) && Number.isFinite(point.y));
  const observations = arrayFrom(obj.observations ?? obj.traverseObservations)
    .map((item) => {
      const observation = objectFrom(item);
      const horizontalDistM = numberFrom(
        observation.horizontalDistM ??
          observation.horizontalDistanceM ??
          observation.horizontal_dist_m ??
          observation.distanceM,
        Number.NaN,
      );
      const slopeDistM = numberFrom(
        observation.slopeDistM ?? observation.slope_dist_m ?? observation.slopeDistanceM,
        Number.NaN,
      );
      const zenithDeg = numberFrom(observation.zenithDeg ?? observation.zenith_deg, Number.NaN);
      return {
        from: textFrom(observation.from ?? observation.station ?? observation.fromId, ""),
        to: textFrom(observation.to ?? observation.target ?? observation.toId, ""),
        hz_angle_deg: numberFrom(
          observation.hzAngleDeg ?? observation.hz_angle_deg ?? observation.horizontalAngleDeg,
          Number.NaN,
        ),
        ...(Number.isFinite(horizontalDistM) ? { horizontal_dist_m: horizontalDistM } : {}),
        ...(Number.isFinite(slopeDistM) ? { slope_dist_m: slopeDistM } : {}),
        ...(Number.isFinite(zenithDeg) ? { zenith_deg: zenithDeg } : {}),
      };
    })
    .filter(
      (observation) =>
        observation.from &&
        observation.to &&
        Number.isFinite(observation.hz_angle_deg) &&
        (Number.isFinite(observation.horizontal_dist_m ?? Number.NaN) ||
          Number.isFinite(observation.slope_dist_m ?? Number.NaN)),
    );
  return {
    tool: "traverse_adjust",
    input: {
      known_points: knownPoints,
      observations,
      params: {
        start_azimuth_deg: numberFrom(params.startAzimuthDeg ?? params.start_azimuth_deg ?? obj.startAzimuthDeg, 0),
        end_azimuth_deg: numberFrom(params.endAzimuthDeg ?? params.end_azimuth_deg ?? obj.endAzimuthDeg, 0),
        dir_mse_sec: numberFrom(params.dirMseSec ?? params.dir_mse_sec, 2),
        dist_fixed_mm: numberFrom(params.distFixedMm ?? params.dist_fixed_mm, 1),
        ppm: numberFrom(params.ppm, 1),
        refraction: numberFrom(params.refraction, 0.14),
        ellipsoid_r: numberFrom(params.ellipsoidR ?? params.ellipsoid_r, 6371000),
        height_projection: params.heightProjection !== false && params.height_projection !== false,
        model: textFrom(params.model, "normal"),
      },
    },
  };
}

function buildSurveyLevelAdjustmentInput(input: unknown): SurveyAdjustmentIpcRequest {
  const obj = objectFrom(input);
  const knownBms = arrayFrom(obj.knownBms ?? obj.known_bms ?? obj.benchmarks ?? obj.knownPoints)
    .map((item, index) => {
      const point = objectFrom(item);
      return {
        name: levelAdjustmentPointName(point, `BM${index + 1}`),
        h: numberFrom(point.h ?? point.height ?? point.elevation ?? point.elevationM, Number.NaN),
        fixed: point.fixed !== false,
      };
    })
    .filter((point) => point.name && Number.isFinite(point.h));
  const segments = arrayFrom(obj.segments ?? obj.levelSegments ?? obj.observations)
    .map((item) => {
      const segment = objectFrom(item);
      const lengthKm = numberFrom(segment.lengthKm ?? segment.length_km ?? segment.routeLengthKm, Number.NaN);
      const nStations = numberFrom(segment.nStations ?? segment.n_stations ?? segment.stationCount, Number.NaN);
      const forwardDhM = numberFrom(segment.forwardDhM ?? segment.forward_dh_m ?? segment.forwardHeightDiffM ?? segment.forwardDh, Number.NaN);
      const backwardDhM = numberFrom(segment.backwardDhM ?? segment.backward_dh_m ?? segment.returnHeightDiffM ?? segment.returnDhM ?? segment.backwardDh, Number.NaN);
      const baselineDhM = numberFrom(segment.baselineDhM ?? segment.baseline_dh_m ?? segment.previousDhM ?? segment.previous_dh_m ?? segment.基准高差, Number.NaN);
      const resurveyDhM = numberFrom(segment.resurveyDhM ?? segment.resurvey_dh_m ?? segment.currentDhM ?? segment.current_dh_m ?? segment.复测高差, Number.NaN);
      return {
        from: textFrom(segment.from ?? segment.start ?? segment.fromId, ""),
        to: textFrom(segment.to ?? segment.end ?? segment.toId, ""),
        dh_m: numberFrom(
          segment.dhM ?? segment.dh_m ?? segment.heightDiffM ?? segment.heightDifferenceM ?? segment.dh,
          Number.NaN,
        ),
        ...(Number.isFinite(lengthKm) ? { length_km: lengthKm } : {}),
        ...(Number.isFinite(nStations) ? { n_stations: nStations } : {}),
        ...(Number.isFinite(forwardDhM) ? { forward_dh_m: forwardDhM } : {}),
        ...(Number.isFinite(backwardDhM) ? { backward_dh_m: backwardDhM } : {}),
        ...(Number.isFinite(baselineDhM) ? { baseline_dh_m: baselineDhM } : {}),
        ...(Number.isFinite(resurveyDhM) ? { resurvey_dh_m: resurveyDhM } : {}),
      };
    })
    .filter((segment) => segment.from && segment.to && Number.isFinite(segment.dh_m));
  const rawWeightMode = textFrom(obj.weightMode ?? obj.weight_mode, "length").toLowerCase();
  const order = levelAdjustmentOrderFrom(obj.order ?? obj.levelOrder ?? obj.level_order ?? obj.等级 ?? obj["水准等级"]);
  const reciprocalToleranceMmPerSqrtKm = numberFrom(
    obj.reciprocalToleranceMmPerSqrtKm ?? obj.reciprocal_tolerance_mm_per_sqrt_km ?? obj.往返高差限差系数,
    Number.NaN,
  );
  const closureToleranceMmPerSqrtKm = numberFrom(
    obj.closureToleranceMmPerSqrtKm ?? obj.closure_tolerance_mm_per_sqrt_km ?? obj.路线闭合差限差系数,
    Number.NaN,
  );
  const resurveyDiffToleranceMmPerSqrtKm = numberFrom(
    obj.resurveyDiffToleranceMmPerSqrtKm ?? obj.resurvey_diff_tolerance_mm_per_sqrt_km ?? obj.CP复测高差限差系数,
    Number.NaN,
  );
  return {
    tool: "level_adjust",
    input: {
      known_bms: knownBms,
      segments,
      weight_mode: rawWeightMode.includes("station") || rawWeightMode.includes("测站") ? "stations" : "length",
      order,
      ...(Number.isFinite(reciprocalToleranceMmPerSqrtKm)
        ? { reciprocal_tolerance_mm_per_sqrt_km: reciprocalToleranceMmPerSqrtKm }
        : {}),
      ...(Number.isFinite(closureToleranceMmPerSqrtKm)
        ? { closure_tolerance_mm_per_sqrt_km: closureToleranceMmPerSqrtKm }
        : {}),
      ...(Number.isFinite(resurveyDiffToleranceMmPerSqrtKm)
        ? { resurvey_diff_tolerance_mm_per_sqrt_km: resurveyDiffToleranceMmPerSqrtKm }
        : {}),
    },
  };
}

function buildSurveyAdjustmentIpcRequest(
  toolId: EngineeringToolId,
  input: unknown,
): SurveyAdjustmentIpcRequest | null {
  if (toolId === "traverse_adjustment") return buildSurveyTraverseAdjustmentInput(input);
  if (toolId === "level_adjustment") return buildSurveyLevelAdjustmentInput(input);
  return null;
}

function surveyAdjustmentSummary(toolId: SurveyAdjustmentWorkbenchToolId, payload: Record<string, unknown>): string {
  if (toolId === "level_adjustment") {
    return `水准内业平差完成：本地 survey-mcp 返回 ${numberFrom(payload.known_bm_count)} 个已知水准点、${numberFrom(
      payload.unknown_point_count,
    )} 个待定点、${numberFrom(payload.segment_count)} 条测段。`;
  }
  return `导线内业平差完成：本地 survey-mcp 返回 ${numberFrom(payload.observation_count)} 站、全长 ${round(
    numberFrom(payload.total_distance_m),
    3,
  )} m。`;
}

function surveyAdjustmentResultFromIpc(
  toolId: SurveyAdjustmentWorkbenchToolId,
  payload: unknown,
): EngineeringResult {
  const obj = objectFrom(payload);
  const closures = objectFrom(obj.closures);
  const metrics: Record<string, Primitive> = {
    calculation_source: "survey_mcp_ipc",
    adjustment_model: textFrom(obj.method, toolId),
  };
  for (const [key, value] of Object.entries(obj)) {
    if (key === "export_rows" || key === "points" || key === "segment_table" || key === "log" || key === "closures") {
      continue;
    }
    metrics[key] = primitiveFromUnknown(value);
  }
  for (const [key, value] of Object.entries(closures)) {
    metrics[key] = primitiveFromUnknown(value);
  }
  const rows = arrayFrom(obj.export_rows).map(primitiveRecordFromUnknown);
  const log = arrayFrom(obj.log).map((item) => String(item)).filter(Boolean);
  return resultFor(
    toolId,
    "ok",
    surveyAdjustmentSummary(toolId, obj),
    metrics,
    rows,
    log.length > 0 ? log : ["已通过本地 survey-mcp 完成内业平差计算。"],
    { algorithm: textFrom(obj.method, toolId) },
  );
}

function pointFrom(value: unknown): Point3 {
  const obj = objectFrom(value);
  return {
    x: numberFrom(obj.x),
    y: numberFrom(obj.y),
    z: obj.z === undefined ? undefined : numberFrom(obj.z),
  };
}

function finiteNumber(value: unknown): value is number {
  return typeof value === "number" && Number.isFinite(value);
}

function point2From(value: unknown): Point2 {
  const point = pointFrom(value);
  return { x: point.x, y: point.y };
}

function normalizeDegrees(degrees: number): number {
  return ((degrees % 360) + 360) % 360;
}

function deltaDegrees(actual: number, design: number): number {
  const diff = ((actual - design + 540) % 360) - 180;
  return round(diff, 9);
}

function radiansToDegrees(value: number): number {
  return (value * 180) / Math.PI;
}

function degreesToRadians(value: number): number {
  return (value * Math.PI) / 180;
}

const ARC_SECONDS_PER_RADIAN = 206264.80624709636;
const TRAVERSE_PRECISION_MODEL = "direction_distance_error_propagation";

function traversePrecisionFromCovariance(
  varX: number,
  varY: number,
  covXY: number,
  fallbackThetaDeg: number,
): TraversePointPrecision {
  const cleanVarX = Math.max(varX, 0);
  const cleanVarY = Math.max(varY, 0);
  const trace = cleanVarX + cleanVarY;
  const halfDiff = (cleanVarX - cleanVarY) / 2;
  const radius = Math.sqrt(halfDiff * halfDiff + covXY * covXY);
  const majorVariance = Math.max(trace / 2 + radius, 0);
  const minorVariance = Math.max(trace / 2 - radius, 0);
  const theta =
    Math.abs(covXY) < 1e-18 && Math.abs(cleanVarX - cleanVarY) < 1e-18
      ? fallbackThetaDeg
      : radiansToDegrees(0.5 * Math.atan2(2 * covXY, cleanVarX - cleanVarY));
  return {
    mxMm: round(Math.sqrt(cleanVarX) * 1000, 3),
    myMm: round(Math.sqrt(cleanVarY) * 1000, 3),
    pointMseMm: round(Math.sqrt(cleanVarX + cleanVarY) * 1000, 3),
    semiMajorMm: round(Math.sqrt(majorVariance) * 1000, 3),
    semiMinorMm: round(Math.sqrt(minorVariance) * 1000, 3),
    thetaDeg: round(normalizeDegrees(theta), 6),
  };
}

function traversePointPrecisions(
  distances: number[],
  azimuths: number[],
  params: Record<string, unknown>,
  closureVarianceM2: number,
): TraversePointPrecision[] {
  const directionMseSec = Math.max(Math.abs(numberFrom(params.dirMseSec ?? params.dir_mse_sec, 1)), 0);
  const distanceFixedM = Math.max(Math.abs(numberFrom(params.distFixedMm ?? params.dist_fixed_mm, 1)), 0) / 1000;
  const ppm = Math.max(Math.abs(numberFrom(params.ppm, 1)), 0);
  let cumulativeVarX = 0;
  let cumulativeVarY = 0;
  let cumulativeCovXY = 0;
  return distances.map((distance, index) => {
    const azimuthRad = degreesToRadians(azimuths[index] ?? 0);
    const sinA = Math.sin(azimuthRad);
    const cosA = Math.cos(azimuthRad);
    const distanceStdM = Math.hypot(distanceFixedM, (ppm * distance) / 1_000_000);
    const directionStdRad = (directionMseSec / ARC_SECONDS_PER_RADIAN) * Math.sqrt(index + 1);
    const distanceVariance = distanceStdM * distanceStdM;
    const directionVariance = directionStdRad * directionStdRad;
    cumulativeVarX += sinA * sinA * distanceVariance + distance * distance * cosA * cosA * directionVariance;
    cumulativeVarY += cosA * cosA * distanceVariance + distance * distance * sinA * sinA * directionVariance;
    cumulativeCovXY += sinA * cosA * distanceVariance - distance * distance * sinA * cosA * directionVariance;
    return traversePrecisionFromCovariance(
      cumulativeVarX + closureVarianceM2,
      cumulativeVarY + closureVarianceM2,
      cumulativeCovXY,
      azimuths[index] ?? 0,
    );
  });
}

function azimuthDegrees(from: Point3, to: Point3): number {
  return normalizeDegrees(radiansToDegrees(Math.atan2(to.x - from.x, to.y - from.y)));
}

function methodFor(toolId: EngineeringToolId, overrides: Partial<EngineeringMethod> = {}): EngineeringMethod {
  const base = TOOL_METHODS[toolId];
  return {
    algorithm: overrides.algorithm ?? base.algorithm,
    dataFormats: overrides.dataFormats ?? base.dataFormats,
    workflow: overrides.workflow ?? base.workflow,
    qualityChecks: overrides.qualityChecks ?? base.qualityChecks,
    deliverables: overrides.deliverables ?? base.deliverables,
    references: overrides.references ?? base.references,
  };
}

function statusFromWarnings(warnings: string[]): EngineeringStatus {
  return warnings.length > 0 ? "warn" : "ok";
}

function resultFor(
  toolId: EngineeringToolId,
  status: EngineeringStatus,
  summary: string,
  metrics: Record<string, Primitive>,
  rows: Array<Record<string, Primitive>>,
  recommendations: string[],
  methodOverrides: Partial<EngineeringMethod> = {},
): EngineeringResult {
  return {
    toolId,
    title: TOOL_BY_ID.get(toolId)?.title ?? toolId,
    status,
    summary,
    metrics,
    rows,
    recommendations,
    method: methodFor(toolId, methodOverrides),
  };
}

function unsupportedEngineeringToolResult(toolId: string): EngineeringResult {
  return {
    toolId: toolId as EngineeringToolId,
    title: toolId,
    status: "error",
    summary: `当前工程分析工具不支持：${toolId}。`,
    metrics: {},
    rows: [],
    recommendations: ["请选择轨道、交通、铁路、测量或监测类工具后重新计算。"],
    method: {
      algorithm: "unsupported",
      dataFormats: [],
      workflow: [],
      qualityChecks: ["工具必须属于当前 Railwise 专业工具集"],
      deliverables: [],
      references: [],
    },
  };
}

function transformPoint2d(params: Helmert2D, point: Point2): Point2 {
  return {
    x: params.tx + params.a * point.x - params.b * point.y,
    y: params.ty + params.b * point.x + params.a * point.y,
  };
}

function helmertFromParameters(params: Record<string, unknown>): Helmert2D {
  const tx = numberFrom(params.tx);
  const ty = numberFrom(params.ty);
  const rotationDeg = numberFrom(params.rotationDeg);
  const scale = 1 + numberFrom(params.scalePpm) / 1_000_000;
  const rotation = degreesToRadians(rotationDeg);
  const a = scale * Math.cos(rotation);
  const b = scale * Math.sin(rotation);
  return {
    tx,
    ty,
    a,
    b,
    scale,
    rotationDeg,
    scalePpm: (scale - 1) * 1_000_000,
  };
}

function fitHelmert2d(
  pairs: Array<{ id: string; source: Point2; target: Point2; weight: number }>,
): Helmert2DFit | null {
  if (pairs.length < 2) return null;
  const weightSum = pairs.reduce((sum, pair) => sum + pair.weight, 0);
  if (weightSum <= 0) return null;

  const sourceCenter = {
    x: pairs.reduce((sum, pair) => sum + pair.source.x * pair.weight, 0) / weightSum,
    y: pairs.reduce((sum, pair) => sum + pair.source.y * pair.weight, 0) / weightSum,
  };
  const targetCenter = {
    x: pairs.reduce((sum, pair) => sum + pair.target.x * pair.weight, 0) / weightSum,
    y: pairs.reduce((sum, pair) => sum + pair.target.y * pair.weight, 0) / weightSum,
  };

  let denominator = 0;
  let aNumerator = 0;
  let bNumerator = 0;
  for (const pair of pairs) {
    const sx = pair.source.x - sourceCenter.x;
    const sy = pair.source.y - sourceCenter.y;
    const tx = pair.target.x - targetCenter.x;
    const ty = pair.target.y - targetCenter.y;
    denominator += pair.weight * (sx * sx + sy * sy);
    aNumerator += pair.weight * (tx * sx + ty * sy);
    bNumerator += pair.weight * (ty * sx - tx * sy);
  }
  if (denominator <= 1e-12) return null;

  const a = aNumerator / denominator;
  const b = bNumerator / denominator;
  const scale = Math.hypot(a, b);
  const rotationDeg = radiansToDegrees(Math.atan2(b, a));
  const params: Helmert2D = {
    a,
    b,
    scale,
    rotationDeg,
    scalePpm: (scale - 1) * 1_000_000,
    tx: targetCenter.x - a * sourceCenter.x + b * sourceCenter.y,
    ty: targetCenter.y - b * sourceCenter.x - a * sourceCenter.y,
  };

  const residuals = pairs.map((pair) => {
    const transformed = transformPoint2d(params, pair.source);
    const dxMm = (transformed.x - pair.target.x) * 1000;
    const dyMm = (transformed.y - pair.target.y) * 1000;
    return {
      id: pair.id,
      dxMm,
      dyMm,
      planarMm: Math.hypot(dxMm, dyMm),
    };
  });
  const rmsMm =
    residuals.length > 0
      ? Math.sqrt(residuals.reduce((sum, item) => sum + item.planarMm ** 2, 0) / residuals.length)
      : 0;
  const maxResidualMm = residuals.reduce((max, item) => Math.max(max, item.planarMm), 0);
  return { params, residuals, rmsMm, maxResidualMm };
}

function diagnoseDatumControlStability(
  pairs: Array<{ id: string; source: Point2; target: Point2; weight: number }>,
  fit: Helmert2DFit,
  toleranceMm: number,
): DatumControlDiagnosis[] {
  const residualRanks = new Map(
    [...fit.residuals]
      .sort((a, b) => b.planarMm - a.planarMm)
      .map((residual, index) => [residual.id, index + 1]),
  );

  return fit.residuals.map((residual) => {
    const leaveOneOutFit = fitHelmert2d(pairs.filter((pair) => pair.id !== residual.id));
    const leaveOneOutRmsMm = leaveOneOutFit?.rmsMm ?? null;
    const leaveOneOutMaxResidualMm = leaveOneOutFit?.maxResidualMm ?? null;
    const settlesRemaining = leaveOneOutMaxResidualMm !== null && leaveOneOutMaxResidualMm <= toleranceMm;
    const improvesRms = leaveOneOutRmsMm !== null && leaveOneOutRmsMm < fit.rmsMm * 0.5;
    const isCandidate = residual.planarMm > toleranceMm && settlesRemaining && improvesRms;
    return {
      id: residual.id,
      residualRank: residualRanks.get(residual.id) ?? 0,
      leaveOneOutRmsMm,
      leaveOneOutMaxResidualMm,
      stabilityDiagnosis: isCandidate ? "candidate_unstable" : residual.planarMm > toleranceMm ? "review" : "stable",
    };
  });
}

function normalizeRadians(value: number): number {
  const full = Math.PI * 2;
  return ((value % full) + full) % full;
}

function deltaRadians(actual: number, design: number): number {
  const full = Math.PI * 2;
  return ((actual - design + Math.PI + full) % full) - Math.PI;
}

function solveLinearSystem(matrix: number[][], vector: number[]): number[] | null {
  const size = vector.length;
  if (matrix.length !== size || matrix.some((row) => row.length !== size)) return null;
  const augmented = matrix.map((row, rowIndex) => [...row, vector[rowIndex] ?? 0]);

  for (let pivotIndex = 0; pivotIndex < size; pivotIndex += 1) {
    let best = pivotIndex;
    for (let row = pivotIndex + 1; row < size; row += 1) {
      if (Math.abs(augmented[row]![pivotIndex] ?? 0) > Math.abs(augmented[best]![pivotIndex] ?? 0)) {
        best = row;
      }
    }
    const pivot = augmented[best]![pivotIndex] ?? 0;
    if (Math.abs(pivot) < 1e-14) return null;
    if (best !== pivotIndex) {
      const swap = augmented[pivotIndex]!;
      augmented[pivotIndex] = augmented[best]!;
      augmented[best] = swap;
    }

    for (let column = pivotIndex; column <= size; column += 1) {
      augmented[pivotIndex]![column] = (augmented[pivotIndex]![column] ?? 0) / pivot;
    }
    for (let row = 0; row < size; row += 1) {
      if (row === pivotIndex) continue;
      const factor = augmented[row]![pivotIndex] ?? 0;
      if (Math.abs(factor) < 1e-18) continue;
      for (let column = pivotIndex; column <= size; column += 1) {
        augmented[row]![column] = (augmented[row]![column] ?? 0) - factor * (augmented[pivotIndex]![column] ?? 0);
      }
    }
  }

  return augmented.map((row) => row[size] ?? 0);
}

function invertMatrix(matrix: number[][]): number[][] | null {
  const size = matrix.length;
  const inverse: number[][] = Array.from({ length: size }, () => Array.from({ length: size }, () => 0));
  for (let column = 0; column < size; column += 1) {
    const unit = Array.from({ length: size }, (_, index) => (index === column ? 1 : 0));
    const solved = solveLinearSystem(matrix, unit);
    if (!solved) return null;
    for (let row = 0; row < size; row += 1) {
      inverse[row]![column] = solved[row] ?? 0;
    }
  }
  return inverse;
}

function parseControlNetworkPoints(value: unknown): ControlNetworkPoint[] {
  return arrayFrom(value)
    .map((item, index) => {
      const point = objectFrom(item);
      return {
        id: textFrom(point.id ?? point.pointId ?? point.name, `P${index + 1}`),
        x: numberFrom(point.x, Number.NaN),
        y: numberFrom(point.y, Number.NaN),
        z: numberFrom(point.z ?? point.elevation ?? point.elevationM ?? point.height ?? point.h, Number.NaN),
      };
    })
    .filter((point) => point.id && ((Number.isFinite(point.x) && Number.isFinite(point.y)) || Number.isFinite(point.z)));
}

function controlObservationType(obs: Record<string, unknown>): ControlNetworkObservationKind | null {
  const raw = textFrom(obs.type ?? obs.kind ?? obs.observationType, "").toLowerCase();
  if (
    raw.includes("dist") ||
    raw.includes("distance") ||
    raw.includes("距") ||
    raw.includes("测边") ||
    raw.includes("边长") ||
    raw.includes("平距") ||
    raw.includes("斜距")
  ) return "distance";
  if (raw.includes("azimuth") || raw.includes("bearing") || raw.includes("方位")) {
    return "azimuth";
  }
  if (
    obs.distanceM !== undefined ||
    obs.distance !== undefined ||
    obs.horizontalDistanceM !== undefined ||
    obs.horizontalDistance !== undefined ||
    obs.measuredDistanceM !== undefined ||
    obs.observedDistanceM !== undefined ||
    obs.sideLengthM !== undefined ||
    obs.edgeLengthM !== undefined
  ) return "distance";
  if (obs.azimuthDeg !== undefined || obs.azimuthDegrees !== undefined || obs.bearingDeg !== undefined) return "azimuth";
  return null;
}

const CONTROL_SLOPE_DISTANCE_ALIASES = [
  "slopeDistanceM",
  "slopeDistance",
  "measuredSlopeDistanceM",
  "measuredSlopeDistance",
  "斜距",
  "斜距m",
  "实测斜距",
  "实测斜距m",
];

const CONTROL_VERTICAL_ANGLE_ALIASES = [
  "verticalAngleDegrees",
  "verticalAngleDeg",
  "verticalAngle",
  "vAngle",
  "elevationAngleDegrees",
  "elevationAngle",
  "垂直角",
  "竖直角",
  "高低角",
  "仰角",
];

const CONTROL_ZENITH_ANGLE_ALIASES = [
  "zenithAngleDegrees",
  "zenithAngleDeg",
  "zenithAngle",
  "zenithDistance",
  "zAngle",
  "天顶距",
  "天顶角",
  "竖盘读数",
];

const CONTROL_INSTRUMENT_HEIGHT_ALIASES = [
  "instrumentHeightM",
  "instrumentHeight",
  "heightOfInstrumentM",
  "heightOfInstrument",
  "hi",
  "仪器高",
  "仪器高m",
  "仪高",
  "仪高m",
];

const CONTROL_TARGET_HEIGHT_ALIASES = [
  "targetHeightM",
  "targetHeight",
  "prismHeightM",
  "prismHeight",
  "reflectorHeightM",
  "reflectorHeight",
  "棱镜高",
  "棱镜高m",
  "镜高",
  "镜高m",
  "目标高",
  "目标高m",
];

function horizontalDistanceFromSlopeDistance(
  slopeDistanceM: number,
  verticalAngleDegrees: number,
  zenithAngleDegrees: number,
): number {
  if (!Number.isFinite(slopeDistanceM)) return Number.NaN;
  if (Number.isFinite(verticalAngleDegrees)) {
    return Math.abs(slopeDistanceM * Math.cos(degreesToRadians(verticalAngleDegrees)));
  }
  if (Number.isFinite(zenithAngleDegrees)) {
    return Math.abs(slopeDistanceM * Math.sin(degreesToRadians(zenithAngleDegrees)));
  }
  return Number.NaN;
}

function heightDifferenceFromTrigonometricObservation(
  slopeDistanceM: number,
  verticalAngleDegrees: number,
  zenithAngleDegrees: number,
  instrumentHeightM: number,
  targetHeightM: number,
): number {
  if (!Number.isFinite(slopeDistanceM)) return Number.NaN;
  let verticalComponentM = Number.NaN;
  if (Number.isFinite(verticalAngleDegrees)) {
    verticalComponentM = slopeDistanceM * Math.sin(degreesToRadians(verticalAngleDegrees));
  } else if (Number.isFinite(zenithAngleDegrees)) {
    verticalComponentM = slopeDistanceM * Math.cos(degreesToRadians(zenithAngleDegrees));
  }
  if (!Number.isFinite(verticalComponentM)) return Number.NaN;
  return (
    verticalComponentM +
    (Number.isFinite(instrumentHeightM) ? instrumentHeightM : 0) -
    (Number.isFinite(targetHeightM) ? targetHeightM : 0)
  );
}

function parseControlNetworkObservation(item: unknown, index: number): ControlNetworkObservation | null {
  const obs = objectFrom(item);
  const type = controlObservationType(obs);
  if (!type) return null;
  const from = textFrom(obs.from ?? obs.fromId ?? obs.station ?? obs.start, "");
  const to = textFrom(obs.to ?? obs.toId ?? obs.target ?? obs.end, "");
  if (!from || !to || from === to) return null;
  const slopeDistanceM = numberByAliases(obs, CONTROL_SLOPE_DISTANCE_ALIASES, Number.NaN);
  const verticalAngleDegrees = numberByAliases(obs, CONTROL_VERTICAL_ANGLE_ALIASES, Number.NaN);
  const zenithAngleDegrees = numberByAliases(obs, CONTROL_ZENITH_ANGLE_ALIASES, Number.NaN);
  const horizontalDistanceM = horizontalDistanceFromSlopeDistance(
    slopeDistanceM,
    verticalAngleDegrees,
    zenithAngleDegrees,
  );
  const explicitDistanceM = numberFrom(
    obs.value ??
      obs.distanceM ??
      obs.distance ??
      obs.horizontalDistanceM ??
      obs.horizontalDistance ??
      obs.measuredDistanceM ??
      obs.observedDistanceM ??
      obs.sideLengthM ??
      obs.edgeLengthM,
    Number.NaN,
  );
  const value =
    type === "distance"
      ? Number.isFinite(explicitDistanceM)
        ? explicitDistanceM
        : Number.isFinite(horizontalDistanceM)
          ? horizontalDistanceM
          : slopeDistanceM
      : numberFrom(
          obs.value ??
            obs.azimuthDegrees ??
            obs.azimuthDeg ??
            obs.bearingDegrees ??
            obs.bearingDeg ??
            obs.coordinateAzimuthDegrees ??
            obs.coordinateAzimuthDeg ??
            obs.coordinateAzimuth ??
            obs.directionDegrees ??
            obs.directionDeg,
          Number.NaN,
        );
  if (!Number.isFinite(value)) return null;

  const sigma =
    type === "distance"
      ? numberFrom(obs.sigmaM ?? obs.stdM, Number.NaN) ||
        numberFrom(obs.sigmaMm ?? obs.stdMm, Number.NaN) / 1000 ||
        (Number.isFinite(numberFrom(obs.weight, Number.NaN)) ? 1 / Math.sqrt(Math.max(0.0001, numberFrom(obs.weight))) : 0.003)
      : numberFrom(obs.sigmaRadians ?? obs.stdRadians, Number.NaN) ||
        degreesToRadians(numberFrom(obs.sigmaDegrees ?? obs.sigmaDeg ?? obs.stdDegrees ?? obs.stdDeg, Number.NaN)) ||
        degreesToRadians(numberFrom(obs.sigmaArcSec ?? obs.stdArcSec, Number.NaN) / 3600) ||
        (Number.isFinite(numberFrom(obs.weight, Number.NaN)) ? 1 / Math.sqrt(Math.max(0.0001, numberFrom(obs.weight))) : degreesToRadians(5 / 3600));

  return {
    id: textFrom(obs.id ?? obs.name, `OBS${index + 1}`),
    type,
    from,
    to,
    observed: type === "distance" ? value : normalizeRadians(degreesToRadians(value)),
    sigma: Math.max(1e-12, sigma),
  };
}

function isControlDirectionObservationType(value: unknown): boolean {
  const raw = textFrom(value, "").toLowerCase();
  return (
    raw.includes("direction") ||
    raw.includes("dirset") ||
    raw.includes("horizontal") ||
    raw.includes("方向") ||
    raw.includes("水平角") ||
    raw.includes("角度")
  );
}

function directionFaceFrom(value: unknown): "left" | "right" | undefined {
  const raw = textFrom(value, "").toLowerCase();
  if (!raw) return undefined;
  if (["left", "l", "fl", "face1", "faceleft", "盘左", "正镜"].includes(raw)) return "left";
  if (["right", "r", "fr", "face2", "faceright", "盘右", "倒镜"].includes(raw)) return "right";
  return undefined;
}

function parseControlDirectionObservation(item: unknown, index: number): ControlDirectionObservation | null {
  const obs = objectFrom(item);
  if (!isControlDirectionObservationType(obs.type ?? obs.kind ?? obs.observationType)) return null;
  const from = textFrom(obs.from ?? obs.fromId ?? obs.station ?? obs.start, "");
  const to = textFrom(obs.to ?? obs.toId ?? obs.target ?? obs.end, "");
  if (!from || !to || from === to) return null;
  const value = numberFrom(
    obs.value ??
      obs.directionDegrees ??
      obs.directionDeg ??
      obs.horizontalDirectionDegrees ??
      obs.horizontalDirectionDeg ??
      obs.readingDegrees ??
      obs.readingDeg,
    Number.NaN,
  );
  if (!Number.isFinite(value)) return null;
  const face = directionFaceFrom(obs.face ?? obs.facePosition ?? obs.position ?? obs.plate ?? obs.盘位);
  const rawObserved = normalizeRadians(degreesToRadians(value));
  const sigma =
    numberFrom(obs.sigmaRadians ?? obs.stdRadians, Number.NaN) ||
    degreesToRadians(numberFrom(obs.sigmaDegrees ?? obs.sigmaDeg ?? obs.stdDegrees ?? obs.stdDeg, Number.NaN)) ||
    degreesToRadians(numberFrom(obs.sigmaArcSec ?? obs.stdArcSec, Number.NaN) / 3600) ||
    (Number.isFinite(numberFrom(obs.weight, Number.NaN))
      ? 1 / Math.sqrt(Math.max(0.0001, numberFrom(obs.weight)))
      : degreesToRadians(5 / 3600));
  return {
    id: textFrom(obs.id ?? obs.name, `DIR${index + 1}`),
    groupId: textFrom(obs.setId ?? obs.groupId ?? obs.directionSet ?? obs.stationSet ?? obs.setupId, from),
    from,
    to,
    rawObserved,
    observed: face === "right" ? normalizeRadians(rawObserved - Math.PI) : rawObserved,
    sigma: Math.max(1e-12, sigma),
    ...(face ? { face } : {}),
    ...(textFrom(obs.roundId ?? obs.round ?? obs.measureRound ?? obs.measurementRound ?? obs.session, "") ? { roundId: textFrom(obs.roundId ?? obs.round ?? obs.measureRound ?? obs.measurementRound ?? obs.session, "") } : {}),
    sequence: numberFrom(obs.sequence ?? obs.order ?? obs.seq, index + 1),
  };
}

function isControlHeightObservationType(value: unknown): boolean {
  const raw = textFrom(value, "").toLowerCase();
  return (
    raw.includes("height") ||
    raw.includes("elevation") ||
    raw.includes("level") ||
    raw.includes("dh") ||
    raw.includes("高差") ||
    raw.includes("水准") ||
    raw.includes("高程")
  );
}

function parseControlHeightObservation(item: unknown, index: number, defaultSigmaMmPerSqrtKm?: number): ControlHeightObservation | null {
  const obs = objectFrom(item);
  const slopeDistanceM = numberByAliases(obs, CONTROL_SLOPE_DISTANCE_ALIASES, Number.NaN);
  const verticalAngleDegrees = numberByAliases(obs, CONTROL_VERTICAL_ANGLE_ALIASES, Number.NaN);
  const zenithAngleDegrees = numberByAliases(obs, CONTROL_ZENITH_ANGLE_ALIASES, Number.NaN);
  const instrumentHeightM = numberByAliases(obs, CONTROL_INSTRUMENT_HEIGHT_ALIASES, Number.NaN);
  const targetHeightM = numberByAliases(obs, CONTROL_TARGET_HEIGHT_ALIASES, Number.NaN);
  const trigonometricHeightDifferenceM = heightDifferenceFromTrigonometricObservation(
    slopeDistanceM,
    verticalAngleDegrees,
    zenithAngleDegrees,
    instrumentHeightM,
    targetHeightM,
  );
  if (
    !isControlHeightObservationType(obs.type ?? obs.kind ?? obs.observationType) &&
    obs.heightDifferenceM === undefined &&
    obs.heightDifference === undefined &&
    obs.elevationDifferenceM === undefined &&
    obs.dh === undefined &&
    !Number.isFinite(trigonometricHeightDifferenceM)
  ) {
    return null;
  }
  const from = textFrom(obs.from ?? obs.fromId ?? obs.station ?? obs.start, "");
  const to = textFrom(obs.to ?? obs.toId ?? obs.target ?? obs.end, "");
  if (!from || !to || from === to) return null;
  const observed = numberFrom(
    obs.value ?? obs.heightDifferenceM ?? obs.heightDifference ?? obs.elevationDifferenceM ?? obs.elevationDifference ?? obs.dh,
    Number.NaN,
  );
  const finalObserved = Number.isFinite(observed) ? observed : trigonometricHeightDifferenceM;
  if (!Number.isFinite(finalObserved)) return null;
  const sigmaM = numberByAliases(obs, ["sigmaM", "stdM", "heightSigmaM", "高差中误差m", "水准中误差m"], Number.NaN);
  const sigmaMm = numberByAliases(obs, ["sigmaMm", "stdMm", "heightSigmaMm", "levelingSigmaMm", "高差中误差mm", "水准中误差mm"], Number.NaN);
  const weight = numberByAliases(obs, ["weight", "权", "权重"], Number.NaN);
  const distanceKmValue = numberByAliases(
    obs,
    [
      "distanceKm",
      "distance_km",
      "routeDistanceKm",
      "routeLengthKm",
      "levelingDistanceKm",
      "lengthKm",
      "测段距离km",
      "距离km",
      "路线长km",
    ],
    Number.NaN,
  );
  const distanceMValue = numberByAliases(
    obs,
    ["distanceM", "distance_m", "routeDistanceM", "routeLengthM", "levelingDistanceM", "lengthM", "测段距离m", "距离m", "路线长m"],
    Number.NaN,
  );
  const distanceKm = Number.isFinite(distanceKmValue) && distanceKmValue > 0
    ? distanceKmValue
    : Number.isFinite(distanceMValue) && distanceMValue > 0
      ? distanceMValue / 1000
      : Number.NaN;
  const sigmaMmPerSqrtKm = numberByAliases(
    obs,
    [
      "levelingSigmaMmPerSqrtKm",
      "sigmaMmPerSqrtKm",
      "stdMmPerSqrtKm",
      "水准每公里中误差mm",
      "每公里中误差mm",
      "每根号公里中误差mm",
    ],
    Number.isFinite(defaultSigmaMmPerSqrtKm ?? Number.NaN) ? defaultSigmaMmPerSqrtKm ?? Number.NaN : Number.NaN,
  );
  let sigma = 0.001;
  let sigmaSource: ControlHeightObservation["sigmaSource"] = "default";
  if (Number.isFinite(sigmaM) && sigmaM > 0) {
    sigma = sigmaM;
    sigmaSource = "explicit";
  } else if (Number.isFinite(sigmaMm) && sigmaMm > 0) {
    sigma = sigmaMm / 1000;
    sigmaSource = "explicit";
  } else if (Number.isFinite(weight) && weight > 0) {
    sigma = 1 / Math.sqrt(weight);
    sigmaSource = "weight";
  } else if (Number.isFinite(distanceKm) && distanceKm > 0) {
    const sigmaScaleMm = Number.isFinite(sigmaMmPerSqrtKm) && sigmaMmPerSqrtKm > 0 ? sigmaMmPerSqrtKm : 1;
    sigma = (sigmaScaleMm * Math.sqrt(distanceKm)) / 1000;
    sigmaSource = "distance";
  }
  return {
    id: textFrom(obs.id ?? obs.name, `HD${index + 1}`),
    from,
    to,
    observed: finalObserved,
    sigma: Math.max(1e-12, sigma),
    ...(Number.isFinite(distanceKm) && distanceKm > 0 ? { distanceKm } : {}),
    sigmaSource,
    sequence: numberByAliases(obs, ["sequence", "seq", "order", "观测顺序", "序号"], index + 1),
  };
}

function isControlBaselineObservationType(value: unknown): boolean {
  const raw = textFrom(value, "").toLowerCase();
  return (
    raw.includes("baseline") ||
    raw.includes("gnss") ||
    raw.includes("vector") ||
    raw.includes("baseline3d") ||
    raw.includes("基线") ||
    raw.includes("向量")
  );
}

function valueByAliases(obj: Record<string, unknown>, aliases: string[]): unknown {
  const normalized = new Map(Object.entries(obj).map(([key, value]) => [normalizeHeader(key), value]));
  for (const alias of aliases) {
    const value = normalized.get(normalizeHeader(alias));
    if (value !== undefined && value !== "") return value;
  }
  return undefined;
}

function numberByAliases(obj: Record<string, unknown>, aliases: string[], fallback = Number.NaN): number {
  const value = valueByAliases(obj, aliases);
  return value === undefined ? fallback : numberFrom(value, fallback);
}

function matrix3FromValue(value: unknown): number[][] | null {
  const rows = arrayFrom(value);
  if (rows.length === 3 && rows.every(Array.isArray)) {
    const matrix = rows.map((row) => arrayFrom(row).map((item) => numberFrom(item, Number.NaN)));
    if (matrix.every((row) => row.length === 3 && row.every(Number.isFinite))) return matrix;
  }
  if (rows.length === 9) {
    const values = rows.map((item) => numberFrom(item, Number.NaN));
    if (values.every(Number.isFinite)) {
      return [
        values.slice(0, 3),
        values.slice(3, 6),
        values.slice(6, 9),
      ];
    }
  }
  return null;
}

function covarianceMatrixFromTerms(obj: Record<string, unknown>, unit: "m2" | "mm2"): number[][] | null {
  const suffix = unit === "m2" ? "M2" : "Mm2";
  const scale = unit === "m2" ? 1 : 1e-6;
  const xx = numberByAliases(obj, [`covXX${suffix}`, `cov_xx_${suffix}`, `cxx${suffix}`, `varianceX${suffix}`, `varX${suffix}`, "covXX", "cxx"]);
  const yy = numberByAliases(obj, [`covYY${suffix}`, `cov_yy_${suffix}`, `cyy${suffix}`, `varianceY${suffix}`, `varY${suffix}`, "covYY", "cyy"]);
  const zz = numberByAliases(obj, [`covZZ${suffix}`, `cov_zz_${suffix}`, `czz${suffix}`, `varianceZ${suffix}`, `varZ${suffix}`, "covZZ", "czz"]);
  if (![xx, yy, zz].every((value) => Number.isFinite(value) && value > 0)) return null;
  const xy = numberByAliases(obj, [`covXY${suffix}`, `cov_xy_${suffix}`, `cxy${suffix}`, "covXY", "cxy"], 0);
  const xz = numberByAliases(obj, [`covXZ${suffix}`, `cov_xz_${suffix}`, `cxz${suffix}`, "covXZ", "cxz"], 0);
  const yz = numberByAliases(obj, [`covYZ${suffix}`, `cov_yz_${suffix}`, `cyz${suffix}`, "covYZ", "cyz"], 0);
  return [
    [xx * scale, xy * scale, xz * scale],
    [xy * scale, yy * scale, yz * scale],
    [xz * scale, yz * scale, zz * scale],
  ];
}

function covarianceMatrixFromObservation(obj: Record<string, unknown>): number[][] | null {
  const explicit = matrix3FromValue(
    valueByAliases(obj, ["covarianceMatrixM2", "covarianceM2", "covarianceMatrix", "covariance", "vcv", "varianceCovariance"]),
  );
  if (explicit) return explicit;
  return covarianceMatrixFromTerms(obj, "m2") ?? covarianceMatrixFromTerms(obj, "mm2");
}

function sigmasFromCovariance(covarianceM2: number[][] | null): [number, number, number] | null {
  if (!covarianceM2) return null;
  const variances = [covarianceM2[0]?.[0], covarianceM2[1]?.[1], covarianceM2[2]?.[2]];
  if (!variances.every((value): value is number => Number.isFinite(value) && value > 0)) return null;
  return [Math.sqrt(variances[0]), Math.sqrt(variances[1]), Math.sqrt(variances[2])];
}

function parseControlBaselineObservation(item: unknown, index: number): ControlBaselineObservation | null {
  const obs = objectFrom(item);
  if (
    !isControlBaselineObservationType(obs.type ?? obs.kind ?? obs.observationType) &&
    obs.dx === undefined &&
    obs.dy === undefined &&
    obs.dz === undefined
  ) {
    return null;
  }
  const from = textFrom(obs.from ?? obs.fromId ?? obs.station ?? obs.start, "");
  const to = textFrom(obs.to ?? obs.toId ?? obs.target ?? obs.end, "");
  if (!from || !to || from === to) return null;
  const dx = numberFrom(obs.dx ?? obs.deltaX ?? obs.x, Number.NaN);
  const dy = numberFrom(obs.dy ?? obs.deltaY ?? obs.y, Number.NaN);
  const dz = numberFrom(obs.dz ?? obs.deltaZ ?? obs.z, Number.NaN);
  if (!Number.isFinite(dx) || !Number.isFinite(dy) || !Number.isFinite(dz)) return null;
  const covarianceM2 = covarianceMatrixFromObservation(obs);
  const covarianceSigmas = sigmasFromCovariance(covarianceM2);
  const defaultSigma =
    numberFrom(obs.sigmaM ?? obs.stdM, Number.NaN) ||
    numberFrom(obs.sigmaMm ?? obs.stdMm, Number.NaN) / 1000 ||
    covarianceSigmas?.[0] ||
    (Number.isFinite(numberFrom(obs.weight, Number.NaN)) ? 1 / Math.sqrt(Math.max(0.0001, numberFrom(obs.weight))) : 0.003);
  return {
    id: textFrom(obs.id ?? obs.name, `BL${index + 1}`),
    from,
    to,
    dx,
    dy,
    dz,
    sigmaX: Math.max(1e-12, numberFrom(obs.sigmaXM ?? obs.stdXM, Number.NaN) || numberFrom(obs.sigmaXMm ?? obs.stdXMm, Number.NaN) / 1000 || covarianceSigmas?.[0] || defaultSigma),
    sigmaY: Math.max(1e-12, numberFrom(obs.sigmaYM ?? obs.stdYM, Number.NaN) || numberFrom(obs.sigmaYMm ?? obs.stdYMm, Number.NaN) / 1000 || covarianceSigmas?.[1] || defaultSigma),
    sigmaZ: Math.max(1e-12, numberFrom(obs.sigmaZM ?? obs.stdZM, Number.NaN) || numberFrom(obs.sigmaZMm ?? obs.stdZMm, Number.NaN) / 1000 || covarianceSigmas?.[2] || defaultSigma),
    ...(covarianceM2 ? { covarianceM2 } : {}),
  };
}

function hasControlNetworkEquationInput(input: Record<string, unknown>): boolean {
  if (arrayFrom(input.knownPoints ?? input.fixedPoints).length > 0) return true;
  if (arrayFrom(input.unknownPoints ?? input.approximatePoints).length > 0) return true;
  return arrayFrom(input.observations).some(
    (item) => parseControlNetworkObservation(item, 0) || parseControlHeightObservation(item, 0) || parseControlBaselineObservation(item, 0),
  );
}

function pointById(
  id: string,
  knownPoints: Map<string, ControlNetworkPoint>,
  unknownPoints: ControlNetworkUnknownPoint[],
): Point2 | null {
  const unknown = unknownPoints.find((point) => point.id === id);
  if (unknown && Number.isFinite(unknown.x) && Number.isFinite(unknown.y)) return unknown;
  const known = knownPoints.get(id);
  return known && Number.isFinite(known.x) && Number.isFinite(known.y) ? known : null;
}

function addControlNetworkDerivative(
  row: number[],
  unknownIndex: Map<string, number>,
  pointId: string,
  dx: number,
  dy: number,
): void {
  const index = unknownIndex.get(pointId);
  if (index === undefined) return;
  row[index * 2] += dx;
  row[index * 2 + 1] += dy;
}

function buildControlNetworkEquations(
  knownPoints: Map<string, ControlNetworkPoint>,
  unknownPoints: ControlNetworkUnknownPoint[],
  observations: ControlNetworkObservation[],
): {
  design: number[][];
  closure: number[];
  weights: number[];
  computed: number[];
  distances: number[];
  skipped: string[];
} {
  const unknownIndex = new Map(unknownPoints.map((point, index) => [point.id, index]));
  const design: number[][] = [];
  const closure: number[] = [];
  const weights: number[] = [];
  const computed: number[] = [];
  const distances: number[] = [];
  const skipped: string[] = [];
  const parameterCount = unknownPoints.length * 2;

  for (const obs of observations) {
    const from = pointById(obs.from, knownPoints, unknownPoints);
    const to = pointById(obs.to, knownPoints, unknownPoints);
    if (!from || !to) {
      skipped.push(`${obs.id}: ${obs.from}-${obs.to} 存在未定义点`);
      continue;
    }
    const dx = to.x - from.x;
    const dy = to.y - from.y;
    const distance = Math.hypot(dx, dy);
    if (distance < 1e-9) {
      skipped.push(`${obs.id}: ${obs.from}-${obs.to} 距离过短`);
      continue;
    }

    const row = Array.from({ length: parameterCount }, () => 0);
    if (obs.type === "distance") {
      addControlNetworkDerivative(row, unknownIndex, obs.from, -dx / distance, -dy / distance);
      addControlNetworkDerivative(row, unknownIndex, obs.to, dx / distance, dy / distance);
      design.push(row);
      closure.push(obs.observed - distance);
      weights.push(1 / obs.sigma ** 2);
      computed.push(distance);
      distances.push(distance);
      continue;
    }

    const radiusSquared = distance ** 2;
    const computedAzimuth = normalizeRadians(Math.atan2(dx, dy));
    addControlNetworkDerivative(row, unknownIndex, obs.from, -dy / radiusSquared, dx / radiusSquared);
    addControlNetworkDerivative(row, unknownIndex, obs.to, dy / radiusSquared, -dx / radiusSquared);
    design.push(row);
    closure.push(deltaRadians(obs.observed, computedAzimuth));
    weights.push(1 / obs.sigma ** 2);
    computed.push(computedAzimuth);
    distances.push(distance);
  }

  return { design, closure, weights, computed, distances, skipped };
}

function normalizedConstraint(row: number[]): number[] | null {
  const norm = Math.hypot(...row);
  if (norm < 1e-12) return null;
  return row.map((value) => value / norm);
}

function freeNetworkDatumConstraints(unknownPoints: ControlNetworkUnknownPoint[], includeRotation: boolean): number[][] {
  const parameterCount = unknownPoints.length * 2;
  const constraints: number[][] = [];
  const translationX = Array.from({ length: parameterCount }, () => 0);
  const translationY = Array.from({ length: parameterCount }, () => 0);
  unknownPoints.forEach((_, index) => {
    translationX[index * 2] = 1;
    translationY[index * 2 + 1] = 1;
  });
  const normalizedTranslationX = normalizedConstraint(translationX);
  const normalizedTranslationY = normalizedConstraint(translationY);
  if (normalizedTranslationX) constraints.push(normalizedTranslationX);
  if (normalizedTranslationY) constraints.push(normalizedTranslationY);

  if (includeRotation) {
    const centerX = unknownPoints.reduce((sum, point) => sum + point.initialX, 0) / Math.max(1, unknownPoints.length);
    const centerY = unknownPoints.reduce((sum, point) => sum + point.initialY, 0) / Math.max(1, unknownPoints.length);
    const rotation = Array.from({ length: parameterCount }, () => 0);
    unknownPoints.forEach((point, index) => {
      rotation[index * 2] = -(point.initialY - centerY);
      rotation[index * 2 + 1] = point.initialX - centerX;
    });
    const normalizedRotation = normalizedConstraint(rotation);
    if (normalizedRotation) constraints.push(normalizedRotation);
  }

  return constraints;
}

type ControlDirectionEquationMeta = {
  kind: "distance" | "azimuth" | "direction";
  obs: ControlNetworkObservation | ControlDirectionObservation;
  groupId?: string;
  computed: number;
  distance: number;
};

function initialDirectionOrientations(
  knownPoints: Map<string, ControlNetworkPoint>,
  unknownPoints: ControlNetworkUnknownPoint[],
  directionObservations: ControlDirectionObservation[],
  groupIds: string[],
): Map<string, number> {
  const sums = new Map<string, { sin: number; cos: number; count: number }>();
  for (const groupId of groupIds) sums.set(groupId, { sin: 0, cos: 0, count: 0 });
  for (const obs of directionObservations) {
    const from = pointById(obs.from, knownPoints, unknownPoints);
    const to = pointById(obs.to, knownPoints, unknownPoints);
    if (!from || !to) continue;
    const dx = to.x - from.x;
    const dy = to.y - from.y;
    if (Math.hypot(dx, dy) < 1e-9) continue;
    const orientation = normalizeRadians(Math.atan2(dx, dy) - obs.observed);
    const sum = sums.get(obs.groupId) ?? { sin: 0, cos: 0, count: 0 };
    sum.sin += Math.sin(orientation);
    sum.cos += Math.cos(orientation);
    sum.count += 1;
    sums.set(obs.groupId, sum);
  }
  return new Map(
    groupIds.map((groupId) => {
      const sum = sums.get(groupId);
      const orientation = sum && sum.count > 0 ? normalizeRadians(Math.atan2(sum.sin, sum.cos)) : 0;
      return [groupId, orientation];
    }),
  );
}

function directionRoundKey(...parts: Array<string | undefined>): string {
  return parts.map((part) => part ?? "").join("\u0000");
}

function meanDirectionRadians(values: number[]): number {
  if (values.length === 0) return 0;
  const sin = values.reduce((sum, value) => sum + Math.sin(value), 0);
  const cos = values.reduce((sum, value) => sum + Math.cos(value), 0);
  return normalizeRadians(Math.atan2(sin, cos));
}

function directionRoundQualityRows(
  observations: ControlDirectionObservation[],
  faceToleranceArcSec: number,
  zeroClosureToleranceArcSec: number,
): {
  faceRows: Array<Record<string, Primitive>>;
  zeroRows: Array<Record<string, Primitive>>;
  summaryRows: Array<Record<string, Primitive>>;
  maxFaceDifferenceArcSec: number;
  maxZeroClosureArcSec: number;
} {
  const byTarget = new Map<string, ControlDirectionObservation[]>();
  const byRound = new Map<string, ControlDirectionObservation[]>();
  for (const obs of observations) {
    const targetKey = directionRoundKey(obs.groupId, obs.from, obs.to, obs.roundId);
    byTarget.set(targetKey, [...(byTarget.get(targetKey) ?? []), obs]);
    const roundKey = directionRoundKey(obs.groupId, obs.from, obs.roundId, obs.face);
    byRound.set(roundKey, [...(byRound.get(roundKey) ?? []), obs]);
  }

  let maxFaceDifferenceArcSec = 0;
  const faceRows = Array.from(byTarget.values()).flatMap((items) => {
    const left = items.filter((item) => item.face === "left");
    const right = items.filter((item) => item.face === "right");
    if (left.length === 0 || right.length === 0) return [];
    const sample = items[0]!;
    const leftMean = meanDirectionRadians(left.map((item) => item.observed));
    const rightMean = meanDirectionRadians(right.map((item) => item.observed));
    const differenceArcSec = radiansToDegrees(deltaRadians(rightMean, leftMean)) * 3600;
    maxFaceDifferenceArcSec = Math.max(maxFaceDifferenceArcSec, Math.abs(differenceArcSec));
    return [
      {
        row_type: "direction_face_pair_check",
        direction_group_id: sample.groupId,
        round_id: sample.roundId ?? "",
        station_id: sample.from,
        target_id: sample.to,
        left_observation_count: left.length,
        right_observation_count: right.length,
        left_mean_degrees: round(radiansToDegrees(leftMean), 9),
        right_reduced_mean_degrees: round(radiansToDegrees(rightMean), 9),
        face_difference_arcsec: round(differenceArcSec, 4),
        tolerance_arcsec: faceToleranceArcSec,
        check_status: Math.abs(differenceArcSec) <= faceToleranceArcSec ? "ok" : "warn",
      },
    ];
  });

  let maxZeroClosureArcSec = 0;
  const zeroRows = Array.from(byRound.values()).flatMap((items) => {
    const sorted = [...items].sort((a, b) => a.sequence - b.sequence);
    const first = sorted[0];
    if (!first) return [];
    const closing = [...sorted].reverse().find((item) => item.id !== first.id && item.to === first.to);
    if (!closing) return [];
    const closureArcSec = radiansToDegrees(deltaRadians(closing.observed, first.observed)) * 3600;
    maxZeroClosureArcSec = Math.max(maxZeroClosureArcSec, Math.abs(closureArcSec));
    return [
      {
        row_type: "direction_zero_closure_check",
        direction_group_id: first.groupId,
        round_id: first.roundId ?? "",
        station_id: first.from,
        target_id: first.to,
        face: first.face ?? "",
        start_observation_id: first.id,
        close_observation_id: closing.id,
        start_direction_degrees: round(radiansToDegrees(first.observed), 9),
        close_direction_degrees: round(radiansToDegrees(closing.observed), 9),
        zero_closure_arcsec: round(closureArcSec, 4),
        tolerance_arcsec: zeroClosureToleranceArcSec,
        check_status: Math.abs(closureArcSec) <= zeroClosureToleranceArcSec ? "ok" : "warn",
      },
    ];
  });

  const summaryGroups = new Map<string, ControlDirectionObservation[]>();
  for (const obs of observations) {
    const summaryKey = directionRoundKey(obs.groupId, obs.from, obs.roundId);
    summaryGroups.set(summaryKey, [...(summaryGroups.get(summaryKey) ?? []), obs]);
  }

  const summaryRows = Array.from(summaryGroups.values()).map((items) => {
    const sample = items[0]!;
    const roundId = sample.roundId ?? "";
    const groupFaceRows = faceRows.filter(
      (row) =>
        row.direction_group_id === sample.groupId &&
        row.station_id === sample.from &&
        row.round_id === roundId,
    );
    const groupZeroRows = zeroRows.filter(
      (row) =>
        row.direction_group_id === sample.groupId &&
        row.station_id === sample.from &&
        row.round_id === roundId,
    );
    const maxRoundFaceDifferenceArcSec = groupFaceRows.reduce(
      (max, row) => Math.max(max, Math.abs(numberFrom(row.face_difference_arcsec))),
      0,
    );
    const maxRoundZeroClosureArcSec = groupZeroRows.reduce(
      (max, row) => Math.max(max, Math.abs(numberFrom(row.zero_closure_arcsec))),
      0,
    );
    const checkStatus =
      maxRoundFaceDifferenceArcSec <= faceToleranceArcSec &&
      maxRoundZeroClosureArcSec <= zeroClosureToleranceArcSec
        ? "ok"
        : "warn";
    return {
      row_type: "direction_round_summary",
      direction_group_id: sample.groupId,
      round_id: roundId,
      station_id: sample.from,
      target_count: new Set(items.map((item) => item.to)).size,
      observation_count: items.length,
      face_pair_check_count: groupFaceRows.length,
      zero_closure_check_count: groupZeroRows.length,
      max_face_difference_arcsec: round(maxRoundFaceDifferenceArcSec, 4),
      face_difference_tolerance_arcsec: faceToleranceArcSec,
      max_zero_closure_arcsec: round(maxRoundZeroClosureArcSec, 4),
      zero_closure_tolerance_arcsec: zeroClosureToleranceArcSec,
      check_status: checkStatus,
      recommended_action: checkStatus === "ok" ? "accept_round" : "review_round_observations",
    };
  });

  return { faceRows, zeroRows, summaryRows, maxFaceDifferenceArcSec, maxZeroClosureArcSec };
}

function buildControlDirectionSetEquations(
  knownPoints: Map<string, ControlNetworkPoint>,
  unknownPoints: ControlNetworkUnknownPoint[],
  observations: ControlNetworkObservation[],
  directionObservations: ControlDirectionObservation[],
  groupIds: string[],
  orientations: Map<string, number>,
): {
  design: number[][];
  closure: number[];
  weights: number[];
  meta: ControlDirectionEquationMeta[];
  skipped: string[];
} {
  const unknownIndex = new Map(unknownPoints.map((point, index) => [point.id, index]));
  const orientationIndex = new Map(groupIds.map((groupId, index) => [groupId, unknownPoints.length * 2 + index]));
  const parameterCount = unknownPoints.length * 2 + groupIds.length;
  const design: number[][] = [];
  const closure: number[] = [];
  const weights: number[] = [];
  const meta: ControlDirectionEquationMeta[] = [];
  const skipped: string[] = [];

  const appendDistanceOrAzimuth = (obs: ControlNetworkObservation) => {
    const from = pointById(obs.from, knownPoints, unknownPoints);
    const to = pointById(obs.to, knownPoints, unknownPoints);
    if (!from || !to) {
      skipped.push(`${obs.id}: ${obs.from}-${obs.to} 存在未定义点`);
      return;
    }
    const dx = to.x - from.x;
    const dy = to.y - from.y;
    const distance = Math.hypot(dx, dy);
    if (distance < 1e-9) {
      skipped.push(`${obs.id}: ${obs.from}-${obs.to} 距离过短`);
      return;
    }
    const row = Array.from({ length: parameterCount }, () => 0);
    if (obs.type === "distance") {
      addControlNetworkDerivative(row, unknownIndex, obs.from, -dx / distance, -dy / distance);
      addControlNetworkDerivative(row, unknownIndex, obs.to, dx / distance, dy / distance);
      design.push(row);
      closure.push(obs.observed - distance);
      weights.push(1 / obs.sigma ** 2);
      meta.push({ kind: "distance", obs, computed: distance, distance });
      return;
    }
    const radiusSquared = distance ** 2;
    const computedAzimuth = normalizeRadians(Math.atan2(dx, dy));
    addControlNetworkDerivative(row, unknownIndex, obs.from, -dy / radiusSquared, dx / radiusSquared);
    addControlNetworkDerivative(row, unknownIndex, obs.to, dy / radiusSquared, -dx / radiusSquared);
    design.push(row);
    closure.push(deltaRadians(obs.observed, computedAzimuth));
    weights.push(1 / obs.sigma ** 2);
    meta.push({ kind: "azimuth", obs, computed: computedAzimuth, distance });
  };

  for (const obs of observations) appendDistanceOrAzimuth(obs);

  for (const obs of directionObservations) {
    const from = pointById(obs.from, knownPoints, unknownPoints);
    const to = pointById(obs.to, knownPoints, unknownPoints);
    const groupParamIndex = orientationIndex.get(obs.groupId);
    if (!from || !to || groupParamIndex === undefined) {
      skipped.push(`${obs.id}: ${obs.from}-${obs.to} 或方向组 ${obs.groupId} 未定义`);
      continue;
    }
    const dx = to.x - from.x;
    const dy = to.y - from.y;
    const distance = Math.hypot(dx, dy);
    if (distance < 1e-9) {
      skipped.push(`${obs.id}: ${obs.from}-${obs.to} 距离过短`);
      continue;
    }
    const row = Array.from({ length: parameterCount }, () => 0);
    const radiusSquared = distance ** 2;
    const computedAzimuth = normalizeRadians(Math.atan2(dx, dy));
    const orientation = orientations.get(obs.groupId) ?? 0;
    const computedDirection = normalizeRadians(computedAzimuth - orientation);
    addControlNetworkDerivative(row, unknownIndex, obs.from, -dy / radiusSquared, dx / radiusSquared);
    addControlNetworkDerivative(row, unknownIndex, obs.to, dy / radiusSquared, -dx / radiusSquared);
    row[groupParamIndex] = -1;
    design.push(row);
    closure.push(deltaRadians(obs.observed, computedDirection));
    weights.push(1 / obs.sigma ** 2);
    meta.push({ kind: "direction", obs, groupId: obs.groupId, computed: computedDirection, distance });
  }

  return { design, closure, weights, meta, skipped };
}

function solveControlNormalEquations(
  design: number[][],
  closure: number[],
  weights: number[],
  parameterCount: number,
  constraints: number[][] = [],
): { normal: number[][]; rhs: number[]; delta: number[]; covariance?: number[][] } | null {
  const normal = Array.from({ length: parameterCount }, () => Array.from({ length: parameterCount }, () => 0));
  const rhs = Array.from({ length: parameterCount }, () => 0);
  for (let rowIndex = 0; rowIndex < design.length; rowIndex += 1) {
    const row = design[rowIndex]!;
    const weight = weights[rowIndex] ?? 1;
    for (let i = 0; i < parameterCount; i += 1) {
      rhs[i] += (row[i] ?? 0) * weight * (closure[rowIndex] ?? 0);
      for (let j = 0; j < parameterCount; j += 1) {
        normal[i]![j] += (row[i] ?? 0) * weight * (row[j] ?? 0);
      }
    }
  }
  if (constraints.length > 0) {
    const size = parameterCount + constraints.length;
    const augmented = Array.from({ length: size }, () => Array.from({ length: size }, () => 0));
    const augmentedRhs = Array.from({ length: size }, () => 0);
    for (let row = 0; row < parameterCount; row += 1) {
      augmentedRhs[row] = rhs[row] ?? 0;
      for (let column = 0; column < parameterCount; column += 1) {
        augmented[row]![column] = normal[row]?.[column] ?? 0;
      }
    }
    constraints.forEach((constraint, constraintIndex) => {
      const augmentedIndex = parameterCount + constraintIndex;
      for (let column = 0; column < parameterCount; column += 1) {
        const value = constraint[column] ?? 0;
        augmented[column]![augmentedIndex] = value;
        augmented[augmentedIndex]![column] = value;
      }
    });
    const solved = solveLinearSystem(augmented, augmentedRhs);
    if (!solved) return null;
    const inverse = invertMatrix(augmented);
    const covariance = inverse
      ? inverse.slice(0, parameterCount).map((row) => row.slice(0, parameterCount))
      : undefined;
    return {
      normal,
      rhs,
      delta: solved.slice(0, parameterCount),
      ...(covariance ? { covariance } : {}),
    };
  }
  const delta = solveLinearSystem(normal, rhs);
  return delta ? { normal, rhs, delta } : null;
}

type WeightedObservationBlock = {
  design: number[][];
  closure: number[];
  weightMatrix: number[][];
};

function solveControlBlockNormalEquations(
  blocks: WeightedObservationBlock[],
  parameterCount: number,
): { normal: number[][]; rhs: number[]; delta: number[] } | null {
  const normal = Array.from({ length: parameterCount }, () => Array.from({ length: parameterCount }, () => 0));
  const rhs = Array.from({ length: parameterCount }, () => 0);
  for (const block of blocks) {
    for (let rowIndex = 0; rowIndex < block.design.length; rowIndex += 1) {
      const row = block.design[rowIndex]!;
      for (let columnIndex = 0; columnIndex < block.design.length; columnIndex += 1) {
        const pairedRow = block.design[columnIndex]!;
        const weight = block.weightMatrix[rowIndex]?.[columnIndex] ?? 0;
        if (Math.abs(weight) < 1e-24) continue;
        for (let i = 0; i < parameterCount; i += 1) {
          rhs[i] += (row[i] ?? 0) * weight * (block.closure[columnIndex] ?? 0);
          for (let j = 0; j < parameterCount; j += 1) {
            normal[i]![j] += (row[i] ?? 0) * weight * (pairedRow[j] ?? 0);
          }
        }
      }
    }
  }
  const delta = solveLinearSystem(normal, rhs);
  return delta ? { normal, rhs, delta } : null;
}

function diagonalMatrix(values: number[]): number[][] {
  return values.map((value, rowIndex) => values.map((_, columnIndex) => (rowIndex === columnIndex ? value : 0)));
}

function quadraticForm(vector: number[], matrix: number[][]): number {
  let sum = 0;
  for (let row = 0; row < vector.length; row += 1) {
    for (let column = 0; column < vector.length; column += 1) {
      sum += (vector[row] ?? 0) * (matrix[row]?.[column] ?? 0) * (vector[column] ?? 0);
    }
  }
  return sum;
}

function controlHeightById(
  id: string,
  knownPoints: Map<string, ControlNetworkPoint>,
  unknownPoints: Array<ControlNetworkPoint & { initialZ: number }>,
): number | null {
  const unknown = unknownPoints.find((point) => point.id === id);
  if (unknown && Number.isFinite(unknown.z)) return unknown.z ?? null;
  const known = knownPoints.get(id);
  return known && Number.isFinite(known.z) ? known.z ?? null : null;
}

function calculateLevelingRouteClosureAdjustment(
  knownPointList: ControlNetworkPoint[],
  observations: ControlHeightObservation[],
  input: Record<string, unknown>,
): EngineeringResult | null {
  if (knownPointList.length < 2 || observations.length === 0) return null;
  const knownPoints = new Map(knownPointList.map((point) => [point.id, point]));
  const route = [...observations].sort((a, b) => a.sequence - b.sequence);
  for (let index = 1; index < route.length; index += 1) {
    if (route[index - 1]?.to !== route[index]?.from) return null;
  }
  const startPoint = knownPoints.get(route[0]?.from ?? "");
  const endPoint = knownPoints.get(route[route.length - 1]?.to ?? "");
  if (!startPoint || !endPoint || !Number.isFinite(startPoint.z) || !Number.isFinite(endPoint.z)) return null;

  const distributionLengths = route.map((obs) => (obs.distanceKm !== undefined && obs.distanceKm > 0 ? obs.distanceKm : 1));
  const distributionTotal = distributionLengths.reduce((sum, value) => sum + value, 0);
  if (!(distributionTotal > 0)) return null;

  const observedHeightDifference = route.reduce((sum, obs) => sum + obs.observed, 0);
  const knownHeightDifference = (endPoint.z ?? 0) - (startPoint.z ?? 0);
  const closureError = observedHeightDifference - knownHeightDifference;
  const closureErrorMm = closureError * 1000;
  const totalLevelingDistanceKm = route.reduce((sum, obs) => sum + (obs.distanceKm ?? 0), 0);
  const closureToleranceMm = numberByAliases(input, ["closureToleranceMm", "levelingClosureToleranceMm", "闭合差限差mm"], Number.NaN);
  const closureToleranceMmPerSqrtKm = numberByAliases(
    input,
    ["closureToleranceMmPerSqrtKm", "levelingClosureToleranceMmPerSqrtKm", "水准闭合差每根号公里限差mm", "闭合差每根号公里限差mm"],
    12,
  );
  const computedToleranceMm = Number.isFinite(closureToleranceMm) && closureToleranceMm > 0
    ? closureToleranceMm
    : totalLevelingDistanceKm > 0
      ? closureToleranceMmPerSqrtKm * Math.sqrt(totalLevelingDistanceKm)
      : Number.POSITIVE_INFINITY;
  const warnings: string[] = [];
  if (Math.abs(closureErrorMm) > computedToleranceMm) {
    warnings.push(`水准路线闭合差 ${round(closureErrorMm, 3)} mm 超过 ${round(computedToleranceMm, 3)} mm`);
  }

  let currentHeight = startPoint.z ?? 0;
  const pointRows: Array<Record<string, Primitive>> = [
    {
      row_type: "leveling_route_point",
      point_id: startPoint.id,
      adjusted_z: round(currentHeight, 6),
      point_role: "known_start",
    },
  ];
  const segmentRows = route.map((obs, index) => {
    const distributionLength = distributionLengths[index] ?? 1;
    const correction = -closureError * distributionLength / distributionTotal;
    const adjustedHeightDifference = obs.observed + correction;
    currentHeight += adjustedHeightDifference;
    pointRows.push({
      row_type: "leveling_route_point",
      point_id: obs.to,
      adjusted_z: round(currentHeight, 6),
      point_role: obs.to === endPoint.id ? "known_end" : "turning_point",
    });
    return {
      row_type: "leveling_route_segment",
      sequence: index + 1,
      observation_id: obs.id,
      from: obs.from,
      to: obs.to,
      observed_height_difference_m: round(obs.observed, 6),
      distance_km: obs.distanceKm === undefined ? null : round(obs.distanceKm, 6),
      distribution_length: round(distributionLength, 6),
      correction_mm: round(correction * 1000, 4),
      adjusted_height_difference_m: round(adjustedHeightDifference, 6),
      adjusted_to_z: round(currentHeight, 6),
    };
  });
  const closurePerSqrtKmMm = totalLevelingDistanceKm > 0 ? Math.abs(closureErrorMm) / Math.sqrt(totalLevelingDistanceKm) : null;

  return resultFor(
    "control_network",
    statusFromWarnings(warnings),
    `附合水准路线闭合差分配完成：${route.length} 段、闭合差 ${round(closureErrorMm, 3)} mm。`,
    {
      adjustment_model: "leveling_route_closure_adjustment",
      segment_count: route.length,
      start_point: startPoint.id,
      end_point: endPoint.id,
      observed_height_difference_m: round(observedHeightDifference, 6),
      known_height_difference_m: round(knownHeightDifference, 6),
      closure_error_mm: round(closureErrorMm, 4),
      total_leveling_distance_km: round(totalLevelingDistanceKm, 6),
      closure_per_sqrt_km_mm: closurePerSqrtKmMm === null ? null : round(closurePerSqrtKmMm, 3),
      closure_tolerance_mm: Number.isFinite(computedToleranceMm) ? round(computedToleranceMm, 3) : null,
      adjusted_point_count: pointRows.length,
    },
    [...segmentRows, ...pointRows],
    warnings.length > 0
      ? [...warnings, "请复核水准路线起终点高程、测段距离和往返测闭合差后再提交成果。"]
      : ["闭合差已按测段距离分配，可输出水准路线成果表；提交前请核对起终点高程基准。"],
    {
      algorithm: "附合水准路线闭合差检核 + 按测段距离比例分配高差改正数",
      workflow: ["读取起终已知水准点和逐段高差/测段距离", "校验观测链连续性", "计算实测总高差与已知高差闭合差", "按测段距离分配改正数", "输出逐段调整高差和转点高程"],
      qualityChecks: ["路线连续性", "起终点已知高程", "总测段距离", "闭合差", "每根号公里闭合差", "逐段改正数"],
      deliverables: ["水准路线闭合差表", "逐段改正数表", "转点调整高程表", "Markdown 复核报告"],
    },
  );
}

function calculateControlHeightAdjustment(input: Record<string, unknown>): EngineeringResult {
  const knownPointList = parseControlNetworkPoints(input.knownPoints ?? input.fixedPoints).filter((point) => Number.isFinite(point.z));
  const unknownPointList = parseControlNetworkPoints(input.unknownPoints ?? input.approximatePoints)
    .filter((point) => Number.isFinite(point.z))
    .map((point) => ({ ...point, initialZ: point.z ?? 0 }));
  const levelingSigmaMmPerSqrtKm = numberByAliases(
    input,
    [
      "levelingSigmaMmPerSqrtKm",
      "sigmaMmPerSqrtKm",
      "levelingStdMmPerSqrtKm",
      "stdMmPerSqrtKm",
      "水准每公里中误差mm",
      "每公里中误差mm",
      "每根号公里中误差mm",
    ],
    Number.NaN,
  );
  const observations = arrayFrom(input.observations)
    .map((item, index) =>
      parseControlHeightObservation(
        item,
        index,
        Number.isFinite(levelingSigmaMmPerSqrtKm) && levelingSigmaMmPerSqrtKm > 0 ? levelingSigmaMmPerSqrtKm : undefined,
      ),
    )
    .filter((obs): obs is ControlHeightObservation => Boolean(obs));
  const knownPoints = new Map(knownPointList.map((point) => [point.id, point]));
  const parameterCount = unknownPointList.length;
  const warnings: string[] = [];

  if (unknownPointList.length === 0) {
    const routeResult = calculateLevelingRouteClosureAdjustment(knownPointList, observations, input);
    if (routeResult) return routeResult;
  }

  if (knownPoints.size === 0 || unknownPointList.length === 0 || observations.length === 0) {
    return resultFor(
      "control_network",
      "error",
      "高差网平差需要 knownPoints.z、unknownPoints.z 和 height_difference observations。",
      {
        adjustment_model: "height_difference_lsq",
        known_height_count: knownPoints.size,
        unknown_height_count: unknownPointList.length,
        observation_count: observations.length,
      },
      [],
      ["请至少提供 1 个已知高程点、1 个未知点近似高程和高差观测。"],
    );
  }

  const unknownIndex = new Map(unknownPointList.map((point, index) => [point.id, index]));
  const design: number[][] = [];
  const closure: number[] = [];
  const weights: number[] = [];
  const computed: number[] = [];
  const usedObservations: ControlHeightObservation[] = [];

  for (const obs of observations) {
    const fromHeight = controlHeightById(obs.from, knownPoints, unknownPointList);
    const toHeight = controlHeightById(obs.to, knownPoints, unknownPointList);
    if (fromHeight === null || toHeight === null) {
      warnings.push(`${obs.id}: ${obs.from}-${obs.to} 存在未定义高程点`);
      continue;
    }
    const row = Array.from({ length: parameterCount }, () => 0);
    const fromIndex = unknownIndex.get(obs.from);
    const toIndex = unknownIndex.get(obs.to);
    if (fromIndex !== undefined) row[fromIndex] -= 1;
    if (toIndex !== undefined) row[toIndex] += 1;
    design.push(row);
    const computedDifference = toHeight - fromHeight;
    closure.push(obs.observed - computedDifference);
    weights.push(1 / obs.sigma ** 2);
    computed.push(computedDifference);
    usedObservations.push(obs);
  }

  if (design.length < parameterCount || parameterCount === 0) {
    return resultFor(
      "control_network",
      "error",
      "高差网有效观测不足，无法形成满秩法方程。",
      {
        adjustment_model: "height_difference_lsq",
        observation_count: design.length,
        unknown_parameter_count: parameterCount,
      },
      [],
      ["检查高差观测是否把未知高程点连接到已知水准点。"],
    );
  }

  const solved = solveControlNormalEquations(design, closure, weights, parameterCount);
  if (!solved) {
    return resultFor(
      "control_network",
      "error",
      "高差网几何结构退化，法方程不可解。",
      {
        adjustment_model: "height_difference_lsq",
        observation_count: design.length,
        unknown_parameter_count: parameterCount,
      },
      [],
      ["增加连接到已知点的水准路线或固定更多高程点。"],
    );
  }

  for (const [index, point] of unknownPointList.entries()) {
    point.z = (point.z ?? 0) + (solved.delta[index] ?? 0);
  }

  const finalComputed = usedObservations.map((obs) => {
    const fromHeight = controlHeightById(obs.from, knownPoints, unknownPointList) ?? 0;
    const toHeight = controlHeightById(obs.to, knownPoints, unknownPointList) ?? 0;
    return toHeight - fromHeight;
  });
  const residuals = usedObservations.map((obs, index) => obs.observed - (finalComputed[index] ?? 0));
  const redundancy = Math.max(0, design.length - parameterCount);
  const weightedResidualSum = residuals.reduce((sum, residual, index) => sum + residual ** 2 * (weights[index] ?? 1), 0);
  const unitWeightStd = redundancy > 0 ? Math.sqrt(weightedResidualSum / redundancy) : 0;
  const covariance = invertMatrix(solved.normal);
  const heightToleranceMm = numberFrom(input.heightToleranceMm ?? input.coordinateToleranceMm, 10);
  const residualToleranceMm = numberFrom(input.residualToleranceMm, 5);
  const levelingDistanceWeightedCount = usedObservations.filter((obs) => obs.sigmaSource === "distance").length;
  const totalLevelingDistanceKm = usedObservations.reduce((sum, obs) => sum + (obs.distanceKm ?? 0), 0);
  let maxHeightStdMm = 0;
  let maxCorrectionMm = 0;
  let maxResidualMm = 0;
  let maxStandardizedResidual = 0;

  const pointRows = unknownPointList.map((point, index) => {
    const correctionMm = ((point.z ?? 0) - point.initialZ) * 1000;
    const stdZMm = unitWeightStd * Math.sqrt(Math.max(0, covariance?.[index]?.[index] ?? 0)) * 1000;
    maxHeightStdMm = Math.max(maxHeightStdMm, stdZMm);
    maxCorrectionMm = Math.max(maxCorrectionMm, Math.abs(correctionMm));
    return {
      row_type: "height_point",
      point_id: point.id,
      initial_z: round(point.initialZ, 6),
      adjusted_z: round(point.z ?? 0, 6),
      correction_dz_mm: round(correctionMm, 3),
      std_z_mm: round(stdZMm, 3),
    };
  });

  const residualRows = usedObservations.map((obs, index) => {
    const residual = residuals[index] ?? 0;
    const residualMm = residual * 1000;
    const standardized = residual / obs.sigma;
    maxResidualMm = Math.max(maxResidualMm, Math.abs(residualMm));
    maxStandardizedResidual = Math.max(maxStandardizedResidual, Math.abs(standardized));
    return {
      row_type: "height_observation_residual",
      observation_id: obs.id,
      observation_type: "height_difference",
      from: obs.from,
      to: obs.to,
      observed_dh_m: round(obs.observed, 6),
      observed_height_difference_m: round(obs.observed, 6),
      computed_height_difference_m: round(finalComputed[index] ?? 0, 6),
      residual_mm: round(residualMm, 4),
      distance_km: obs.distanceKm === undefined ? null : round(obs.distanceKm, 6),
      sigma_mm: round(obs.sigma * 1000, 4),
      sigma_source: obs.sigmaSource,
      standardized_residual: round(standardized, 4),
    };
  });

  if (redundancy === 0) warnings.push("观测冗余度为 0，无法可靠估计单位权中误差");
  if (maxHeightStdMm > heightToleranceMm) warnings.push(`最大高程中误差 ${round(maxHeightStdMm, 3)} mm 超过 ${heightToleranceMm} mm`);
  if (maxResidualMm > residualToleranceMm) warnings.push(`最大高差残差 ${round(maxResidualMm, 3)} mm 超过 ${residualToleranceMm} mm`);

  return resultFor(
    "control_network",
    statusFromWarnings(warnings),
    `高差网最小二乘平差完成：${unknownPointList.length} 个未知高程点、${usedObservations.length} 条有效高差观测、冗余度 ${redundancy}。`,
    {
      adjustment_model: "height_difference_lsq",
      known_height_count: knownPoints.size,
      unknown_height_count: unknownPointList.length,
      observation_count: usedObservations.length,
      unknown_parameter_count: parameterCount,
      redundancy,
      max_correction_mm: round(maxCorrectionMm, 3),
      unit_weight_std: round(unitWeightStd, 6),
      max_height_std_mm: round(maxHeightStdMm, 3),
      max_residual_mm: round(maxResidualMm, 3),
      max_standardized_residual: round(maxStandardizedResidual, 4),
      leveling_distance_weighted_count: levelingDistanceWeightedCount,
      total_leveling_distance_km: round(totalLevelingDistanceKm, 6),
      ...(Number.isFinite(levelingSigmaMmPerSqrtKm) && levelingSigmaMmPerSqrtKm > 0
        ? { leveling_sigma_mm_per_sqrt_km: round(levelingSigmaMmPerSqrtKm, 3) }
        : {}),
    },
    [...pointRows, ...residualRows],
    warnings.length > 0
      ? [...warnings, "请复核水准路线闭合差、往返观测和观测权后重新平差。"]
      : ["高差网结果可用于竖向控制复核；提交前请核对水准路线闭合差和高程基准。"],
  );
}

function controlPoint3ById(
  id: string,
  knownPoints: Map<string, ControlNetworkPoint>,
  unknownPoints: Array<ControlNetworkPoint & { initialX: number; initialY: number; initialZ: number }>,
): Point3 | null {
  const unknown = unknownPoints.find((point) => point.id === id);
  if (unknown && Number.isFinite(unknown.x) && Number.isFinite(unknown.y) && Number.isFinite(unknown.z)) {
    return { x: unknown.x, y: unknown.y, z: unknown.z };
  }
  const known = knownPoints.get(id);
  if (known && Number.isFinite(known.x) && Number.isFinite(known.y) && Number.isFinite(known.z)) {
    return { x: known.x, y: known.y, z: known.z };
  }
  return null;
}

function addBaselineDerivative(row: number[], unknownIndex: Map<string, number>, pointId: string, component: 0 | 1 | 2, sign: number): void {
  const index = unknownIndex.get(pointId);
  if (index === undefined) return;
  row[index * 3 + component] += sign;
}

type ControlBaselineEquationBlock = WeightedObservationBlock & {
  obs: ControlBaselineObservation;
  computedInitial: [number, number, number];
  covarianceM2: number[][] | null;
  covarianceModel: "full_3x3" | "diagonal_sigma";
  sigmas: [number, number, number];
};

function baselineDiagonalWeightMatrix(obs: ControlBaselineObservation): number[][] {
  return diagonalMatrix([1 / obs.sigmaX ** 2, 1 / obs.sigmaY ** 2, 1 / obs.sigmaZ ** 2]);
}

function buildBaselineEquationBlock(
  obs: ControlBaselineObservation,
  knownPoints: Map<string, ControlNetworkPoint>,
  unknownPoints: Array<ControlNetworkPoint & { initialX: number; initialY: number; initialZ: number }>,
  unknownIndex: Map<string, number>,
  parameterCount: number,
): { block: ControlBaselineEquationBlock | null; warning?: string } {
  const from = controlPoint3ById(obs.from, knownPoints, unknownPoints);
  const to = controlPoint3ById(obs.to, knownPoints, unknownPoints);
  if (!from || !to || to.z === undefined || from.z === undefined) {
    return { block: null, warning: `${obs.id}: ${obs.from}-${obs.to} 存在未定义三维点` };
  }

  const computedValues: [number, number, number] = [to.x - from.x, to.y - from.y, to.z - from.z];
  const observedValues: [number, number, number] = [obs.dx, obs.dy, obs.dz];
  const design = [0, 1, 2].map((component) => {
    const row = Array.from({ length: parameterCount }, () => 0);
    addBaselineDerivative(row, unknownIndex, obs.from, component as 0 | 1 | 2, -1);
    addBaselineDerivative(row, unknownIndex, obs.to, component as 0 | 1 | 2, 1);
    return row;
  });
  const closure = observedValues.map((observed, component) => observed - (computedValues[component] ?? 0));
  const covarianceInverse = obs.covarianceM2 ? invertMatrix(obs.covarianceM2) : null;
  const covarianceValid = Boolean(obs.covarianceM2 && covarianceInverse);
  const sigmas: [number, number, number] = [
    Math.sqrt(Math.max(0, obs.covarianceM2?.[0]?.[0] ?? obs.sigmaX ** 2)),
    Math.sqrt(Math.max(0, obs.covarianceM2?.[1]?.[1] ?? obs.sigmaY ** 2)),
    Math.sqrt(Math.max(0, obs.covarianceM2?.[2]?.[2] ?? obs.sigmaZ ** 2)),
  ];
  return {
    block: {
      obs,
      design,
      closure,
      weightMatrix: covarianceValid ? covarianceInverse! : baselineDiagonalWeightMatrix(obs),
      computedInitial: computedValues,
      covarianceM2: covarianceValid ? obs.covarianceM2! : null,
      covarianceModel: covarianceValid ? "full_3x3" : "diagonal_sigma",
      sigmas,
    },
    warning: obs.covarianceM2 && !covarianceInverse ? `${obs.id}: GNSS 基线协方差矩阵不可逆，已退回分量 sigma 权` : undefined,
  };
}

function calculateControlBaselineAdjustment(input: Record<string, unknown>): EngineeringResult {
  const knownPointList = parseControlNetworkPoints(input.knownPoints ?? input.fixedPoints).filter(
    (point) => Number.isFinite(point.x) && Number.isFinite(point.y) && Number.isFinite(point.z),
  );
  const unknownPointList = parseControlNetworkPoints(input.unknownPoints ?? input.approximatePoints)
    .filter((point) => Number.isFinite(point.x) && Number.isFinite(point.y) && Number.isFinite(point.z))
    .map((point) => ({ ...point, initialX: point.x, initialY: point.y, initialZ: point.z ?? 0 }));
  const observations = arrayFrom(input.observations)
    .map((item, index) => parseControlBaselineObservation(item, index))
    .filter((obs): obs is ControlBaselineObservation => Boolean(obs));
  const knownPoints = new Map(knownPointList.map((point) => [point.id, point]));
  const unknownIndex = new Map(unknownPointList.map((point, index) => [point.id, index]));
  const parameterCount = unknownPointList.length * 3;
  const warnings: string[] = [];

  if (knownPoints.size === 0 || unknownPointList.length === 0 || observations.length === 0) {
    return resultFor(
      "control_network",
      "error",
      "三维基线网平差需要 knownPoints xyz、unknownPoints xyz 和 gnss_baseline observations。",
      {
        adjustment_model: "gnss_baseline_3d_lsq",
        known_point_count: knownPoints.size,
        unknown_point_count: unknownPointList.length,
        baseline_count: observations.length,
      },
      [],
      ["请至少提供 1 个三维已知点、1 个三维未知点近似坐标和 GNSS 基线向量观测。"],
    );
  }

  const blocks: ControlBaselineEquationBlock[] = [];
  for (const obs of observations) {
    const built = buildBaselineEquationBlock(obs, knownPoints, unknownPointList, unknownIndex, parameterCount);
    if (built.warning) warnings.push(built.warning);
    if (built.block) blocks.push(built.block);
  }
  const observationComponentCount = blocks.length * 3;
  const covarianceMatrixCount = blocks.filter((block) => block.covarianceModel === "full_3x3").length;

  if (observationComponentCount < parameterCount || parameterCount === 0) {
    return resultFor(
      "control_network",
      "error",
      "三维基线网有效观测不足，无法形成满秩法方程。",
      {
        adjustment_model: "gnss_baseline_3d_lsq",
        observation_component_count: observationComponentCount,
        unknown_parameter_count: parameterCount,
      },
      [],
      ["检查基线是否把未知三维点连接到已知控制点，或固定更多点。"],
    );
  }

  const solved = solveControlBlockNormalEquations(blocks, parameterCount);
  if (!solved) {
    return resultFor(
      "control_network",
      "error",
      "三维基线网几何结构退化，法方程不可解。",
      {
        adjustment_model: "gnss_baseline_3d_lsq",
        observation_component_count: observationComponentCount,
        unknown_parameter_count: parameterCount,
      },
      [],
      ["增加不同方向的基线或固定更多三维控制点。"],
    );
  }

  for (const [index, point] of unknownPointList.entries()) {
    point.x += solved.delta[index * 3] ?? 0;
    point.y += solved.delta[index * 3 + 1] ?? 0;
    point.z = (point.z ?? 0) + (solved.delta[index * 3 + 2] ?? 0);
  }

  const redundancy = Math.max(0, observationComponentCount - parameterCount);
  const residualBlocks = blocks.map((block) => {
    const from = controlPoint3ById(block.obs.from, knownPoints, unknownPointList);
    const to = controlPoint3ById(block.obs.to, knownPoints, unknownPointList);
    const computed: [number, number, number] = [
      (to?.x ?? 0) - (from?.x ?? 0),
      (to?.y ?? 0) - (from?.y ?? 0),
      (to?.z ?? 0) - (from?.z ?? 0),
    ];
    const residuals: [number, number, number] = [
      block.obs.dx - computed[0],
      block.obs.dy - computed[1],
      block.obs.dz - computed[2],
    ];
    return { block, computed, residuals };
  });
  const weightedResidualSum = residualBlocks.reduce(
    (sum, item) => sum + quadraticForm(item.residuals, item.block.weightMatrix),
    0,
  );
  const unitWeightStd = redundancy > 0 ? Math.sqrt(weightedResidualSum / redundancy) : 0;
  const covariance = invertMatrix(solved.normal);
  const coordinateToleranceMm = numberFrom(input.coordinateToleranceMm, 20);
  const residualToleranceMm = numberFrom(input.residualToleranceMm, 10);
  let maxCoordinateStdMm = 0;
  let maxCorrectionMm = 0;
  let maxVectorResidualMm = 0;
  let maxStandardizedResidual = 0;

  const pointRows = unknownPointList.map((point, index) => {
    const stdX = unitWeightStd * Math.sqrt(Math.max(0, covariance?.[index * 3]?.[index * 3] ?? 0)) * 1000;
    const stdY = unitWeightStd * Math.sqrt(Math.max(0, covariance?.[index * 3 + 1]?.[index * 3 + 1] ?? 0)) * 1000;
    const stdZ = unitWeightStd * Math.sqrt(Math.max(0, covariance?.[index * 3 + 2]?.[index * 3 + 2] ?? 0)) * 1000;
    const std3d = Math.hypot(stdX, stdY, stdZ);
    const correctionDxMm = (point.x - point.initialX) * 1000;
    const correctionDyMm = (point.y - point.initialY) * 1000;
    const correctionDzMm = ((point.z ?? 0) - point.initialZ) * 1000;
    const correction3dMm = Math.hypot(correctionDxMm, correctionDyMm, correctionDzMm);
    maxCoordinateStdMm = Math.max(maxCoordinateStdMm, std3d);
    maxCorrectionMm = Math.max(maxCorrectionMm, correction3dMm);
    return {
      row_type: "gnss_point",
      point_id: point.id,
      initial_x: round(point.initialX, 4),
      initial_y: round(point.initialY, 4),
      initial_z: round(point.initialZ, 4),
      adjusted_x: round(point.x, 6),
      adjusted_y: round(point.y, 6),
      adjusted_z: round(point.z ?? 0, 6),
      correction_dx_mm: round(correctionDxMm, 3),
      correction_dy_mm: round(correctionDyMm, 3),
      correction_dz_mm: round(correctionDzMm, 3),
      correction_3d_mm: round(correction3dMm, 3),
      std_x_mm: round(stdX, 3),
      std_y_mm: round(stdY, 3),
      std_z_mm: round(stdZ, 3),
      std_3d_mm: round(std3d, 3),
    };
  });

  const residualRows = residualBlocks.map(({ block, computed, residuals }) => {
    const obs = block.obs;
    const [computedDx, computedDy, computedDz] = computed;
    const [residualDx, residualDy, residualDz] = residuals;
    const residualVectorMm = Math.hypot(residualDx, residualDy, residualDz) * 1000;
    const mahalanobisResidual = Math.sqrt(Math.max(0, quadraticForm(residuals, block.weightMatrix)));
    maxVectorResidualMm = Math.max(maxVectorResidualMm, residualVectorMm);
    maxStandardizedResidual = Math.max(
      maxStandardizedResidual,
      Math.abs(residualDx / block.sigmas[0]),
      Math.abs(residualDy / block.sigmas[1]),
      Math.abs(residualDz / block.sigmas[2]),
      mahalanobisResidual,
    );
    return {
      row_type: "gnss_baseline_residual",
      observation_id: obs.id,
      observation_type: "gnss_baseline",
      covariance_model: block.covarianceModel,
      from: obs.from,
      to: obs.to,
      observed_dx_m: round(obs.dx, 6),
      observed_dy_m: round(obs.dy, 6),
      observed_dz_m: round(obs.dz, 6),
      computed_dx_m: round(computedDx, 6),
      computed_dy_m: round(computedDy, 6),
      computed_dz_m: round(computedDz, 6),
      residual_dx_mm: round(residualDx * 1000, 4),
      residual_dy_mm: round(residualDy * 1000, 4),
      residual_dz_mm: round(residualDz * 1000, 4),
      vector_residual_mm: round(residualVectorMm, 4),
      sigma_x_mm: round(block.sigmas[0] * 1000, 4),
      sigma_y_mm: round(block.sigmas[1] * 1000, 4),
      sigma_z_mm: round(block.sigmas[2] * 1000, 4),
      covariance_xy_m2: block.covarianceM2 ? round(block.covarianceM2[0]?.[1] ?? 0, 12) : "",
      covariance_xz_m2: block.covarianceM2 ? round(block.covarianceM2[0]?.[2] ?? 0, 12) : "",
      covariance_yz_m2: block.covarianceM2 ? round(block.covarianceM2[1]?.[2] ?? 0, 12) : "",
      mahalanobis_residual: round(mahalanobisResidual, 4),
    };
  });

  if (redundancy === 0) warnings.push("观测冗余度为 0，无法可靠估计单位权中误差");
  if (maxCoordinateStdMm > coordinateToleranceMm) warnings.push(`最大三维点位中误差 ${round(maxCoordinateStdMm, 3)} mm 超过 ${coordinateToleranceMm} mm`);
  if (maxVectorResidualMm > residualToleranceMm) warnings.push(`最大基线向量残差 ${round(maxVectorResidualMm, 3)} mm 超过 ${residualToleranceMm} mm`);

  return resultFor(
    "control_network",
    statusFromWarnings(warnings),
    `三维 GNSS 基线网最小二乘平差完成：${unknownPointList.length} 个未知点、${blocks.length} 条基线、${observationComponentCount} 个分量观测、冗余度 ${redundancy}。`,
    {
      adjustment_model: "gnss_baseline_3d_lsq",
      known_point_count: knownPoints.size,
      unknown_point_count: unknownPointList.length,
      baseline_count: blocks.length,
      observation_component_count: observationComponentCount,
      unknown_parameter_count: parameterCount,
      baseline_covariance_matrix_count: covarianceMatrixCount,
      redundancy,
      max_correction_mm: round(maxCorrectionMm, 3),
      unit_weight_std: round(unitWeightStd, 6),
      max_coordinate_std_mm: round(maxCoordinateStdMm, 3),
      max_vector_residual_mm: round(maxVectorResidualMm, 3),
      max_standardized_residual: round(maxStandardizedResidual, 4),
    },
    [...pointRows, ...residualRows],
    warnings.length > 0
      ? [...warnings, "请复核基线解算质量、固定点稳定性和协方差/权阵设置后重新平差。"]
      : ["GNSS 基线网结果可用于三维控制复核；正式成果提交前请核对固定点、天线高和基线质量指标。"],
  );
}

function calculateControlDirectionSetAdjustment(input: Record<string, unknown>): EngineeringResult {
  const knownPointList = parseControlNetworkPoints(input.knownPoints ?? input.fixedPoints);
  const unknownPointList = parseControlNetworkPoints(input.unknownPoints ?? input.approximatePoints).map((point) => ({
    ...point,
    initialX: point.x,
    initialY: point.y,
  }));
  const allObservationInputs = arrayFrom(input.observations);
  const directionObservations = allObservationInputs
    .map((item, index) => parseControlDirectionObservation(item, index))
    .filter((obs): obs is ControlDirectionObservation => Boolean(obs));
  const observations = allObservationInputs
    .map((item, index) => parseControlNetworkObservation(item, index))
    .filter((obs): obs is ControlNetworkObservation => Boolean(obs));
  const knownPoints = new Map(knownPointList.map((point) => [point.id, point]));
  const groupIds = Array.from(new Set(directionObservations.map((obs) => obs.groupId)));
  const parameterCount = unknownPointList.length * 2 + groupIds.length;
  const coordinateParameterCount = unknownPointList.length * 2;
  const warnings: string[] = [];

  if (knownPoints.size === 0 || unknownPointList.length === 0 || directionObservations.length === 0 || groupIds.length === 0) {
    return resultFor(
      "control_network",
      "error",
      "方向组平差需要 knownPoints、unknownPoints 和 direction observations。",
      {
        adjustment_model: "distance_direction_set_lsq",
        known_point_count: knownPoints.size,
        unknown_point_count: unknownPointList.length,
        direction_observation_count: directionObservations.length,
        direction_group_count: groupIds.length,
      },
      [],
      ["请至少提供 1 个已知点、1 个未知点近似坐标，以及带 setId/directionSet 的方向观测。"],
    );
  }

  if (observations.length + directionObservations.length < parameterCount) {
    return resultFor(
      "control_network",
      "error",
      `观测数 ${observations.length + directionObservations.length} 少于未知参数数 ${parameterCount}，无法平差。`,
      {
        adjustment_model: "distance_direction_set_lsq",
        observation_count: observations.length + directionObservations.length,
        unknown_parameter_count: parameterCount,
        orientation_parameter_count: groupIds.length,
      },
      [],
      ["增加方向组内照准点、距离观测或固定更多控制点后重新平差。"],
    );
  }

  const maxIterations = Math.max(1, Math.min(50, Math.round(numberFrom(input.maxIterations, 12))));
  const convergenceMm = Math.max(0.0001, numberFrom(input.convergenceMm, 0.01));
  const orientationConvergenceArcSec = Math.max(0.000001, numberFrom(input.orientationConvergenceArcSec, 0.001));
  const initialOrientations = initialDirectionOrientations(knownPoints, unknownPointList, directionObservations, groupIds);
  const orientations = new Map(initialOrientations);
  let iterationCount = 0;
  let maxCorrectionMm = Number.POSITIVE_INFINITY;
  let maxOrientationCorrectionArcSec = Number.POSITIVE_INFINITY;
  let lastNormal: number[][] | null = null;

  for (let iteration = 0; iteration < maxIterations; iteration += 1) {
    const equations = buildControlDirectionSetEquations(knownPoints, unknownPointList, observations, directionObservations, groupIds, orientations);
    if (equations.skipped.length > 0) warnings.push(...equations.skipped);
    if (equations.design.length < parameterCount) {
      return resultFor(
        "control_network",
        "error",
        "方向组有效观测不足，无法形成满秩法方程。",
        {
          adjustment_model: "distance_direction_set_lsq",
          observation_count: equations.design.length,
          unknown_parameter_count: parameterCount,
          orientation_parameter_count: groupIds.length,
        },
        [],
        ["检查方向组是否包含后视/前视读数，且点号能够连接到已知控制点。"],
      );
    }
    const solved = solveControlNormalEquations(equations.design, equations.closure, equations.weights, parameterCount);
    if (!solved) {
      return resultFor(
        "control_network",
        "error",
        "方向组控制网几何结构退化，法方程不可解。",
        {
          adjustment_model: "distance_direction_set_lsq",
          observation_count: equations.design.length,
          unknown_parameter_count: parameterCount,
          orientation_parameter_count: groupIds.length,
        },
        [],
        ["每个方向组通常需要至少一个后视方向和一个待定点方向，并配合距离或交会约束。"],
      );
    }
    lastNormal = solved.normal;
    maxCorrectionMm = 0;
    maxOrientationCorrectionArcSec = 0;
    for (let pointIndex = 0; pointIndex < unknownPointList.length; pointIndex += 1) {
      const dx = solved.delta[pointIndex * 2] ?? 0;
      const dy = solved.delta[pointIndex * 2 + 1] ?? 0;
      unknownPointList[pointIndex]!.x += dx;
      unknownPointList[pointIndex]!.y += dy;
      maxCorrectionMm = Math.max(maxCorrectionMm, Math.hypot(dx, dy) * 1000);
    }
    for (const [groupIndex, groupId] of groupIds.entries()) {
      const delta = solved.delta[coordinateParameterCount + groupIndex] ?? 0;
      orientations.set(groupId, normalizeRadians((orientations.get(groupId) ?? 0) + delta));
      maxOrientationCorrectionArcSec = Math.max(maxOrientationCorrectionArcSec, Math.abs(radiansToDegrees(delta) * 3600));
    }
    iterationCount = iteration + 1;
    if (maxCorrectionMm <= convergenceMm && maxOrientationCorrectionArcSec <= orientationConvergenceArcSec) break;
  }

  const finalEquations = buildControlDirectionSetEquations(knownPoints, unknownPointList, observations, directionObservations, groupIds, orientations);
  const residuals = finalEquations.closure;
  const redundancy = Math.max(0, finalEquations.design.length - parameterCount);
  const weightedResidualSum = residuals.reduce((sum, residual, index) => sum + residual ** 2 * (finalEquations.weights[index] ?? 1), 0);
  const unitWeightStd = redundancy > 0 ? Math.sqrt(weightedResidualSum / redundancy) : 0;
  const covariance = lastNormal ? invertMatrix(lastNormal) : null;
  const coordinateToleranceMm = numberFrom(input.coordinateToleranceMm, 20);
  const residualToleranceMm = numberFrom(input.residualToleranceMm, 10);
  const directionResidualToleranceArcSec = numberFrom(input.directionResidualToleranceArcSec, 10);
  const faceDifferenceToleranceArcSec = numberFrom(input.faceDifferenceToleranceArcSec, 12);
  const zeroClosureToleranceArcSec = numberFrom(input.zeroClosureToleranceArcSec, 12);
  const directionQuality = directionRoundQualityRows(directionObservations, faceDifferenceToleranceArcSec, zeroClosureToleranceArcSec);
  let maxCoordinateStdMm = 0;
  let maxResidualMm = 0;
  let maxDirectionResidualArcSec = 0;
  let maxStandardizedResidual = 0;

  const pointRows = unknownPointList.map((point, index) => {
    const stdX = unitWeightStd * Math.sqrt(Math.max(0, covariance?.[index * 2]?.[index * 2] ?? 0)) * 1000;
    const stdY = unitWeightStd * Math.sqrt(Math.max(0, covariance?.[index * 2 + 1]?.[index * 2 + 1] ?? 0)) * 1000;
    const stdPlanar = Math.hypot(stdX, stdY);
    maxCoordinateStdMm = Math.max(maxCoordinateStdMm, stdPlanar);
    return {
      row_type: "point",
      point_id: point.id,
      initial_x: round(point.initialX, 4),
      initial_y: round(point.initialY, 4),
      adjusted_x: round(point.x, 4),
      adjusted_y: round(point.y, 4),
      correction_dx_mm: round((point.x - point.initialX) * 1000, 3),
      correction_dy_mm: round((point.y - point.initialY) * 1000, 3),
      correction_mm: round(Math.hypot(point.x - point.initialX, point.y - point.initialY) * 1000, 3),
      std_x_mm: round(stdX, 3),
      std_y_mm: round(stdY, 3),
      std_planar_mm: round(stdPlanar, 3),
    };
  });

  const orientationRows = groupIds.map((groupId, index) => {
    const obs = directionObservations.find((item) => item.groupId === groupId);
    const orientation = orientations.get(groupId) ?? 0;
    const initialOrientation = initialOrientations.get(groupId) ?? 0;
    const stdOrientationArcSec =
      unitWeightStd * Math.sqrt(Math.max(0, covariance?.[coordinateParameterCount + index]?.[coordinateParameterCount + index] ?? 0)) * 180 / Math.PI * 3600;
    return {
      row_type: "direction_set_orientation",
      direction_group_id: groupId,
      station_id: obs?.from ?? "",
      orientation_degrees: round(normalizeDegrees(radiansToDegrees(orientation)), 9),
      orientation_correction_arcsec: round(radiansToDegrees(deltaRadians(orientation, initialOrientation)) * 3600, 4),
      std_orientation_arcsec: round(stdOrientationArcSec, 4),
      observation_count: directionObservations.filter((item) => item.groupId === groupId).length,
    };
  });

  const residualRows = finalEquations.meta.map((meta, index) => {
    const residual = residuals[index] ?? 0;
    const residualArcSec = meta.kind === "distance" ? 0 : radiansToDegrees(residual) * 3600;
    const residualMm = meta.kind === "distance" ? residual * 1000 : residual * meta.distance * 1000;
    const standardized = residual / meta.obs.sigma;
    maxResidualMm = Math.max(maxResidualMm, Math.abs(residualMm));
    maxDirectionResidualArcSec = Math.max(maxDirectionResidualArcSec, Math.abs(residualArcSec));
    maxStandardizedResidual = Math.max(maxStandardizedResidual, Math.abs(standardized));
    return {
      row_type: meta.kind === "direction" ? "direction_observation_residual" : "observation_residual",
      observation_id: meta.obs.id,
      observation_type: meta.kind,
      direction_group_id: meta.groupId ?? "",
      from: meta.obs.from,
      to: meta.obs.to,
      observed: round(meta.kind === "distance" ? meta.obs.observed : radiansToDegrees(meta.obs.observed), 9),
      observed_distance_m: meta.kind === "distance" ? round(meta.obs.observed, 9) : null,
      computed: round(meta.kind === "distance" ? meta.computed : radiansToDegrees(meta.computed), 9),
      computed_distance_m: meta.kind === "distance" ? round(meta.computed, 9) : null,
      residual_mm: round(residualMm, 4),
      residual_arcsec: meta.kind === "distance" ? "" : round(residualArcSec, 4),
      sigma: round(meta.obs.sigma, 12),
      standardized_residual: round(standardized, 4),
    };
  });

  if (redundancy === 0) warnings.push("观测冗余度为 0，无法可靠估计单位权中误差");
  if (iterationCount >= maxIterations && (maxCorrectionMm > convergenceMm || maxOrientationCorrectionArcSec > orientationConvergenceArcSec)) {
    warnings.push(`迭代 ${iterationCount} 次后方向组平差仍未充分收敛`);
  }
  if (maxCoordinateStdMm > coordinateToleranceMm) warnings.push(`最大点位中误差 ${round(maxCoordinateStdMm, 3)} mm 超过 ${coordinateToleranceMm} mm`);
  if (maxResidualMm > residualToleranceMm) warnings.push(`最大观测残差 ${round(maxResidualMm, 3)} mm 超过 ${residualToleranceMm} mm`);
  if (maxDirectionResidualArcSec > directionResidualToleranceArcSec) {
    warnings.push(`最大方向残差 ${round(maxDirectionResidualArcSec, 3)}″ 超过 ${directionResidualToleranceArcSec}″`);
  }
  if (directionQuality.maxFaceDifferenceArcSec > faceDifferenceToleranceArcSec) {
    warnings.push(`最大半测回差 ${round(directionQuality.maxFaceDifferenceArcSec, 3)}″ 超过 ${faceDifferenceToleranceArcSec}″`);
  }
  if (directionQuality.maxZeroClosureArcSec > zeroClosureToleranceArcSec) {
    warnings.push(`最大归零差 ${round(directionQuality.maxZeroClosureArcSec, 3)}″ 超过 ${zeroClosureToleranceArcSec}″`);
  }

  return resultFor(
    "control_network",
    statusFromWarnings(warnings),
    `方向组控制网最小二乘平差完成：${unknownPointList.length} 个未知点、${groupIds.length} 个方向组、${finalEquations.design.length} 条有效观测、冗余度 ${redundancy}。`,
    {
      adjustment_model: "distance_direction_set_lsq",
      known_point_count: knownPoints.size,
      unknown_point_count: unknownPointList.length,
      observation_count: finalEquations.design.length,
      distance_azimuth_observation_count: observations.length,
      direction_observation_count: directionObservations.length,
      direction_group_count: groupIds.length,
      coordinate_parameter_count: coordinateParameterCount,
      orientation_parameter_count: groupIds.length,
      unknown_parameter_count: parameterCount,
      redundancy,
      iteration_count: iterationCount,
      max_correction_mm: round(maxCorrectionMm, 4),
      max_orientation_correction_arcsec: round(maxOrientationCorrectionArcSec, 6),
      unit_weight_std: round(unitWeightStd, 6),
      max_coordinate_std_mm: round(maxCoordinateStdMm, 3),
      max_residual_mm: round(maxResidualMm, 3),
      max_direction_residual_arcsec: round(maxDirectionResidualArcSec, 4),
      direction_face_pair_count: directionQuality.faceRows.length,
      direction_round_summary_count: directionQuality.summaryRows.length,
      max_face_difference_arcsec: round(directionQuality.maxFaceDifferenceArcSec, 4),
      face_difference_tolerance_arcsec: faceDifferenceToleranceArcSec,
      direction_zero_closure_count: directionQuality.zeroRows.length,
      max_zero_closure_arcsec: round(directionQuality.maxZeroClosureArcSec, 4),
      zero_closure_tolerance_arcsec: zeroClosureToleranceArcSec,
      max_standardized_residual: round(maxStandardizedResidual, 4),
    },
    [
      ...pointRows,
      ...orientationRows,
      ...directionQuality.summaryRows,
      ...directionQuality.faceRows,
      ...directionQuality.zeroRows,
      ...residualRows,
    ],
    warnings.length > 0
      ? [...warnings, "请复核测站定向、后视点稳定性、方向组读数和观测权后重新平差。"]
      : ["方向组边角网结果可用于全站仪控制复核；正式成果提交前请核对归零差、测回差和仪器改正。"],
    {
      algorithm: "距离/绝对方位角观测方程 + 方向组测站定向未知数联合最小二乘",
      workflow: ["读取已知点、未知点、距离/方位角和方向组读数", "为每个方向组估计测站定向角", "联合解算点位与定向角", "输出点位精度、方向组定向和方向残差"],
      qualityChecks: ["方向组内后视/前视连通性", "半测回差", "归零差", "观测冗余度", "方向残差", "点位中误差", "单位权中误差"],
      deliverables: ["平差坐标表", "方向组定向表", "半测回差/归零差质控表", "距离/方向残差表", "Markdown 复核报告"],
    },
  );
}

function calculateControlNetworkAdjustment(input: Record<string, unknown>): EngineeringResult {
  const baselineObservations = arrayFrom(input.observations)
    .map((item, index) => parseControlBaselineObservation(item, index))
    .filter((obs): obs is ControlBaselineObservation => Boolean(obs));
  if (baselineObservations.length > 0) return calculateControlBaselineAdjustment(input);

  const levelingSigmaMmPerSqrtKm = numberByAliases(
    input,
    [
      "levelingSigmaMmPerSqrtKm",
      "sigmaMmPerSqrtKm",
      "levelingStdMmPerSqrtKm",
      "stdMmPerSqrtKm",
      "水准每公里中误差mm",
      "每公里中误差mm",
      "每根号公里中误差mm",
    ],
    Number.NaN,
  );
  const heightObservations = arrayFrom(input.observations)
    .map((item, index) =>
      parseControlHeightObservation(
        item,
        index,
        Number.isFinite(levelingSigmaMmPerSqrtKm) && levelingSigmaMmPerSqrtKm > 0 ? levelingSigmaMmPerSqrtKm : undefined,
      ),
    )
    .filter((obs): obs is ControlHeightObservation => Boolean(obs));
  if (heightObservations.length > 0) return calculateControlHeightAdjustment(input);

  const directionObservations = arrayFrom(input.observations)
    .map((item, index) => parseControlDirectionObservation(item, index))
    .filter((obs): obs is ControlDirectionObservation => Boolean(obs));
  if (directionObservations.length > 0) return calculateControlDirectionSetAdjustment(input);

  const knownPointList = parseControlNetworkPoints(input.knownPoints ?? input.fixedPoints);
  const unknownPointList = parseControlNetworkPoints(input.unknownPoints ?? input.approximatePoints).map((point) => ({
    ...point,
    initialX: point.x,
    initialY: point.y,
  }));
  const observations = arrayFrom(input.observations)
    .map((item, index) => parseControlNetworkObservation(item, index))
    .filter((obs): obs is ControlNetworkObservation => Boolean(obs));
  const knownPoints = new Map(knownPointList.map((point) => [point.id, point]));
  const warnings: string[] = [];
  const parameterCount = unknownPointList.length * 2;
  const modeText = textFrom(input.networkMode ?? input.adjustmentMode ?? input.mode, "").toLowerCase();
  const freeNetworkRequested = input.freeNetwork === true || modeText.includes("free") || modeText.includes("自由");
  const isFreeNetwork = freeNetworkRequested && knownPoints.size === 0;
  const datumConstraints = isFreeNetwork ? freeNetworkDatumConstraints(unknownPointList, observations.every((obs) => obs.type === "distance")) : [];
  const effectiveParameterCount = Math.max(0, parameterCount - datumConstraints.length);
  const adjustmentModel = isFreeNetwork ? "free_distance_azimuth_lsq" : "distance_azimuth_lsq";

  if ((!isFreeNetwork && knownPoints.size === 0) || unknownPointList.length === 0 || observations.length === 0) {
    return resultFor(
      "control_network",
      "error",
      isFreeNetwork
        ? "自由网平差需要 unknownPoints 和 distance/azimuth observations。"
        : "控制网平差需要 knownPoints、unknownPoints 和 distance/azimuth observations。",
      {
        adjustment_model: adjustmentModel,
        known_point_count: knownPoints.size,
        unknown_point_count: unknownPointList.length,
        observation_count: observations.length,
        datum_constraint_count: datumConstraints.length,
      },
      [],
      isFreeNetwork
        ? ["请提供待定点近似坐标和足够的边角观测。"]
        : ["请至少提供 1 个已知点、1 个未知点近似坐标和足够的距离/方位角观测。"],
    );
  }
  if (observations.length < effectiveParameterCount) {
    return resultFor(
      "control_network",
      "error",
      `观测数 ${observations.length} 少于有效未知参数数 ${effectiveParameterCount}，无法平差。`,
      {
        adjustment_model: adjustmentModel,
        known_point_count: knownPoints.size,
        unknown_point_count: unknownPointList.length,
        observation_count: observations.length,
        unknown_parameter_count: parameterCount,
        effective_parameter_count: effectiveParameterCount,
        datum_constraint_count: datumConstraints.length,
      },
      [],
      ["增加观测冗余，或固定更多控制点后重新平差。"],
    );
  }

  const maxIterations = Math.max(1, Math.min(50, Math.round(numberFrom(input.maxIterations, 12))));
  const convergenceMm = Math.max(0.0001, numberFrom(input.convergenceMm, 0.01));
  let iterationCount = 0;
  let maxCorrectionMm = Number.POSITIVE_INFINITY;
  let lastNormal: number[][] | null = null;
  let lastCovariance: number[][] | null = null;

  for (let iteration = 0; iteration < maxIterations; iteration += 1) {
    const equations = buildControlNetworkEquations(knownPoints, unknownPointList, observations);
    if (equations.skipped.length > 0) warnings.push(...equations.skipped);
    if (equations.design.length < effectiveParameterCount) {
      return resultFor(
        "control_network",
        "error",
        "有效观测不足，无法形成满秩法方程。",
        {
          adjustment_model: adjustmentModel,
          observation_count: equations.design.length,
          unknown_parameter_count: parameterCount,
          effective_parameter_count: effectiveParameterCount,
          datum_constraint_count: datumConstraints.length,
        },
        [],
        ["检查点号是否匹配、观测边是否连接到已知点和未知点。"],
      );
    }
    const solved = solveControlNormalEquations(equations.design, equations.closure, equations.weights, parameterCount, datumConstraints);
    if (!solved) {
      return resultFor(
        "control_network",
        "error",
        isFreeNetwork ? "自由网几何结构退化，内约束法方程不可解。" : "控制网几何结构退化，法方程不可解。",
        {
          adjustment_model: adjustmentModel,
          observation_count: equations.design.length,
          unknown_parameter_count: parameterCount,
          effective_parameter_count: effectiveParameterCount,
          datum_constraint_count: datumConstraints.length,
        },
        [],
        ["增加不同方向的观测，避免所有观测几何共线或缺少定向约束。"],
      );
    }
    lastNormal = solved.normal;
    lastCovariance = solved.covariance ?? null;
    maxCorrectionMm = 0;
    for (let pointIndex = 0; pointIndex < unknownPointList.length; pointIndex += 1) {
      const dx = solved.delta[pointIndex * 2] ?? 0;
      const dy = solved.delta[pointIndex * 2 + 1] ?? 0;
      unknownPointList[pointIndex]!.x += dx;
      unknownPointList[pointIndex]!.y += dy;
      maxCorrectionMm = Math.max(maxCorrectionMm, Math.hypot(dx, dy) * 1000);
    }
    iterationCount = iteration + 1;
    if (maxCorrectionMm <= convergenceMm) break;
  }

  const finalEquations = buildControlNetworkEquations(knownPoints, unknownPointList, observations);
  const residuals = finalEquations.closure;
  const redundancy = Math.max(0, finalEquations.design.length - effectiveParameterCount);
  const weightedResidualSum = residuals.reduce((sum, residual, index) => sum + residual ** 2 * (finalEquations.weights[index] ?? 1), 0);
  const unitWeightStd = redundancy > 0 ? Math.sqrt(weightedResidualSum / redundancy) : 0;
  const covariance = lastCovariance ?? (lastNormal ? invertMatrix(lastNormal) : null);
  const coordinateToleranceMm = numberFrom(input.coordinateToleranceMm, 20);
  const residualToleranceMm = numberFrom(input.residualToleranceMm, 10);
  const datumResidualToleranceMm = numberFrom(input.datumResidualToleranceMm ?? input.controlToleranceMm, 5);
  const grossErrorStandardizedThreshold = Math.max(
    0.1,
    numberFrom(input.standardizedResidualTolerance ?? input.grossErrorStandardizedThreshold ?? input.grossErrorThreshold, 3),
  );
  const suppressGrossErrorRecompute = input.__suppressGrossErrorRecompute === true;
  let maxCoordinateStdMm = 0;
  let maxResidualMm = 0;
  let maxStandardizedResidual = 0;

  const pointRows = unknownPointList.map((point, index) => {
    const stdX = unitWeightStd * Math.sqrt(Math.max(0, covariance?.[index * 2]?.[index * 2] ?? 0)) * 1000;
    const stdY = unitWeightStd * Math.sqrt(Math.max(0, covariance?.[index * 2 + 1]?.[index * 2 + 1] ?? 0)) * 1000;
    const stdPlanar = Math.hypot(stdX, stdY);
    maxCoordinateStdMm = Math.max(maxCoordinateStdMm, stdPlanar);
    return {
      row_type: "point",
      point_id: point.id,
      initial_x: round(point.initialX, 4),
      initial_y: round(point.initialY, 4),
      adjusted_x: round(point.x, 4),
      adjusted_y: round(point.y, 4),
      correction_dx_mm: round((point.x - point.initialX) * 1000, 3),
      correction_dy_mm: round((point.y - point.initialY) * 1000, 3),
      correction_mm: round(Math.hypot(point.x - point.initialX, point.y - point.initialY) * 1000, 3),
      std_x_mm: round(stdX, 3),
      std_y_mm: round(stdY, 3),
      std_planar_mm: round(stdPlanar, 3),
    };
  });

  const datumControlPoints = parseControlNetworkPoints(
    input.datumControlPoints ?? input.stableControlPoints ?? input.constraintPoints ?? input.datumPoints,
  ).filter((point) => Number.isFinite(point.x) && Number.isFinite(point.y));
  const adjustedPointsById = new Map(unknownPointList.map((point) => [point.id, point]));
  const datumPairs = datumControlPoints
    .map((point) => {
      const source = adjustedPointsById.get(point.id);
      return source
        ? {
            id: point.id,
            source: { x: source.x, y: source.y },
            target: { x: point.x, y: point.y },
            weight: 1,
          }
        : null;
    })
    .filter((pair): pair is { id: string; source: Point2; target: Point2; weight: number } => Boolean(pair));
  const datumFitted = isFreeNetwork && datumPairs.length > 0 ? fitHelmert2d(datumPairs) : null;
  const constrainedRows = datumFitted
    ? unknownPointList.map((point) => {
        const constrained = transformPoint2d(datumFitted.params, point);
        return {
          row_type: "constrained_point",
          point_id: point.id,
          free_x: round(point.x, 6),
          free_y: round(point.y, 6),
          constrained_x: round(constrained.x, 6),
          constrained_y: round(constrained.y, 6),
        };
      })
    : [];
  const datumDiagnostics = datumFitted
    ? diagnoseDatumControlStability(datumPairs, datumFitted, datumResidualToleranceMm)
    : [];
  const datumDiagnosticsById = new Map(datumDiagnostics.map((diagnosis) => [diagnosis.id, diagnosis]));
  const datumCandidateDiagnostics = datumDiagnostics
    .filter((diagnosis) => diagnosis.stabilityDiagnosis === "candidate_unstable")
    .sort((a, b) => (a.leaveOneOutRmsMm ?? Number.POSITIVE_INFINITY) - (b.leaveOneOutRmsMm ?? Number.POSITIVE_INFINITY));
  const datumBestExclusion = datumCandidateDiagnostics[0];
  const datumRecomputedFit = datumBestExclusion
    ? fitHelmert2d(datumPairs.filter((pair) => pair.id !== datumBestExclusion.id))
    : null;
  const constrainedByPointId = new Map(
    constrainedRows.map((row) => [
      String(row.point_id),
      {
        x: numberFrom(row.constrained_x),
        y: numberFrom(row.constrained_y),
      },
    ]),
  );
  const datumExclusionRows =
    datumBestExclusion && datumRecomputedFit
      ? [
          {
            row_type: "datum_exclusion_comparison",
            excluded_point_id: datumBestExclusion.id,
            before_rms_mm: round(datumFitted?.rmsMm ?? 0, 4),
            before_max_residual_mm: round(datumFitted?.maxResidualMm ?? 0, 4),
            after_rms_mm: round(datumRecomputedFit.rmsMm, 4),
            after_max_residual_mm: round(datumRecomputedFit.maxResidualMm, 4),
            rms_improvement_mm: round((datumFitted?.rmsMm ?? 0) - datumRecomputedFit.rmsMm, 4),
            max_residual_improvement_mm: round((datumFitted?.maxResidualMm ?? 0) - datumRecomputedFit.maxResidualMm, 4),
            recommended_action: "review_excluded_point_before_finalizing",
          },
        ]
      : [];
  const recomputedConstrainedRows =
    datumBestExclusion && datumRecomputedFit
      ? unknownPointList.map((point) => {
          const recomputed = transformPoint2d(datumRecomputedFit.params, point);
          const original = constrainedByPointId.get(point.id);
          return {
            row_type: "constrained_point_recomputed",
            point_id: point.id,
            excluded_point_id: datumBestExclusion.id,
            free_x: round(point.x, 6),
            free_y: round(point.y, 6),
            constrained_x: round(recomputed.x, 6),
            constrained_y: round(recomputed.y, 6),
            original_constrained_x: round(original?.x ?? 0, 6),
            original_constrained_y: round(original?.y ?? 0, 6),
            delta_from_original_constraint_mm: round(
              original ? Math.hypot(recomputed.x - original.x, recomputed.y - original.y) * 1000 : 0,
              4,
            ),
          };
        })
      : [];
  const recomputedDatumResidualRows =
    datumBestExclusion && datumRecomputedFit
      ? datumRecomputedFit.residuals.map((residual) => ({
          row_type: "datum_control_residual_recomputed",
          point_id: residual.id,
          excluded_point_id: datumBestExclusion.id,
          residual_dx_mm: round(residual.dxMm, 4),
          residual_dy_mm: round(residual.dyMm, 4),
          planar_residual_mm: round(residual.planarMm, 4),
          tolerance_mm: datumResidualToleranceMm,
          check_status: residual.planarMm <= datumResidualToleranceMm ? "ok" : "warn",
        }))
      : [];
  const datumResidualRows = datumFitted
    ? datumFitted.residuals.map((residual) => ({
        row_type: "datum_control_residual",
        point_id: residual.id,
        residual_dx_mm: round(residual.dxMm, 4),
        residual_dy_mm: round(residual.dyMm, 4),
        planar_residual_mm: round(residual.planarMm, 4),
        tolerance_mm: datumResidualToleranceMm,
        check_status: residual.planarMm <= datumResidualToleranceMm ? "ok" : "warn",
        residual_rank: datumDiagnosticsById.get(residual.id)?.residualRank ?? "",
        leave_one_out_rms_mm:
          datumDiagnosticsById.get(residual.id)?.leaveOneOutRmsMm === null
            ? ""
            : round(datumDiagnosticsById.get(residual.id)?.leaveOneOutRmsMm ?? 0, 4),
        leave_one_out_max_residual_mm:
          datumDiagnosticsById.get(residual.id)?.leaveOneOutMaxResidualMm === null
            ? ""
            : round(datumDiagnosticsById.get(residual.id)?.leaveOneOutMaxResidualMm ?? 0, 4),
        stability_diagnosis: datumDiagnosticsById.get(residual.id)?.stabilityDiagnosis ?? "",
      }))
    : [];

  const rawResidualRows = observations.map((obs, index) => {
    const residual = residuals[index] ?? 0;
    const distance = finalEquations.distances[index] ?? 0;
    const residualMm = obs.type === "distance" ? residual * 1000 : residual * distance * 1000;
    const standardized = residual / obs.sigma;
    maxResidualMm = Math.max(maxResidualMm, Math.abs(residualMm));
    maxStandardizedResidual = Math.max(maxStandardizedResidual, Math.abs(standardized));
    return {
      row_type: "observation_residual",
      observation_id: obs.id,
      observation_type: obs.type,
      from: obs.from,
      to: obs.to,
      observed: round(obs.type === "distance" ? obs.observed : radiansToDegrees(obs.observed), 9),
      observed_distance_m: obs.type === "distance" ? round(obs.observed, 9) : null,
      computed: round(obs.type === "distance" ? finalEquations.computed[index] ?? 0 : radiansToDegrees(finalEquations.computed[index] ?? 0), 9),
      computed_distance_m: obs.type === "distance" ? round(finalEquations.computed[index] ?? 0, 9) : null,
      residual_mm: round(residualMm, 4),
      residual_arcsec: obs.type === "azimuth" ? round(radiansToDegrees(residual) * 3600, 4) : "",
      sigma: round(obs.sigma, 12),
      standardized_residual: round(standardized, 4),
    };
  });
  const residualRanks = new Map(
    [...rawResidualRows]
      .sort((a, b) => Math.abs(numberFrom(b.standardized_residual)) - Math.abs(numberFrom(a.standardized_residual)))
      .map((row, index) => [String(row.observation_id), index + 1]),
  );
  const residualRows = rawResidualRows.map((row) => {
    const standardized = Math.abs(numberFrom(row.standardized_residual));
    const residualMm = Math.abs(numberFrom(row.residual_mm));
    const qualityStatus =
      standardized >= grossErrorStandardizedThreshold
        ? "gross_error_candidate"
        : residualMm > residualToleranceMm
          ? "review"
          : "ok";
    return {
      ...row,
      residual_rank: residualRanks.get(String(row.observation_id)) ?? "",
      gross_error_threshold: grossErrorStandardizedThreshold,
      quality_status: qualityStatus,
      recommended_action:
        qualityStatus === "gross_error_candidate"
          ? "remeasure_or_downweight"
          : qualityStatus === "review"
            ? "review_weight_and_geometry"
            : "accept",
    };
  });
  const grossErrorCandidates = residualRows.filter((row) => row.quality_status === "gross_error_candidate");
  const worstResidualRow = residualRows.find((row) => row.residual_rank === 1);
  const grossErrorRecomputedResult =
    !suppressGrossErrorRecompute &&
    worstResidualRow?.quality_status === "gross_error_candidate" &&
    observations.length - 1 >= effectiveParameterCount
      ? calculateControlNetworkAdjustment({
          ...input,
          knownPoints: knownPointList.map((point) => ({ ...point })),
          unknownPoints: unknownPointList.map((point) => ({
            id: point.id,
            x: point.initialX,
            y: point.initialY,
            ...(Number.isFinite(point.z) ? { z: point.z } : {}),
          })),
          observations: observations
            .filter((obs) => obs.id !== String(worstResidualRow.observation_id))
            .map((obs) =>
              obs.type === "distance"
                ? {
                    id: obs.id,
                    type: obs.type,
                    from: obs.from,
                    to: obs.to,
                    value: obs.observed,
                    sigmaMm: obs.sigma * 1000,
                  }
                : {
                    id: obs.id,
                    type: obs.type,
                    from: obs.from,
                    to: obs.to,
                    value: radiansToDegrees(obs.observed),
                    sigmaArcSec: radiansToDegrees(obs.sigma) * 3600,
                  },
            ),
          __suppressGrossErrorRecompute: true,
        })
      : null;
  const grossErrorRecomputedPointRows = grossErrorRecomputedResult
    ? grossErrorRecomputedResult.rows
        .filter((row) => row.row_type === "point")
        .map((row) => {
          const original = pointRows.find((pointRow) => pointRow.point_id === row.point_id);
          return {
            ...row,
            row_type: "point_recomputed",
            excluded_observation_id: worstResidualRow?.observation_id ?? "",
            original_adjusted_x: round(numberFrom(original?.adjusted_x), 4),
            original_adjusted_y: round(numberFrom(original?.adjusted_y), 4),
            delta_from_original_adjustment_mm: round(
              Math.hypot(
                numberFrom(row.adjusted_x) - numberFrom(original?.adjusted_x),
                numberFrom(row.adjusted_y) - numberFrom(original?.adjusted_y),
              ) * 1000,
              4,
            ),
          };
        })
    : [];
  const grossErrorRecomputedResidualRows = grossErrorRecomputedResult
    ? grossErrorRecomputedResult.rows
        .filter((row) => row.row_type === "observation_residual")
        .map((row) => ({
          ...row,
          row_type: "observation_residual_recomputed",
          excluded_observation_id: worstResidualRow?.observation_id ?? "",
        }))
    : [];
  const grossErrorExclusionRows =
    grossErrorRecomputedResult && worstResidualRow
      ? [
          {
            row_type: "gross_error_exclusion_comparison",
            excluded_observation_id: worstResidualRow.observation_id,
            before_max_residual_mm: round(maxResidualMm, 4),
            before_max_standardized_residual: round(maxStandardizedResidual, 4),
            before_unit_weight_std: round(unitWeightStd, 6),
            after_status: grossErrorRecomputedResult.status,
            after_observation_count: numberFrom(grossErrorRecomputedResult.metrics.observation_count),
            after_max_residual_mm: round(numberFrom(grossErrorRecomputedResult.metrics.max_residual_mm), 4),
            after_max_standardized_residual: round(
              numberFrom(grossErrorRecomputedResult.metrics.max_standardized_residual),
              4,
            ),
            after_unit_weight_std: round(numberFrom(grossErrorRecomputedResult.metrics.unit_weight_std), 6),
            max_standardized_improvement: round(
              maxStandardizedResidual - numberFrom(grossErrorRecomputedResult.metrics.max_standardized_residual),
              4,
            ),
            recommended_action: "review_excluded_observation_before_finalizing",
          },
        ]
      : [];

  if (redundancy === 0) warnings.push("观测冗余度为 0，无法可靠估计单位权中误差");
  if (iterationCount >= maxIterations && maxCorrectionMm > convergenceMm) {
    warnings.push(`迭代 ${iterationCount} 次后最大改正仍为 ${round(maxCorrectionMm, 4)} mm，可能未充分收敛`);
  }
  if (maxCoordinateStdMm > coordinateToleranceMm) {
    warnings.push(`最大点位中误差 ${round(maxCoordinateStdMm, 3)} mm 超过 ${coordinateToleranceMm} mm`);
  }
  if (maxResidualMm > residualToleranceMm) {
    warnings.push(`最大观测残差 ${round(maxResidualMm, 3)} mm 超过 ${residualToleranceMm} mm`);
  }
  if (grossErrorCandidates.length > 0 && worstResidualRow) {
    warnings.push(
      `疑似粗差观测 ${worstResidualRow.observation_id} 标准化残差 ${round(
        Math.abs(numberFrom(worstResidualRow.standardized_residual)),
        4,
      )} 超过 ${grossErrorStandardizedThreshold}`,
    );
  }
  if (isFreeNetwork && datumControlPoints.length > 0 && !datumFitted) {
    warnings.push("稳定控制点少于 2 个或几何退化，无法执行自由网约束转换");
  }
  if (datumFitted && datumFitted.maxResidualMm > datumResidualToleranceMm) {
    warnings.push(`稳定控制点最大残差 ${round(datumFitted.maxResidualMm, 3)} mm 超过 ${datumResidualToleranceMm} mm`);
  }
  if (datumBestExclusion) {
    warnings.push(
      `稳定控制点 ${datumBestExclusion.id} 可作为候选不稳定点优先复核；剔除后剩余点 RMS ${round(
        datumBestExclusion.leaveOneOutRmsMm ?? 0,
        3,
      )} mm`,
    );
  }

  return resultFor(
    "control_network",
    statusFromWarnings(warnings),
    `${isFreeNetwork ? "二维自由网内约束" : "二维控制网"}最小二乘平差完成：${unknownPointList.length} 个未知点、${finalEquations.design.length} 条有效观测、冗余度 ${redundancy}。`,
    {
      adjustment_model: adjustmentModel,
      network_datum: isFreeNetwork ? "inner_constraints" : "fixed_control",
      known_point_count: knownPoints.size,
      unknown_point_count: unknownPointList.length,
      observation_count: finalEquations.design.length,
      unknown_parameter_count: parameterCount,
      effective_parameter_count: effectiveParameterCount,
      datum_constraint_count: datumConstraints.length,
      datum_control_count: datumPairs.length,
      datum_transform_model: datumFitted ? "helmert_2d" : "",
      datum_transform_tx: round(datumFitted?.params.tx ?? 0, 6),
      datum_transform_ty: round(datumFitted?.params.ty ?? 0, 6),
      datum_transform_rotation_degrees: round(datumFitted?.params.rotationDeg ?? 0, 9),
      datum_transform_scale_ppm: round(datumFitted?.params.scalePpm ?? 0, 6),
      datum_control_rms_mm: round(datumFitted?.rmsMm ?? 0, 4),
      datum_control_max_residual_mm: round(datumFitted?.maxResidualMm ?? 0, 4),
      datum_control_candidate_count: datumCandidateDiagnostics.length,
      datum_control_best_exclusion_point: datumBestExclusion?.id ?? "",
      datum_control_best_exclusion_rms_mm: round(datumBestExclusion?.leaveOneOutRmsMm ?? 0, 4),
      datum_control_best_exclusion_max_residual_mm: round(datumBestExclusion?.leaveOneOutMaxResidualMm ?? 0, 4),
      datum_control_recomputed_model: datumRecomputedFit ? "helmert_2d_leave_one_out" : "",
      datum_control_recomputed_excluded_point: datumBestExclusion?.id ?? "",
      datum_control_recomputed_rms_mm: round(datumRecomputedFit?.rmsMm ?? 0, 4),
      datum_control_recomputed_max_residual_mm: round(datumRecomputedFit?.maxResidualMm ?? 0, 4),
      datum_control_recomputed_rotation_degrees: round(datumRecomputedFit?.params.rotationDeg ?? 0, 9),
      datum_control_recomputed_scale_ppm: round(datumRecomputedFit?.params.scalePpm ?? 0, 6),
      redundancy,
      iteration_count: iterationCount,
      max_correction_mm: round(maxCorrectionMm, 4),
      unit_weight_std: round(unitWeightStd, 6),
      max_coordinate_std_mm: round(maxCoordinateStdMm, 3),
      max_residual_mm: round(maxResidualMm, 3),
      max_standardized_residual: round(maxStandardizedResidual, 4),
      gross_error_standardized_threshold: grossErrorStandardizedThreshold,
      gross_error_candidate_count: grossErrorCandidates.length,
      worst_observation_id: worstResidualRow?.observation_id ?? "",
      worst_observation_residual_mm: round(numberFrom(worstResidualRow?.residual_mm), 4),
      worst_observation_standardized_residual: round(Math.abs(numberFrom(worstResidualRow?.standardized_residual)), 4),
      gross_error_recomputed_model: grossErrorRecomputedResult ? "leave_one_out_lsq" : "",
      gross_error_recomputed_excluded_observation: grossErrorRecomputedResult ? String(worstResidualRow?.observation_id ?? "") : "",
      gross_error_recomputed_status: grossErrorRecomputedResult?.status ?? "",
      gross_error_recomputed_observation_count: numberFrom(grossErrorRecomputedResult?.metrics.observation_count),
      gross_error_recomputed_unit_weight_std: round(numberFrom(grossErrorRecomputedResult?.metrics.unit_weight_std), 6),
      gross_error_recomputed_max_residual_mm: round(numberFrom(grossErrorRecomputedResult?.metrics.max_residual_mm), 4),
      gross_error_recomputed_max_standardized_residual: round(
        numberFrom(grossErrorRecomputedResult?.metrics.max_standardized_residual),
        4,
      ),
    },
    [
      ...pointRows,
      ...constrainedRows,
      ...datumResidualRows,
      ...datumExclusionRows,
      ...recomputedConstrainedRows,
      ...recomputedDatumResidualRows,
      ...grossErrorExclusionRows,
      ...grossErrorRecomputedPointRows,
      ...grossErrorRecomputedResidualRows,
      ...residualRows,
    ],
    warnings.length > 0
      ? [...warnings, "请复核控制点稳定性、观测权和粗差观测后重新平差。"]
      : [
          isFreeNetwork
            ? "自由网结果可用于相对几何复核；正式坐标成果仍需通过稳定控制点进行约束转换。"
            : "平差结果可用于现场复核；正式成果提交前仍应核对仪器改正、投影面和控制点等级。",
        ],
  );
}

function formatStation(stationM: number): string {
  const sign = stationM < 0 ? "-" : "";
  const abs = Math.abs(stationM);
  const km = Math.floor(abs / 1000);
  const meters = abs - km * 1000;
  return `${sign}K${km}+${meters.toFixed(3).padStart(7, "0")}`;
}

function linearRegression(xs: number[], ys: number[]): { slope: number; intercept: number; r2: number } {
  if (xs.length !== ys.length || xs.length < 2) return { slope: 0, intercept: ys[0] ?? 0, r2: 0 };
  const meanX = xs.reduce((sum, value) => sum + value, 0) / xs.length;
  const meanY = ys.reduce((sum, value) => sum + value, 0) / ys.length;
  let sxx = 0;
  let sxy = 0;
  let syy = 0;
  for (let i = 0; i < xs.length; i += 1) {
    const dx = xs[i]! - meanX;
    const dy = ys[i]! - meanY;
    sxx += dx * dx;
    sxy += dx * dy;
    syy += dy * dy;
  }
  const slope = sxx > 0 ? sxy / sxx : 0;
  const intercept = meanY - slope * meanX;
  const r2 = sxx > 0 && syy > 0 ? (sxy * sxy) / (sxx * syy) : 0;
  return { slope, intercept, r2 };
}

function parseDelimitedRows(text: string, delimiter: "," | "\t"): string[][] {
  const rows: string[][] = [];
  let row: string[] = [];
  let field = "";
  let quoted = false;
  const source = text.replace(/\r\n/g, "\n").replace(/\r/g, "\n");
  for (let index = 0; index < source.length; index += 1) {
    const char = source[index]!;
    const next = source[index + 1];
    if (char === "\"") {
      if (quoted && next === "\"") {
        field += "\"";
        index += 1;
      } else {
        quoted = !quoted;
      }
      continue;
    }
    if (!quoted && char === delimiter) {
      row.push(field.trim());
      field = "";
      continue;
    }
    if (!quoted && char === "\n") {
      row.push(field.trim());
      if (row.some((value) => value.length > 0)) rows.push(row);
      row = [];
      field = "";
      continue;
    }
    field += char;
  }
  row.push(field.trim());
  if (row.some((value) => value.length > 0)) rows.push(row);
  return rows;
}

function normalizeHeader(value: string): string {
  return value.trim().toLowerCase().replace(/[\s_\-./（）()]/g, "");
}

export function getEngineeringFieldDefinitions(toolId: EngineeringToolId): EngineeringFieldDefinition[] {
  return FIELD_DEFINITIONS[toolId] ?? [];
}

function scoreFieldColumn(definition: EngineeringFieldDefinition, columnName: string): number {
  const normalizedColumn = normalizeHeader(columnName);
  if (!normalizedColumn) return 0;
  let best = 0;
  for (const alias of [definition.key, ...definition.aliases]) {
    const normalizedAlias = normalizeHeader(alias);
    if (!normalizedAlias) continue;
    if (normalizedColumn === normalizedAlias) best = Math.max(best, 100);
    else if (normalizedColumn.includes(normalizedAlias)) best = Math.max(best, 82);
    else if (normalizedAlias.includes(normalizedColumn) && normalizedColumn.length >= 2) best = Math.max(best, 68);
  }
  return best;
}

function detectEngineeringFieldUnit(columnName: string): EngineeringFieldUnit | null {
  const normalized = columnName.toLowerCase();
  if (/\bkm\b|公里|千米/.test(normalized)) return "km";
  if (/\bcm\b|厘米/.test(normalized)) return "cm";
  if (/\bmm\b|毫米/.test(normalized)) return "mm";
  if (/\bm\b|（m）|\(m\)|米/.test(normalized)) return "m";
  return null;
}

export function suggestEngineeringFieldMapping(
  toolId: EngineeringToolId,
  columnNames: string[],
): EngineeringFieldMappingConfig {
  const fields: Record<string, string> = {};
  const units: Record<string, EngineeringFieldUnit> = {};
  const used = new Set<string>();
  for (const definition of getEngineeringFieldDefinitions(toolId)) {
    let bestColumn = "";
    let bestScore = 0;
    for (const column of columnNames) {
      if (used.has(column)) continue;
      const score = scoreFieldColumn(definition, column);
      if (score > bestScore) {
        bestColumn = column;
        bestScore = score;
      }
    }
    if (bestColumn && bestScore >= 68) {
      fields[definition.key] = bestColumn;
      used.add(bestColumn);
      const unit = definition.baseUnit ? detectEngineeringFieldUnit(bestColumn) : null;
      if (unit) units[definition.key] = unit;
    }
  }
  return { fields, ...(Object.keys(units).length > 0 ? { units } : {}) };
}

function unitFactorToBase(unit: EngineeringFieldUnit, baseUnit: EngineeringFieldUnit): number {
  const meters = unit === "km" ? 1000 : unit === "m" ? 1 : unit === "cm" ? 0.01 : 0.001;
  if (baseUnit === "km") return meters / 1000;
  if (baseUnit === "m") return meters;
  if (baseUnit === "cm") return meters * 100;
  return meters * 1000;
}

