function mappingForAvailableColumns(toolId: EngineeringToolId, columnNames: string[]): EngineeringFieldMappingConfig {
  const suggested = suggestEngineeringFieldMapping(toolId, columnNames);
  const saved = readSavedFieldMapping(toolId);
  if (!saved) return suggested;
  const fields = { ...suggested.fields };
  const units = { ...(suggested.units ?? {}) };
  for (const [key, sourceColumn] of Object.entries(saved.fields)) {
    if (!sourceColumnExists(columnNames, sourceColumn)) continue;
    fields[key] = sourceColumn;
    const unit = saved.units?.[key];
    if (unit) units[key] = unit;
  }
  return { fields, ...(Object.keys(units).length > 0 ? { units } : {}) };
}

function convertMappedValue(value: string, definition: EngineeringFieldDefinition, unit?: EngineeringFieldUnit): string {
  if (!unit || !definition.baseUnit) return value;
  const numeric = Number(value.replace(/,/g, ""));
  if (!Number.isFinite(numeric)) return value;
  return String(round(numeric * unitFactorToBase(unit, definition.baseUnit), 9));
}

function applyEngineeringFieldMapping(
  rows: Array<Record<string, string>>,
  toolId: EngineeringToolId,
  mapping?: EngineeringFieldMappingConfig,
): { rows: Array<Record<string, string>>; warnings: string[] } {
  if (!mapping || Object.keys(mapping.fields).length === 0) return { rows, warnings: [] };
  const definitions = new Map(getEngineeringFieldDefinitions(toolId).map((definition) => [definition.key, definition]));
  const warnings: string[] = [];
  const mappedRows = rows.map((row) => ({ ...row }));
  for (const [targetKey, sourceColumn] of Object.entries(mapping.fields)) {
    const definition = definitions.get(targetKey);
    if (!definition || !sourceColumn) continue;
    const sourceKey = normalizeHeader(sourceColumn);
    if (!rows.some((row) => row[sourceKey] !== undefined)) {
      warnings.push(`字段映射 ${definition.label} 的来源列 ${sourceColumn} 不存在`);
      continue;
    }
    const targetHeader = normalizeHeader(definition.key);
    const unit = mapping.units?.[targetKey];
    for (const row of mappedRows) {
      const value = row[sourceKey];
      if (value !== undefined) row[targetHeader] = convertMappedValue(value, definition, unit);
    }
  }
  return { rows: mappedRows, warnings };
}

function tableFromText(
  text: string,
  format: "csv" | "tsv" | "xlsx",
): {
  columnNames: string[];
  rows: Array<Record<string, string>>;
  previewRows: Array<Record<string, string>>;
} {
  const rawRows = parseDelimitedRows(text, format === "csv" ? "," : "\t");
  const columnNames = rawRows[0] ?? [];
  const normalizedHeaders = columnNames.map(normalizeHeader);
  const rows = rawRows.slice(1).map((cells) => {
    const row: Record<string, string> = {};
    for (let index = 0; index < normalizedHeaders.length; index += 1) {
      const header = normalizedHeaders[index];
      if (header) row[header] = cells[index] ?? "";
    }
    return row;
  });
  const previewRows = rawRows.slice(1, 6).map((cells) => {
    const row: Record<string, string> = {};
    for (let index = 0; index < columnNames.length; index += 1) {
      const header = columnNames[index];
      if (header) row[header] = cells[index] ?? "";
    }
    return row;
  });
  return { columnNames, rows, previewRows };
}

function importText(row: Record<string, string>, aliases: string[], fallback = ""): string {
  for (const alias of aliases.map(normalizeHeader)) {
    const value = row[alias];
    if (value !== undefined && value.trim() !== "") return value.trim();
  }
  return fallback;
}

function importDate(row: Record<string, string>, aliases: string[], fallback = ""): string {
  const value = importText(row, aliases, "");
  if (!value) return fallback;
  return fieldDateFromText(value) ?? value.trim();
}

function importNumber(row: Record<string, string>, aliases: string[], fallback = Number.NaN): number {
  const value = importText(row, aliases);
  if (!value) return fallback;
  const chainage = chainageFromText(value);
  if (chainage !== null) return chainage;
  const quadrantBearingDegrees = quadrantBearingDegreesFromText(value);
  if (quadrantBearingDegrees !== null) return quadrantBearingDegrees;
  const dmsDegrees = decimalDegreesFromDmsText(value);
  if (dmsDegrees !== null) return dmsDegrees;
  const numeric = numericCellFromText(value);
  return numeric !== null ? numeric : fallback;
}

function importNumberList(row: Record<string, string>, aliases: string[]): number[] {
  const value = importText(row, aliases);
  if (!value) return [];
  return value
    .split(/[;,，、\s]+/)
    .map((cell) => numberFrom(cell, Number.NaN))
    .filter((cell) => Number.isFinite(cell));
}

function millimeterUnitFactorFromHeader(header: string): number {
  if (header.endsWith("mm") || header.endsWith("毫米")) return 1;
  if (header.endsWith("cm") || header.endsWith("厘米")) return 10;
  if (header.endsWith("m") || header.endsWith("米") || header.endsWith("公尺")) return 1000;
  return 1;
}

function millimeterUnitFactorFromValue(value: string): number {
  const compact = normalizeFullWidthAscii(value).trim().toLowerCase().replace(/\s+/g, "");
  if (/(-?\d+(?:\.\d+)?)mm$|毫米$/.test(compact)) return 1;
  if (/(-?\d+(?:\.\d+)?)cm$|厘米$/.test(compact)) return 10;
  if (/(-?\d+(?:\.\d+)?)m$|米$|公尺$/.test(compact)) return 1000;
  return 1;
}

function normalizedMillimeterAliases(aliases: string[]): string[] {
  const normalized = aliases.map(normalizeHeader).filter(Boolean);
  const unitless = normalized
    .map((alias) => alias.replace(/(毫米|厘米|公尺|mm|cm|米)$/u, ""))
    .filter((alias) => alias.length > 0);
  return Array.from(new Set([...normalized, ...unitless]));
}

function importMillimeterNumber(row: Record<string, string>, aliases: string[], fallback = Number.NaN): number {
  const normalizedAliases = normalizedMillimeterAliases(aliases);
  for (const [header, rawValue] of Object.entries(row)) {
    if (!rawValue) continue;
    const normalizedHeader = normalizeHeader(header);
    const matched = normalizedAliases.some(
      (alias) =>
        normalizedHeader === alias ||
        normalizedHeader === `${alias}mm` ||
        normalizedHeader === `${alias}毫米` ||
        normalizedHeader === `${alias}cm` ||
        normalizedHeader === `${alias}厘米` ||
        normalizedHeader === `${alias}m` ||
        normalizedHeader === `${alias}米` ||
        normalizedHeader === `${alias}公尺`,
    );
    if (!matched) continue;
    const numeric = numericCellFromText(rawValue);
    if (numeric === null) continue;
    const headerFactor = millimeterUnitFactorFromHeader(normalizedHeader);
    const valueFactor = headerFactor === 1 ? millimeterUnitFactorFromValue(rawValue) : headerFactor;
    return numeric * valueFactor;
  }
  return fallback;
}

const MILLIMETER_PER_DAY_UNITS = [
  { factor: 1, suffixes: ["mmperday", "mmday", "mmd", "mm天", "mm日", "毫米perday", "毫米day", "毫米d", "毫米天", "毫米日"] },
  { factor: 10, suffixes: ["cmperday", "cmday", "cmd", "cm天", "cm日", "厘米perday", "厘米day", "厘米d", "厘米天", "厘米日"] },
  { factor: 1000, suffixes: ["mperday", "mday", "md", "m天", "m日", "米perday", "米day", "米d", "米天", "米日"] },
];

function normalizedMillimeterPerDayAliases(aliases: string[]): string[] {
  const unitSuffixes = MILLIMETER_PER_DAY_UNITS.flatMap((unit) => unit.suffixes).sort((a, b) => b.length - a.length);
  const normalized = aliases.map(normalizeHeader).filter(Boolean);
  const unitless = normalized
    .map((alias) => {
      const suffix = unitSuffixes.find((unitSuffix) => alias.endsWith(unitSuffix));
      return suffix ? alias.slice(0, -suffix.length) : alias;
    })
    .filter((alias) => alias.length > 0);
  return Array.from(new Set([...normalized, ...unitless]));
}

function millimeterPerDayUnitFactorFromHeader(header: string): number {
  for (const unit of MILLIMETER_PER_DAY_UNITS) {
    if (unit.suffixes.some((suffix) => header.endsWith(suffix))) return unit.factor;
  }
  return 1;
}

function importMillimeterPerDayNumber(row: Record<string, string>, aliases: string[], fallback = Number.NaN): number {
  const normalizedAliases = normalizedMillimeterPerDayAliases(aliases);
  for (const [header, rawValue] of Object.entries(row)) {
    if (!rawValue) continue;
    const normalizedHeader = normalizeHeader(header);
    const matched = normalizedAliases.some(
      (alias) =>
        normalizedHeader === alias ||
        MILLIMETER_PER_DAY_UNITS.some((unit) => unit.suffixes.some((suffix) => normalizedHeader === `${alias}${suffix}`)),
    );
    if (!matched) continue;
    const numeric = numericCellFromText(rawValue);
    if (numeric === null) continue;
    return numeric * millimeterPerDayUnitFactorFromHeader(normalizedHeader);
  }
  return fallback;
}

function importArcSecondNumber(row: Record<string, string>, aliases: string[], fallback = Number.NaN): number {
  const normalizedAliases = aliases.map(normalizeHeader).filter(Boolean);
  for (const [header, rawValue] of Object.entries(row)) {
    if (!rawValue) continue;
    const normalizedHeader = normalizeHeader(header);
    const matched = normalizedAliases.some(
      (alias) =>
        normalizedHeader === alias ||
        normalizedHeader === `${alias}arcsec` ||
        normalizedHeader === `${alias}sec` ||
        normalizedHeader === `${alias}seconds` ||
        normalizedHeader === `${alias}s` ||
        normalizedHeader === `${alias}秒` ||
        normalizedHeader === `${alias}角秒` ||
        normalizedHeader === `${alias}″` ||
        normalizedHeader === `${alias}”`,
    );
    if (!matched) continue;
    const numeric = numericCellFromText(rawValue) ?? numericCellFromText(rawValue.replace(/[″”"]/g, "秒"));
    if (numeric !== null) return numeric;
  }
  return fallback;
}

function hasImportNumber(row: Record<string, string>, aliases: string[]): boolean {
  return Number.isFinite(importNumber(row, aliases, Number.NaN));
}

function roleOf(row: Record<string, string>): string {
  return importText(row, ["role", "kind", "type", "rowType", "line", "surface", "类别", "类型", "行类型", "记录类型"]).toLowerCase();
}

function importDistanceAzimuthRows(rows: Array<Record<string, string>>): { input: unknown; warnings: string[] } {
  const segments: Array<Record<string, unknown>> = [];
  const warnings: string[] = [];

  rows.forEach((row, index) => {
    const id = importText(row, ["segmentid", "id", "edgeid", "lineid", "边号", "边段编号", "测段"], `S${index + 1}`);
    const fromX = importNumber(
      row,
      ["fromx", "from_x", "startx", "start_x", "x1", "fromeasting", "starteasting", "起点x", "起点坐标x", "起点东坐标", "起点东坐标m", "起点e", "起点东", "始点东坐标", "始点东坐标m"],
      Number.NaN,
    );
    const fromY = importNumber(
      row,
      ["fromy", "from_y", "starty", "start_y", "y1", "fromnorthing", "startnorthing", "起点y", "起点坐标y", "起点北坐标", "起点北坐标m", "起点n", "起点北", "始点北坐标", "始点北坐标m"],
      Number.NaN,
    );
    const toX = importNumber(
      row,
      ["tox", "to_x", "endx", "end_x", "x2", "toeasting", "endeasting", "终点x", "终点坐标x", "终点东坐标", "终点东坐标m", "终点e", "终点东", "止点东坐标", "止点东坐标m"],
      Number.NaN,
    );
    const toY = importNumber(
      row,
      ["toy", "to_y", "endy", "end_y", "y2", "tonorthing", "endnorthing", "终点y", "终点坐标y", "终点北坐标", "终点北坐标m", "终点n", "终点北", "止点北坐标", "止点北坐标m"],
      Number.NaN,
    );
    if (!Number.isFinite(fromX) || !Number.isFinite(fromY) || !Number.isFinite(toX) || !Number.isFinite(toY)) {
      warnings.push(`第 ${index + 2} 行缺少 fromX/fromY/toX/toY，已跳过`);
      return;
    }
    const fromZ = importNumber(row, ["fromz", "from_z", "startz", "start_z", "z1", "起点高程", "起点高程m", "起点z", "始点高程", "始点高程m"], Number.NaN);
    const toZ = importNumber(row, ["toz", "to_z", "endz", "end_z", "z2", "终点高程", "终点高程m", "终点z", "止点高程", "止点高程m"], Number.NaN);
    const observedHorizontalDistanceM = importNumber(
      row,
      [
        "observedhorizontaldistancem",
        "observeddistancem",
        "distancem",
        "observeddistance",
        "measuredhorizontaldistancem",
        "观测平距",
        "观测平距m",
        "实测平距",
        "实测平距m",
        "测距",
        "测距m",
        "观测距离",
        "观测距离m",
        "实测距离",
        "实测距离m",
        "边长观测值",
        "边长观测值m",
      ],
      Number.NaN,
    );
    const slopeDistanceM = importNumber(row, CONTROL_SLOPE_DISTANCE_ALIASES, Number.NaN);
    const verticalAngleDegrees = importNumber(row, CONTROL_VERTICAL_ANGLE_ALIASES, Number.NaN);
    const zenithAngleDegrees = importNumber(row, CONTROL_ZENITH_ANGLE_ALIASES, Number.NaN);
    const observedDistanceFromSlopeM = horizontalDistanceFromSlopeDistance(
      slopeDistanceM,
      verticalAngleDegrees,
      zenithAngleDegrees,
    );
    const finalObservedHorizontalDistanceM = Number.isFinite(observedHorizontalDistanceM)
      ? observedHorizontalDistanceM
      : Number.isFinite(observedDistanceFromSlopeM)
        ? observedDistanceFromSlopeM
        : Number.NaN;
    const toleranceMm = importMillimeterNumber(
      row,
      [
        "tolerance",
        "tolerancemm",
        "distancetolerance",
        "distancetolerancemm",
        "residualtolerance",
        "residualtolerancemm",
        "限差",
        "限差mm",
        "测距限差",
        "测距限差mm",
        "距离残差限差",
        "距离残差限差mm",
      ],
      Number.NaN,
    );
    const group = importText(row, ["group", "groupkey", "network", "route", "边组", "线路", "分组"], "");
    const fromId = importText(row, ["fromid", "from", "startid", "起点", "起点点号", "测站点"], "");
    const toId = importText(row, ["toid", "to", "endid", "终点", "终点点号", "照准点"], "");
    const remark = importText(row, ["remark", "remarks", "note", "comment", "备注", "说明"], "");
    segments.push({
      id,
      ...(group ? { group } : {}),
      fromId,
      toId,
      from: { x: fromX, y: fromY, ...(Number.isFinite(fromZ) ? { z: fromZ } : {}) },
      to: { x: toX, y: toY, ...(Number.isFinite(toZ) ? { z: toZ } : {}) },
      ...(Number.isFinite(finalObservedHorizontalDistanceM) ? { observedHorizontalDistanceM: finalObservedHorizontalDistanceM } : {}),
      ...(Number.isFinite(slopeDistanceM) ? { observedSlopeDistanceM: slopeDistanceM } : {}),
      ...(Number.isFinite(verticalAngleDegrees) ? { observedVerticalAngleDegrees: verticalAngleDegrees } : {}),
      ...(Number.isFinite(zenithAngleDegrees) ? { observedZenithAngleDegrees: zenithAngleDegrees } : {}),
      ...(Number.isFinite(toleranceMm) ? { toleranceMm } : {}),
      ...(remark ? { remark } : {}),
    });
  });

  return {
    input: { segments },
    warnings,
  };
}

function importAngleConversionRows(rows: Array<Record<string, string>>): { input: unknown; warnings: string[] } {
  const angles: Array<Record<string, unknown>> = [];
  const warnings: string[] = [];

  rows.forEach((row, index) => {
    const id = importText(row, ["angleid", "id", "observationid", "name", "角度编号", "观测号"], `A${index + 1}`);
    const decimalValue = importNumber(
      row,
      [
        "value",
        "angle",
        "decimaldegrees",
        "degreesdecimal",
        "directionreading",
        "observeddirection",
        "anglereading",
        "角度值",
        "十进制度",
        "方向读数",
        "方向值",
        "观测方向",
        "观测角",
        "实测角度",
        "实测方向",
        "读数",
      ],
      Number.NaN,
    );
    const degrees = importNumber(row, ["degrees", "deg", "d", "度"], Number.NaN);
    const hasDecimal = Number.isFinite(decimalValue);
    const hasDms = Number.isFinite(degrees);
    if (!hasDecimal && !hasDms) {
      warnings.push(`第 ${index + 2} 行缺少 value 或 degrees/minutes/seconds，已跳过`);
      return;
    }
    const minutes = importNumber(row, ["minutes", "minute", "min", "m", "分"], 0);
    const seconds = importNumber(row, ["seconds", "second", "sec", "s", "秒"], 0);
    const designDegrees = importNumber(
      row,
      [
        "designdegrees",
        "designangle",
        "targetdegrees",
        "designdirection",
        "targetdirection",
        "设计角度",
        "理论角度",
        "设计方向",
        "理论方向",
        "目标方向",
        "目标角度",
      ],
      Number.NaN,
    );
    const designMinutes = importNumber(row, ["designminutes", "designmin", "设计分"], 0);
    const designSeconds = importNumber(row, ["designseconds", "designsec", "设计秒"], 0);
    const group = importText(row, ["group", "groupkey", "setid", "方向组", "测站组", "分组"], "");
    const roundId = importText(row, ["roundid", "round", "session", "测回号", "测回"], "");
    const unit = importText(row, ["unit", "angleunit", "单位"], "degrees");
    const toleranceArcSec = importArcSecondNumber(
      row,
      [
        "tolerancearcsec",
        "arcsectolerance",
        "angletolerancearcsec",
        "directiontolerancearcsec",
        "tolerance",
        "angletolerance",
        "directiontolerance",
        "限差",
        "限差秒",
        "角秒限差",
        "方向限差",
        "方向限差秒",
        "方向限差秒值",
        "方向限差s",
      ],
      Number.NaN,
    );
    const remark = importText(row, ["remark", "remarks", "note", "comment", "备注", "说明"], "");
    angles.push({
      id,
      ...(group ? { group } : {}),
      ...(roundId ? { roundId } : {}),
      ...(hasDecimal ? { value: decimalValue, unit } : { dms: { degrees, minutes, seconds } }),
      ...(Number.isFinite(designDegrees) ? { designDms: { degrees: designDegrees, minutes: designMinutes, seconds: designSeconds } } : {}),
      ...(Number.isFinite(toleranceArcSec) ? { toleranceArcSec } : {}),
      ...(remark ? { remark } : {}),
    });
  });

  return {
    input: { angles },
    warnings,
  };
}

function importCoordTransformRows(rows: Array<Record<string, string>>): { input: unknown; warnings: string[] } {
  const controlPairs: Array<{
    id: string;
    source: Point2;
    target: Point2;
    weight?: number;
    remark?: string;
  }> = [];
  const checkPoints: Array<{
    id: string;
    source: Point2;
    target: Point2;
    toleranceMm?: number;
    remark?: string;
  }> = [];
  const source: Array<{ id: string; x: number; y: number; remark?: string }> = [];
  const warnings: string[] = [];

  rows.forEach((row, index) => {
    const role = roleOf(row);
    const id = importText(row, ["id", "pointid", "name", "点号", "点名", "编号"], `P${index + 1}`);
    const sourceXAliases = [
      "sourcex",
      "source_x",
      "sx",
      "sourceeasting",
      "源x",
      "源坐标x",
      "源东坐标",
      "源东坐标m",
      "源e",
      "原x",
      "原坐标x",
      "原东坐标",
      "原东坐标m",
      "转换前x",
      "转换前东坐标",
      "待转x",
      "待转东坐标",
    ];
    const sourceYAliases = [
      "sourcey",
      "source_y",
      "sy",
      "sourcenorthing",
      "源y",
      "源坐标y",
      "源北坐标",
      "源北坐标m",
      "源n",
      "原y",
      "原坐标y",
      "原北坐标",
      "原北坐标m",
      "转换前y",
      "转换前北坐标",
      "待转y",
      "待转北坐标",
    ];
    const targetXAliases = [
      "targetx",
      "target_x",
      "tx",
      "targeteasting",
      "目标x",
      "目标坐标x",
      "目标东坐标",
      "目标东坐标m",
      "目标e",
      "成果x",
      "成果东坐标",
      "成果东坐标m",
      "转换后x",
      "转换后东坐标",
    ];
    const targetYAliases = [
      "targety",
      "target_y",
      "ty",
      "targetnorthing",
      "目标y",
      "目标坐标y",
      "目标北坐标",
      "目标北坐标m",
      "目标n",
      "成果y",
      "成果北坐标",
      "成果北坐标m",
      "转换后y",
      "转换后北坐标",
    ];
    const hasPairedCoordinates =
      hasImportNumber(row, sourceXAliases) &&
      hasImportNumber(row, sourceYAliases) &&
      hasImportNumber(row, targetXAliases) &&
      hasImportNumber(row, targetYAliases);
    const sourcePoint = {
      x: importNumber(row, sourceXAliases),
      y: importNumber(row, sourceYAliases),
    };
    const targetPoint = {
      x: importNumber(row, targetXAliases),
      y: importNumber(row, targetYAliases),
    };
    const toleranceMm = importMillimeterNumber(
      row,
      [
        "tolerance",
        "tolerancemm",
        "residualtolerance",
        "residualtolerancemm",
        "checktolerance",
        "checktolerancemm",
        "controltolerance",
        "controltolerancemm",
        "限差",
        "限差mm",
        "残差限差",
        "残差限差mm",
        "检核限差",
        "检核限差mm",
        "控制限差",
        "控制限差mm",
      ],
      Number.NaN,
    );
    const remark = importText(row, ["remark", "remarks", "note", "comment", "备注", "说明"], "");
    const isCheckRole = role.includes("check") || role.includes("validation") || role.includes("检核") || role.includes("检查") || role.includes("校核");
    const isControlRole = role.includes("control") || role.includes("gcp") || role.includes("控制");
    if (hasPairedCoordinates && isCheckRole) {
      checkPoints.push({
        id,
        source: sourcePoint,
        target: targetPoint,
        ...(Number.isFinite(toleranceMm) ? { toleranceMm } : {}),
        ...(remark ? { remark } : {}),
      });
      return;
    }
    if (hasPairedCoordinates && (isControlRole || !role)) {
      controlPairs.push({
        id,
        source: sourcePoint,
        target: targetPoint,
        weight: importNumber(row, ["weight", "权"], Number.NaN),
        ...(remark ? { remark } : {}),
      });
      return;
    }
    const x = importNumber(row, ["x", "east", "easting", "东坐标", "坐标x", ...sourceXAliases]);
    const y = importNumber(row, ["y", "north", "northing", "北坐标", "坐标y", ...sourceYAliases]);
    if (Number.isFinite(x) && Number.isFinite(y)) {
      source.push({ id, x, y, ...(remark ? { remark } : {}) });
    } else {
      warnings.push(`第 ${index + 2} 行缺少可识别坐标，已跳过`);
    }
  });

  return {
    input: {
      controlPairs: controlPairs.map((pair) => ({
        id: pair.id,
        source: pair.source,
        target: pair.target,
        ...(Number.isFinite(pair.weight) ? { weight: pair.weight } : {}),
        ...(pair.remark ? { remark: pair.remark } : {}),
      })),
      checkPoints,
      source,
    },
    warnings,
  };
}

