const CPIII_DESIGN_X_ALIASES = ["designx", "design_x", "theoryx", "targetx", "designeasting", "设计x", "设计xm", "理论x", "设计坐标x", "设计坐标xm", "设计东坐标", "设计东坐标m"];
const CPIII_DESIGN_Y_ALIASES = ["designy", "design_y", "theoryy", "targety", "designnorthing", "设计y", "设计ym", "理论y", "设计坐标y", "设计坐标ym", "设计北坐标", "设计北坐标m"];
const CPIII_DESIGN_Z_ALIASES = ["designz", "design_z", "designelevationm", "theoryz", "targetz", "设计高程", "设计高程m", "设计z", "设计zm"];
const CPIII_ACTUAL_X_ALIASES = ["actualx", "actual_x", "measuredx", "measured_x", "recheckx", "actualeasting", "currentx", "currenteasting", "复测x", "复测xm", "实测x", "实测xm", "复测坐标x", "复测坐标xm", "实测坐标x", "实测坐标xm", "复测东坐标", "实测东坐标", "本期x", "本期坐标x", "本期坐标xm", "本期东坐标", "本期东坐标m", "本次x", "本次坐标x", "本次坐标xm", "本次东坐标", "本次东坐标m", "观测x", "观测东坐标"];
const CPIII_ACTUAL_Y_ALIASES = ["actualy", "actual_y", "measuredy", "measured_y", "rechecky", "actualnorthing", "currenty", "currentnorthing", "复测y", "复测ym", "实测y", "实测ym", "复测坐标y", "复测坐标ym", "实测坐标y", "实测坐标ym", "复测北坐标", "实测北坐标", "本期y", "本期坐标y", "本期坐标ym", "本期北坐标", "本期北坐标m", "本次y", "本次坐标y", "本次坐标ym", "本次北坐标", "本次北坐标m", "观测y", "观测北坐标"];
const CPIII_ACTUAL_Z_ALIASES = ["actualz", "actual_z", "actualelevationm", "measuredz", "recheckz", "currentz", "currentelevationm", "复测高程", "复测高程m", "实测高程", "实测高程m", "复测h", "复测hm", "实测h", "实测hm", "本期高程", "本期高程m", "本期h", "本期hm", "本次高程", "本次高程m", "本次h", "本次hm", "观测高程", "观测高程m"];
const CPIII_DX_MM_ALIASES = ["dxmm", "demm", "deltaxmm", "deltaemm", "deviationxmm", "deviationemm", "offsetxmm", "offsetemm", "δxmm", "Δxmm", "δemm", "Δemm", "dx", "de", "δx", "Δx", "δe", "Δe", "x偏差", "x偏差mm", "e偏差", "e偏差mm", "东坐标偏差", "东坐标偏差mm", "坐标x偏差", "坐标x偏差mm", "坐标较差x", "坐标较差xmm", "坐标x较差", "坐标x较差mm", "较差x", "较差xmm", "x较差", "x较差mm", "较差e", "较差emm", "e较差", "e较差mm", "东坐标较差", "东坐标较差mm"];
const CPIII_DY_MM_ALIASES = ["dymm", "dnmm", "deltaymm", "deltanmm", "deviationymm", "deviationnmm", "offsetymm", "offsetnmm", "δymm", "Δymm", "δnmm", "Δnmm", "dy", "dn", "δy", "Δy", "δn", "Δn", "y偏差", "y偏差mm", "n偏差", "n偏差mm", "北坐标偏差", "北坐标偏差mm", "坐标y偏差", "坐标y偏差mm", "坐标较差y", "坐标较差ymm", "坐标y较差", "坐标y较差mm", "较差y", "较差ymm", "y较差", "y较差mm", "较差n", "较差nmm", "n较差", "n较差mm", "北坐标较差", "北坐标较差mm"];
const CPIII_DZ_MM_ALIASES = ["dzmm", "dhmm", "deltazmm", "deltahmm", "deviationzmm", "heightdeviationmm", "δzmm", "Δzmm", "δhmm", "Δhmm", "dz", "dh", "δz", "Δz", "δh", "Δh", "高程偏差", "高程偏差mm", "h偏差", "h偏差mm", "较差z", "较差zmm", "z较差", "z较差mm", "较差h", "较差hmm", "h较差", "h较差mm", "高程较差", "高程较差mm"];
const CPIII_HORIZONTAL_TOLERANCE_ALIASES = ["tolerancehorizontal", "tolerancehorizontalmm", "horizontaltolerance", "horizontaltolerancemm", "planartolerance", "planartolerancemm", "平面限差", "平面限差mm", "水平限差", "水平限差mm"];
const CPIII_VERTICAL_TOLERANCE_ALIASES = ["tolerancevertical", "toleranceverticalmm", "verticaltolerance", "verticaltolerancemm", "heighttolerance", "heighttolerancemm", "高程限差", "高程限差mm", "竖向限差", "竖向限差mm"];
const CPIII_MEASURE_DATE_ALIASES = ["measuredate", "date", "observedat", "复测日期", "观测日期"];

function cpiiiDeviationImportPreflight(
  rows: Array<Record<string, string>>,
  points: Array<Record<string, unknown>>,
): EngineeringImportPreflight {
  const recognized = new Set<string>();
  for (const row of rows) {
    if (importText(row, CPIII_POINT_ID_ALIASES)) recognized.add("pointId");
    if (hasImportNumber(row, CPIII_DESIGN_X_ALIASES)) recognized.add("designX");
    if (hasImportNumber(row, CPIII_DESIGN_Y_ALIASES)) recognized.add("designY");
    if (hasImportNumber(row, CPIII_DESIGN_Z_ALIASES)) recognized.add("designZ");
    const hasActualX = hasImportNumber(row, CPIII_ACTUAL_X_ALIASES);
    const hasActualY = hasImportNumber(row, CPIII_ACTUAL_Y_ALIASES);
    const hasDx = Number.isFinite(importMillimeterNumber(row, CPIII_DX_MM_ALIASES, Number.NaN));
    const hasDy = Number.isFinite(importMillimeterNumber(row, CPIII_DY_MM_ALIASES, Number.NaN));
    const hasDz = Number.isFinite(importMillimeterNumber(row, CPIII_DZ_MM_ALIASES, Number.NaN));
    if (hasActualX || hasDx) recognized.add("actualX");
    if (hasActualY || hasDy) recognized.add("actualY");
    if (hasImportNumber(row, CPIII_ACTUAL_Z_ALIASES) || hasDz) recognized.add("actualZ");
    if (hasDx) recognized.add("dxMm");
    if (hasDy) recognized.add("dyMm");
    if (hasDz) recognized.add("dzMm");
    if (Number.isFinite(importMillimeterNumber(row, CPIII_HORIZONTAL_TOLERANCE_ALIASES, Number.NaN))) {
      recognized.add("toleranceHorizontalMm");
    }
    if (Number.isFinite(importMillimeterNumber(row, CPIII_VERTICAL_TOLERANCE_ALIASES, Number.NaN))) {
      recognized.add("toleranceVerticalMm");
    }
    if (importText(row, CPIII_MEASURE_DATE_ALIASES)) recognized.add("measureDate");
  }
  const required = ["pointId", "designX", "designY", "actualX", "actualY"];
  const missingRequiredFields = points.length > 0 ? [] : required.filter((field) => !recognized.has(field));
  return {
    targetWorkflow: "cpiii_deviation",
    readyForCalculation: points.length > 0,
    requiredFieldsPresent: points.length > 0 ? ["points", ...required] : required.filter((field) => recognized.has(field)),
    missingRequiredFields,
    recognizedFields: Array.from(recognized),
    qualityStatus: points.length > 0 ? "ready" : "review_missing_fields",
  };
}

