function importAlignmentDistanceM(
  row: Record<string, string>,
  meterAliases: string[],
  millimeterAliases: string[],
  fallback = Number.NaN,
): number {
  const millimeters = importNumber(row, millimeterAliases, Number.NaN);
  if (Number.isFinite(millimeters)) return millimeters / 1000;
  return importNumber(row, meterAliases, fallback);
}

function rightSideSignedValue(value: number): number {
  if (!Number.isFinite(value)) return value;
  return value > 0 ? -value : value;
}

function importDirectionalAlignmentDistanceM(
  row: Record<string, string>,
  genericMeterAliases: string[],
  genericMillimeterAliases: string[],
  leftMeterAliases: string[],
  leftMillimeterAliases: string[],
  rightMeterAliases: string[],
  rightMillimeterAliases: string[],
  fallback = Number.NaN,
): number {
  const rightDistanceM = importAlignmentDistanceM(row, rightMeterAliases, rightMillimeterAliases, Number.NaN);
  if (Number.isFinite(rightDistanceM)) return rightSideSignedValue(rightDistanceM);
  const leftDistanceM = importAlignmentDistanceM(row, leftMeterAliases, leftMillimeterAliases, Number.NaN);
  if (Number.isFinite(leftDistanceM)) return leftDistanceM;
  return importAlignmentDistanceM(row, genericMeterAliases, genericMillimeterAliases, fallback);
}

function importDirectionalAlignmentDeviationMm(
  row: Record<string, string>,
  genericAliases: string[],
  leftAliases: string[],
  rightAliases: string[],
  fallback = Number.NaN,
): number {
  const rightDeviationMm = importMillimeterNumber(row, rightAliases, Number.NaN);
  if (Number.isFinite(rightDeviationMm)) return rightSideSignedValue(rightDeviationMm);
  const leftDeviationMm = importMillimeterNumber(row, leftAliases, Number.NaN);
  if (Number.isFinite(leftDeviationMm)) return leftDeviationMm;
  return importMillimeterNumber(row, genericAliases, fallback);
}

