function buildProjectArchiveRectificationLedgerArtifact(input: {
  generatedAt: string;
  batchName: string;
  sourceReconciliationFingerprint: string;
  rows: EngineeringProjectArchiveRectificationLedgerRow[];
}): EngineeringProjectArchiveRectificationLedger {
  const body = {
    schema: "railwise.engineering.batch.projectArchiveRectificationLedger.v1" as const,
    generatedAt: input.generatedAt,
    batchName: input.batchName,
    sourceReconciliationFingerprint: input.sourceReconciliationFingerprint,
    rowCount: input.rows.length,
    openCount: input.rows.filter((row) => row.closureStatus === "open").length,
    highPriorityCount: input.rows.filter((row) => row.priority === "high").length,
    rows: input.rows,
  };
  const ledgerFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    ledgerFingerprint,
  };
  const csv = projectArchiveRectificationCsv(input.rows);
  const markdown = projectArchiveRectificationMarkdown(withoutArtifacts);
  const json = JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json,
  };
}

export function buildEngineeringProjectArchiveRectificationLedger(
  reconciliation: EngineeringProjectArchiveChecklistReconciliation,
  options: EngineeringProjectArchiveRectificationLedgerOptions = {},
): EngineeringProjectArchiveRectificationLedger {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const defaultDueDays = options.defaultDueDays ?? 7;
  const dueAt = addDaysIsoDate(generatedAt, defaultDueDays);
  const rows: EngineeringProjectArchiveRectificationLedgerRow[] = reconciliation.rows
    .filter((row) => row.reconciliationStatus !== "matched")
    .map((row, index) => ({
      issueId: `${reconciliation.batchName}-${String(index + 1).padStart(3, "0")}`,
      issueType: row.reconciliationStatus as EngineeringProjectArchiveRectificationIssueType,
      priority: projectArchiveRectificationPriority(row),
      closureStatus: "open",
      itemId: row.itemId,
      sourceName: row.sourceName,
      toolId: row.toolId,
      tableTitle: row.tableTitle,
      fileName: row.fileName,
      owner: row.owner,
      dueAt,
      action: row.action,
      sourceReconciliationStatus: row.reconciliationStatus,
      closedAt: null,
      closedBy: null,
      closureNote: "",
      closureSourceStatus: "generated_open",
    }));
  return buildProjectArchiveRectificationLedgerArtifact({
    generatedAt,
    batchName: reconciliation.batchName,
    sourceReconciliationFingerprint: reconciliation.reconciliationFingerprint,
    rows,
  });
}

const ENGINEERING_PROJECT_ARCHIVE_RECTIFICATION_CLOSURE_FIELD_ALIASES: Record<
  EngineeringProjectArchiveRectificationClosureField,
  string[]
> = {
  issueId: ["issue_id", "issueId", "问题编号", "整改编号", "整改项编号", "问题单号", "item_id", "资料编号"],
  closureStatus: ["closure_status", "closureStatus", "闭环状态", "整改状态", "处理状态", "状态", "是否闭环"],
  owner: ["owner", "责任人", "负责人", "责任单位", "处理人"],
  dueAt: ["due_at", "dueAt", "截止日期", "整改期限", "计划完成", "要求完成时间", "闭合期限"],
  closedAt: ["closed_at", "closedAt", "完成时间", "闭环时间", "销项时间", "验收时间", "归档时间"],
  closedBy: ["closed_by", "closedBy", "完成人", "闭环人", "验收人", "复核人", "销项人"],
  closureNote: ["closure_note", "closureNote", "整改说明", "处理说明", "闭环说明", "验收意见", "备注", "处理意见"],
};

type EngineeringProjectArchiveRectificationClosureRecord = {
  rowNumber: number;
  issueId: string;
  closureStatus: EngineeringProjectArchiveRectificationClosureStatus;
  owner: string | null;
  dueAt: string | null;
  closedAt: string | null;
  closedBy: string | null;
  closureNote: string;
};

function scoreProjectArchiveRectificationClosureColumn(
  field: EngineeringProjectArchiveRectificationClosureField,
  columnName: string,
): number {
  const normalizedColumn = normalizeHeader(columnName);
  if (!normalizedColumn) return 0;
  let best = 0;
  for (const alias of ENGINEERING_PROJECT_ARCHIVE_RECTIFICATION_CLOSURE_FIELD_ALIASES[field]) {
    const normalizedAlias = normalizeHeader(alias);
    if (!normalizedAlias) continue;
    if (normalizedColumn === normalizedAlias) best = Math.max(best, 100);
    else if (normalizedColumn.includes(normalizedAlias)) best = Math.max(best, 82);
    else if (normalizedAlias.includes(normalizedColumn) && normalizedColumn.length >= 2) best = Math.max(best, 68);
  }
  return best;
}

function suggestProjectArchiveRectificationClosureMapping(
  columnNames: string[],
): EngineeringProjectArchiveRectificationClosureMapping {
  const mapping: EngineeringProjectArchiveRectificationClosureMapping = {};
  const used = new Set<string>();
  const fieldOrder: EngineeringProjectArchiveRectificationClosureField[] = [
    "issueId",
    "closureStatus",
    "closedAt",
    "closedBy",
    "closureNote",
    "owner",
    "dueAt",
  ];
  for (const field of fieldOrder) {
    let bestColumn = "";
    let bestScore = 0;
    for (const column of columnNames) {
      if (used.has(column)) continue;
      const score = scoreProjectArchiveRectificationClosureColumn(field, column);
      if (score > bestScore) {
        bestColumn = column;
        bestScore = score;
      }
    }
    if (bestColumn && bestScore >= 68) {
      mapping[field] = bestColumn;
      used.add(bestColumn);
    }
  }
  return mapping;
}

function filterProjectArchiveRectificationClosureMappingForColumns(
  mapping: EngineeringProjectArchiveRectificationClosureMapping | null | undefined,
  columnNames: string[],
): EngineeringProjectArchiveRectificationClosureMapping {
  const filtered: EngineeringProjectArchiveRectificationClosureMapping = {};
  if (!mapping) return filtered;
  for (const [field, columnName] of Object.entries(mapping) as Array<
    [EngineeringProjectArchiveRectificationClosureField, string | undefined]
  >) {
    if (columnName && sourceColumnExists(columnNames, columnName)) filtered[field] = columnName;
  }
  return filtered;
}

function projectArchiveRectificationClosureMappingForColumns(
  columnNames: string[],
  inputMapping?: EngineeringProjectArchiveRectificationClosureMapping,
): {
  mapping: EngineeringProjectArchiveRectificationClosureMapping;
  mappingSource: EngineeringProjectArchiveMappingSource;
  savedMappingKey: string | null;
} {
  const suggested = suggestProjectArchiveRectificationClosureMapping(columnNames);
  const saved = filterProjectArchiveRectificationClosureMappingForColumns(
    readSavedProjectArchiveMapping<EngineeringProjectArchiveRectificationClosureMapping>(
      PROJECT_ARCHIVE_RECTIFICATION_CLOSURE_MAPPING_STORAGE_KEY,
    ),
    columnNames,
  );
  const explicit = filterProjectArchiveRectificationClosureMappingForColumns(inputMapping, columnNames);
  const hasExplicit = Object.keys(inputMapping ?? {}).length > 0;
  const hasSaved = Object.keys(saved).length > 0;
  return {
    mapping: {
      ...suggested,
      ...(hasSaved ? saved : {}),
      ...(hasExplicit ? explicit : {}),
    },
    mappingSource: hasExplicit ? "input" : hasSaved ? "saved" : "auto",
    savedMappingKey: !hasExplicit && hasSaved ? PROJECT_ARCHIVE_RECTIFICATION_CLOSURE_MAPPING_STORAGE_KEY : null,
  };
}

function rectificationClosureFormatFromInput(
  input: EngineeringProjectArchiveRectificationClosureInput,
): EngineeringProjectArchiveRectificationClosureFormat {
  if (input.format === "tsv" || input.format === "xlsx") return input.format;
  return "csv";
}

function mappedProjectArchiveRectificationClosureValue(
  row: Record<string, string>,
  mapping: EngineeringProjectArchiveRectificationClosureMapping,
  field: EngineeringProjectArchiveRectificationClosureField,
): string {
  const columnName = mapping[field];
  if (!columnName) return "";
  return textFrom(row[normalizeHeader(columnName)], "").trim();
}

function normalizeProjectArchiveRectificationClosureStatus(
  value: string,
): EngineeringProjectArchiveRectificationClosureStatus {
  const normalized = normalizeLedgerStatus(value);
  return normalized === "closed" || normalized === "ok" ? "closed" : "open";
}

function parseProjectArchiveRectificationClosureInput(input: EngineeringProjectArchiveRectificationClosureInput): {
  source: EngineeringProjectArchiveRectificationClosureSource;
  records: EngineeringProjectArchiveRectificationClosureRecord[];
} {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const format = rectificationClosureFormatFromInput(input);
  const table = tableFromText(input.text, format);
  const { mapping, mappingSource, savedMappingKey } = projectArchiveRectificationClosureMappingForColumns(
    table.columnNames,
    input.mapping,
  );
  const records = table.rows
    .map((row, index): EngineeringProjectArchiveRectificationClosureRecord => {
      const issueId = mappedProjectArchiveRectificationClosureValue(row, mapping, "issueId");
      const closureStatusRaw = mappedProjectArchiveRectificationClosureValue(row, mapping, "closureStatus");
      const owner = mappedProjectArchiveRectificationClosureValue(row, mapping, "owner") || null;
      const dueAt = mappedProjectArchiveRectificationClosureValue(row, mapping, "dueAt") || null;
      const closedAt = mappedProjectArchiveRectificationClosureValue(row, mapping, "closedAt") || null;
      const closedBy = mappedProjectArchiveRectificationClosureValue(row, mapping, "closedBy") || null;
      const closureNote = mappedProjectArchiveRectificationClosureValue(row, mapping, "closureNote");
      return {
        rowNumber: index + 2,
        issueId,
        closureStatus: normalizeProjectArchiveRectificationClosureStatus(closureStatusRaw),
        owner,
        dueAt,
        closedAt,
        closedBy,
        closureNote,
      };
    })
    .filter(
      (record) =>
        record.issueId || record.owner || record.dueAt || record.closedAt || record.closedBy || record.closureNote,
    );
  const sourceBody = {
    sourceName: input.sourceName ?? null,
    importedAt,
    format,
    columnNames: table.columnNames,
    mapping,
    mappingSource,
    savedMappingKey,
    records,
  };
  const source: EngineeringProjectArchiveRectificationClosureSource = {
    schema: "railwise.engineering.projectArchiveRectificationClosureSource.v1",
    sourceName: input.sourceName ?? null,
    importedAt,
    format,
    rowCount: records.length,
    columnNames: table.columnNames,
    mapping,
    mappingSource,
    savedMappingKey,
    closureSourceFingerprint: fnv1a32Fingerprint(JSON.stringify(sourceBody)),
  };
  return { source, records };
}

