function buildTraverseAdjustmentExchangeContent(
  result: EngineeringResult,
  format: (typeof ADJUSTMENT_EXCHANGE_FORMATS)[number],
  generatedAt: string,
): string {
  const summaryRows = adjustmentRowsOfType(result, "traverse_adjustment_summary");
  const coordinateRows = adjustmentRowsOfType(result, "traverse_adjusted_coordinate").map((row) => ({
    point_name: textFrom(valueFromKeys(row, ["point_name", "name"]), ""),
    x_m: fixedExchangeNumber(valueFromKeys(row, ["adjusted_x", "x", "center_x"]), 4),
    y_m: fixedExchangeNumber(valueFromKeys(row, ["adjusted_y", "y", "center_y"]), 4),
    mx_mm: fixedExchangeNumber(valueFromKeys(row, ["mx_mm", "mx", "point_mse_mm"]), 3),
    my_mm: fixedExchangeNumber(valueFromKeys(row, ["my_mm", "my", "point_mse_mm"]), 3),
    point_mse_mm: fixedExchangeNumber(valueFromKeys(row, ["point_mse_mm", "mp_mm"]), 3),
  }));
  const ellipseRows = adjustmentRowsOfType(result, "traverse_error_ellipse").map((row) => ({
    point_name: textFrom(valueFromKeys(row, ["point_name", "name"]), ""),
    center_x_m: fixedExchangeNumber(valueFromKeys(row, ["center_x", "adjusted_x", "x"]), 4),
    center_y_m: fixedExchangeNumber(valueFromKeys(row, ["center_y", "adjusted_y", "y"]), 4),
    semi_major_mm: fixedExchangeNumber(valueFromKeys(row, ["semi_major_mm", "a_mm"]), 3),
    semi_minor_mm: fixedExchangeNumber(valueFromKeys(row, ["semi_minor_mm", "b_mm"]), 3),
    theta_deg: fixedExchangeNumber(valueFromKeys(row, ["theta_deg", "azimuth_degrees"]), 6),
  }));
  const azimuthRows = adjustmentRowsOfType(result, "traverse_adjusted_azimuth").map((row) => ({
    from: textFrom(row.from, ""),
    to: textFrom(row.to, ""),
    azimuth_deg: fixedExchangeNumber(valueFromKeys(row, ["azimuth_degrees", "azimuth_deg"]), 6),
    horizontal_distance_m: fixedExchangeNumber(valueFromKeys(row, ["horizontal_distance_m", "distance_m"]), 4),
  }));
  const edgePrecisionRows = traverseAdjustmentEdgePrecisionExchangeRows(result);
  const correctionRows = traverseAdjustmentCorrectionExchangeRows(result);
  const controlCompatibilityRows = traverseAdjustmentControlCompatibilityExchangeRows(result);
  return [
    `# ${format.title} Railwise 导线平差交换成果`,
    `# marker=${format.marker}`,
    `# generated_at=${generatedAt}`,
    `# source_tool=${result.toolId}`,
    "[RAILWISE_TRAVERSE_ADJUSTMENT]",
    "SUMMARY",
    csvFromRows(
      [
        "row_type",
        "model",
        "start_azimuth_deg",
        "end_azimuth_deg",
        "dir_mse_sec",
        "dist_fixed_mm",
        "ppm",
        "refraction",
        "ellipsoid_r",
        "height_projection",
        "observation_count",
        "total_distance_m",
        "angular_closure_sec",
        "coordinate_closure_mm",
        "relative_closure",
        "unit_weight_mse_mm",
      ],
      summaryRows.map((row) => ({
        row_type: "traverse_adjustment_summary",
        model: textFrom(valueFromKeys(row, ["model", "adjustment_model"]), textFrom(result.metrics.adjustment_model, "")),
        start_azimuth_deg: fixedExchangeNumber(valueFromKeys(row, ["start_azimuth_deg", "startAzimuthDeg"]), 6),
        end_azimuth_deg: fixedExchangeNumber(valueFromKeys(row, ["end_azimuth_deg", "endAzimuthDeg"]), 6),
        dir_mse_sec: fixedExchangeNumber(valueFromKeys(row, ["dir_mse_sec", "dirMseSec"]), 3),
        dist_fixed_mm: fixedExchangeNumber(valueFromKeys(row, ["dist_fixed_mm", "distFixedMm"]), 3),
        ppm: fixedExchangeNumber(valueFromKeys(row, ["ppm"]), 3),
        refraction: fixedExchangeNumber(valueFromKeys(row, ["refraction"]), 6),
        ellipsoid_r: fixedExchangeNumber(valueFromKeys(row, ["ellipsoid_r", "ellipsoidR"]), 3),
        height_projection: valueFromKeys(row, ["height_projection", "heightProjection"]) === false ? false : true,
        observation_count: fixedExchangeNumber(valueFromKeys(row, ["observation_count"]), 0),
        total_distance_m: fixedExchangeNumber(valueFromKeys(row, ["total_distance_m"]), 4),
        angular_closure_sec: fixedExchangeNumber(valueFromKeys(row, ["angular_closure_sec"]), 3),
        coordinate_closure_mm: fixedExchangeNumber(valueFromKeys(row, ["coordinate_closure_mm"]), 3),
        relative_closure: textFrom(valueFromKeys(row, ["relative_closure"]), textFrom(result.metrics.relative_closure, "")),
        unit_weight_mse_mm: fixedExchangeNumber(valueFromKeys(row, ["unit_weight_mse_mm"]), 3),
      })),
    ),
    "COORDINATES",
    csvFromRows(["point_name", "x_m", "y_m", "mx_mm", "my_mm", "point_mse_mm"], coordinateRows),
    "ERROR_ELLIPSE",
    csvFromRows(["point_name", "center_x_m", "center_y_m", "semi_major_mm", "semi_minor_mm", "theta_deg"], ellipseRows),
    "EDGE_PRECISION",
    csvFromRows(
      ["edge_id", "from", "to", "horizontal_distance_m", "distance_mse_mm", "relative_mse_ratio", "relative_mse", "tolerance_ratio", "status"],
      edgePrecisionRows,
    ),
    "CORRECTIONS",
    csvFromRows(
      [
        "edge_id",
        "from",
        "to",
        "observed_hz_angle_deg",
        "angle_correction_sec",
        "adjusted_hz_angle_deg",
        "dx_correction_mm",
        "dy_correction_mm",
        "coordinate_correction_mm",
        "raw_dx_m",
        "raw_dy_m",
        "adjusted_dx_m",
        "adjusted_dy_m",
        "distance_weight_ratio",
      ],
      correctionRows,
    ),
    "CONTROL_COMPATIBILITY",
    csvFromRows(
      [
        "start_point",
        "end_point",
        "fixed_dx_m",
        "fixed_dy_m",
        "observed_dx_m",
        "observed_dy_m",
        "fx_mm",
        "fy_mm",
        "coordinate_closure_mm",
        "angle_closure_sec",
        "relative_closure",
        "status",
        "coordinate_tolerance_mm",
        "angle_tolerance_sec",
      ],
      controlCompatibilityRows,
    ),
    "ADJUSTED_AZIMUTHS",
    csvFromRows(["from", "to", "azimuth_deg", "horizontal_distance_m"], azimuthRows),
  ].join("\n");
}

function buildLevelAdjustmentExchangeContent(
  result: EngineeringResult,
  format: (typeof ADJUSTMENT_EXCHANGE_FORMATS)[number],
  generatedAt: string,
): string {
  const summaryRows = adjustmentRowsOfType(result, "level_adjustment_summary");
  const heightRows = adjustmentRowsOfType(result, "level_adjusted_height").map((row) => ({
    point_name: textFrom(valueFromKeys(row, ["point_name", "name"]), ""),
    adjusted_height_m: fixedExchangeNumber(valueFromKeys(row, ["adjusted_height_m", "h"]), 4),
    mh_mm: fixedExchangeNumber(valueFromKeys(row, ["mh_mm", "mh"]), 3),
    fixed: textFrom(valueFromKeys(row, ["fixed"]), "false"),
  }));
  const residualRows = adjustmentRowsOfType(result, "level_adjust_segment_residual").map((row) => ({
    from: textFrom(row.from, ""),
    to: textFrom(row.to, ""),
    dh_m: fixedExchangeNumber(valueFromKeys(row, ["dh_m", "dhM"]), 6),
    length_km: fixedExchangeNumber(valueFromKeys(row, ["length_km", "lengthKm"]), 6),
    n_stations: fixedExchangeNumber(valueFromKeys(row, ["n_stations", "nStations"]), 3),
    residual_mm: fixedExchangeNumber(valueFromKeys(row, ["residual_mm"]), 3),
    weight: fixedExchangeNumber(valueFromKeys(row, ["weight"]), 6),
  }));
  return [
    `# ${format.title} Railwise 水准平差交换成果`,
    `# marker=${format.marker}`,
    `# generated_at=${generatedAt}`,
    `# source_tool=${result.toolId}`,
    "[RAILWISE_LEVEL_ADJUSTMENT]",
    "SUMMARY",
    csvFromRows(
      [
        "row_type",
        "known_bm_count",
        "unknown_point_count",
        "segment_count",
        "redundancy",
        "weight_mode",
        "unit_weight_mse_mm",
        "max_residual_mm",
      ],
      summaryRows.map((row) => ({
        row_type: "level_adjustment_summary",
        known_bm_count: fixedExchangeNumber(valueFromKeys(row, ["known_bm_count"]), 0),
        unknown_point_count: fixedExchangeNumber(valueFromKeys(row, ["unknown_point_count"]), 0),
        segment_count: fixedExchangeNumber(valueFromKeys(row, ["segment_count"]), 0),
        redundancy: fixedExchangeNumber(valueFromKeys(row, ["redundancy"]), 0),
        weight_mode: textFrom(valueFromKeys(row, ["weight_mode"]), textFrom(result.metrics.weight_mode, "")),
        unit_weight_mse_mm: fixedExchangeNumber(valueFromKeys(row, ["unit_weight_mse_mm"]), 3),
        max_residual_mm: fixedExchangeNumber(valueFromKeys(row, ["max_residual_mm"]), 3),
      })),
    ),
    "HEIGHTS",
    csvFromRows(["point_name", "adjusted_height_m", "mh_mm", "fixed"], heightRows),
    "SEGMENT_RESIDUALS",
    csvFromRows(["from", "to", "dh_m", "length_km", "n_stations", "residual_mm", "weight"], residualRows),
  ].join("\n");
}

