function buildEngineeringBatchApprovalCoverFromAuditReport(
  report: Omit<EngineeringBatchAuditReport, "markdown" | "html" | "json">,
): EngineeringBatchApprovalCover {
  const body: EngineeringBatchApprovalCoverBody = {
    schema: "railwise.engineering.batch.approvalCover.v1",
    generatedAt: report.generatedAt,
    batchName: report.batchName,
    approvalStatus: report.approvalStatus,
    auditFingerprint: report.auditFingerprint,
    runCount: report.runCount,
    issueCount: report.qualitySummary.issueCount,
    preparedBy: report.roleMatrix.find((role) => role.roleId === "prepared_by")?.actor ?? null,
    currentReviewer: report.reviewSignoff.reviewer,
    currentConclusion: report.reviewSignoff.conclusion,
    roles: report.roleMatrix.map((role) => ({
      roleId: role.roleId,
      roleName: role.roleName,
      actor: role.actor,
      status: role.status,
      evidence: role.evidence,
      requiredAction: role.requiredAction,
      signatureLabel: "签名：________________",
      dateLabel: "日期：____年__月__日",
      sealLabel: role.roleId === "archive_approver" ? "单位/盖章：________________" : "盖章/确认：________________",
    })),
    coverFingerprint: "",
  };
  const coverFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...body, coverFingerprint: undefined }));
  const withFingerprint = { ...body, coverFingerprint };
  const html = buildEngineeringBatchApprovalCoverHtml(withFingerprint);
  const json = JSON.stringify(withFingerprint, null, 2);
  return {
    ...withFingerprint,
    html,
    json,
  };
}

type EngineeringBatchQualityDashboardBody = Omit<EngineeringBatchQualityDashboard, "svg" | "html" | "json">;

function dashboardStatusRows(qualitySummary: EngineeringBatchQualitySummary): EngineeringBatchQualityDashboardStatusRow[] {
  const warn = qualitySummary.warningRunCount;
  const error = qualitySummary.errorRunCount;
  const ok = Math.max(0, qualitySummary.rowCount - warn - error);
  const total = Math.max(1, qualitySummary.rowCount);
  return [
    { status: "ok", label: "正常", count: ok, percent: Math.round((ok / total) * 100) },
    { status: "warn", label: "预警", count: warn, percent: Math.round((warn / total) * 100) },
    { status: "error", label: "错误", count: error, percent: Math.round((error / total) * 100) },
  ];
}

function dashboardIssueRows(qualitySummary: EngineeringBatchQualitySummary): EngineeringBatchQualityDashboardIssueRow[] {
  return qualitySummary.rows
    .filter((row) => row.issueCount > 0 || row.status !== "ok")
    .sort((left, right) => {
      const severity = (status: EngineeringStatus) => (status === "error" ? 2 : status === "warn" ? 1 : 0);
      return severity(right.status) - severity(left.status) || right.issueCount - left.issueCount;
    })
    .slice(0, 8)
    .map((row) => ({
      runId: row.runId,
      sourceName: row.sourceName,
      toolTitle: row.toolTitle,
      status: row.status,
      issueCount: row.issueCount,
      worstMetricName: row.worstMetricName,
      worstMetricValue: row.worstMetricValue,
      issueFocus: row.issueFocus,
      recommendation: row.primaryRecommendation,
    }));
}

function dashboardGateRows(
  report: Omit<EngineeringBatchAuditReport, "markdown" | "html" | "json">,
): EngineeringBatchQualityDashboardGateRow[] {
  return [
    ["quality", "质量结论", report.qualityGate],
    ["ledger", "台账闭环", report.ledgerGate],
    ["review", "复核签注", report.reviewGate],
    ["replay", "可复现性", report.replayGate],
    ["scenario", "场景模板", report.scenarioTemplateGate],
    ["tolerance", "限差库变更", report.toleranceLibraryChangeGate],
  ].map(([gateId, label, gate]) => ({
    gateId: String(gateId),
    label: String(label),
    status: (gate as EngineeringBatchAuditGate).status,
    evidence: (gate as EngineeringBatchAuditGate).evidence,
    requiredAction: (gate as EngineeringBatchAuditGate).requiredAction,
  }));
}

function dashboardColor(status: EngineeringStatus | EngineeringBatchAuditGateStatus | EngineeringBatchArchiveChecklistStatus): string {
  if (status === "ok" || status === "ready") return "#2f855a";
  if (status === "warn" || status === "warning" || status === "optional") return "#b7791f";
  if (status === "error" || status === "blocked" || status === "missing") return "#c53030";
  return "#697386";
}

function buildEngineeringBatchQualityDashboardSvg(dashboard: EngineeringBatchQualityDashboardBody): string {
  const statusBars = dashboard.statusRows
    .map((row, index) => {
      const y = 54 + index * 34;
      const width = Math.max(4, Math.round(row.percent * 2.6));
      return [
        `<text x="24" y="${y + 14}" class="label">${htmlEscape(row.label)}</text>`,
        `<rect x="92" y="${y}" width="260" height="18" rx="3" fill="#edf2f7"/>`,
        `<rect x="92" y="${y}" width="${width}" height="18" rx="3" fill="${dashboardColor(row.status)}"/>`,
        `<text x="366" y="${y + 14}" class="value">${row.count} 项 · ${row.percent}%</text>`,
      ].join("");
    })
    .join("");
  const issueMax = Math.max(1, ...dashboard.issueRows.map((row) => row.issueCount));
  const issueBars = dashboard.issueRows.length
    ? dashboard.issueRows
        .slice(0, 5)
        .map((row, index) => {
          const y = 190 + index * 36;
          const width = Math.max(4, Math.round((row.issueCount / issueMax) * 250));
          const label = `${row.sourceName ?? row.runId} · ${row.issueFocus || row.worstMetricName || "待复核"}`;
          return [
            `<text x="24" y="${y + 14}" class="label">${htmlEscape(label.slice(0, 30))}</text>`,
            `<rect x="220" y="${y}" width="250" height="18" rx="3" fill="#edf2f7"/>`,
            `<rect x="220" y="${y}" width="${width}" height="18" rx="3" fill="${dashboardColor(row.status)}"/>`,
            `<text x="486" y="${y + 14}" class="value">${row.issueCount}</text>`,
          ].join("");
        })
        .join("")
    : '<text x="24" y="210" class="muted">未发现质量问题</text>';
  const gateDots = dashboard.gateRows
    .map((row, index) => {
      const x = 30 + index * 96;
      return [
        `<circle cx="${x}" cy="410" r="9" fill="${dashboardColor(row.status)}"/>`,
        `<text x="${x - 24}" y="436" class="gate">${htmlEscape(row.label)}</text>`,
      ].join("");
    })
    .join("");
  return [
    '<svg xmlns="http://www.w3.org/2000/svg" role="img" aria-label="批次质量图表" viewBox="0 0 620 470">',
    "<title>批次质量图表</title>",
    "<style>.title{font:700 20px -apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;fill:#1f2933}.subtitle,.label,.value,.gate,.muted{font:12px -apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;fill:#52606d}.label{fill:#243b53}.value{fill:#1f2933}.gate{text-anchor:middle}</style>",
    `<text x="24" y="30" class="title">批次质量图表</text>`,
    `<text x="220" y="30" class="subtitle">${htmlEscape(dashboard.batchName)} · 运行 ${dashboard.runCount} · 问题 ${dashboard.issueCount}</text>`,
    `<text x="24" y="48" class="subtitle">状态分布</text>`,
    statusBars,
    `<text x="24" y="174" class="subtitle">质量问题排行</text>`,
    issueBars,
    `<text x="24" y="388" class="subtitle">门禁状态总览</text>`,
    gateDots,
    "</svg>",
  ].join("");
}

function qualityDashboardSectionHtml(dashboard: EngineeringBatchQualityDashboard): string {
  const issueRows = dashboard.issueRows.length
    ? auditHtmlTable(
        ["运行", "工具", "状态", "问题数", "问题焦点", "处理建议"],
        dashboard.issueRows.map((row) => [
          row.sourceName ?? row.runId,
          row.toolTitle,
          statusLabel(row.status),
          String(row.issueCount),
          row.issueFocus || row.worstMetricName || "-",
          row.recommendation || "-",
        ]),
      )
    : '<p class="muted">未发现需要展示的质量问题。</p>';
  const gateRows = auditHtmlTable(
    ["门禁", "状态", "证据", "处理要求"],
    dashboard.gateRows.map((row) => [row.label, auditGateLabel(row.status), row.evidence, row.requiredAction]),
  );
  const blockedItems = dashboard.blockedArchiveItems.length
    ? auditHtmlTable(
        ["归档项", "状态", "证据"],
        dashboard.blockedArchiveItems.map((item) => [
          item.item,
          archiveChecklistStatusLabel(item.status),
          item.evidence,
        ]),
      )
    : '<p class="muted">无阻断或缺失归档项。</p>';
  return [
    `<section class="quality-dashboard" data-schema="${dashboard.schema}">`,
    "<h2>批次质量图表</h2>",
    '<div class="chart-wrap">',
    dashboard.svg,
    "</div>",
    "<h2>质量问题排行</h2>",
    issueRows,
    "<h2>门禁状态总览</h2>",
    gateRows,
    "<h2>归档阻断项</h2>",
    blockedItems,
    `<p class="fingerprint">质控页指纹：${htmlEscape(dashboard.dashboardFingerprint)}</p>`,
    "</section>",
  ].join("\n");
}

