export function buildEngineeringBatchAuditReport(
  items: EngineeringBatchPackageItem[],
  context: EngineeringBatchAuditReportContext = {},
): EngineeringBatchAuditReport {
  const generatedAt = context.generatedAt ?? new Date().toISOString();
  const batchName = context.batchName ?? `工程分析审计批次-${generatedAt.slice(0, 10)}`;
  const qualitySummary = buildEngineeringBatchQualitySummary(items);
  const reviewSignoffInput = context.reviewSignoff ?? context.reviewHistory?.at(-1);
  const reviewSignoff = buildEngineeringReviewSignoff(reviewSignoffInput, generatedAt);
  const reviewHistory = buildEngineeringReviewHistory(context.reviewHistory, reviewSignoffInput, generatedAt);
  const ledgerReconciliation = context.ledgerReconciliation ?? null;
  const replayReport = context.replayReport ?? null;
  const qualityGate = buildQualityAuditGate(qualitySummary, context.importFailures);
  const ledgerGate = buildLedgerAuditGate(ledgerReconciliation);
  const reviewGate = buildReviewAuditGate(reviewSignoff, reviewHistory);
  const replayGate = buildReplayAuditGate(replayReport);
  const scenarioTemplateApplications = scenarioTemplateApplicationsFromItems(items);
  const scenarioTemplateGate = buildScenarioTemplateAuditGate(items, scenarioTemplateApplications);
  const toleranceLibraryComparison = context.toleranceLibraryComparison ?? null;
  const toleranceLibraryApproval = context.toleranceLibraryApproval ?? null;
  const toleranceLibraryChangeGate = buildToleranceLibraryChangeAuditGate(
    toleranceLibraryComparison,
    toleranceLibraryApproval,
  );
  const approvalStatus = auditApprovalStatus(
    qualityGate,
    ledgerGate,
    reviewGate,
    replayGate,
    toleranceLibraryChangeGate,
  );
  const roleMatrix = buildAuditRoleMatrix(context, reviewSignoff, ledgerReconciliation, approvalStatus, {
    qualityGate,
    ledgerGate,
    reviewGate,
    toleranceLibraryChangeGate,
  });
  const archiveChecklist = buildArchiveChecklist(
    items,
    qualityGate,
    ledgerGate,
    reviewGate,
    replayGate,
    scenarioTemplateGate,
    scenarioTemplateApplications,
    toleranceLibraryChangeGate,
    toleranceLibraryComparison,
  );
  const reportBody = {
    schema: "railwise.engineering.batch.auditReport.v1" as const,
    generatedAt,
    batchName,
    approvalStatus,
    runCount: items.length,
    qualitySummary,
    reviewSignoff,
    reviewHistory,
    ledgerReconciliation,
    replayReportFingerprint: replayReport?.reportFingerprint ?? null,
    qualityGate,
    ledgerGate,
    reviewGate,
    replayGate,
    scenarioTemplateGate,
    scenarioTemplateApplications,
    toleranceLibraryChangeGate,
    toleranceLibraryComparison,
    toleranceLibraryApproval,
    roleMatrix,
    archiveChecklist,
  };
  const auditFingerprint = fnv1a32Fingerprint(JSON.stringify(reportBody));
  const reportWithoutArtifacts = {
    ...reportBody,
    auditFingerprint,
  };
  const markdown = buildEngineeringBatchAuditReportMarkdown(reportWithoutArtifacts);
  const html = buildEngineeringBatchAuditReportHtml(reportWithoutArtifacts);
  const json = JSON.stringify(reportWithoutArtifacts, null, 2);
  return {
    ...reportWithoutArtifacts,
    markdown,
    html,
    json,
  };
}

function utf8Bytes(text: string): Uint8Array {
  return new TextEncoder().encode(text);
}

function bytesToBase64(bytes: Uint8Array): string {
  const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
  let output = "";
  for (let index = 0; index < bytes.length; index += 3) {
    const a = bytes[index] ?? 0;
    const b = bytes[index + 1] ?? 0;
    const c = bytes[index + 2] ?? 0;
    const triple = (a << 16) | (b << 8) | c;
    output += alphabet[(triple >> 18) & 63];
    output += alphabet[(triple >> 12) & 63];
    output += index + 1 < bytes.length ? alphabet[(triple >> 6) & 63] : "=";
    output += index + 2 < bytes.length ? alphabet[triple & 63] : "=";
  }
  return output;
}

function base64ToBytes(base64: string): number[] {
  const alphabet = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
  const clean = base64.replace(/[^A-Za-z0-9+/=]/g, "");
  const bytes: number[] = [];
  for (let index = 0; index < clean.length; index += 4) {
    const a = alphabet.indexOf(clean[index] ?? "A");
    const b = alphabet.indexOf(clean[index + 1] ?? "A");
    const c = clean[index + 2] === "=" ? -1 : alphabet.indexOf(clean[index + 2] ?? "A");
    const d = clean[index + 3] === "=" ? -1 : alphabet.indexOf(clean[index + 3] ?? "A");
    const triple = (Math.max(a, 0) << 18) | (Math.max(b, 0) << 12) | (Math.max(c, 0) << 6) | Math.max(d, 0);
    bytes.push((triple >> 16) & 255);
    if (c >= 0) bytes.push((triple >> 8) & 255);
    if (d >= 0) bytes.push(triple & 255);
  }
  return bytes;
}

const CRC32_TABLE = (() => {
  const table = new Uint32Array(256);
  for (let index = 0; index < 256; index++) {
    let value = index;
    for (let bit = 0; bit < 8; bit++) value = value & 1 ? 0xedb88320 ^ (value >>> 1) : value >>> 1;
    table[index] = value >>> 0;
  }
  return table;
})();

function crc32(bytes: Uint8Array): number {
  let crc = 0xffffffff;
  for (const byte of bytes) crc = CRC32_TABLE[(crc ^ byte) & 0xff]! ^ (crc >>> 8);
  return (crc ^ 0xffffffff) >>> 0;
}

function u16(value: number): number[] {
  return [value & 255, (value >>> 8) & 255];
}

function u32(value: number): number[] {
  return [value & 255, (value >>> 8) & 255, (value >>> 16) & 255, (value >>> 24) & 255];
}

function concatBytes(parts: Uint8Array[]): Uint8Array {
  const total = parts.reduce((sum, part) => sum + part.length, 0);
  const output = new Uint8Array(total);
  let offset = 0;
  for (const part of parts) {
    output.set(part, offset);
    offset += part.length;
  }
  return output;
}

function bytesFromNumbers(values: number[]): Uint8Array {
  return new Uint8Array(values);
}

function buildZip(entries: Array<{ name: string; data: Uint8Array }>): Uint8Array {
  const localParts: Uint8Array[] = [];
  const centralParts: Uint8Array[] = [];
  let offset = 0;
  for (const entry of entries) {
    const name = utf8Bytes(entry.name);
    const checksum = crc32(entry.data);
    const localHeader = bytesFromNumbers([
      ...u32(0x04034b50),
      ...u16(20),
      ...u16(0x0800),
      ...u16(0),
      ...u16(0),
      ...u16(0),
      ...u32(checksum),
      ...u32(entry.data.length),
      ...u32(entry.data.length),
      ...u16(name.length),
      ...u16(0),
    ]);
    localParts.push(localHeader, name, entry.data);
    const centralHeader = bytesFromNumbers([
      ...u32(0x02014b50),
      ...u16(20),
      ...u16(20),
      ...u16(0x0800),
      ...u16(0),
      ...u16(0),
      ...u16(0),
      ...u32(checksum),
      ...u32(entry.data.length),
      ...u32(entry.data.length),
      ...u16(name.length),
      ...u16(0),
      ...u16(0),
      ...u16(0),
      ...u16(0),
      ...u32(0),
      ...u32(offset),
    ]);
    centralParts.push(centralHeader, name);
    offset += localHeader.length + name.length + entry.data.length;
  }
  const centralDirectory = concatBytes(centralParts);
  const end = bytesFromNumbers([
    ...u32(0x06054b50),
    ...u16(0),
    ...u16(0),
    ...u16(entries.length),
    ...u16(entries.length),
    ...u32(centralDirectory.length),
    ...u32(offset),
    ...u16(0),
  ]);
  return concatBytes([...localParts, centralDirectory, end]);
}

export function buildEngineeringProfessionalCsvSamplePack(options: {
  exportedAt?: string;
} = {}): EngineeringProfessionalCsvSamplePack {
  const exportedAt = options.exportedAt ?? new Date().toISOString();
  const samples = getEngineeringProfessionalCsvSamples();
  const sampleFiles = samples.map((sample) => {
    const tool = TOOL_BY_ID.get(sample.toolId);
    const path = `samples/${sample.toolId}/${sample.sourceName}`;
    return {
      path,
      sample,
      toolTitle: tool?.title ?? sample.toolId,
      toolCategory: tool?.category ?? "",
    };
  });
  const csvIndex = csvFromRows(
    ["tool_id", "tool_title", "sample_id", "title", "path", "description"],
    sampleFiles.map((file) => ({
      tool_id: file.sample.toolId,
      tool_title: file.toolTitle,
      sample_id: file.sample.id,
      title: file.sample.title,
      path: file.path,
      description: file.sample.description,
    })),
  );
  const markdown = [
    "# Railwise 专业 CSV 样表包",
    "",
    `- 导出时间：${exportedAt}`,
    `- 样表数量：${samples.length}`,
    "- 使用方式：打开对应工具的 CSV 文件，保留表头，替换为现场观测数据后导入内业平差工作台或轨道测量监测工具。",
    "",
    "| 工具 | 样表 | 文件 |",
    "| --- | --- | --- |",
    ...sampleFiles.map((file) => `| ${file.toolTitle} | ${file.sample.title} | ${file.path} |`),
    "",
  ].join("\n");
  const manifestBody = {
    schema: "railwise.engineering.professionalCsvSamplePack.manifest.v1",
    exportedAt,
    sampleCount: samples.length,
    files: sampleFiles.map((file) => ({
      path: file.path,
      toolId: file.sample.toolId,
      toolTitle: file.toolTitle,
      toolCategory: file.toolCategory,
      sampleId: file.sample.id,
      title: file.sample.title,
      sourceName: file.sample.sourceName,
      description: file.sample.description,
      fingerprint: fnv1a32Fingerprint(file.sample.csv),
    })),
  };
  const manifest = JSON.stringify(
    {
      ...manifestBody,
      packageFingerprint: fnv1a32Fingerprint(JSON.stringify({ ...manifestBody, csvIndex, markdown })),
    },
    null,
    2,
  );
  const entries = [
    { name: "manifest.json", data: utf8Bytes(manifest) },
    { name: "README.md", data: utf8Bytes(markdown) },
    { name: "sample-index.csv", data: utf8Bytes(csvIndex) },
    ...sampleFiles.map((file) => ({ name: file.path, data: utf8Bytes(file.sample.csv) })),
  ];
  const zipBytes = buildZip(entries);
  return {
    schema: "railwise.engineering.professionalCsvSamplePack.v1",
    exportedAt,
    fileName: "railwise-professional-csv-samples.zip",
    mimeType: "application/zip",
    sampleCount: samples.length,
    entryCount: entries.length,
    byteLength: zipBytes.length,
    manifest,
    markdown,
    csvIndex,
    packageFingerprint: fnv1a32Fingerprint(
      JSON.stringify({ exportedAt, sampleCount: samples.length, manifest, markdown, csvIndex }),
    ),
    base64: bytesToBase64(zipBytes),
  };
}

function xmlEscape(value: string): string {
  return value
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;")
    .replace(/"/g, "&quot;");
}

function markdownPlainLines(markdown: string, maxLines = 56): string[] {
  return markdown
    .split(/\r?\n/)
    .map((line) =>
      line
        .replace(/^#{1,6}\s*/, "")
        .replace(/^\|\s*/, "")
        .replace(/\s*\|$/, "")
        .replace(/\|/g, " / ")
        .trim(),
    )
    .filter((line) => line && !/^[-\s/]+$/.test(line))
    .slice(0, maxLines);
}

function buildDocxDocumentXmlFromLines(lines: string[]): string {
  const paragraphXml = lines
    .map((line) => `<w:p><w:r><w:t xml:space="preserve">${xmlEscape(line)}</w:t></w:r></w:p>`)
    .join("");
  return [
    '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
    '<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main">',
    "<w:body>",
    paragraphXml,
    '<w:sectPr><w:pgSz w:w="11906" w:h="16838"/><w:pgMar w:top="1134" w:right="907" w:bottom="1134" w:left="907"/></w:sectPr>',
    "</w:body>",
    "</w:document>",
  ].join("");
}

function buildDocxBytesFromMarkdown(markdown: string, maxLines = 160): Uint8Array {
  return buildZip([
    {
      name: "[Content_Types].xml",
      data: utf8Bytes(
        [
          '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
          '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">',
          '<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>',
          '<Default Extension="xml" ContentType="application/xml"/>',
          '<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>',
          "</Types>",
        ].join(""),
      ),
    },
    {
      name: "_rels/.rels",
      data: utf8Bytes(
        [
          '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
          '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">',
          '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/>',
          "</Relationships>",
        ].join(""),
      ),
    },
    { name: "word/document.xml", data: utf8Bytes(buildDocxDocumentXmlFromLines(markdownPlainLines(markdown, maxLines))) },
  ]);
}

function pdfUtf16Hex(value: string): string {
  let hex = "";
  for (let index = 0; index < value.length; index++) {
    hex += value.charCodeAt(index).toString(16).padStart(4, "0");
  }
  return hex;
}

function pdfSafeLineChunks(line: string, chunkSize = 42): string[] {
  const chunks: string[] = [];
  for (let index = 0; index < line.length; index += chunkSize) chunks.push(line.slice(index, index + chunkSize));
  return chunks.length > 0 ? chunks : [""];
}

function buildPdfBytesFromMarkdown(title: string, sourceFingerprint: string, markdown: string): Uint8Array {
  const textLines = [
    title,
    `报告指纹：${sourceFingerprint}`,
    ...markdownPlainLines(markdown, 34),
  ].flatMap((line) => pdfSafeLineChunks(line));
  const content = [
    "BT",
    "/F1 10 Tf",
    "50 800 Td",
    ...textLines.map((line, index) => `${index === 0 ? "" : "0 -16 Td "}<${pdfUtf16Hex(line)}> Tj`.trim()),
    "ET",
  ].join("\n");
  const contentBytes = utf8Bytes(content);
  const objects = [
    "<< /Type /Catalog /Pages 2 0 R >>",
    "<< /Type /Pages /Kids [3 0 R] /Count 1 >>",
    "<< /Type /Page /Parent 2 0 R /MediaBox [0 0 595 842] /Resources << /Font << /F1 4 0 R >> >> /Contents 6 0 R >>",
    "<< /Type /Font /Subtype /Type0 /BaseFont /STSong-Light /Encoding /UniGB-UCS2-H /DescendantFonts [5 0 R] >>",
    "<< /Type /Font /Subtype /CIDFontType0 /BaseFont /STSong-Light /CIDSystemInfo << /Registry (Adobe) /Ordering (GB1) /Supplement 5 >> >>",
    `<< /Length ${contentBytes.length} >>\nstream\n${content}\nendstream`,
  ];
  const header = `%PDF-1.4\n% ${title} ${sourceFingerprint}\n`;
  const parts: string[] = [header];
  const offsets: number[] = [];
  let byteOffset = utf8Bytes(header).length;
  objects.forEach((object, index) => {
    offsets.push(byteOffset);
    const objectText = `${index + 1} 0 obj\n${object}\nendobj\n`;
    parts.push(objectText);
    byteOffset += utf8Bytes(objectText).length;
  });
  const xrefOffset = byteOffset;
  const xref = [
    "xref",
    `0 ${objects.length + 1}`,
    "0000000000 65535 f ",
    ...offsets.map((value) => `${String(value).padStart(10, "0")} 00000 n `),
    "trailer",
    `<< /Size ${objects.length + 1} /Root 1 0 R >>`,
    "startxref",
    String(xrefOffset),
    "%%EOF",
  ].join("\n");
  return utf8Bytes(`${parts.join("")}${xref}`);
}

function buildAuditDocxBytes(report: EngineeringBatchAuditReport): Uint8Array {
  return buildDocxBytesFromMarkdown(report.markdown, 160);
}

function buildAuditPdfBytes(report: EngineeringBatchAuditReport): Uint8Array {
  return buildPdfBytesFromMarkdown("工程批处理审计归档报告", report.auditFingerprint, report.markdown);
}

type EngineeringWorkbookSheet = {
  name: string;
  headers: string[];
  rows: Primitive[][];
};

function xlsxColumnLetter(index: number): string {
  let output = "";
  let current = index;
  while (current >= 0) {
    output = String.fromCharCode(65 + (current % 26)) + output;
    current = Math.floor(current / 26) - 1;
  }
  return output;
}

function xlsxSheetName(name: string): string {
  const cleaned = name.replace(/[\\/?*:[\]]/g, " ").trim() || "Sheet";
  return [...cleaned].slice(0, 31).join("");
}

function uniqueXlsxSheetNames(sheets: EngineeringWorkbookSheet[]): EngineeringWorkbookSheet[] {
  const used = new Set<string>();
  return sheets.map((sheet) => {
    const base = xlsxSheetName(sheet.name);
    let name = base;
    let index = 2;
    while (used.has(name)) {
      const suffix = `_${index}`;
      name = `${[...base].slice(0, Math.max(1, 31 - suffix.length)).join("")}${suffix}`;
      index += 1;
    }
    used.add(name);
    return { ...sheet, name };
  });
}

function xlsxCellXml(value: Primitive, ref: string, header = false): string {
  const style = header ? ' s="1"' : "";
  if (value === null) return `<c r="${ref}"${style}/>`;
  if (typeof value === "number") return `<c r="${ref}" s="${header ? 1 : 2}"><v>${value}</v></c>`;
  if (typeof value === "boolean") return `<c r="${ref}" t="b"${style}><v>${value ? 1 : 0}</v></c>`;
  return `<c r="${ref}" t="inlineStr"${style}><is><t xml:space="preserve">${xmlEscape(value)}</t></is></c>`;
}

function buildXlsxWorksheetXml(sheet: EngineeringWorkbookSheet): string {
  const columnCount = Math.max(1, sheet.headers.length);
  const lastColumn = xlsxColumnLetter(columnCount - 1);
  const lastRow = sheet.rows.length + 1;
  const widths = sheet.headers
    .map((header, index) => {
      const maxCell = sheet.rows.reduce((max, row) => {
        const value = row[index];
        return Math.max(max, value === null ? 0 : String(value).length);
      }, 0);
      const width = Math.min(Math.max([...header].length + 4, maxCell + 2, 10), 56);
      return `<col min="${index + 1}" max="${index + 1}" width="${width}" customWidth="1"/>`;
    })
    .join("");
  const headerRow = `<row r="1">${sheet.headers
    .map((header, index) => xlsxCellXml(header, `${xlsxColumnLetter(index)}1`, true))
    .join("")}</row>`;
  const dataRows = sheet.rows
    .map((row, rowIndex) => {
      const rowNumber = rowIndex + 2;
      return `<row r="${rowNumber}">${sheet.headers
        .map((_, columnIndex) => xlsxCellXml(row[columnIndex] ?? null, `${xlsxColumnLetter(columnIndex)}${rowNumber}`))
        .join("")}</row>`;
    })
    .join("");
  return [
    '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
    '<worksheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">',
    `<dimension ref="A1:${lastColumn}${lastRow}"/>`,
    `<cols>${widths}</cols>`,
    '<sheetViews><sheetView workbookViewId="0"><pane ySplit="1" topLeftCell="A2" activePane="bottomLeft" state="frozen"/></sheetView></sheetViews>',
    `<sheetData>${headerRow}${dataRows}</sheetData>`,
    `<autoFilter ref="A1:${lastColumn}${lastRow}"/>`,
    "</worksheet>",
  ].join("");
}

function buildXlsxWorkbookBytes(sheets: EngineeringWorkbookSheet[]): { bytes: Uint8Array; sheets: EngineeringWorkbookSheet[] } {
  const namedSheets = uniqueXlsxSheetNames(sheets);
  const sheetRefs = namedSheets
    .map((sheet, index) => `<sheet name="${xmlEscape(sheet.name)}" sheetId="${index + 1}" r:id="rId${index + 1}"/>`)
    .join("");
  const sheetRelationships = namedSheets
    .map(
      (_, index) =>
        `<Relationship Id="rId${index + 1}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/worksheet" Target="worksheets/sheet${index + 1}.xml"/>`,
    )
    .join("");
  const sheetContentTypes = namedSheets
    .map(
      (_, index) =>
        `<Override PartName="/xl/worksheets/sheet${index + 1}.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.worksheet+xml"/>`,
    )
    .join("");
  const files: Array<{ name: string; data: Uint8Array }> = [
    {
      name: "[Content_Types].xml",
      data: utf8Bytes(
        [
          '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
          '<Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types">',
          '<Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/>',
          '<Default Extension="xml" ContentType="application/xml"/>',
          '<Override PartName="/xl/workbook.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.sheet.main+xml"/>',
          '<Override PartName="/xl/styles.xml" ContentType="application/vnd.openxmlformats-officedocument.spreadsheetml.styles+xml"/>',
          sheetContentTypes,
          "</Types>",
        ].join(""),
      ),
    },
    {
      name: "_rels/.rels",
      data: utf8Bytes(
        [
          '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
          '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">',
          '<Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="xl/workbook.xml"/>',
          "</Relationships>",
        ].join(""),
      ),
    },
    {
      name: "xl/workbook.xml",
      data: utf8Bytes(
        [
          '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
          '<workbook xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main" xmlns:r="http://schemas.openxmlformats.org/officeDocument/2006/relationships">',
          `<sheets>${sheetRefs}</sheets>`,
          "</workbook>",
        ].join(""),
      ),
    },
    {
      name: "xl/_rels/workbook.xml.rels",
      data: utf8Bytes(
        [
          '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
          '<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships">',
          sheetRelationships,
          `<Relationship Id="rId${namedSheets.length + 1}" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/styles" Target="styles.xml"/>`,
          "</Relationships>",
        ].join(""),
      ),
    },
    {
      name: "xl/styles.xml",
      data: utf8Bytes(
        [
          '<?xml version="1.0" encoding="UTF-8" standalone="yes"?>',
          '<styleSheet xmlns="http://schemas.openxmlformats.org/spreadsheetml/2006/main">',
          '<fonts count="2"><font><sz val="11"/><name val="等线"/></font><font><b/><sz val="11"/><name val="等线"/></font></fonts>',
          '<fills count="3"><fill><patternFill patternType="none"/></fill><fill><patternFill patternType="gray125"/></fill><fill><patternFill patternType="solid"><fgColor rgb="FFD9E2F3"/></patternFill></fill></fills>',
          '<borders count="2"><border/><border><left style="thin"/><right style="thin"/><top style="thin"/><bottom style="thin"/></border></borders>',
          '<cellStyleXfs count="1"><xf numFmtId="0" fontId="0" fillId="0" borderId="0"/></cellStyleXfs>',
          '<cellXfs count="3"><xf numFmtId="0" fontId="0" fillId="0" borderId="0"/><xf numFmtId="0" fontId="1" fillId="2" borderId="1" applyFont="1" applyFill="1" applyBorder="1"/><xf numFmtId="4" fontId="0" fillId="0" borderId="1" applyNumberFormat="1" applyBorder="1"/></cellXfs>',
          "</styleSheet>",
        ].join(""),
      ),
    },
  ];
  namedSheets.forEach((sheet, index) => {
    files.push({ name: `xl/worksheets/sheet${index + 1}.xml`, data: utf8Bytes(buildXlsxWorksheetXml(sheet)) });
  });
  return { bytes: buildZip(files), sheets: namedSheets };
}

function engineeringDeliverableResultMeta(deliverables: EngineeringDeliverables): {
  result: EngineeringResult | null;
  toolTitle: string;
  toolId: string;
  resultFingerprint: string;
  reportFingerprint: string;
} {
  try {
    const projectPackage = JSON.parse(deliverables.projectPackageJson) as {
      result?: unknown;
      tool?: { id?: unknown; title?: unknown };
      traceability?: { resultFingerprint?: unknown; reportFingerprint?: unknown };
    };
    const result = objectFrom(projectPackage.result);
    const rows = Array.isArray(result.rows) ? (result.rows as EngineeringResult["rows"]) : [];
    const metrics = objectFrom(result.metrics) as Record<string, Primitive>;
    return {
      result: {
        toolId: textFrom(result.toolId, textFrom(projectPackage.tool?.id, "unknown")) as EngineeringToolId,
        title: textFrom(result.title, textFrom(projectPackage.tool?.title, deliverables.baseName)),
        status: textFrom(result.status, "ok") as EngineeringStatus,
        summary: textFrom(result.summary, ""),
        metrics,
        rows,
        method: objectFrom(result.method) as EngineeringResult["method"],
        recommendations: arrayFrom(result.recommendations).map((item) => textFrom(item, "")),
      },
      toolTitle: textFrom(projectPackage.tool?.title, deliverables.baseName),
      toolId: textFrom(projectPackage.tool?.id, "unknown"),
      resultFingerprint: textFrom(projectPackage.traceability?.resultFingerprint, fnv1a32Fingerprint(deliverables.json)),
      reportFingerprint: textFrom(projectPackage.traceability?.reportFingerprint, fnv1a32Fingerprint(deliverables.markdown)),
    };
  } catch {
    return {
      result: null,
      toolTitle: deliverables.baseName,
      toolId: "unknown",
      resultFingerprint: fnv1a32Fingerprint(deliverables.json),
      reportFingerprint: fnv1a32Fingerprint(deliverables.markdown),
    };
  }
}

function workbookSheetsFromEngineeringResult(
  result: EngineeringResult,
  meta: { toolTitle: string; toolId: string; resultFingerprint: string; reportFingerprint: string },
): { sheets: EngineeringWorkbookSheet[]; rowTypeCounts: Record<string, number> } {
  const grouped = new Map<string, EngineeringResult["rows"]>();
  for (const row of result.rows) {
    const rowType = textFrom(row.row_type, "result") || "result";
    const rows = grouped.get(rowType) ?? [];
    rows.push(row);
    grouped.set(rowType, rows);
  }
  const rowTypeCounts = Object.fromEntries([...grouped.entries()].map(([rowType, rows]) => [rowType, rows.length]));
  const tableSummary = buildEngineeringResultTableSummary(result);
  const isAdjustmentResult = result.toolId === "traverse_adjustment" || result.toolId === "level_adjustment";
  const workbookSummaryRows: Primitive[][] = [
    ["工具", meta.toolTitle],
    ["工具ID", meta.toolId],
    ["状态", result.status],
    ["摘要", result.summary],
    ...(isAdjustmentResult
      ? [
          ["成果类型", "内业平差专项"] as Primitive[],
          ["专项工具", result.toolId === "traverse_adjustment" ? "导线内业" : "水准内业"] as Primitive[],
        ]
      : []),
    ["成果表数量", tableSummary.length],
    ["明细行数", result.rows.length],
    ["结果指纹", meta.resultFingerprint],
    ["报告指纹", meta.reportFingerprint],
  ];
  const sheets: EngineeringWorkbookSheet[] = [
    {
      name: "成果清单",
      headers: ["项目", "值"],
      rows: workbookSummaryRows,
    },
    {
      name: "质量摘要",
      headers: ["指标", "值"],
      rows:
        Object.keys(result.metrics).length > 0
          ? Object.entries(result.metrics).map(([key, value]) => [key, value])
          : [
              ["status", result.status],
              ["summary", result.summary],
            ],
    },
  ];
  if (grouped.size === 0) {
    sheets.push({
      name: "成果数据",
      headers: ["项目", "值"],
      rows: [["暂无明细数据", result.summary]],
    });
  } else {
    for (const [rowType, rows] of grouped) {
      const headers = Array.from(new Set(rows.flatMap((row) => Object.keys(row))));
      sheets.push({
        name: resultTableTitle(rowType),
        headers,
        rows: rows.map((row) => headers.map((header) => row[header] ?? null)),
      });
    }
  }
  return { sheets, rowTypeCounts };
}

function importEvidenceWorkbookSheetsFromDeliverables(
  deliverables: EngineeringDeliverables,
): { sheets: EngineeringWorkbookSheet[]; rowTypeCounts: Record<string, number> } {
  try {
    const projectPackage = objectFrom(JSON.parse(deliverables.projectPackageJson));
    const input = objectFrom(projectPackage.input);
    const preflight = normalizeEngineeringImportPreflight(input.preflight);
    const previewRows = normalizeEngineeringImportPreviewRows(input.previewRows);
    const warnings = stringArrayFromUnknown(input.warnings);
    const columnNames = stringArrayFromUnknown(input.columnNames);
    const sheets: EngineeringWorkbookSheet[] = [];
    const rowTypeCounts: Record<string, number> = {};

    if (preflight) {
      sheets.push({
        name: "导入预检",
        headers: ["项目", "值"],
        rows: [
          ["源文件", textFrom(input.sourceName, "未命名")],
          ["源路径", textFrom(input.sourcePath, "")],
          ["输入格式", textFrom(input.format, "")],
          ["输入行数", numberFrom(input.rowCount, 0)],
          ["预检流程", preflight.targetWorkflow],
          ["计算状态", preflight.readyForCalculation ? "可计算" : "需补字段"],
          ["质量状态", preflight.qualityStatus],
          ["已满足字段", preflight.requiredFieldsPresent.join("、") || "无"],
          ["缺失字段", preflight.missingRequiredFields.join("、") || "无"],
          ["已识别字段", preflight.recognizedFields.join("、") || "无"],
          ["原始列名", columnNames.join("、") || "无"],
          ["导入警告", warnings.join("、") || "无"],
        ],
      });
      rowTypeCounts.engineering_import_preflight = 1;
    }

    if (previewRows.length > 0) {
      const headers = Array.from(new Set(previewRows.flatMap((row) => Object.keys(row))));
      sheets.push({
        name: "导入预览",
        headers,
        rows: previewRows.map((row) => headers.map((header) => row[header] ?? "")),
      });
      rowTypeCounts.engineering_import_preview = previewRows.length;
    }

    return { sheets, rowTypeCounts };
  } catch {
    return { sheets: [], rowTypeCounts: {} };
  }
}

function deliverySignoffWorkbookSheetFromDeliverables(
  deliverables: EngineeringDeliverables,
): { sheet: EngineeringWorkbookSheet; rowTypeCount: number } {
  let traceability: Record<string, unknown> = {};
  let input: Record<string, unknown> = {};
  try {
    const projectPackage = objectFrom(JSON.parse(deliverables.projectPackageJson));
    traceability = objectFrom(projectPackage.traceability);
    input = objectFrom(projectPackage.input);
  } catch {
    traceability = {};
    input = {};
  }

  const rows: Primitive[][] = [];
  const addRow = (
    category: string,
    item: string,
    fileName: string,
    status: string,
    reviewRequirement: string,
    evidence: string,
  ) => {
    rows.push([category, item, fileName, status, reviewRequirement, evidence, "", "", ""]);
  };
  const generated = (value: string | undefined): string => (value && value.length > 0 ? "已生成" : "缺失");
  const optionalGenerated = (value: string | undefined, fallback = "未配置"): string =>
    value && value.length > 0 ? "已生成" : fallback;
  const preflight = normalizeEngineeringImportPreflight(input.preflight);
  const preflightStatus = preflight ? (preflight.readyForCalculation ? "可计算" : "需补字段") : "未记录";
  const preflightEvidence = preflight
    ? `targetWorkflow=${preflight.targetWorkflow}; quality=${preflight.qualityStatus}; missing=${
        preflight.missingRequiredFields.join("、") || "无"
      }`
    : "preflight=missing";
  const sourceName = textFrom(input.sourceName, "") || textFrom(input.sourcePath, "") || `${deliverables.baseName}-导入数据`;

  addRow(
    "报告",
    "报告 Markdown",
    `${deliverables.baseName}-报告.md`,
    generated(deliverables.markdown),
    "复核工程上下文、平差结论和质量说明",
    textFrom(traceability.reportFingerprint, fnv1a32Fingerprint(deliverables.markdown)),
  );
  addRow(
    "数据",
    "成果 CSV",
    `${deliverables.baseName}-成果.csv`,
    generated(deliverables.csv),
    "复核成果表字段、单位和行数",
    textFrom(traceability.csvFingerprint, fnv1a32Fingerprint(deliverables.csv)),
  );
  addRow(
    "数据",
    "成果 JSON",
    `${deliverables.baseName}-成果.json`,
    generated(deliverables.json),
    "复核结构化结果、指标和方法元数据",
    textFrom(traceability.resultFingerprint, fnv1a32Fingerprint(deliverables.json)),
  );
  addRow(
    "空间",
    "GeoJSON 空间成果",
    `${deliverables.baseName}.geojson`,
    optionalGenerated(deliverables.geojson, deliverables.spatialArtifactsDeferred ? "已延迟生成" : "未生成"),
    "复核空间坐标、点线图层和属性",
    deliverables.spatialArtifactsDeferred?.deferredFingerprint ?? fnv1a32Fingerprint(deliverables.geojson),
  );
  addRow(
    "空间",
    "DXF 空间成果",
    `${deliverables.baseName}.dxf`,
    optionalGenerated(deliverables.dxf, deliverables.spatialArtifactsDeferred ? "已延迟生成" : "未生成"),
    "复核 CAD 图层、点位和网形",
    deliverables.spatialArtifactsDeferred?.deferredFingerprint ?? fnv1a32Fingerprint(deliverables.dxf),
  );
  addRow(
    "目录",
    "成果表目录",
    `${deliverables.baseName}-成果表目录.md/csv/json`,
    generated(deliverables.resultTableCatalogJson),
    "复核每类成果表是否纳入目录",
    fnv1a32Fingerprint(deliverables.resultTableCatalogJson),
  );
  addRow(
    "模板",
    "字段映射模板",
    `${deliverables.baseName}-字段映射模板.csv/json`,
    generated(deliverables.fieldMappingTemplateJson),
    "复核导入字段和单位映射",
    fnv1a32Fingerprint(deliverables.fieldMappingTemplateJson),
  );
  addRow(
    "输入",
    "导入字段预检状态",
    sourceName,
    preflightStatus,
    "复核外业字段分组、缺失项和计算前状态",
    preflightEvidence,
  );
  addRow(
    "Excel",
    "成果 XLSX",
    `${deliverables.baseName}-成果表.xlsx`,
    "随本工作簿生成",
    "复核工作簿 sheet、导入预检、交换回读和签收列",
    "engineering_result_workbook",
  );
  addRow(
    "交换",
    "平差交换清单",
    `${deliverables.baseName}-平差交换-manifest.json`,
    generated(deliverables.adjustmentExchangeManifestJson),
    "复核交换文件数量、格式和回读状态",
    fnv1a32Fingerprint(deliverables.adjustmentExchangeManifestJson),
  );
  if (deliverables.adjustmentExchangeProtocolChecklistJson) {
    addRow(
      "交换",
      "平差交换协议字段清单",
      `${deliverables.baseName}-平差交换协议清单.json/csv`,
      generated(deliverables.adjustmentExchangeProtocolChecklistJson),
      "复核每类交换格式的 marker、区段、字段和回读成果类型",
      fnv1a32Fingerprint(deliverables.adjustmentExchangeProtocolChecklistJson),
    );
  }

  for (const file of deliverables.adjustmentExchangeFiles) {
    addRow(
      "交换",
      file.title,
      file.fileName,
      file.readbackValidation.status === "ok" ? "回读校验通过" : "需复核",
      `${file.extension.toUpperCase()} 格式交付复核`,
      file.exchangeFingerprint,
    );
  }

  if (deliverables.offlineAcceptanceJson) {
    addRow(
      "验收",
      "离线验收证据",
      `${deliverables.baseName}-离线验收.json`,
      "已生成",
      "复核断网计算、导出和交换文件证据",
      fnv1a32Fingerprint(deliverables.offlineAcceptanceJson),
    );
  }
  if (deliverables.performanceAcceptanceJson) {
    addRow(
      "验收",
      "性能验收证据",
      `${deliverables.baseName}-性能验收.json`,
      "已生成",
      "复核数百点内业平差耗时和样本量",
      fnv1a32Fingerprint(deliverables.performanceAcceptanceJson),
    );
  }
  if (deliverables.aiAdjustmentReportMarkdown) {
    addRow(
      "报告",
      "AI 平差报告草稿",
      `${deliverables.baseName}-AI平差报告.md`,
      "已生成",
      "复核 AI 草稿与实算成果一致性",
      fnv1a32Fingerprint(deliverables.aiAdjustmentReportMarkdown),
    );
  }

  return {
    sheet: {
      name: "交付清单复核签收",
      headers: ["类别", "交付项", "文件/格式", "状态", "复核要求", "指纹/说明", "复核人", "签收日期", "意见"],
      rows,
    },
    rowTypeCount: rows.length,
  };
}

function engineeringDeliverableReportMeta(deliverables: EngineeringDeliverables): {
  toolTitle: string;
  reportFingerprint: string;
} {
  try {
    const parsed = JSON.parse(deliverables.projectPackageJson) as {
      tool?: { title?: unknown };
      traceability?: { reportFingerprint?: unknown };
    };
    return {
      toolTitle: typeof parsed.tool?.title === "string" ? parsed.tool.title : deliverables.baseName,
      reportFingerprint:
        typeof parsed.traceability?.reportFingerprint === "string"
          ? parsed.traceability.reportFingerprint
          : fnv1a32Fingerprint(deliverables.markdown),
    };
  } catch {
    return {
      toolTitle: deliverables.baseName,
      reportFingerprint: fnv1a32Fingerprint(deliverables.markdown),
    };
  }
}

export function buildEngineeringReportDocxExport(deliverables: EngineeringDeliverables): EngineeringReportDocxExport {
  const meta = engineeringDeliverableReportMeta(deliverables);
  const bytes = buildDocxBytesFromMarkdown(deliverables.markdown);
  const generatedAt = new Date().toISOString();
  const body = {
    schema: "railwise.engineering.report.docxExport.v1" as const,
    generatedAt,
    fileName: `${deliverables.baseName}-报告.docx`,
    mimeType: "application/vnd.openxmlformats-officedocument.wordprocessingml.document" as const,
    byteLength: bytes.length,
    sourceReportFingerprint: meta.reportFingerprint,
    base64: bytesToBase64(bytes),
  };
  return {
    ...body,
    exportFingerprint: fnv1a32Fingerprint(JSON.stringify({ ...body, toolTitle: meta.toolTitle })),
  };
}

