export function buildEngineeringResultWorkbookXlsxExport(
  deliverables: EngineeringDeliverables,
): EngineeringResultWorkbookXlsxExport {
  const meta = engineeringDeliverableResultMeta(deliverables);
  const fallbackResult: EngineeringResult = {
    toolId: "distance_azimuth",
    title: meta.toolTitle,
    status: "ok",
    summary: "成果包未包含可解析的计算结果，已导出基础报告追溯信息。",
    metrics: {},
    rows: [],
    method: {
      algorithm: "",
      workflow: [],
      qualityChecks: [],
      dataFormats: [],
      deliverables: [],
      references: [],
    },
    recommendations: [],
  };
  const result = meta.result ?? fallbackResult;
  const workbookFileName = isIndoorAdjustmentToolId(result.toolId)
    ? `${deliverables.baseName}-内业平差成果表.xlsx`
    : `${deliverables.baseName}-成果表.xlsx`;
  const { sheets, rowTypeCounts } = workbookSheetsFromEngineeringResult(result, meta);
  if (result.toolId === "traverse_adjustment" || result.toolId === "level_adjustment") {
    const deliverySignoff = deliverySignoffWorkbookSheetFromDeliverables(deliverables);
    sheets.push(deliverySignoff.sheet);
    rowTypeCounts.engineering_delivery_signoff = deliverySignoff.rowTypeCount;
  }
  const importEvidence = importEvidenceWorkbookSheetsFromDeliverables(deliverables);
  sheets.push(...importEvidence.sheets);
  Object.assign(rowTypeCounts, importEvidence.rowTypeCounts);
  if (
    (result.toolId === "traverse_adjustment" || result.toolId === "level_adjustment") &&
    deliverables.adjustmentExchangeFiles.length > 0
  ) {
    const readbackRowType =
      result.toolId === "traverse_adjustment"
        ? "traverse_adjustment_exchange_readback"
        : "level_adjustment_exchange_readback";
    sheets.push({
      name: "平差交换回读",
      headers: [
        "格式",
        "标题",
        "扩展名",
        "源工具",
        "回读状态",
        "输入格式",
        "回读行数",
        "结果行数",
        "警告数",
        "比对状态",
        "验收结论",
        "最大数值差",
        "差异数",
        "指标",
        "validationFingerprint",
      ],
      rows: deliverables.adjustmentExchangeFiles.map((file) => [
        file.format,
        file.title,
        file.extension,
        file.readbackValidation.sourceToolId,
        file.readbackValidation.status,
        file.readbackValidation.inputFormat,
        file.readbackValidation.importedRowCount,
        file.readbackValidation.resultRowCount,
        file.readbackValidation.warningCount,
        file.readbackValidation.comparison.status,
        file.readbackValidation.comparison.conclusion,
        file.readbackValidation.comparison.maxNumericDelta,
        file.readbackValidation.comparison.mismatchCount,
        JSON.stringify(file.readbackValidation.metrics),
        file.readbackValidation.validationFingerprint,
      ]),
    });
    rowTypeCounts[readbackRowType] = deliverables.adjustmentExchangeFiles.length;
  }
  if (
    (result.toolId === "traverse_adjustment" || result.toolId === "level_adjustment") &&
    deliverables.adjustmentExchangeProtocolChecklistJson
  ) {
    const protocolRowType =
      result.toolId === "traverse_adjustment"
        ? "traverse_adjustment_exchange_protocol"
        : "level_adjustment_exchange_protocol";
    const checklist = JSON.parse(deliverables.adjustmentExchangeProtocolChecklistJson) as EngineeringAdjustmentExchangeProtocolChecklist;
    sheets.push({
      name: "平差交换协议",
      headers: [
        "格式",
        "标题",
        "扩展名",
        "marker",
        "区段",
        "字段组",
        "成果类型统计",
        "回读状态",
        "比对状态",
        "验收结论",
        "比对行数",
        "差异数",
        "缺失数",
        "多余数",
        "最大数值差",
        "最大差值字段",
        "比对容差",
        "比对说明",
        "validationFingerprint",
      ],
      rows: checklist.rows.map((row) => [
        row.format,
        row.title,
        row.extension,
        row.marker,
        row.sections,
        row.fieldGroups,
        row.rowTypeCounts,
        row.readbackStatus,
        row.comparisonStatus,
        row.comparisonConclusion,
        row.comparedRowCount,
        row.mismatchCount,
        row.missingRowCount,
        row.extraRowCount,
        row.maxNumericDelta,
        row.maxNumericDeltaField,
        row.comparisonTolerance,
        row.comparisonSummary,
        row.validationFingerprint,
      ]),
    });
    rowTypeCounts[protocolRowType] = checklist.rows.length;
  }
  const workbook = buildXlsxWorkbookBytes(sheets);
  const generatedAt = new Date().toISOString();
  const workbookFingerprint = fnv1a32Fingerprint(
    JSON.stringify({
      generatedAt,
      sourceResultFingerprint: meta.resultFingerprint,
      sheets: workbook.sheets.map((sheet) => ({
        name: sheet.name,
        headers: sheet.headers,
        rowCount: sheet.rows.length,
      })),
      rowTypeCounts,
    }),
  );
  const body = {
    schema: "railwise.engineering.resultWorkbook.xlsxExport.v1" as const,
    generatedAt,
    fileName: workbookFileName,
    mimeType: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" as const,
    byteLength: workbook.bytes.length,
    sheetCount: workbook.sheets.length,
    totalRows: workbook.sheets.reduce((sum, sheet) => sum + sheet.rows.length, 0),
    rowTypeCounts,
    sourceResultFingerprint: meta.resultFingerprint,
    sourceReportFingerprint: meta.reportFingerprint,
    workbookFingerprint,
    base64: bytesToBase64(workbook.bytes),
  };
  return {
    ...body,
    exportFingerprint: fnv1a32Fingerprint(JSON.stringify({ ...body, toolTitle: meta.toolTitle })),
  };
}

