function externalUploadArchiveFieldValue(
  manifest: EngineeringBatchExternalUploadManifest,
  fieldKey: string,
): string {
  const uploadField = manifest.uploadFields.find((field) => field.fieldKey === fieldKey);
  if (uploadField) return uploadField.value;
  if (fieldKey === "archiveFolderName") return manifest.archiveFolderName;
  if (fieldKey === "archivePackageName") return manifest.archivePackageName;
  if (fieldKey === "approvalStatusLabel") return manifest.approvalStatusLabel;
  if (fieldKey === "auditFingerprint") return manifest.auditFingerprint;
  if (fieldKey === "batchFingerprint") return manifest.batchFingerprint;
  return "";
}

function externalUploadFileFieldValue(file: EngineeringBatchExternalUploadFile, fieldKey: string): string {
  const value = (file as unknown as Record<string, string | number | boolean | null | undefined>)[fieldKey];
  if (value === null || value === undefined) return "";
  return String(value);
}

function buildEngineeringBatchExternalSystemUploadAdapters(
  manifest: EngineeringBatchExternalUploadManifest,
  adapterDefinitions: EngineeringBatchExternalSystemUploadAdapterDefinition[] = EXTERNAL_SYSTEM_UPLOAD_ADAPTER_BLUEPRINTS,
): EngineeringBatchExternalSystemUploadAdapters {
  const rows: EngineeringBatchExternalSystemUploadRow[] = [];
  const adapterBlueprints = cleanExternalSystemUploadAdapterDefinitions(adapterDefinitions).adapters;
  const adapters = (adapterBlueprints.length > 0 ? adapterBlueprints : EXTERNAL_SYSTEM_UPLOAD_ADAPTER_BLUEPRINTS).map((adapter) => {
    const adapterRows: EngineeringBatchExternalSystemUploadRow[] = [];
    for (const mapping of adapter.fieldMappings) {
      if (mapping.recordType === "archive") {
        adapterRows.push({
          adapterId: adapter.adapterId,
          targetSystem: adapter.targetSystem,
          recordType: "archive",
          filePath: "",
          externalFieldKey: mapping.externalFieldKey,
          externalFieldLabel: mapping.externalFieldLabel,
          sourceFieldKey: mapping.sourceFieldKey,
          value: externalUploadArchiveFieldValue(manifest, mapping.sourceFieldKey),
          required: mapping.required,
        });
        continue;
      }
      for (const file of manifest.files) {
        adapterRows.push({
          adapterId: adapter.adapterId,
          targetSystem: adapter.targetSystem,
          recordType: "file",
          filePath: file.path,
          externalFieldKey: mapping.externalFieldKey,
          externalFieldLabel: mapping.externalFieldLabel,
          sourceFieldKey: mapping.sourceFieldKey,
          value: externalUploadFileFieldValue(file, mapping.sourceFieldKey),
          required: mapping.required,
        });
      }
    }
    rows.push(...adapterRows);
    return {
      ...adapter,
      uploadRowCount: adapterRows.length,
    };
  });
  const body = {
    schema: "railwise.engineering.batch.externalSystemUploadAdapters.v1" as const,
    generatedAt: manifest.generatedAt,
    batchName: manifest.batchName,
    archiveFolderName: manifest.archiveFolderName,
    archivePackageName: manifest.archivePackageName,
    adapterIds: adapters.map((adapter) => adapter.adapterId),
    adapters,
    rows,
  };
  const adapterFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const finalBody = {
    ...body,
    adapterFingerprint,
  };
  const csv = csvFromRows(
    [
      "adapter_id",
      "target_system",
      "record_type",
      "file_path",
      "external_field_key",
      "external_field_label",
      "source_field_key",
      "value",
      "required",
    ],
    rows.map((row) => ({
      adapter_id: row.adapterId,
      target_system: row.targetSystem,
      record_type: row.recordType,
      file_path: row.filePath,
      external_field_key: row.externalFieldKey,
      external_field_label: row.externalFieldLabel,
      source_field_key: row.sourceFieldKey,
      value: row.value,
      required: row.required,
    })),
  );
  return {
    ...finalBody,
    csv,
    json: JSON.stringify(finalBody, null, 2),
  };
}

