function archiveTransferWorkflowFileMatches(
  receiver: EngineeringBatchArchiveTransferReceiver,
  file: EngineeringBatchExternalUploadFile,
): boolean {
  if (receiver.receiverRole === "owner") {
    return (
      file.required ||
      file.role.startsWith("archive_release") ||
      file.role === "audit_report" ||
      file.role === "archive_inspection_report" ||
      file.role === "archive_inspection_signoff"
    );
  }
  if (receiver.receiverRole === "supervision") {
    return (
      file.path.startsWith("audit/") ||
      file.role.includes("quality") ||
      file.role.includes("approval") ||
      file.role.includes("external") ||
      file.role === "batch_result_table_catalog" ||
      file.role === "archive_release_cross_project_baseline" ||
      file.role === "archive_release_cross_project_auto_review"
    );
  }
  if (receiver.receiverRole === "contractor") {
    return (
      file.path.startsWith("runs/") ||
      file.role === "batch_quality_summary" ||
      file.role === "batch_run_manifest" ||
      file.role === "batch_result_table_catalog" ||
      file.role.includes("rectification")
    );
  }
  return (
    file.path.startsWith("runs/") ||
    file.role === "audit_quality_dashboard" ||
    file.role === "archive_inspection_report" ||
    file.role === "batch_result_table_catalog"
  );
}

function archiveTransferWorkflowAdapterAvailable(
  receiver: EngineeringBatchArchiveTransferReceiver,
  file: EngineeringBatchExternalUploadFile,
  adapters: EngineeringBatchExternalSystemUploadAdapters,
): boolean {
  return adapters.rows.some(
    (row) =>
      row.recordType === "file" &&
      row.filePath === file.path &&
      (row.targetSystem.includes(receiver.targetSystem) ||
        receiver.targetSystem.includes(row.targetSystem) ||
        (receiver.receiverRole === "owner" && row.adapterId.includes("owner")) ||
        (receiver.receiverRole === "supervision" && row.adapterId.includes("supervision"))),
  );
}

function archiveTransferWorkflowAction(row: Omit<EngineeringBatchArchiveTransferWorkflowRow, "action">): string {
  const method = row.handoverMethod === "external_system_adapter" ? "通过外部系统上传行入库" : "随归档包人工签收";
  const required = row.required ? "必交资料" : "辅助资料";
  return `${row.receiverName}在 ${row.dueAt ?? "约定期限"} 前${method}并回填签收状态；${row.documentType}为${required}，需核对文件路径、CRC32/FNV 指纹和外部记录号。`;
}

function archiveTransferWorkflowCsv(rows: EngineeringBatchArchiveTransferWorkflowRow[]): string {
  return csvFromRows(
    [
      "receiver_id",
      "receiver_role",
      "receiver_name",
      "transfer_stage",
      "file_path",
      "document_type",
      "required",
      "signoff_required",
      "due_at",
      "action",
      "target_system",
      "archive_category",
      "handover_method",
      "expected_receipt_fields",
    ],
    rows.map((row) => ({
      receiver_id: row.receiverId,
      receiver_role: row.receiverRole,
      receiver_name: row.receiverName,
      transfer_stage: row.transferStage,
      file_path: row.filePath,
      document_type: row.documentType,
      required: row.required,
      signoff_required: row.signoffRequired,
      due_at: row.dueAt ?? "",
      action: row.action,
      target_system: row.targetSystem,
      archive_category: row.archiveCategory,
      handover_method: row.handoverMethod,
      expected_receipt_fields: row.expectedReceiptFields.join(";"),
    })),
  );
}

function archiveTransferWorkflowSignatureCsv(rows: EngineeringBatchArchiveTransferSignatureTemplateRow[]): string {
  return csvFromRows(
    [
      "receiver_id",
      "receiver_name",
      "file_path",
      "document_type",
      "signer_role",
      "signoff_status",
      "signed_at",
      "external_record_id",
      "receipt_status",
      "remarks",
    ],
    rows.map((row) => ({
      receiver_id: row.receiverId,
      receiver_name: row.receiverName,
      file_path: row.filePath,
      document_type: row.documentType,
      signer_role: row.signerRole,
      signoff_status: row.signoffStatus,
      signed_at: row.signedAt,
      external_record_id: row.externalRecordId,
      receipt_status: row.receiptStatus,
      remarks: row.remarks,
    })),
  );
}

function archiveTransferWorkflowMarkdown(
  template: Omit<EngineeringBatchArchiveTransferWorkflowTemplate, "markdown" | "csv" | "signatureCsv" | "json">,
): string {
  return [
    "# 资料移交流程模板",
    "",
    `- 批次：${template.batchName}`,
    `- 生成时间：${template.generatedAt}`,
    `- 归档目录：${template.archiveFolderName}`,
    `- 接收方：${template.receiverCount}`,
    `- 移交文件：${template.fileCount}`,
    `- 流程行：${template.workflowRowCount}`,
    `- 签收模板行：${template.signatureTemplateRowCount}`,
    "",
    "| 接收方 | 阶段 | 文件 | 类型 | 必交 | 签收 | 处理动作 |",
    "| --- | --- | --- | --- | --- | --- | --- |",
    ...template.rows
      .slice(0, 80)
      .map(
        (row) =>
          `| ${row.receiverName} | ${row.transferStage} | ${row.filePath} | ${row.documentType} | ${
            row.required ? "是" : "否"
          } | ${row.signoffRequired ? "是" : "否"} | ${row.action} |`,
      ),
    template.rows.length > 80 ? `| 其余 ${template.rows.length - 80} 行 | - | - | - | - | - | 详见 CSV |` : "",
    "",
    `templateFingerprint：${template.templateFingerprint}`,
    "",
  ].filter((line) => line !== "").join("\n");
}

function finalizeEngineeringBatchArchiveTransferWorkflowTemplate(
  body: Omit<
    EngineeringBatchArchiveTransferWorkflowTemplate,
    "templateFingerprint" | "markdown" | "csv" | "signatureCsv" | "json"
  >,
): EngineeringBatchArchiveTransferWorkflowTemplate {
  const templateFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withFingerprint = {
    ...body,
    templateFingerprint,
  };
  const csv = archiveTransferWorkflowCsv(body.rows);
  const signatureCsv = archiveTransferWorkflowSignatureCsv(body.signatureRows);
  const markdown = archiveTransferWorkflowMarkdown(withFingerprint);
  return {
    ...withFingerprint,
    markdown,
    csv,
    signatureCsv,
    json: JSON.stringify({ ...withFingerprint, markdown, csv, signatureCsv }, null, 2),
  };
}

export function buildEngineeringBatchArchiveTransferWorkflowTemplate(
  manifest: EngineeringBatchExternalUploadManifest,
  adapters: EngineeringBatchExternalSystemUploadAdapters,
  options: { generatedAt?: string; dueAt?: string | null; receivers?: EngineeringBatchArchiveTransferReceiver[] } = {},
): EngineeringBatchArchiveTransferWorkflowTemplate {
  const generatedAt = options.generatedAt ?? manifest.generatedAt;
  const receivers = options.receivers ?? ARCHIVE_TRANSFER_RECEIVERS;
  const expectedReceiptFields = ["signoff_status", "signed_at", "external_record_id", "receipt_status", "remarks"];
  const rows: EngineeringBatchArchiveTransferWorkflowRow[] = receivers.flatMap((receiver) =>
    manifest.files
      .filter((file) => archiveTransferWorkflowFileMatches(receiver, file))
      .map((file) => {
        const handoverMethod = archiveTransferWorkflowAdapterAvailable(receiver, file, adapters)
          ? "external_system_adapter"
          : receiver.defaultHandoverMethod;
        const rowWithoutAction: Omit<EngineeringBatchArchiveTransferWorkflowRow, "action"> = {
          receiverId: receiver.receiverId,
          receiverRole: receiver.receiverRole,
          receiverName: receiver.receiverName,
          targetSystem: receiver.targetSystem,
          transferStage: receiver.transferStage,
          filePath: file.path,
          documentType: file.documentType,
          archiveCategory: file.archiveCategory,
          required: file.required,
          handoverMethod,
          signoffRequired: file.required || receiver.receiverRole === "owner" || receiver.receiverRole === "supervision",
          expectedReceiptFields,
          dueAt: options.dueAt?.trim() || null,
        };
        return {
          ...rowWithoutAction,
          action: archiveTransferWorkflowAction(rowWithoutAction),
        };
      }),
  );
  const signatureRows = rows
    .filter((row) => row.signoffRequired)
    .map((row): EngineeringBatchArchiveTransferSignatureTemplateRow => {
      const receiver = receivers.find((item) => item.receiverId === row.receiverId);
      return {
        receiverId: row.receiverId,
        receiverName: row.receiverName,
        filePath: row.filePath,
        documentType: row.documentType,
        signerRole: receiver?.signerRole ?? "资料签收人",
        signoffStatus: "pending",
        signedAt: "",
        externalRecordId: "",
        receiptStatus: "",
        remarks: "",
      };
    });
  const body = {
    schema: "railwise.engineering.batch.archiveTransferWorkflowTemplate.v1" as const,
    generatedAt,
    batchName: manifest.batchName,
    archiveFolderName: manifest.archiveFolderName,
    archivePackageName: manifest.archivePackageName,
    sourceExternalUploadManifestFingerprint: manifest.manifestFingerprint,
    sourceExternalSystemAdapterFingerprint: adapters.adapterFingerprint,
    receiverCount: receivers.length,
    fileCount: manifest.files.length,
    requiredFileCount: manifest.files.filter((file) => file.required).length,
    workflowRowCount: rows.length,
    signatureTemplateRowCount: signatureRows.length,
    receivers,
    rows,
    signatureRows,
  };
  return finalizeEngineeringBatchArchiveTransferWorkflowTemplate(body);
}

export function buildEngineeringBatchArchiveTransferWorkflowTemplateExport(
  items: EngineeringBatchPackageItem[],
  context: EngineeringBatchArchiveZipExportContext = {},
  options: { generatedAt?: string; dueAt?: string | null } = {},
): EngineeringBatchArchiveTransferWorkflowTemplate {
  const payload = buildEngineeringBatchArchivePayload(items, context);
  return buildEngineeringBatchArchiveTransferWorkflowTemplate(
    payload.externalUploadManifest,
    payload.externalSystemUploadAdapters,
    {
      generatedAt: options.generatedAt ?? payload.exportedAt,
      dueAt: options.dueAt ?? addDaysIsoDate(payload.exportedAt, 3),
    },
  );
}

function archiveTransferSignatureReceiptFieldTemplateDefaultRow(
  fieldKey: EngineeringBatchArchiveTransferSignatureReceiptField,
): EngineeringBatchArchiveTransferSignatureReceiptFieldTemplateRow {
  return (
    ARCHIVE_TRANSFER_SIGNATURE_RECEIPT_FIELD_TEMPLATE_ROWS.find((row) => row.fieldKey === fieldKey) ??
    ARCHIVE_TRANSFER_SIGNATURE_RECEIPT_FIELD_TEMPLATE_ROWS[0]!
  );
}

function archiveTransferSignatureReceiptFieldKey(
  value: unknown,
): EngineeringBatchArchiveTransferSignatureReceiptField | null {
  const fieldKey = textFrom(value, "") as EngineeringBatchArchiveTransferSignatureReceiptField;
  return ARCHIVE_TRANSFER_SIGNATURE_RECEIPT_FIELD_TEMPLATE_ROWS.some((row) => row.fieldKey === fieldKey)
    ? fieldKey
    : null;
}

function cleanArchiveTransferSignatureReceiptFieldTemplateRows(
  source: unknown,
  fieldAliases: Partial<Record<EngineeringBatchArchiveTransferSignatureReceiptField, string[]>> = {},
): {
  rows: EngineeringBatchArchiveTransferSignatureReceiptFieldTemplateRow[];
  warnings: string[];
} {
  const warnings: string[] = [];
  const rowsByKey = new Map<
    EngineeringBatchArchiveTransferSignatureReceiptField,
    EngineeringBatchArchiveTransferSignatureReceiptFieldTemplateRow
  >();
  for (const rawRow of arrayFrom(source)) {
    const row = objectFrom(rawRow);
    const fieldKey = archiveTransferSignatureReceiptFieldKey(row.fieldKey);
    if (!fieldKey) {
      const rawFieldKey = textFrom(row.fieldKey, "");
      if (rawFieldKey) warnings.push(`忽略未知资料移交签收字段：${rawFieldKey}`);
      continue;
    }
    const defaults = archiveTransferSignatureReceiptFieldTemplateDefaultRow(fieldKey);
    rowsByKey.set(fieldKey, {
      fieldKey,
      fieldLabel: textFrom(row.fieldLabel, defaults.fieldLabel) || defaults.fieldLabel,
      required: typeof row.required === "boolean" ? row.required : defaults.required,
      aliases: uniqueNonEmptyStrings([...defaults.aliases, ...arrayFrom(row.aliases), ...(fieldAliases[fieldKey] ?? [])]),
      description: textFrom(row.description, defaults.description) || defaults.description,
    });
  }
  for (const defaults of ARCHIVE_TRANSFER_SIGNATURE_RECEIPT_FIELD_TEMPLATE_ROWS) {
    const current = rowsByKey.get(defaults.fieldKey);
    rowsByKey.set(defaults.fieldKey, {
      ...defaults,
      ...current,
      aliases: uniqueNonEmptyStrings([
        ...defaults.aliases,
        ...(current?.aliases ?? []),
        ...(fieldAliases[defaults.fieldKey] ?? []),
      ]),
    });
  }
  return {
    rows: ARCHIVE_TRANSFER_SIGNATURE_RECEIPT_FIELD_TEMPLATE_ROWS.map((row) => rowsByKey.get(row.fieldKey)!),
    warnings,
  };
}

type SavedEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate = {
  projectName: string | null;
  templateFingerprint: string;
  rows: EngineeringBatchArchiveTransferSignatureReceiptFieldTemplateRow[];
};

function readSavedEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate():
  | SavedEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate
  | null {
  try {
    const raw = engineeringLocalStorage()?.getItem(ARCHIVE_TRANSFER_SIGNATURE_RECEIPT_FIELD_TEMPLATE_STORAGE_KEY);
    if (!raw) return null;
    const parsed = objectFrom(JSON.parse(raw));
    const { rows } = cleanArchiveTransferSignatureReceiptFieldTemplateRows(parsed.rows);
    return rows.length > 0
      ? {
          projectName: textFrom(parsed.projectName, "") || null,
          templateFingerprint: textFrom(parsed.templateFingerprint, ""),
          rows,
        }
      : null;
  } catch {
    return null;
  }
}

function writeSavedEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate(
  template: Pick<EngineeringBatchArchiveTransferSignatureReceiptFieldTemplate, "projectName" | "templateFingerprint" | "rows">,
): boolean {
  try {
    const { rows } = cleanArchiveTransferSignatureReceiptFieldTemplateRows(template.rows);
    if (rows.length === 0) return false;
    engineeringLocalStorage()?.setItem(
      ARCHIVE_TRANSFER_SIGNATURE_RECEIPT_FIELD_TEMPLATE_STORAGE_KEY,
      JSON.stringify({
        schema: "railwise.engineering.batch.archiveTransferSignatureReceiptFieldTemplate.v1",
        projectName: template.projectName,
        templateFingerprint: template.templateFingerprint,
        rows,
      }),
    );
    return true;
  } catch {
    return false;
  }
}

export function clearSavedEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate(): boolean {
  try {
    engineeringLocalStorage()?.removeItem(ARCHIVE_TRANSFER_SIGNATURE_RECEIPT_FIELD_TEMPLATE_STORAGE_KEY);
    return true;
  } catch {
    return false;
  }
}

export function buildEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate(
  options: EngineeringBatchArchiveTransferSignatureReceiptFieldTemplateOptions = {},
): EngineeringBatchArchiveTransferSignatureReceiptFieldTemplate {
  const exportedAt = options.exportedAt ?? new Date().toISOString();
  const projectName = options.projectName?.trim() || null;
  const { rows } = cleanArchiveTransferSignatureReceiptFieldTemplateRows(
    options.rows ?? ARCHIVE_TRANSFER_SIGNATURE_RECEIPT_FIELD_TEMPLATE_ROWS,
    options.fieldAliases,
  );
  const body = {
    schema: "railwise.engineering.batch.archiveTransferSignatureReceiptFieldTemplate.v1" as const,
    exportedAt,
    projectName,
    templateStorageKey: ARCHIVE_TRANSFER_SIGNATURE_RECEIPT_FIELD_TEMPLATE_STORAGE_KEY,
    fieldKeys: rows.map((row) => row.fieldKey),
    requiredFieldKeys: rows.filter((row) => row.required).map((row) => row.fieldKey),
    rows,
  };
  const templateFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutJson = {
    ...body,
    templateFingerprint,
  };
  return {
    ...withoutJson,
    json: JSON.stringify(withoutJson, null, 2),
  };
}

export function buildSavedEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate(
  options: Omit<EngineeringBatchArchiveTransferSignatureReceiptFieldTemplateOptions, "rows" | "fieldAliases"> = {},
): EngineeringBatchArchiveTransferSignatureReceiptFieldTemplate {
  const saved = readSavedEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate();
  return buildEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate({
    ...options,
    projectName: options.projectName ?? saved?.projectName ?? undefined,
    rows: saved?.rows ?? ARCHIVE_TRANSFER_SIGNATURE_RECEIPT_FIELD_TEMPLATE_ROWS,
  });
}

export function applyEngineeringBatchArchiveTransferSignatureReceiptFieldTemplateJson(
  text: string,
  options: { importedAt?: string } = {},
): EngineeringBatchArchiveTransferSignatureReceiptFieldTemplateImportReport {
  const importedAt = options.importedAt ?? new Date().toISOString();
  const parsed = objectFrom(JSON.parse(text));
  const schema = textFrom(parsed.schema, "");
  if (schema !== "railwise.engineering.batch.archiveTransferSignatureReceiptFieldTemplate.v1") {
    throw new Error("不是 Railwise 资料移交签收回执字段模板文件");
  }
  const { rows, warnings } = cleanArchiveTransferSignatureReceiptFieldTemplateRows(parsed.rows);
  const templateFingerprint = textFrom(parsed.templateFingerprint, "");
  const templateApplied =
    rows.length > 0 &&
    writeSavedEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate({
      projectName: textFrom(parsed.projectName, "") || null,
      templateFingerprint,
      rows,
    });
  if (!templateApplied) warnings.push("资料移交签收回执字段模板为空或保存失败");
  return {
    schema: "railwise.engineering.batch.archiveTransferSignatureReceiptFieldTemplateImport.v1",
    importedAt,
    projectName: textFrom(parsed.projectName, "") || null,
    templateFingerprint,
    templateApplied,
    fieldCount: rows.length,
    fieldKeys: rows.map((row) => row.fieldKey),
    warnings,
  };
}

type ArchiveTransferSignatureReceiptRecord = {
  receiverId: string;
  receiverName: string;
  filePath: string;
  documentType: string;
  signerRole: string;
  signoffStatus: "pending" | "signed" | "rejected";
  signedAt: string;
  externalRecordId: string;
  receiptStatus: EngineeringBatchExternalSystemImportReceiptStatus | null;
  remarks: string;
  sourceRowNumber: number;
};

function archiveTransferReceiptSignoffStatus(
  value: string,
  receiptStatus: EngineeringBatchExternalSystemImportReceiptStatus | null,
): "pending" | "signed" | "rejected" {
  const normalized = value.trim().toLowerCase();
  if (["signed", "approved", "accepted", "success", "succeeded", "ok", "已签收", "签收", "通过", "已入库", "成功"].includes(normalized)) {
    return "signed";
  }
  if (["rejected", "reject", "failed", "error", "退回", "拒绝", "失败", "不通过"].includes(normalized)) {
    return "rejected";
  }
  if (["pending", "processing", "wait", "待签收", "待签", "待处理", "处理中"].includes(normalized)) {
    return "pending";
  }
  if (receiptStatus === "accepted") return "signed";
  if (receiptStatus === "rejected") return "rejected";
  return "pending";
}

function archiveTransferReceiptKey(receiverId: string, filePath: string): string {
  return `${receiverId.trim().toLowerCase()}::${filePath.trim().toLowerCase()}`;
}

function archiveTransferSignatureReceiptFieldTemplateForInput(
  input: EngineeringBatchArchiveTransferSignatureReceiptInput,
): {
  rows: EngineeringBatchArchiveTransferSignatureReceiptFieldTemplateRow[];
  templateFingerprint: string | null;
} {
  if (input.fieldTemplate) {
    return {
      rows: input.fieldTemplate.rows,
      templateFingerprint: input.fieldTemplate.templateFingerprint,
    };
  }
  const saved = readSavedEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate();
  if (saved) {
    return {
      rows: saved.rows,
      templateFingerprint: saved.templateFingerprint || null,
    };
  }
  const defaults = buildEngineeringBatchArchiveTransferSignatureReceiptFieldTemplate({
    exportedAt: "railwise-system-default",
  });
  return {
    rows: defaults.rows,
    templateFingerprint: defaults.templateFingerprint,
  };
}

function archiveTransferSignatureReceiptAliases(
  rows: EngineeringBatchArchiveTransferSignatureReceiptFieldTemplateRow[],
  fieldKey: EngineeringBatchArchiveTransferSignatureReceiptField,
): string[] {
  return (
    rows.find((row) => row.fieldKey === fieldKey)?.aliases ??
    archiveTransferSignatureReceiptFieldTemplateDefaultRow(fieldKey).aliases
  );
}

function archiveTransferSignatureReceiptInput(input: EngineeringBatchArchiveTransferSignatureReceiptInput): {
  source: EngineeringBatchArchiveTransferSignatureReceiptSource;
  records: ArchiveTransferSignatureReceiptRecord[];
} {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const format = input.format ?? "csv";
  const rows = externalSystemReceiptRowsFromText(input.text, format);
  const columnNames =
    format === "json"
      ? uniqueNonEmptyStrings(rows.flatMap((row) => Object.keys(row)))
      : (parseDelimitedRows(input.text, format === "tsv" ? "\t" : ",")[0] ?? []);
  const fieldTemplate = archiveTransferSignatureReceiptFieldTemplateForInput(input);
  const records = rows
    .map((row, index): ArchiveTransferSignatureReceiptRecord => {
      const receiptStatus = externalSystemReceiptStatus(
        finalReceiptValue(row, archiveTransferSignatureReceiptAliases(fieldTemplate.rows, "receiptStatus")),
      );
      const signoffStatus = archiveTransferReceiptSignoffStatus(
        finalReceiptValue(row, archiveTransferSignatureReceiptAliases(fieldTemplate.rows, "signoffStatus")),
        receiptStatus,
      );
      return {
        receiverId: finalReceiptValue(row, archiveTransferSignatureReceiptAliases(fieldTemplate.rows, "receiverId")),
        receiverName: finalReceiptValue(row, archiveTransferSignatureReceiptAliases(fieldTemplate.rows, "receiverName")),
        filePath: finalReceiptValue(row, archiveTransferSignatureReceiptAliases(fieldTemplate.rows, "filePath")),
        documentType: finalReceiptValue(row, archiveTransferSignatureReceiptAliases(fieldTemplate.rows, "documentType")),
        signerRole: finalReceiptValue(row, archiveTransferSignatureReceiptAliases(fieldTemplate.rows, "signerRole")),
        signoffStatus,
        signedAt: finalReceiptValue(row, archiveTransferSignatureReceiptAliases(fieldTemplate.rows, "signedAt")),
        externalRecordId: finalReceiptValue(row, archiveTransferSignatureReceiptAliases(fieldTemplate.rows, "externalRecordId")),
        receiptStatus,
        remarks: finalReceiptValue(row, archiveTransferSignatureReceiptAliases(fieldTemplate.rows, "remarks")),
        sourceRowNumber: index + 2,
      };
    })
    .filter((record) => record.receiverId || record.filePath);
  const sourceBody = {
    schema: "railwise.engineering.archiveTransferSignatureReceiptSource.v1" as const,
    importedAt,
    sourceName: input.sourceName?.trim() || null,
    format,
    rowCount: records.length,
    columnNames,
    fieldTemplateFingerprint: fieldTemplate.templateFingerprint,
  };
  const receiptSourceFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...sourceBody, records }));
  return {
    source: {
      ...sourceBody,
      receiptSourceFingerprint,
    },
    records,
  };
}

function archiveTransferSignatureReceiptAction(row: EngineeringBatchArchiveTransferSignatureReceiptUpdateRow): string {
  if (row.updateStatus === "missing_receipt") {
    return `尚未收到 ${row.receiverName} 对 ${row.filePath} 的资料移交签收回执。`;
  }
  if (row.updateStatus === "unmatched_receipt") {
    return `签收回执未匹配当前移交流程模板，请核对 receiver_id 和 file_path：${row.receiverId || "-"} / ${row.filePath || "-"}.`;
  }
  if (row.signoffStatus === "signed") {
    return `${row.receiverName}已完成 ${row.documentType} 签收，外部记录号 ${row.externalRecordId || "待补"}。`;
  }
  if (row.signoffStatus === "rejected") {
    return `${row.receiverName}退回 ${row.documentType}，需按备注整改后重新移交：${row.remarks || "未提供退回原因"}`;
  }
  return `${row.receiverName}仍在处理 ${row.documentType}，需继续跟踪签收状态。`;
}

function archiveTransferSignatureReceiptUpdateCsv(
  rows: EngineeringBatchArchiveTransferSignatureReceiptUpdateRow[],
): string {
  return csvFromRows(
    [
      "update_status",
      "receiver_id",
      "receiver_role",
      "receiver_name",
      "file_path",
      "document_type",
      "signer_role",
      "signoff_status",
      "signed_at",
      "external_record_id",
      "receipt_status",
      "remarks",
      "source_row_number",
      "action",
    ],
    rows.map((row) => ({
      update_status: row.updateStatus,
      receiver_id: row.receiverId,
      receiver_role: row.receiverRole,
      receiver_name: row.receiverName,
      file_path: row.filePath,
      document_type: row.documentType,
      signer_role: row.signerRole,
      signoff_status: row.signoffStatus,
      signed_at: row.signedAt,
      external_record_id: row.externalRecordId,
      receipt_status: row.receiptStatus ?? "",
      remarks: row.remarks,
      source_row_number: row.sourceRowNumber ?? "",
      action: row.action,
    })),
  );
}

function archiveTransferSignatureReceiptUpdateMarkdown(
  update: Omit<EngineeringBatchArchiveTransferSignatureReceiptUpdate, "markdown" | "csv" | "json">,
): string {
  return [
    "# 资料移交签收回执更新",
    "",
    `- 批次：${update.batchName}`,
    `- 导入时间：${update.importedAt}`,
    `- 回执来源：${update.source.sourceName ?? "未命名签收回执"}`,
    `- 已更新：${update.updatedCount}`,
    `- 已签收：${update.signedCount}`,
    `- 已退回：${update.rejectedCount}`,
    `- 待处理：${update.pendingCount}`,
    `- 缺回执：${update.missingReceiptCount}`,
    `- 未匹配：${update.unmatchedReceiptCount}`,
    `- 来源模板指纹：${update.sourceTemplateFingerprint}`,
    `- 更新后模板指纹：${update.updatedTemplateFingerprint}`,
    "",
    "| 状态 | 接收方 | 文件 | 签收 | 回执 | 外部记录号 | 行号 | 处理要求 |",
    "| --- | --- | --- | --- | --- | --- | --- | --- |",
    ...update.rows
      .slice(0, 120)
      .map(
        (row) =>
          `| ${row.updateStatus} | ${row.receiverName || "-"} | ${row.filePath || "-"} | ${row.signoffStatus} | ${row.receiptStatus ?? "-"} | ${row.externalRecordId || "-"} | ${row.sourceRowNumber ?? "-"} | ${row.action} |`,
      ),
    update.rows.length > 120 ? `| 其余 ${update.rows.length - 120} 行 | - | - | - | - | - | - | 详见 CSV |` : "",
    "",
    `updateFingerprint：${update.updateFingerprint}`,
    "",
  ].filter((line) => line !== "").join("\n");
}

export function buildEngineeringBatchArchiveTransferSignatureReceiptUpdate(
  template: EngineeringBatchArchiveTransferWorkflowTemplate,
  input: EngineeringBatchArchiveTransferSignatureReceiptInput,
): EngineeringBatchArchiveTransferSignatureReceiptUpdate {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const { source, records } = archiveTransferSignatureReceiptInput({ ...input, importedAt });
  const recordsByKey = new Map(records.map((record) => [archiveTransferReceiptKey(record.receiverId, record.filePath), record]));
  const matchedRecords = new Set<ArchiveTransferSignatureReceiptRecord>();
  const workflowByKey = new Map(template.rows.map((row) => [archiveTransferReceiptKey(row.receiverId, row.filePath), row]));
  const updateRows: EngineeringBatchArchiveTransferSignatureReceiptUpdateRow[] = [];
  const updatedSignatureRows = template.signatureRows.map((row) => {
    const workflowRow = workflowByKey.get(archiveTransferReceiptKey(row.receiverId, row.filePath));
    const record = recordsByKey.get(archiveTransferReceiptKey(row.receiverId, row.filePath));
    if (!record) {
      const missingRow: EngineeringBatchArchiveTransferSignatureReceiptUpdateRow = {
        updateStatus: "missing_receipt",
        receiverId: row.receiverId,
        receiverRole: workflowRow?.receiverRole ?? "",
        receiverName: row.receiverName,
        filePath: row.filePath,
        documentType: row.documentType,
        signerRole: row.signerRole,
        signoffStatus: row.signoffStatus,
        signedAt: row.signedAt,
        externalRecordId: row.externalRecordId,
        receiptStatus: row.receiptStatus || null,
        remarks: row.remarks,
        sourceRowNumber: null,
        action: "",
      };
      updateRows.push({
        ...missingRow,
        action: archiveTransferSignatureReceiptAction(missingRow),
      });
      return row;
    }
    matchedRecords.add(record);
    const updatedSignatureRow: EngineeringBatchArchiveTransferSignatureTemplateRow = {
      receiverId: row.receiverId,
      receiverName: record.receiverName || row.receiverName,
      filePath: row.filePath,
      documentType: record.documentType || row.documentType,
      signerRole: record.signerRole || row.signerRole,
      signoffStatus: record.signoffStatus,
      signedAt: record.signedAt,
      externalRecordId: record.externalRecordId,
      receiptStatus: record.receiptStatus ?? "",
      remarks: record.remarks,
    };
    const updateRow: EngineeringBatchArchiveTransferSignatureReceiptUpdateRow = {
      updateStatus: "updated",
      receiverId: row.receiverId,
      receiverRole: workflowRow?.receiverRole ?? "",
      receiverName: updatedSignatureRow.receiverName,
      filePath: row.filePath,
      documentType: updatedSignatureRow.documentType,
      signerRole: updatedSignatureRow.signerRole,
      signoffStatus: updatedSignatureRow.signoffStatus,
      signedAt: updatedSignatureRow.signedAt,
      externalRecordId: updatedSignatureRow.externalRecordId,
      receiptStatus: record.receiptStatus,
      remarks: updatedSignatureRow.remarks,
      sourceRowNumber: record.sourceRowNumber,
      action: "",
    };
    updateRows.push({
      ...updateRow,
      action: archiveTransferSignatureReceiptAction(updateRow),
    });
    return updatedSignatureRow;
  });
  for (const record of records) {
    if (matchedRecords.has(record)) continue;
    const unmatchedRow: EngineeringBatchArchiveTransferSignatureReceiptUpdateRow = {
      updateStatus: "unmatched_receipt",
      receiverId: record.receiverId,
      receiverRole: "",
      receiverName: record.receiverName,
      filePath: record.filePath,
      documentType: record.documentType,
      signerRole: record.signerRole,
      signoffStatus: record.signoffStatus,
      signedAt: record.signedAt,
      externalRecordId: record.externalRecordId,
      receiptStatus: record.receiptStatus,
      remarks: record.remarks,
      sourceRowNumber: record.sourceRowNumber,
      action: "",
    };
    updateRows.push({
      ...unmatchedRow,
      action: archiveTransferSignatureReceiptAction(unmatchedRow),
    });
  }
  const updatedTemplate = finalizeEngineeringBatchArchiveTransferWorkflowTemplate({
    schema: template.schema,
    generatedAt: importedAt,
    batchName: template.batchName,
    archiveFolderName: template.archiveFolderName,
    archivePackageName: template.archivePackageName,
    sourceExternalUploadManifestFingerprint: template.sourceExternalUploadManifestFingerprint,
    sourceExternalSystemAdapterFingerprint: template.sourceExternalSystemAdapterFingerprint,
    receiverCount: template.receiverCount,
    fileCount: template.fileCount,
    requiredFileCount: template.requiredFileCount,
    workflowRowCount: template.workflowRowCount,
    signatureTemplateRowCount: updatedSignatureRows.length,
    receivers: template.receivers,
    rows: template.rows,
    signatureRows: updatedSignatureRows,
  });
  const body = {
    schema: "railwise.engineering.batch.archiveTransferSignatureReceiptUpdate.v1" as const,
    importedAt,
    source,
    batchName: template.batchName,
    sourceTemplateFingerprint: template.templateFingerprint,
    updatedTemplateFingerprint: updatedTemplate.templateFingerprint,
    receiverCount: template.receiverCount,
    signatureTemplateRowCount: template.signatureRows.length,
    updatedCount: updateRows.filter((row) => row.updateStatus === "updated").length,
    signedCount: updateRows.filter((row) => row.updateStatus === "updated" && row.signoffStatus === "signed").length,
    rejectedCount: updateRows.filter((row) => row.updateStatus === "updated" && row.signoffStatus === "rejected").length,
    pendingCount: updateRows.filter((row) => row.updateStatus === "updated" && row.signoffStatus === "pending").length,
    missingReceiptCount: updateRows.filter((row) => row.updateStatus === "missing_receipt").length,
    unmatchedReceiptCount: updateRows.filter((row) => row.updateStatus === "unmatched_receipt").length,
    rows: updateRows,
    updatedTemplate,
  };
  const csv = archiveTransferSignatureReceiptUpdateCsv(updateRows);
  const updateFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...body, csv }));
  const withoutArtifacts = {
    ...body,
    updateFingerprint,
  };
  const markdown = archiveTransferSignatureReceiptUpdateMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveTransferRectificationType(
  row: EngineeringBatchArchiveTransferSignatureReceiptUpdateRow,
): EngineeringBatchArchiveTransferRectificationType | null {
  if (row.updateStatus === "missing_receipt") return "missing_receipt";
  if (row.updateStatus === "unmatched_receipt") return "unmatched_receipt";
  if (row.updateStatus === "updated" && row.signoffStatus === "rejected") return "rejected_signature";
  if (row.updateStatus === "updated" && row.signoffStatus === "pending") return "pending_signature";
  return null;
}

function archiveTransferRectificationPriority(
  type: EngineeringBatchArchiveTransferRectificationType,
): EngineeringProjectArchiveRectificationPriority {
  if (type === "rejected_signature" || type === "unmatched_receipt") return "high";
  return "normal";
}

function archiveTransferRectificationAction(
  row: Pick<
    EngineeringBatchArchiveTransferRectificationRow,
    "rectificationType" | "receiverName" | "filePath" | "remarks" | "externalRecordId"
  >,
): string {
  if (row.rectificationType === "rejected_signature") {
    return `${row.receiverName || "接收方"}退回 ${row.filePath || "资料"}，请按退回意见整改后重新移交并回填销项回执：${row.remarks || "未提供退回意见"}`;
  }
  if (row.rectificationType === "pending_signature") {
    return `${row.receiverName || "接收方"}仍在处理 ${row.filePath || "资料"}，请跟踪最终签收状态并补交最终回执。`;
  }
  if (row.rectificationType === "missing_receipt") {
    return `尚未收到 ${row.receiverName || "接收方"} 对 ${row.filePath || "资料"} 的签收回执，请按接收方派单催办。`;
  }
  return `回执 ${row.externalRecordId || "未提供外部记录号"} 未匹配当前移交流程，请核对接收方和资料路径后归并或重开派单。`;
}

function archiveTransferRectificationCsv(rows: EngineeringBatchArchiveTransferRectificationRow[]): string {
  return csvFromRows(
    [
      "issue_id",
      "receiver_id",
      "receiver_role",
      "receiver_name",
      "file_path",
      "document_type",
      "rectification_type",
      "priority",
      "status",
      "due_at",
      "source_update_status",
      "signoff_status",
      "receipt_status",
      "external_record_id",
      "remarks",
      "closed_at",
      "closed_by",
      "closure_note",
      "closure_external_record_id",
      "action",
    ],
    rows.map((row) => ({
      issue_id: row.issueId,
      receiver_id: row.receiverId,
      receiver_role: row.receiverRole,
      receiver_name: row.receiverName,
      file_path: row.filePath,
      document_type: row.documentType,
      rectification_type: row.rectificationType,
      priority: row.priority,
      status: row.status,
      due_at: row.dueAt,
      source_update_status: row.sourceUpdateStatus,
      signoff_status: row.signoffStatus,
      receipt_status: row.receiptStatus ?? "",
      external_record_id: row.externalRecordId,
      remarks: row.remarks,
      closed_at: row.closedAt,
      closed_by: row.closedBy,
      closure_note: row.closureNote,
      closure_external_record_id: row.closureExternalRecordId,
      action: row.action,
    })),
  );
}

function archiveTransferRectificationClosureTemplateCsv(rows: EngineeringBatchArchiveTransferRectificationRow[]): string {
  return csvFromRows(
    ["issue_id", "receiver_id", "receiver_name", "file_path", "closure_status", "closed_at", "closed_by", "closure_note", "external_record_id"],
    rows.map((row) => ({
      issue_id: row.issueId,
      receiver_id: row.receiverId,
      receiver_name: row.receiverName,
      file_path: row.filePath,
      closure_status: row.status === "closed" ? "closed" : "",
      closed_at: row.closedAt,
      closed_by: row.closedBy,
      closure_note: row.closureNote,
      external_record_id: row.closureExternalRecordId || row.externalRecordId,
    })),
  );
}

function archiveTransferRectificationReceiverSummaries(
  rows: EngineeringBatchArchiveTransferRectificationRow[],
): EngineeringBatchArchiveTransferRectificationReceiverSummary[] {
  const byReceiver = new Map<string, EngineeringBatchArchiveTransferRectificationRow[]>();
  for (const row of rows) {
    const key = row.receiverId || `${row.receiverName}:${row.receiverRole}`;
    byReceiver.set(key, [...(byReceiver.get(key) ?? []), row]);
  }
  return [...byReceiver.values()]
    .map((receiverRows) => {
      const first = receiverRows[0]!;
      const openRows = receiverRows.filter((row) => row.status === "open");
      return {
        receiverId: first.receiverId,
        receiverRole: first.receiverRole,
        receiverName: first.receiverName,
        issueCount: receiverRows.length,
        openCount: openRows.length,
        closedCount: receiverRows.filter((row) => row.status === "closed").length,
        blockingCount: openRows.filter((row) => row.priority === "high").length,
        followUpCount: openRows.filter((row) => row.priority !== "high").length,
      };
    })
    .sort((left, right) => right.openCount - left.openCount || left.receiverName.localeCompare(right.receiverName));
}

function archiveTransferRectificationMarkdown(
  ledger: Omit<EngineeringBatchArchiveTransferRectificationLedger, "markdown" | "csv" | "closureTemplateCsv" | "json">,
): string {
  return [
    "# 资料移交签收整改派单",
    "",
    `- 批次：${ledger.batchName}`,
    `- 生成时间：${ledger.generatedAt}`,
    `- 问题数：${ledger.issueCount}`,
    `- 未闭环：${ledger.openCount}`,
    `- 已闭环：${ledger.closedCount}`,
    `- 阻断派单：${ledger.blockingCount}`,
    `- 跟踪派单：${ledger.followUpCount}`,
    `- 来源签收回执指纹：${ledger.sourceReceiptUpdateFingerprint}`,
    "",
    "## 接收方汇总",
    "",
    "| 接收方 | 角色 | 问题 | 未闭环 | 阻断 | 跟踪 |",
    "| --- | --- | --- | --- | --- | --- |",
    ...ledger.receiverSummaries.map(
      (row) =>
        `| ${row.receiverName || "-"} | ${row.receiverRole || "-"} | ${row.issueCount} | ${row.openCount} | ${row.blockingCount} | ${row.followUpCount} |`,
    ),
    "",
    "## 派单明细",
    "",
    "| 问题编号 | 接收方 | 资料 | 类型 | 优先级 | 状态 | 截止 | 处理要求 |",
    "| --- | --- | --- | --- | --- | --- | --- | --- |",
    ...ledger.rows
      .slice(0, 120)
      .map(
        (row) =>
          `| ${row.issueId} | ${row.receiverName || "-"} | ${row.filePath || "-"} | ${row.rectificationType} | ${row.priority} | ${row.status} | ${row.dueAt} | ${row.action} |`,
      ),
    ledger.rows.length > 120 ? `| 其余 ${ledger.rows.length - 120} 项 | - | - | - | - | - | - | 详见 CSV |` : "",
    "",
    `ledgerFingerprint：${ledger.ledgerFingerprint}`,
    "",
  ].filter((line) => line !== "").join("\n");
}

function buildArchiveTransferRectificationLedgerArtifact(input: {
  generatedAt: string;
  batchName: string;
  sourceReceiptUpdateFingerprint: string;
  sourceTemplateFingerprint: string;
  updatedTemplateFingerprint: string;
  rows: EngineeringBatchArchiveTransferRectificationRow[];
}): EngineeringBatchArchiveTransferRectificationLedger {
  const openRows = input.rows.filter((row) => row.status === "open");
  const body = {
    schema: "railwise.engineering.batch.archiveTransferRectificationLedger.v1" as const,
    generatedAt: input.generatedAt,
    batchName: input.batchName,
    sourceReceiptUpdateFingerprint: input.sourceReceiptUpdateFingerprint,
    sourceTemplateFingerprint: input.sourceTemplateFingerprint,
    updatedTemplateFingerprint: input.updatedTemplateFingerprint,
    issueCount: input.rows.length,
    openCount: openRows.length,
    closedCount: input.rows.filter((row) => row.status === "closed").length,
    blockingCount: openRows.filter((row) => row.priority === "high").length,
    followUpCount: openRows.filter((row) => row.priority !== "high").length,
    rejectedCount: input.rows.filter((row) => row.rectificationType === "rejected_signature").length,
    pendingCount: input.rows.filter((row) => row.rectificationType === "pending_signature").length,
    missingReceiptCount: input.rows.filter((row) => row.rectificationType === "missing_receipt").length,
    unmatchedReceiptCount: input.rows.filter((row) => row.rectificationType === "unmatched_receipt").length,
    receiverSummaries: archiveTransferRectificationReceiverSummaries(input.rows),
    rows: input.rows,
  };
  const ledgerFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    ledgerFingerprint,
  };
  const csv = archiveTransferRectificationCsv(input.rows);
  const closureTemplateCsv = archiveTransferRectificationClosureTemplateCsv(input.rows);
  const markdown = archiveTransferRectificationMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    closureTemplateCsv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv, closureTemplateCsv }, null, 2),
  };
}

export function buildEngineeringBatchArchiveTransferRectificationLedger(
  receiptUpdate: EngineeringBatchArchiveTransferSignatureReceiptUpdate,
  options: { generatedAt?: string; defaultDueDays?: number } = {},
): EngineeringBatchArchiveTransferRectificationLedger {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const dueAt = addDaysIsoDate(generatedAt, options.defaultDueDays ?? 3);
  const rows: EngineeringBatchArchiveTransferRectificationRow[] = receiptUpdate.rows.flatMap((row, index) => {
    const rectificationType = archiveTransferRectificationType(row);
    if (!rectificationType) return [];
    const priority = archiveTransferRectificationPriority(rectificationType);
    const draft: EngineeringBatchArchiveTransferRectificationRow = {
      issueId: `${receiptUpdate.batchName}-TRANSFER-${String(index + 1).padStart(3, "0")}`,
      receiverId: row.receiverId,
      receiverRole: row.receiverRole,
      receiverName: row.receiverName,
      filePath: row.filePath,
      documentType: row.documentType,
      rectificationType,
      priority,
      status: "open",
      dueAt,
      sourceUpdateStatus: row.updateStatus,
      signoffStatus: row.signoffStatus,
      receiptStatus: row.receiptStatus,
      externalRecordId: row.externalRecordId,
      remarks: row.remarks,
      action: "",
      closedAt: null,
      closedBy: null,
      closureNote: "",
      closureExternalRecordId: "",
      closureSourceStatus: "generated_open",
    };
    return [
      {
        ...draft,
        action: archiveTransferRectificationAction(draft),
      },
    ];
  });
  return buildArchiveTransferRectificationLedgerArtifact({
    generatedAt,
    batchName: receiptUpdate.batchName,
    sourceReceiptUpdateFingerprint: receiptUpdate.updateFingerprint,
    sourceTemplateFingerprint: receiptUpdate.sourceTemplateFingerprint,
    updatedTemplateFingerprint: receiptUpdate.updatedTemplateFingerprint,
    rows,
  });
}

type EngineeringBatchArchiveTransferRectificationClosureRecord = {
  rowNumber: number;
  issueId: string;
  receiverId: string;
  filePath: string;
  closureStatus: EngineeringProjectArchiveRectificationClosureStatus;
  closedAt: string | null;
  closedBy: string | null;
  closureNote: string;
  externalRecordId: string;
};

function archiveTransferRectificationClosureTemplateDefaultRow(
  fieldKey: EngineeringBatchArchiveTransferRectificationClosureField,
): EngineeringBatchArchiveTransferRectificationClosureTemplateRow {
  return (
    ARCHIVE_TRANSFER_RECTIFICATION_CLOSURE_TEMPLATE_ROWS.find((row) => row.fieldKey === fieldKey) ??
    ARCHIVE_TRANSFER_RECTIFICATION_CLOSURE_TEMPLATE_ROWS[0]!
  );
}

function archiveTransferRectificationClosureFieldKey(
  value: unknown,
): EngineeringBatchArchiveTransferRectificationClosureField | null {
  const fieldKey = textFrom(value, "") as EngineeringBatchArchiveTransferRectificationClosureField;
  return ARCHIVE_TRANSFER_RECTIFICATION_CLOSURE_TEMPLATE_ROWS.some((row) => row.fieldKey === fieldKey)
    ? fieldKey
    : null;
}

function cleanArchiveTransferRectificationClosureTemplateRows(
  source: unknown,
  fieldAliases: Partial<Record<EngineeringBatchArchiveTransferRectificationClosureField, string[]>> = {},
): {
  rows: EngineeringBatchArchiveTransferRectificationClosureTemplateRow[];
  warnings: string[];
} {
  const warnings: string[] = [];
  const rowsByKey = new Map<
    EngineeringBatchArchiveTransferRectificationClosureField,
    EngineeringBatchArchiveTransferRectificationClosureTemplateRow
  >();
  for (const rawRow of arrayFrom(source)) {
    const row = objectFrom(rawRow);
    const fieldKey = archiveTransferRectificationClosureFieldKey(row.fieldKey);
    if (!fieldKey) {
      const rawFieldKey = textFrom(row.fieldKey, "");
      if (rawFieldKey) warnings.push(`忽略未知资料移交整改销项字段：${rawFieldKey}`);
      continue;
    }
    const defaults = archiveTransferRectificationClosureTemplateDefaultRow(fieldKey);
    rowsByKey.set(fieldKey, {
      fieldKey,
      fieldLabel: textFrom(row.fieldLabel, defaults.fieldLabel) || defaults.fieldLabel,
      required: typeof row.required === "boolean" ? row.required : defaults.required,
      aliases: uniqueNonEmptyStrings([...defaults.aliases, ...arrayFrom(row.aliases), ...(fieldAliases[fieldKey] ?? [])]),
      description: textFrom(row.description, defaults.description) || defaults.description,
    });
  }
  for (const defaults of ARCHIVE_TRANSFER_RECTIFICATION_CLOSURE_TEMPLATE_ROWS) {
    const current = rowsByKey.get(defaults.fieldKey);
    rowsByKey.set(defaults.fieldKey, {
      ...defaults,
      ...current,
      aliases: uniqueNonEmptyStrings([
        ...defaults.aliases,
        ...(current?.aliases ?? []),
        ...(fieldAliases[defaults.fieldKey] ?? []),
      ]),
    });
  }
  return {
    rows: ARCHIVE_TRANSFER_RECTIFICATION_CLOSURE_TEMPLATE_ROWS.map((row) => rowsByKey.get(row.fieldKey)!),
    warnings,
  };
}

type SavedEngineeringBatchArchiveTransferRectificationClosureTemplate = {
  projectName: string | null;
  templateFingerprint: string;
  rows: EngineeringBatchArchiveTransferRectificationClosureTemplateRow[];
};

function readSavedEngineeringBatchArchiveTransferRectificationClosureTemplate():
  | SavedEngineeringBatchArchiveTransferRectificationClosureTemplate
  | null {
  try {
    const raw = engineeringLocalStorage()?.getItem(ARCHIVE_TRANSFER_RECTIFICATION_CLOSURE_TEMPLATE_STORAGE_KEY);
    if (!raw) return null;
    const parsed = objectFrom(JSON.parse(raw));
    const { rows } = cleanArchiveTransferRectificationClosureTemplateRows(parsed.rows);
    return rows.length > 0
      ? {
          projectName: textFrom(parsed.projectName, "") || null,
          templateFingerprint: textFrom(parsed.templateFingerprint, ""),
          rows,
        }
      : null;
  } catch {
    return null;
  }
}

function writeSavedEngineeringBatchArchiveTransferRectificationClosureTemplate(
  template: Pick<
    EngineeringBatchArchiveTransferRectificationClosureTemplate,
    "projectName" | "templateFingerprint" | "rows"
  >,
): boolean {
  try {
    const { rows } = cleanArchiveTransferRectificationClosureTemplateRows(template.rows);
    if (rows.length === 0) return false;
    engineeringLocalStorage()?.setItem(
      ARCHIVE_TRANSFER_RECTIFICATION_CLOSURE_TEMPLATE_STORAGE_KEY,
      JSON.stringify({
        schema: "railwise.engineering.batch.archiveTransferRectificationClosureTemplate.v1",
        projectName: template.projectName,
        templateFingerprint: template.templateFingerprint,
        rows,
      }),
    );
    return true;
  } catch {
    return false;
  }
}

export function clearSavedEngineeringBatchArchiveTransferRectificationClosureTemplate(): boolean {
  try {
    engineeringLocalStorage()?.removeItem(ARCHIVE_TRANSFER_RECTIFICATION_CLOSURE_TEMPLATE_STORAGE_KEY);
    return true;
  } catch {
    return false;
  }
}

export function buildEngineeringBatchArchiveTransferRectificationClosureTemplate(
  options: EngineeringBatchArchiveTransferRectificationClosureTemplateOptions = {},
): EngineeringBatchArchiveTransferRectificationClosureTemplate {
  const exportedAt = options.exportedAt ?? new Date().toISOString();
  const projectName = options.projectName?.trim() || null;
  const { rows } = cleanArchiveTransferRectificationClosureTemplateRows(
    options.rows ?? ARCHIVE_TRANSFER_RECTIFICATION_CLOSURE_TEMPLATE_ROWS,
    options.fieldAliases,
  );
  const body = {
    schema: "railwise.engineering.batch.archiveTransferRectificationClosureTemplate.v1" as const,
    exportedAt,
    projectName,
    templateStorageKey: ARCHIVE_TRANSFER_RECTIFICATION_CLOSURE_TEMPLATE_STORAGE_KEY,
    fieldKeys: rows.map((row) => row.fieldKey),
    requiredFieldKeys: rows.filter((row) => row.required).map((row) => row.fieldKey),
    rows,
  };
  const templateFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutJson = {
    ...body,
    templateFingerprint,
  };
  return {
    ...withoutJson,
    json: JSON.stringify(withoutJson, null, 2),
  };
}

export function buildSavedEngineeringBatchArchiveTransferRectificationClosureTemplate(
  options: Omit<
    EngineeringBatchArchiveTransferRectificationClosureTemplateOptions,
    "rows" | "fieldAliases"
  > = {},
): EngineeringBatchArchiveTransferRectificationClosureTemplate {
  const saved = readSavedEngineeringBatchArchiveTransferRectificationClosureTemplate();
  return buildEngineeringBatchArchiveTransferRectificationClosureTemplate({
    ...options,
    projectName: options.projectName ?? saved?.projectName ?? undefined,
    rows: saved?.rows ?? ARCHIVE_TRANSFER_RECTIFICATION_CLOSURE_TEMPLATE_ROWS,
  });
}

export function applyEngineeringBatchArchiveTransferRectificationClosureTemplateJson(
  text: string,
  options: { importedAt?: string } = {},
): EngineeringBatchArchiveTransferRectificationClosureTemplateImportReport {
  const importedAt = options.importedAt ?? new Date().toISOString();
  const parsed = objectFrom(JSON.parse(text));
  const schema = textFrom(parsed.schema, "");
  if (schema !== "railwise.engineering.batch.archiveTransferRectificationClosureTemplate.v1") {
    throw new Error("不是 Railwise 资料移交整改销项字段模板文件");
  }
  const { rows, warnings } = cleanArchiveTransferRectificationClosureTemplateRows(parsed.rows);
  const templateFingerprint = textFrom(parsed.templateFingerprint, "");
  const templateApplied =
    rows.length > 0 &&
    writeSavedEngineeringBatchArchiveTransferRectificationClosureTemplate({
      projectName: textFrom(parsed.projectName, "") || null,
      templateFingerprint,
      rows,
    });
  if (!templateApplied) warnings.push("资料移交整改销项字段模板为空或保存失败");
  return {
    schema: "railwise.engineering.batch.archiveTransferRectificationClosureTemplateImport.v1",
    importedAt,
    projectName: textFrom(parsed.projectName, "") || null,
    templateFingerprint,
    templateApplied,
    fieldCount: rows.length,
    fieldKeys: rows.map((row) => row.fieldKey),
    warnings,
  };
}

function archiveTransferRectificationClosureTemplateForInput(
  input: EngineeringBatchArchiveTransferRectificationClosureInput,
): {
  rows: EngineeringBatchArchiveTransferRectificationClosureTemplateRow[];
  templateFingerprint: string | null;
} {
  if (input.fieldTemplate) {
    return {
      rows: input.fieldTemplate.rows,
      templateFingerprint: input.fieldTemplate.templateFingerprint,
    };
  }
  const saved = readSavedEngineeringBatchArchiveTransferRectificationClosureTemplate();
  if (saved) {
    return {
      rows: saved.rows,
      templateFingerprint: saved.templateFingerprint || null,
    };
  }
  const defaults = buildEngineeringBatchArchiveTransferRectificationClosureTemplate({
    exportedAt: "railwise-system-default",
  });
  return {
    rows: defaults.rows,
    templateFingerprint: defaults.templateFingerprint,
  };
}

function archiveTransferRectificationClosureAliases(
  rows: EngineeringBatchArchiveTransferRectificationClosureTemplateRow[],
  fieldKey: EngineeringBatchArchiveTransferRectificationClosureField,
): string[] {
  return (
    rows.find((row) => row.fieldKey === fieldKey)?.aliases ??
    archiveTransferRectificationClosureTemplateDefaultRow(fieldKey).aliases
  );
}

function archiveTransferRectificationClosureFormat(
  input: EngineeringBatchArchiveTransferRectificationClosureInput,
): EngineeringBatchArchiveTransferRectificationClosureFormat {
  if (input.format === "json" || input.format === "tsv") return input.format;
  return "csv";
}

function normalizeArchiveTransferRectificationClosureStatus(
  value: string,
): EngineeringProjectArchiveRectificationClosureStatus {
  const normalized = normalizeLedgerStatus(value);
  return normalized === "closed" || normalized === "ok" ? "closed" : "open";
}

function parseArchiveTransferRectificationClosureInput(
  input: EngineeringBatchArchiveTransferRectificationClosureInput,
): {
  source: EngineeringBatchArchiveTransferRectificationClosureSource;
  records: EngineeringBatchArchiveTransferRectificationClosureRecord[];
} {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const format = archiveTransferRectificationClosureFormat(input);
  const rows = externalSystemReceiptRowsFromText(input.text, format);
  const columnNames =
    format === "json"
      ? uniqueNonEmptyStrings(rows.flatMap((row) => Object.keys(row)))
      : (parseDelimitedRows(input.text, format === "tsv" ? "\t" : ",")[0] ?? []);
  const fieldTemplate = archiveTransferRectificationClosureTemplateForInput(input);
  const records = rows
    .map((row, index): EngineeringBatchArchiveTransferRectificationClosureRecord => {
      const closureStatusText = finalReceiptValue(
        row,
        archiveTransferRectificationClosureAliases(fieldTemplate.rows, "closureStatus"),
      );
      return {
        rowNumber: index + 2,
        issueId: finalReceiptValue(row, archiveTransferRectificationClosureAliases(fieldTemplate.rows, "issueId")),
        receiverId: finalReceiptValue(row, archiveTransferRectificationClosureAliases(fieldTemplate.rows, "receiverId")),
        filePath: finalReceiptValue(row, archiveTransferRectificationClosureAliases(fieldTemplate.rows, "filePath")),
        closureStatus: normalizeArchiveTransferRectificationClosureStatus(closureStatusText),
        closedAt: finalReceiptValue(row, archiveTransferRectificationClosureAliases(fieldTemplate.rows, "closedAt")) || null,
        closedBy: finalReceiptValue(row, archiveTransferRectificationClosureAliases(fieldTemplate.rows, "closedBy")) || null,
        closureNote: finalReceiptValue(row, archiveTransferRectificationClosureAliases(fieldTemplate.rows, "closureNote")),
        externalRecordId: finalReceiptValue(
          row,
          archiveTransferRectificationClosureAliases(fieldTemplate.rows, "externalRecordId"),
        ),
      };
    })
    .filter(
      (record) =>
        record.issueId ||
        record.receiverId ||
        record.filePath ||
        record.closedAt ||
        record.closedBy ||
        record.closureNote ||
        record.externalRecordId,
    );
  const sourceBody = {
    schema: "railwise.engineering.archiveTransferRectificationClosureSource.v1" as const,
    sourceName: input.sourceName ?? null,
    importedAt,
    format,
    rowCount: records.length,
    columnNames,
    fieldTemplateFingerprint: fieldTemplate.templateFingerprint,
  };
  return {
    source: {
      ...sourceBody,
      closureSourceFingerprint: fnv1a32Fingerprint(JSON.stringify({ ...sourceBody, records })),
    },
    records,
  };
}

function archiveTransferRectificationClosureKey(receiverId: string, filePath: string): string {
  return `${rectificationIssueKey(receiverId)}::${rectificationIssueKey(filePath)}`;
}

function archiveTransferRectificationClosureCsv(
  rows: EngineeringBatchArchiveTransferRectificationClosureUpdateRow[],
): string {
  return csvFromRows(
    [
      "update_status",
      "issue_id",
      "receiver_id",
      "receiver_name",
      "file_path",
      "closure_status",
      "closed_at",
      "closed_by",
      "closure_note",
      "external_record_id",
      "source_row_number",
      "action",
    ],
    rows.map((row) => ({
      update_status: row.updateStatus,
      issue_id: row.issueId,
      receiver_id: row.receiverId,
      receiver_name: row.receiverName,
      file_path: row.filePath,
      closure_status: row.closureStatus,
      closed_at: row.closedAt,
      closed_by: row.closedBy,
      closure_note: row.closureNote,
      external_record_id: row.externalRecordId,
      source_row_number: row.sourceRowNumber,
      action: row.action,
    })),
  );
}

function archiveTransferRectificationClosureMarkdown(
  update: Omit<EngineeringBatchArchiveTransferRectificationClosureUpdate, "markdown" | "csv" | "json">,
): string {
  return [
    "# 资料移交整改销项回执",
    "",
    `- 批次：${update.batchName}`,
    `- 回执：${update.source.sourceName ?? "未命名销项回执"}`,
    `- 导入时间：${update.importedAt}`,
    `- 已闭环：${update.closedCount}`,
    `- 待闭环：${update.stillOpenCount}`,
    `- 未回执：${update.missingUpdateCount}`,
    `- 未匹配回执：${update.unmatchedUpdateCount}`,
    `- 来源台账指纹：${update.sourceLedgerFingerprint}`,
    `- 更新后台账指纹：${update.updatedLedgerFingerprint}`,
    "",
    "| 回写状态 | 问题编号 | 接收方 | 资料 | 闭环状态 | 完成时间 | 完成人 | 外部记录 | 说明 |",
    "| --- | --- | --- | --- | --- | --- | --- | --- | --- |",
    ...update.rows.map(
      (row) =>
        `| ${row.updateStatus} | ${row.issueId || "-"} | ${row.receiverName || "-"} | ${row.filePath || "-"} | ${row.closureStatus} | ${row.closedAt ?? "-"} | ${row.closedBy ?? "-"} | ${row.externalRecordId || "-"} | ${row.closureNote || "-"} |`,
    ),
    "",
    `updateFingerprint：${update.updateFingerprint}`,
    "",
  ].join("\n");
}

export function buildEngineeringBatchArchiveTransferRectificationClosureUpdate(
  ledger: EngineeringBatchArchiveTransferRectificationLedger,
  input: EngineeringBatchArchiveTransferRectificationClosureInput,
): EngineeringBatchArchiveTransferRectificationClosureUpdate {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const { source, records } = parseArchiveTransferRectificationClosureInput({ ...input, importedAt });
  const recordsByIssueId = new Map<string, EngineeringBatchArchiveTransferRectificationClosureRecord>();
  const recordsByReceiverFile = new Map<string, EngineeringBatchArchiveTransferRectificationClosureRecord>();
  for (const record of records) {
    if (record.issueId) recordsByIssueId.set(rectificationIssueKey(record.issueId), record);
    if (record.receiverId && record.filePath) {
      recordsByReceiverFile.set(archiveTransferRectificationClosureKey(record.receiverId, record.filePath), record);
    }
  }
  const matchedRecords = new Set<EngineeringBatchArchiveTransferRectificationClosureRecord>();
  const updateRows: EngineeringBatchArchiveTransferRectificationClosureUpdateRow[] = [];
  const updatedRows = ledger.rows.map((row): EngineeringBatchArchiveTransferRectificationRow => {
    const record =
      recordsByIssueId.get(rectificationIssueKey(row.issueId)) ??
      recordsByReceiverFile.get(archiveTransferRectificationClosureKey(row.receiverId, row.filePath)) ??
      null;
    if (!record) {
      updateRows.push({
        updateStatus: "missing_update",
        issueId: row.issueId,
        receiverId: row.receiverId,
        receiverName: row.receiverName,
        filePath: row.filePath,
        closureStatus: row.status,
        closedAt: row.closedAt,
        closedBy: row.closedBy,
        closureNote: row.closureNote,
        externalRecordId: row.closureExternalRecordId || row.externalRecordId,
        sourceRowNumber: null,
        action: "尚未收到该资料移交整改派单的销项回执。",
      });
      return {
        ...row,
        closureSourceStatus: row.status === "closed" ? row.closureSourceStatus : "missing_rectification_receipt",
      };
    }
    matchedRecords.add(record);
    const closedAt = record.closureStatus === "closed" ? record.closedAt ?? importedAt.slice(0, 10) : record.closedAt;
    const nextRow: EngineeringBatchArchiveTransferRectificationRow = {
      ...row,
      status: record.closureStatus,
      closedAt,
      closedBy: record.closedBy ?? row.closedBy,
      closureNote: record.closureNote || row.closureNote,
      closureExternalRecordId: record.externalRecordId || row.closureExternalRecordId || row.externalRecordId,
      closureSourceStatus:
        record.closureStatus === "closed"
          ? "closed_by_rectification_receipt"
          : "kept_open_by_rectification_receipt",
    };
    updateRows.push({
      updateStatus: record.closureStatus === "closed" ? "closed" : "kept_open",
      issueId: row.issueId,
      receiverId: row.receiverId,
      receiverName: row.receiverName,
      filePath: row.filePath,
      closureStatus: record.closureStatus,
      closedAt: nextRow.closedAt,
      closedBy: nextRow.closedBy,
      closureNote: nextRow.closureNote,
      externalRecordId: nextRow.closureExternalRecordId,
      sourceRowNumber: record.rowNumber,
      action:
        record.closureStatus === "closed"
          ? "销项回执确认该资料移交整改派单已闭环。"
          : "销项回执仍保持打开，请继续跟踪接收方处理结果。",
    });
    return nextRow;
  });
  for (const record of records) {
    if (matchedRecords.has(record) || (!record.issueId && (!record.receiverId || !record.filePath))) continue;
    updateRows.push({
      updateStatus: "unmatched_update",
      issueId: record.issueId,
      receiverId: record.receiverId,
      receiverName: "",
      filePath: record.filePath,
      closureStatus: record.closureStatus,
      closedAt: record.closedAt,
      closedBy: record.closedBy,
      closureNote: record.closureNote,
      externalRecordId: record.externalRecordId,
      sourceRowNumber: record.rowNumber,
      action: "销项回执未匹配当前资料移交整改台账，请核对 issue_id 或 receiver_id + file_path。",
    });
  }
  const updatedLedger = buildArchiveTransferRectificationLedgerArtifact({
    generatedAt: ledger.generatedAt,
    batchName: ledger.batchName,
    sourceReceiptUpdateFingerprint: ledger.sourceReceiptUpdateFingerprint,
    sourceTemplateFingerprint: ledger.sourceTemplateFingerprint,
    updatedTemplateFingerprint: ledger.updatedTemplateFingerprint,
    rows: updatedRows,
  });
  const csv = archiveTransferRectificationClosureCsv(updateRows);
  const body = {
    schema: "railwise.engineering.batch.archiveTransferRectificationClosureUpdate.v1" as const,
    importedAt,
    batchName: ledger.batchName,
    source,
    sourceLedgerFingerprint: ledger.ledgerFingerprint,
    updatedLedgerFingerprint: updatedLedger.ledgerFingerprint,
    closedCount: updatedLedger.closedCount,
    stillOpenCount: updatedLedger.openCount,
    missingUpdateCount: updateRows.filter((row) => row.updateStatus === "missing_update").length,
    unmatchedUpdateCount: updateRows.filter((row) => row.updateStatus === "unmatched_update").length,
    rows: updateRows,
    updatedLedger,
  };
  const updateFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...body, csv }));
  const withoutArtifacts = {
    ...body,
    updateFingerprint,
  };
  const markdown = archiveTransferRectificationClosureMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

