export function buildEngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationClosureUpdate(
  ledger: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationLedger,
  input: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationClosureInput,
): EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationClosureUpdate {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const { source, records } = parseArchiveTransferFinalSignoffExternalSyncRectificationClosureInput({
    ...input,
    importedAt,
  });
  const recordsByIssueId = new Map<string, EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationClosureRecord>();
  const recordsByFilePath = new Map<string, EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationClosureRecord>();
  for (const record of records) {
    if (record.issueId) recordsByIssueId.set(rectificationIssueKey(record.issueId), record);
    if (record.filePath) recordsByFilePath.set(rectificationIssueKey(record.filePath), record);
  }
  const matchedRecords = new Set<EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationClosureRecord>();
  const updateRows: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationClosureUpdateRow[] = [];
  const updatedRows = ledger.rows.map((row): EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationRow => {
    const record =
      recordsByIssueId.get(rectificationIssueKey(row.issueId)) ??
      recordsByFilePath.get(rectificationIssueKey(row.filePath)) ??
      null;
    if (!record) {
      if (row.closureStatus === "closed") {
        return row;
      }
      updateRows.push({
        issueId: row.issueId,
        filePath: row.filePath,
        updateStatus: "missing_update",
        closureStatus: row.closureStatus,
        closedAt: row.closedAt,
        closedBy: row.closedBy,
        closureNote: row.closureNote,
        externalRecordId: row.closureExternalRecordId || row.externalRecordId,
        sourceRowNumber: null,
      });
      return {
        ...row,
        closureSourceStatus: "missing_rectification_receipt",
      };
    }
    matchedRecords.add(record);
    const closedAt = record.closureStatus === "closed" ? record.closedAt ?? importedAt.slice(0, 10) : record.closedAt;
    const nextRow: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationRow = {
      ...row,
      closureStatus: record.closureStatus,
      closedAt,
      closedBy: record.closedBy ?? row.closedBy,
      closureNote: record.closureNote || row.closureNote,
      closureExternalRecordId: record.externalRecordId || row.closureExternalRecordId || row.externalRecordId,
      closureSourceStatus:
        record.closureStatus === "closed"
          ? "closed_by_rectification_receipt"
          : "kept_open_by_rectification_receipt",
    };
    updateRows.push({
      issueId: row.issueId,
      filePath: row.filePath,
      updateStatus: record.closureStatus === "closed" ? "closed" : "kept_open",
      closureStatus: record.closureStatus,
      closedAt: nextRow.closedAt,
      closedBy: nextRow.closedBy,
      closureNote: nextRow.closureNote,
      externalRecordId: nextRow.closureExternalRecordId,
      sourceRowNumber: record.rowNumber,
    });
    return nextRow;
  });
  for (const record of records) {
    if (matchedRecords.has(record) || (!record.issueId && !record.filePath)) continue;
    updateRows.push({
      issueId: record.issueId,
      filePath: record.filePath,
      updateStatus: "unmatched_update",
      closureStatus: record.closureStatus,
      closedAt: record.closedAt,
      closedBy: record.closedBy,
      closureNote: record.closureNote,
      externalRecordId: record.externalRecordId,
      sourceRowNumber: record.rowNumber,
    });
  }
  const updatedLedger = buildArchiveTransferFinalSignoffExternalSyncRectificationLedgerArtifact({
    generatedAt: ledger.generatedAt,
    batchName: ledger.batchName,
    sourceReceiptFingerprint: ledger.sourceReceiptFingerprint,
    sourceSignoffFingerprint: ledger.sourceSignoffFingerprint,
    sourceLedgerFingerprint: ledger.sourceLedgerFingerprint,
    sourceReissueHistoryFingerprint: ledger.sourceReissueHistoryFingerprint,
    rows: updatedRows,
  });
  const csv = archiveTransferFinalSignoffExternalSyncRectificationClosureCsv(updateRows);
  const body = {
    schema: "railwise.engineering.batch.archiveTransferFinalSignoffExternalSyncRectificationClosureUpdate.v1" as const,
    importedAt,
    batchName: ledger.batchName,
    source,
    sourceLedgerFingerprint: ledger.rectificationFingerprint,
    updatedLedgerFingerprint: updatedLedger.rectificationFingerprint,
    closedCount: updatedLedger.closedCount,
    stillOpenCount: updatedLedger.openCount,
    missingUpdateCount: updateRows.filter((row) => row.updateStatus === "missing_update").length,
    unmatchedUpdateCount: updateRows.filter((row) => row.updateStatus === "unmatched_update").length,
    rows: updateRows,
    updatedLedger,
  };
  const updateFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...body, csv }));
  const withoutArtifacts = {
    ...body,
    updateFingerprint,
  };
  const markdown = archiveTransferFinalSignoffExternalSyncRectificationClosureMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

