function archiveTransferFinalConfirmationBatchSignoffExternalSyncReceiptAction(
  status: EngineeringBatchExternalSystemImportReceiptReconciliationStatus,
  message: string,
): string {
  if (status === "accepted") return "外部系统已确认资料移交最终签发回传完成。";
  if (status === "rejected") return `外部系统拒绝资料移交最终签发回传：${message || "未提供原因"}`;
  if (status === "pending") return "外部系统仍在处理资料移交最终签发回传，请继续追踪。";
  if (status === "skipped") return `外部系统跳过资料移交最终签发回传：${message || "未提供原因"}`;
  if (status === "missing_receipt") return "未收到该资料移交最终签发文件的外部回传回执，请按 file_path 追踪。";
  return "回传回执未匹配当前资料移交最终签发文件，请核对 file_path。";
}

