export function buildEngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncReceipt(
  signoff: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoff,
  options: {
    text: string;
    format?: "csv" | "tsv" | "json";
    sourceName?: string;
    importedAt?: string;
  },
): EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncReceipt {
  const importedAt = options.importedAt ?? new Date().toISOString();
  const receiptRows = externalSystemReceiptRowsFromText(options.text, options.format ?? "csv");
  const receiptsByFilePath = new Map<string, Record<string, string>>();
  for (const row of receiptRows) {
    const filePath = textFrom(row.file_path ?? row.signoff_file_path, "");
    if (filePath) receiptsByFilePath.set(filePath, row);
  }
  const signoffFilePaths = new Set(signoff.rows.map((row) => row.filePath));
  const rows: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncReceiptRow[] =
    signoff.rows.map((signoffRow) => {
      const receipt = receiptsByFilePath.get(signoffRow.filePath);
      const receiptStatus = receipt ? externalSystemReceiptStatus(textFrom(receipt.receipt_status, "")) : null;
      const reconciliationStatus: EngineeringBatchExternalSystemImportReceiptReconciliationStatus =
        receiptStatus ?? "missing_receipt";
      const receiptMessage = receipt ? textFrom(receipt.receipt_message, "") : "";
      return {
        filePath: signoffRow.filePath,
        fileType: signoffRow.fileType,
        signatureStatus: signoffRow.signatureStatus,
        confirmationStatus: signoffRow.confirmationStatus,
        externalRecordId: receipt ? textFrom(receipt.external_record_id, "") : "",
        receiptStatus,
        receiptMessage,
        receivedAt: receipt ? textFrom(receipt.received_at, "") : "",
        syncedReleaseVersion: receipt
          ? textFrom(receipt.synced_release_version ?? receipt.release_version ?? receipt.current_release_version, "")
          : "",
        reconciliationStatus,
        action: archiveTransferFinalConfirmationBatchSignoffExternalSyncReceiptAction(reconciliationStatus, receiptMessage),
      };
    });
  for (const receipt of receiptRows) {
    const filePath = textFrom(receipt.file_path ?? receipt.signoff_file_path, "");
    if (!filePath || signoffFilePaths.has(filePath)) continue;
    const receiptStatus = externalSystemReceiptStatus(textFrom(receipt.receipt_status, ""));
    const receiptMessage = textFrom(receipt.receipt_message, "");
    rows.push({
      filePath,
      fileType: archiveTransferFinalSignoffExternalSyncReceiptFileType(filePath),
      signatureStatus: "pending",
      confirmationStatus: "unmatched_confirmation",
      externalRecordId: textFrom(receipt.external_record_id, ""),
      receiptStatus,
      receiptMessage,
      receivedAt: textFrom(receipt.received_at, ""),
      syncedReleaseVersion: textFrom(receipt.synced_release_version ?? receipt.release_version ?? receipt.current_release_version, ""),
      reconciliationStatus: "unmatched_receipt",
      action: archiveTransferFinalConfirmationBatchSignoffExternalSyncReceiptAction("unmatched_receipt", receiptMessage),
    });
  }
  const acceptedCount = rows.filter((row) => row.reconciliationStatus === "accepted").length;
  const rejectedCount = rows.filter((row) => row.reconciliationStatus === "rejected").length;
  const pendingCount = rows.filter((row) => row.reconciliationStatus === "pending").length;
  const skippedCount = rows.filter((row) => row.reconciliationStatus === "skipped").length;
  const missingReceiptCount = rows.filter((row) => row.reconciliationStatus === "missing_receipt").length;
  const unmatchedReceiptCount = rows.filter((row) => row.reconciliationStatus === "unmatched_receipt").length;
  const body = {
    schema:
      "railwise.engineering.batch.archiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncReceipt.v1" as const,
    importedAt,
    sourceName: options.sourceName?.trim() || null,
    batchName: signoff.batchName,
    sourceSignoffFingerprint: signoff.signoffFingerprint,
    sourceConfirmationFingerprint: signoff.sourceConfirmationFingerprint,
    sourceHistoryFingerprint: signoff.sourceHistoryFingerprint,
    sourceReceiptFingerprint: signoff.sourceReceiptFingerprint,
    finalLedgerFingerprint: signoff.finalLedgerFingerprint,
    fileCount: signoff.fileCount,
    rowCount: rows.length,
    acceptedCount,
    rejectedCount,
    pendingCount,
    skippedCount,
    missingReceiptCount,
    unmatchedReceiptCount,
    followUpCount: rejectedCount + pendingCount + missingReceiptCount + unmatchedReceiptCount,
    rows,
  };
  const receiptFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    receiptFingerprint,
  };
  const csv = archiveTransferFinalConfirmationBatchSignoffExternalSyncReceiptCsv(rows);
  const markdown = archiveTransferFinalConfirmationBatchSignoffExternalSyncReceiptMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationIssueType(
  status: EngineeringBatchExternalSystemImportReceiptReconciliationStatus,
): EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationIssueType | null {
  if (status === "rejected" || status === "pending" || status === "missing_receipt" || status === "unmatched_receipt") {
    return status;
  }
  return null;
}

function archiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationPriority(
  issueType: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationIssueType,
): EngineeringProjectArchiveRectificationPriority {
  return issueType === "pending" ? "normal" : "high";
}

function archiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationAction(
  row: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncReceiptRow,
): string {
  if (row.reconciliationStatus === "rejected") {
    return `按外部系统拒绝原因修正最终签发回传文件、版本号或平台字段后重传：${row.receiptMessage || "未提供原因"}`;
  }
  if (row.reconciliationStatus === "pending") {
    return "外部系统仍在处理最终签发回传，请保留外部记录号、同步版本并在截止日前补齐最终回执。";
  }
  if (row.reconciliationStatus === "missing_receipt") {
    return "未收到该最终签发文件回传回执，请按 file_path 向外部系统补取回执或重新提交最终签发文件。";
  }
  return "外部系统返回的最终签发回传文件不在当前批量签发清单内，请核对 file_path 后拆分处理。";
}

