export function buildEngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationLedger(
  receipt: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncReceipt,
  options: { generatedAt?: string; defaultDueDays?: number } = {},
): EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationLedger {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const dueAt = addDaysIsoDate(generatedAt, options.defaultDueDays ?? 2);
  const rows = receipt.rows.flatMap(
    (
      row,
      index,
    ): EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationRow[] => {
      const issueType = archiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationIssueType(
        row.reconciliationStatus,
      );
      if (!issueType) return [];
      return [
        {
          issueId: `${receipt.batchName}-FINAL-SIGNOFF-SYNC-${String(index + 1).padStart(3, "0")}`,
          filePath: row.filePath,
          fileType: row.fileType,
          signatureStatus: row.signatureStatus,
          confirmationStatus: row.confirmationStatus,
          issueType,
          priority: archiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationPriority(issueType),
          dueAt,
          externalRecordId: row.externalRecordId,
          receiptStatus: row.receiptStatus,
          reconciliationStatus: row.reconciliationStatus,
          receiptMessage: row.receiptMessage,
          receivedAt: row.receivedAt,
          syncedReleaseVersion: row.syncedReleaseVersion,
          closureStatus: "open",
          closedAt: null,
          closedBy: null,
          closureNote: "",
          closureExternalRecordId: "",
          closureSourceStatus: "generated_open",
          action: archiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationAction(row),
        },
      ];
    },
  );
  return buildArchiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationLedgerArtifact({
    generatedAt,
    batchName: receipt.batchName,
    sourceReceiptFingerprint: receipt.receiptFingerprint,
    sourceSignoffFingerprint: receipt.sourceSignoffFingerprint,
    sourceConfirmationFingerprint: receipt.sourceConfirmationFingerprint,
    sourceHistoryFingerprint: receipt.sourceHistoryFingerprint,
    finalLedgerFingerprint: receipt.finalLedgerFingerprint,
    rows,
  });
}

