function archiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationReissueHistoryAction(
  updatedLedger: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationLedger,
): string {
  if (updatedLedger.openCount === 0) {
    return "本轮后资料移交终态签发回传整改最终签发回传整改全部闭环，可进入最终接收登记。";
  }
  return `本轮后仍有 ${updatedLedger.openCount} 项最终签发回传整改未闭环，需要继续重派并跟踪平台销项。`;
}

function archiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationRowsByFile(
  rows: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationRow[],
): Map<
  string,
  EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationRow[]
> {
  const byFile = new Map<
    string,
    EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationRow[]
  >();
  for (const row of rows) {
    const key = rectificationIssueKey(row.filePath || row.issueId);
    byFile.set(key, [...(byFile.get(key) ?? []), row]);
  }
  return byFile;
}

function archiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationReissueFileSummaries(options: {
  initialLedger: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationLedger;
  finalLedger: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationLedger;
  rounds: EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationReissueHistoryRoundInput[];
}): EngineeringBatchArchiveTransferFinalSignoffExternalSyncRectificationFinalConfirmationBatchSignoffExternalSyncRectificationReissueHistoryFileSummary[] {
  const initialByFile = archiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationRowsByFile(
    options.initialLedger.rows,
  );
  const finalByFile = archiveTransferFinalConfirmationBatchSignoffExternalSyncRectificationRowsByFile(
    options.finalLedger.rows,
  );
  const roundNosByFile = new Map<string, Set<number>>();
  const reissuedByFile = new Map<string, number>();
  for (const [index, round] of options.rounds.entries()) {
    const roundNo = round.roundNo ?? index + 1;
    const updatedLedger = round.closureUpdate?.updatedLedger ?? round.updatedLedger ?? round.sourceLedger;
    const relatedRows = [...round.sourceLedger.rows, ...updatedLedger.rows];
    for (const row of relatedRows) {
      const key = rectificationIssueKey(row.filePath || row.issueId);
      const current = roundNosByFile.get(key) ?? new Set<number>();
      current.add(roundNo);
      roundNosByFile.set(key, current);
    }
    for (const row of updatedLedger.rows.filter((ledgerRow) => ledgerRow.closureStatus === "open")) {
      const key = rectificationIssueKey(row.filePath || row.issueId);
      reissuedByFile.set(key, (reissuedByFile.get(key) ?? 0) + 1);
    }
  }
  const keys = new Set<string>([
    ...initialByFile.keys(),
    ...finalByFile.keys(),
    ...roundNosByFile.keys(),
  ]);
  return [...keys]
    .map((key) => {
      const initialRows = initialByFile.get(key) ?? [];
      const finalRows = finalByFile.get(key) ?? [];
      const displayRow = finalRows[0] ?? initialRows[0];
      const roundNos = [...(roundNosByFile.get(key) ?? new Set<number>())].sort((left, right) => left - right);
      const finalOpenRows = finalRows.filter((row) => row.closureStatus === "open");
      const finalOpenCount = finalOpenRows.length;
      return {
        filePath: displayRow?.filePath ?? "",
        fileType: displayRow?.fileType ?? "other",
        issueType: displayRow?.issueType ?? "",
        roundCount: roundNos.length,
        firstRoundNo: roundNos[0] ?? null,
        lastRoundNo: roundNos.at(-1) ?? null,
        initialIssueCount: initialRows.length,
        finalOpenCount,
        totalClosedCount: finalRows.filter((row) => row.closureStatus === "closed").length,
        totalReissuedCount: reissuedByFile.get(key) ?? 0,
        highPriorityCount: finalOpenRows.filter((row) => row.priority === "high").length,
        action:
          finalOpenCount === 0
            ? "该最终签发回传整改已闭环，可进入最终接收登记。"
            : `该最终签发文件仍有 ${finalOpenCount} 项回传整改未闭环，需要继续重派并核对平台销项。`,
      };
    })
    .sort(
      (left, right) =>
        right.finalOpenCount - left.finalOpenCount ||
        right.highPriorityCount - left.highPriorityCount ||
        left.filePath.localeCompare(right.filePath),
    );
}

