function archiveTransferFinalAcceptanceReceiptReviewDashboardStage(
  review: EngineeringBatchArchiveTransferFinalAcceptanceRegistrationReceiptReview | null,
): EngineeringBatchArchiveTransferFinalAcceptanceArchiveDashboardStageStatus {
  if (!review) return "missing";
  if (review.rejectedCount > 0 || review.missingReceiptCount > 0) return "blocked";
  if (review.reviewStatus === "accepted" && review.pendingCount === 0) return "ready";
  return "needs_review";
}

function archiveTransferFinalAcceptanceCrossPlatformDashboardStage(
  review: EngineeringBatchArchiveTransferFinalAcceptanceRegistrationCrossPlatformReview | null,
): EngineeringBatchArchiveTransferFinalAcceptanceArchiveDashboardStageStatus {
  if (!review) return "missing";
  if (review.blockingIssueCount > 0) return "blocked";
  if (review.reviewStatus === "passed") return "ready";
  return "needs_review";
}

function archiveTransferFinalAcceptanceDashboardStatus(
  rows: EngineeringBatchArchiveTransferFinalAcceptanceArchiveDashboardRow[],
): EngineeringBatchArchiveTransferFinalAcceptanceArchiveDashboardStatus {
  if (rows.some((row) => row.stageStatus === "blocked" || row.stageStatus === "missing")) return "blocked";
  if (rows.some((row) => row.stageStatus === "needs_review")) return "needs_review";
  return "ready_for_archive";
}

export function buildEngineeringBatchArchiveTransferFinalAcceptanceArchiveDashboard(
  registration: EngineeringBatchArchiveTransferFinalAcceptanceRegistration,
  receiptReview: EngineeringBatchArchiveTransferFinalAcceptanceRegistrationReceiptReview | null = null,
  crossPlatformReview: EngineeringBatchArchiveTransferFinalAcceptanceRegistrationCrossPlatformReview | null = null,
  options: {
    generatedAt?: string;
    batchName?: string;
    fieldTemplateFingerprint?: string | null;
  } = {},
): EngineeringBatchArchiveTransferFinalAcceptanceArchiveDashboard {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const registrationReady =
    registration.registrationStatus === "registered" &&
    registration.finalOpenCount === 0 &&
    registration.signedReceipt.signatureStatus === "signed";
  const receiptStage = archiveTransferFinalAcceptanceReceiptReviewDashboardStage(receiptReview);
  const crossPlatformStage =
    archiveTransferFinalAcceptanceCrossPlatformDashboardStage(crossPlatformReview);
  const fieldTemplateFingerprint =
    options.fieldTemplateFingerprint ?? receiptReview?.source.fieldTemplateFingerprint ?? null;
  const fieldTemplateStage: EngineeringBatchArchiveTransferFinalAcceptanceArchiveDashboardStageStatus =
    fieldTemplateFingerprint ? "ready" : "needs_review";
  const rows: EngineeringBatchArchiveTransferFinalAcceptanceArchiveDashboardRow[] = [
    {
      stageKey: "registration",
      stageName: "最终接收登记",
      stageStatus: registrationReady ? "ready" : "blocked",
      evidenceFingerprint: registration.registrationFingerprint,
      artifactPath:
        "batch/archive-transfer-final-signoff-external-sync-rectification-final-acceptance-registration.json",
      issueCount: registration.finalOpenCount,
      action: registrationReady
        ? "最终接收登记已签收，可进入回执复核和归档入库。"
        : "最终接收登记尚未满足签收和零未闭环要求，需完成登记后再入库。",
    },
    {
      stageKey: "receipt_review",
      stageName: "接收登记回执复核",
      stageStatus: receiptStage,
      evidenceFingerprint: receiptReview?.reviewFingerprint ?? "",
      artifactPath:
        "batch/archive-transfer-final-signoff-external-sync-rectification-final-acceptance-registration-receipt-review.json",
      issueCount: receiptReview
        ? receiptReview.rejectedCount + receiptReview.pendingCount + receiptReview.missingReceiptCount
        : 1,
      action:
        receiptStage === "ready"
          ? "最终接收登记回执已 accepted，可作为入库证据。"
          : receiptStage === "missing"
            ? "尚未导入最终接收登记回执，需补取平台回执。"
            : "最终接收登记回执仍存在拒收、待处理或缺回执项，需复核后再入库。",
    },
    {
      stageKey: "cross_platform_review",
      stageName: "跨平台终态一致性",
      stageStatus: crossPlatformStage,
      evidenceFingerprint: crossPlatformReview?.reviewFingerprint ?? "",
      artifactPath:
        "batch/archive-transfer-final-signoff-external-sync-rectification-final-acceptance-registration-cross-platform-review.json",
      issueCount: crossPlatformReview?.issueCount ?? 1,
      action:
        crossPlatformStage === "ready"
          ? "多平台最终接收回执一致，可进入归档看板固化。"
          : crossPlatformStage === "missing"
            ? "尚未生成跨平台差异复核，建议至少比对业主、监理或城建档案平台。"
            : "跨平台最终接收存在差异，需完成问题闭环后再入库。",
    },
    {
      stageKey: "field_template",
      stageName: "回执字段模板",
      stageStatus: fieldTemplateStage,
      evidenceFingerprint: fieldTemplateFingerprint ?? "",
      artifactPath: "localStorage:archiveTransferFinalAcceptanceRegistrationReceiptFieldTemplate",
      issueCount: fieldTemplateFingerprint ? 0 : 1,
      action: fieldTemplateFingerprint
        ? "最终接收回执字段模板已固化到 source 指纹，后续导入可追溯。"
        : "尚未记录最终接收回执字段模板，需导入或导出模板后再固化。",
    },
  ];
  const status = archiveTransferFinalAcceptanceDashboardStatus(rows);
  rows.push({
    stageKey: "archive_readiness",
    stageName: "最终接收归档入库",
    stageStatus:
      status === "ready_for_archive" ? "ready" : status === "blocked" ? "blocked" : "needs_review",
    evidenceFingerprint: "",
    artifactPath: "batch/archive-transfer-final-acceptance-archive-dashboard.json",
    issueCount: rows.reduce((sum, row) => sum + row.issueCount, 0),
    action:
      status === "ready_for_archive"
        ? "最终接收登记、平台回执和跨平台一致性均满足归档入库要求。"
        : status === "blocked"
          ? "存在阻断或缺失证据，暂不建议最终归档入库。"
          : "证据链基本具备，但仍建议补齐跨平台或字段模板复核后入库。",
  });
  const blockingIssueCount = rows.filter((row) => row.stageStatus === "blocked" || row.stageStatus === "missing").length;
  const warningIssueCount = rows.filter((row) => row.stageStatus === "needs_review").length;
  const body = {
    schema: "railwise.engineering.batch.archiveTransferFinalAcceptanceArchiveDashboard.v1" as const,
    generatedAt,
    batchName: options.batchName?.trim() || registration.receiverName,
    registrationId: registration.registrationId,
    dashboardStatus: status,
    registrationFingerprint: registration.registrationFingerprint,
    receiptReviewFingerprint: receiptReview?.reviewFingerprint ?? null,
    crossPlatformReviewFingerprint: crossPlatformReview?.reviewFingerprint ?? null,
    fieldTemplateFingerprint,
    sourceHistoryFingerprint: registration.sourceHistoryFingerprint,
    finalLedgerFingerprint: registration.finalLedgerFingerprint,
    platformCount: crossPlatformReview?.platformCount ?? (receiptReview ? 1 : 0),
    evidenceCount: rows.filter((row) => row.evidenceFingerprint.trim() !== "").length,
    blockingIssueCount,
    warningIssueCount,
    rows,
  };
  const dashboardFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    dashboardFingerprint,
  };
  const csv = archiveTransferFinalAcceptanceArchiveDashboardCsv(rows);
  const markdown = archiveTransferFinalAcceptanceArchiveDashboardMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveTransferFinalAcceptanceCrossProjectBaselineRisk(
  dashboard: EngineeringBatchArchiveTransferFinalAcceptanceArchiveDashboard,
): EngineeringBatchArchiveTransferFinalAcceptanceCrossProjectBaselineRisk {
  if (
    dashboard.dashboardStatus === "blocked" ||
    dashboard.blockingIssueCount > 0 ||
    dashboard.rows.some((row) => row.stageStatus === "blocked" || row.stageStatus === "missing")
  ) {
    return "critical";
  }
  if (
    dashboard.dashboardStatus === "needs_review" ||
    dashboard.warningIssueCount > 0 ||
    dashboard.platformCount < 2 ||
    !dashboard.fieldTemplateFingerprint ||
    dashboard.rows.some((row) => row.stageStatus === "needs_review")
  ) {
    return "warning";
  }
  return "stable";
}

function archiveTransferFinalAcceptanceCrossProjectBaselineRiskScore(
  dashboard: EngineeringBatchArchiveTransferFinalAcceptanceArchiveDashboard,
): number {
  const missingStageCount = dashboard.rows.filter((row) => row.stageStatus === "missing").length;
  const blockedStageCount = dashboard.rows.filter((row) => row.stageStatus === "blocked").length;
  const needsReviewStageCount = dashboard.rows.filter((row) => row.stageStatus === "needs_review").length;
  const statusScore =
    dashboard.dashboardStatus === "blocked" ? 30 : dashboard.dashboardStatus === "needs_review" ? 10 : 0;
  const platformCoverageScore = dashboard.platformCount < 2 ? 5 : 0;
  const fieldTemplateScore = dashboard.fieldTemplateFingerprint ? 0 : 5;
  return (
    statusScore +
    dashboard.blockingIssueCount * 25 +
    missingStageCount * 20 +
    blockedStageCount * 20 +
    dashboard.warningIssueCount * 8 +
    needsReviewStageCount * 6 +
    platformCoverageScore +
    fieldTemplateScore
  );
}

function archiveTransferFinalAcceptanceCrossProjectBaselineAction(
  row: Pick<
    EngineeringBatchArchiveTransferFinalAcceptanceCrossProjectBaselineRow,
    | "projectName"
    | "registrationId"
    | "dashboardStatus"
    | "baselineRisk"
    | "blockingIssueCount"
    | "warningIssueCount"
    | "missingStageCount"
    | "blockedStageCount"
    | "needsReviewStageCount"
    | "platformCount"
  >,
): string {
  if (row.baselineRisk === "critical") {
    const reasons = [
      row.blockingIssueCount > 0 ? `阻断 ${row.blockingIssueCount} 项` : "",
      row.blockedStageCount > 0 ? `阻断阶段 ${row.blockedStageCount} 个` : "",
      row.missingStageCount > 0 ? `缺失阶段 ${row.missingStageCount} 个` : "",
    ].filter(Boolean);
    return `${row.projectName} 最终接收登记 ${row.registrationId || "-"} 存在${reasons.join("、")}，需先完成接收回执、跨平台差异和字段模板整改后再入库。`;
  }
  if (row.baselineRisk === "warning") {
    const reasons = [
      row.warningIssueCount > 0 ? `提示 ${row.warningIssueCount} 项` : "",
      row.needsReviewStageCount > 0 ? `待复核阶段 ${row.needsReviewStageCount} 个` : "",
      row.platformCount < 2 ? "平台覆盖不足 2 个" : "",
    ].filter(Boolean);
    return `${row.projectName} 最终接收登记 ${row.registrationId || "-"} 已形成看板，但仍有${reasons.join("、") || "待确认事项"}，建议补齐后作为跨项目基线。`;
  }
  return `${row.projectName} 最终接收登记 ${row.registrationId || "-"} 已达到跨项目最终接收基线要求，可作为移交验收样板。`;
}

