export function buildEngineeringBatchArchiveTransferFinalAcceptanceTrendReport(
  baselines: EngineeringBatchArchiveTransferFinalAcceptanceCrossProjectBaseline[],
  options: { generatedAt?: string } = {},
): EngineeringBatchArchiveTransferFinalAcceptanceTrendReport {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const sortedBaselines = baselines
    .filter(
      (baseline) =>
        baseline.schema === "railwise.engineering.batch.archiveTransferFinalAcceptanceCrossProjectBaseline.v1",
    )
    .slice()
    .sort((a, b) => a.generatedAt.localeCompare(b.generatedAt));
  const baselineTrendRows: EngineeringBatchArchiveTransferFinalAcceptanceTrendBaselineRow[] = sortedBaselines.map(
    (baseline, index) => {
      const rowWithoutAction: Omit<
        EngineeringBatchArchiveTransferFinalAcceptanceTrendBaselineRow,
        "action"
      > = {
        baselineNo: index + 1,
        generatedAt: baseline.generatedAt,
        baselineFingerprint: baseline.baselineFingerprint,
        projectCount: baseline.projectCount,
        readyProjectCount: baseline.readyProjectCount,
        needsReviewProjectCount: baseline.needsReviewProjectCount,
        blockedProjectCount: baseline.blockedProjectCount,
        criticalProjectCount: baseline.criticalProjectCount,
        warningProjectCount: baseline.warningProjectCount,
        stableProjectCount: baseline.stableProjectCount,
        totalBlockingIssueCount: baseline.totalBlockingIssueCount,
        totalWarningIssueCount: baseline.totalWarningIssueCount,
        totalRiskScore: baseline.rows.reduce((sum, row) => sum + row.riskScore, 0),
      };
      return {
        ...rowWithoutAction,
        action: archiveTransferFinalAcceptanceTrendBaselineAction(rowWithoutAction),
      };
    },
  );
  const firstBaseline = sortedBaselines[0] ?? null;
  const latestBaseline = sortedBaselines.at(-1) ?? null;
  const firstTrend = baselineTrendRows[0] ?? null;
  const latestTrend = baselineTrendRows.at(-1) ?? null;
  const projectNames = uniqueNonEmptyStrings(
    sortedBaselines.flatMap((baseline) => baseline.rows.map((row) => row.projectName)),
  ).sort((a, b) => a.localeCompare(b));
  const latestRowsByProjectName = new Map((latestBaseline?.rows ?? []).map((row) => [row.projectName, row]));
  const firstRowsByProjectName = new Map((firstBaseline?.rows ?? []).map((row) => [row.projectName, row]));
  const allRowsByProjectName = new Map<
    string,
    EngineeringBatchArchiveTransferFinalAcceptanceCrossProjectBaselineRow[]
  >();
  for (const baseline of sortedBaselines) {
    for (const row of baseline.rows) {
      allRowsByProjectName.set(row.projectName, [...(allRowsByProjectName.get(row.projectName) ?? []), row]);
    }
  }
  const projectTrendRows: EngineeringBatchArchiveTransferFinalAcceptanceTrendProjectRow[] = projectNames
    .map((projectName, index) => {
      const firstRow = firstRowsByProjectName.get(projectName) ?? null;
      const latestRow = latestRowsByProjectName.get(projectName) ?? null;
      const rows = allRowsByProjectName.get(projectName) ?? [];
      const firstRisk: EngineeringBatchArchiveTransferFinalAcceptanceTrendProjectRisk =
        firstRow?.baselineRisk ?? "missing";
      const latestRisk: EngineeringBatchArchiveTransferFinalAcceptanceTrendProjectRisk =
        latestRow?.baselineRisk ?? "missing";
      const firstRiskScore = firstRow?.riskScore ?? 0;
      const latestRiskScore = latestRow?.riskScore ?? 0;
      const riskTrend = archiveTransferFinalAcceptanceTrendDirection(
        firstRisk,
        latestRisk,
        firstRiskScore,
        latestRiskScore,
      );
      const rowWithoutAction: Omit<
        EngineeringBatchArchiveTransferFinalAcceptanceTrendProjectRow,
        "action"
      > = {
        projectKey: latestRow?.projectKey ?? firstRow?.projectKey ?? `project-${index + 1}`,
        projectName,
        appearanceCount: rows.length,
        firstBaselineRisk: firstRisk,
        latestBaselineRisk: latestRisk,
        riskTrend,
        firstDashboardStatus: firstRow?.dashboardStatus ?? "missing",
        latestDashboardStatus: latestRow?.dashboardStatus ?? "missing",
        firstRiskScore,
        latestRiskScore,
        riskScoreDelta: latestRiskScore - firstRiskScore,
        latestRegistrationId: latestRow?.registrationId ?? "",
        latestSourceDashboardFingerprint: latestRow?.sourceDashboardFingerprint ?? "",
      };
      return {
        ...rowWithoutAction,
        action: archiveTransferFinalAcceptanceTrendProjectAction(rowWithoutAction),
      };
    })
    .sort((a, b) => {
      if (b.latestRiskScore !== a.latestRiskScore) return b.latestRiskScore - a.latestRiskScore;
      return a.projectName.localeCompare(b.projectName);
    });
  const body = {
    schema: "railwise.engineering.batch.archiveTransferFinalAcceptanceTrendReport.v1" as const,
    generatedAt,
    sourceBaselineFingerprints: sortedBaselines.map((baseline) => baseline.baselineFingerprint),
    baselineCount: sortedBaselines.length,
    firstBaselineAt: firstBaseline?.generatedAt ?? null,
    latestBaselineAt: latestBaseline?.generatedAt ?? null,
    trendStatus: archiveTransferFinalAcceptanceTrendStatus(firstTrend, latestTrend),
    latestProjectCount: latestBaseline?.projectCount ?? 0,
    latestReadyProjectCount: latestBaseline?.readyProjectCount ?? 0,
    latestNeedsReviewProjectCount: latestBaseline?.needsReviewProjectCount ?? 0,
    latestBlockedProjectCount: latestBaseline?.blockedProjectCount ?? 0,
    latestCriticalProjectCount: latestBaseline?.criticalProjectCount ?? 0,
    latestWarningProjectCount: latestBaseline?.warningProjectCount ?? 0,
    latestStableProjectCount: latestBaseline?.stableProjectCount ?? 0,
    criticalProjectDelta:
      (latestBaseline?.criticalProjectCount ?? 0) - (firstBaseline?.criticalProjectCount ?? 0),
    blockedProjectDelta:
      (latestBaseline?.blockedProjectCount ?? 0) - (firstBaseline?.blockedProjectCount ?? 0),
    totalRiskScoreDelta: (latestTrend?.totalRiskScore ?? 0) - (firstTrend?.totalRiskScore ?? 0),
    totalBlockingIssueDelta:
      (latestBaseline?.totalBlockingIssueCount ?? 0) - (firstBaseline?.totalBlockingIssueCount ?? 0),
    totalWarningIssueDelta:
      (latestBaseline?.totalWarningIssueCount ?? 0) - (firstBaseline?.totalWarningIssueCount ?? 0),
    baselineTrendRows,
    projectTrendRows,
  };
  const trendFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    trendFingerprint,
  };
  const baselineTrendCsv = archiveTransferFinalAcceptanceBaselineTrendCsv(baselineTrendRows);
  const projectTrendCsv = archiveTransferFinalAcceptanceProjectTrendCsv(projectTrendRows);
  const markdown = archiveTransferFinalAcceptanceTrendMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    baselineTrendCsv,
    projectTrendCsv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, baselineTrendCsv, projectTrendCsv }, null, 2),
  };
}

function archiveTransferFinalAcceptanceRectificationIssueType(
  row: EngineeringBatchArchiveTransferFinalAcceptanceTrendProjectRow,
): EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregationIssueType | null {
  if (row.latestBaselineRisk === "critical") return "critical_project";
  if (row.latestBaselineRisk === "missing" || row.riskTrend === "missing") return "missing_project";
  if (row.latestDashboardStatus === "blocked") return "blocked_project";
  if (row.riskTrend === "worsening") return "worsening_project";
  if (row.riskTrend === "new" && row.latestBaselineRisk === "warning") return "new_warning_project";
  if (row.latestBaselineRisk === "warning" || row.latestDashboardStatus === "needs_review") {
    return "warning_project";
  }
  return null;
}

function archiveTransferFinalAcceptanceRectificationPriority(
  issueType: EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregationIssueType,
): EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregationPriority {
  if (issueType === "critical_project" || issueType === "blocked_project") return "P0";
  if (
    issueType === "missing_project" ||
    issueType === "worsening_project" ||
    issueType === "new_warning_project"
  ) {
    return "P1";
  }
  return "P2";
}

function archiveTransferFinalAcceptanceRectificationAction(
  row: Pick<
    EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregationRow,
    | "projectName"
    | "issueType"
    | "latestBaselineRisk"
    | "riskTrend"
    | "latestDashboardStatus"
    | "riskScoreDelta"
  >,
): string {
  if (row.issueType === "critical_project") {
    return `${row.projectName} 最新风险为 Critical，需立即核对最终接收看板、平台回执和阻断阶段，并形成整改销项证据。`;
  }
  if (row.issueType === "missing_project") {
    return `${row.projectName} 在最新基线缺失，需确认项目是否漏导入、撤项或未完成最终接收登记。`;
  }
  if (row.issueType === "blocked_project") {
    return `${row.projectName} 最新看板仍为 blocked，需先解除阻断阶段后再进入最终入库。`;
  }
  if (row.issueType === "worsening_project") {
    return `${row.projectName} 风险上升 ${row.riskScoreDelta} 分，需复核恶化原因并追加整改责任人。`;
  }
  if (row.issueType === "new_warning_project") {
    return `${row.projectName} 为新增 Warning 项目，需纳入本轮最终接收整改聚合并跟踪复核结论。`;
  }
  return `${row.projectName} 最新状态为 ${row.latestBaselineRisk}/${row.latestDashboardStatus}，需完成复核后再转入稳定入库。`;
}

