function buildArchiveTransferFinalAcceptanceRectificationAggregationArtifact(input: {
  generatedAt: string;
  owner: string;
  sourceTrendFingerprint: string;
  sourceBaselineFingerprints: string[];
  rows: EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregationRow[];
}): EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregation {
  const openRows = input.rows.filter((row) => row.closureStatus === "open");
  const body = {
    schema:
      "railwise.engineering.batch.archiveTransferFinalAcceptanceRectificationAggregation.v1" as const,
    generatedAt: input.generatedAt,
    owner: input.owner,
    sourceTrendFingerprint: input.sourceTrendFingerprint,
    sourceBaselineFingerprints: input.sourceBaselineFingerprints,
    aggregationStatus: openRows.length > 0 ? ("action_required" as const) : ("ready" as const),
    issueCount: input.rows.length,
    openIssueCount: openRows.length,
    closedIssueCount: input.rows.filter((row) => row.closureStatus === "closed").length,
    criticalIssueCount: input.rows.filter((row) => row.issueType === "critical_project").length,
    worseningIssueCount: input.rows.filter((row) => row.riskTrend === "worsening").length,
    missingIssueCount: input.rows.filter((row) => row.issueType === "missing_project").length,
    newIssueCount: input.rows.filter((row) => row.riskTrend === "new").length,
    warningIssueCount: input.rows.filter((row) => row.latestBaselineRisk === "warning").length,
    blockedIssueCount: input.rows.filter((row) => row.latestDashboardStatus === "blocked").length,
    rows: input.rows,
  };
  const aggregationFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    aggregationFingerprint,
  };
  const csv = archiveTransferFinalAcceptanceRectificationCsv(input.rows);
  const markdown = archiveTransferFinalAcceptanceRectificationMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

export function buildEngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregation(
  trendReport: EngineeringBatchArchiveTransferFinalAcceptanceTrendReport,
  options: { generatedAt?: string; owner?: string } = {},
): EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregation {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const owner = options.owner ?? "资料负责人";
  const issueDate = generatedAt.slice(0, 10).replace(/-/g, "");
  const priorityWeight: Record<EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregationPriority, number> = {
    P0: 0,
    P1: 1,
    P2: 2,
  };
  const issueRows = trendReport.projectTrendRows
    .map((projectRow) => {
      const issueType = archiveTransferFinalAcceptanceRectificationIssueType(projectRow);
      if (!issueType) return null;
      const priority = archiveTransferFinalAcceptanceRectificationPriority(issueType);
      const rowWithoutIdAndAction: Omit<
        EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregationRow,
        "issueId" | "action"
      > = {
        projectKey: projectRow.projectKey,
        projectName: projectRow.projectName,
        issueType,
        priority,
        owner,
        firstBaselineRisk: projectRow.firstBaselineRisk,
        latestBaselineRisk: projectRow.latestBaselineRisk,
        riskTrend: projectRow.riskTrend,
        latestDashboardStatus: projectRow.latestDashboardStatus,
        firstRiskScore: projectRow.firstRiskScore,
        latestRiskScore: projectRow.latestRiskScore,
        riskScoreDelta: projectRow.riskScoreDelta,
        appearanceCount: projectRow.appearanceCount,
        latestRegistrationId: projectRow.latestRegistrationId,
        latestSourceDashboardFingerprint: projectRow.latestSourceDashboardFingerprint,
        sourceTrendFingerprint: trendReport.trendFingerprint,
        closureStatus: "open",
        closedAt: null,
        closedBy: null,
        closureNote: "",
        closureExternalRecordId: "",
        closureSourceStatus: "generated_open",
      };
      const rowForAction = {
        ...rowWithoutIdAndAction,
        issueId: "",
        action: "",
      };
      return {
        ...rowWithoutIdAndAction,
        action: archiveTransferFinalAcceptanceRectificationAction(rowForAction),
      };
    })
    .filter((row): row is Omit<EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregationRow, "issueId"> =>
      Boolean(row),
    )
    .sort((a, b) => {
      if (priorityWeight[a.priority] !== priorityWeight[b.priority]) {
        return priorityWeight[a.priority] - priorityWeight[b.priority];
      }
      if (b.latestRiskScore !== a.latestRiskScore) return b.latestRiskScore - a.latestRiskScore;
      return a.projectName.localeCompare(b.projectName);
    });
  const rows: EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregationRow[] = issueRows.map(
    (row, index) => ({
      issueId: `FTA-RECT-${issueDate}-${String(index + 1).padStart(3, "0")}`,
      ...row,
    }),
  );
  return buildArchiveTransferFinalAcceptanceRectificationAggregationArtifact({
    generatedAt,
    owner,
    sourceTrendFingerprint: trendReport.trendFingerprint,
    sourceBaselineFingerprints: trendReport.sourceBaselineFingerprints,
    rows,
  });
}

type EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureRecord = {
  rowNumber: number;
  issueId: string;
  projectKey: string;
  projectName: string;
  closureStatus: EngineeringProjectArchiveRectificationClosureStatus;
  closedAt: string | null;
  closedBy: string | null;
  closureNote: string;
  externalRecordId: string;
};

function archiveTransferFinalAcceptanceRectificationClosureFormat(
  input: EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureInput,
): EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureFormat {
  if (input.format === "json" || input.format === "tsv") return input.format;
  return "csv";
}

function archiveTransferFinalAcceptanceRectificationClosureValue(
  row: Record<string, string>,
  aliases: string[],
): string {
  return externalSystemImportRectificationClosureValue(row, aliases);
}

function normalizeArchiveTransferFinalAcceptanceRectificationClosureStatus(
  value: string,
): EngineeringProjectArchiveRectificationClosureStatus {
  const normalized = normalizeLedgerStatus(value);
  return normalized === "closed" || normalized === "ok" ? "closed" : "open";
}

function parseArchiveTransferFinalAcceptanceRectificationClosureInput(
  input: EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureInput,
): {
  source: EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureSource;
  records: EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureRecord[];
} {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const format = archiveTransferFinalAcceptanceRectificationClosureFormat(input);
  const rows = externalSystemReceiptRowsFromText(input.text, format);
  const columnNames =
    format === "json"
      ? uniqueNonEmptyStrings(rows.flatMap((row) => Object.keys(row)))
      : (parseDelimitedRows(input.text, format === "tsv" ? "\t" : ",")[0] ?? []);
  const records = rows
    .map((row, index): EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureRecord => {
      const closureStatusText = archiveTransferFinalAcceptanceRectificationClosureValue(row, [
        "closure_status",
        "status",
        "处理状态",
        "闭环状态",
        "销项状态",
        "平台处理状态",
      ]);
      return {
        rowNumber: index + 2,
        issueId: archiveTransferFinalAcceptanceRectificationClosureValue(row, [
          "issue_id",
          "issueId",
          "问题编号",
          "平台问题号",
        ]),
        projectKey: archiveTransferFinalAcceptanceRectificationClosureValue(row, [
          "project_key",
          "projectKey",
          "项目编码",
          "项目编号",
        ]),
        projectName: archiveTransferFinalAcceptanceRectificationClosureValue(row, [
          "project_name",
          "projectName",
          "项目名称",
          "标段",
        ]),
        closureStatus: normalizeArchiveTransferFinalAcceptanceRectificationClosureStatus(closureStatusText),
        closedAt:
          archiveTransferFinalAcceptanceRectificationClosureValue(row, [
            "closed_at",
            "closedAt",
            "completed_at",
            "完成时间",
            "平台完成时间",
          ]) || null,
        closedBy:
          archiveTransferFinalAcceptanceRectificationClosureValue(row, [
            "closed_by",
            "closedBy",
            "operator",
            "完成人",
            "平台处理人",
          ]) || null,
        closureNote: archiveTransferFinalAcceptanceRectificationClosureValue(row, [
          "closure_note",
          "closureNote",
          "note",
          "备注",
          "处理说明",
        ]),
        externalRecordId: archiveTransferFinalAcceptanceRectificationClosureValue(row, [
          "external_record_id",
          "externalRecordId",
          "record_id",
          "平台记录号",
          "平台档案号",
        ]),
      };
    })
    .filter(
      (record) =>
        record.issueId ||
        record.projectKey ||
        record.projectName ||
        record.closedAt ||
        record.closedBy ||
        record.closureNote ||
        record.externalRecordId,
    );
  const sourceBody = {
    schema: "railwise.engineering.archiveTransferFinalAcceptanceRectificationClosureSource.v1" as const,
    sourceName: input.sourceName ?? null,
    importedAt,
    format,
    rowCount: records.length,
    columnNames,
  };
  return {
    source: {
      ...sourceBody,
      closureSourceFingerprint: fnv1a32Fingerprint(JSON.stringify({ ...sourceBody, records })),
    },
    records,
  };
}

