function archiveTransferFinalAcceptanceRectificationClosureProjectKey(
  projectKey: string,
  projectName: string,
): string {
  return `${rectificationIssueKey(projectKey)}::${rectificationIssueKey(projectName)}`;
}

export function buildEngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureUpdate(
  aggregation: EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregation,
  input: EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureInput,
): EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureUpdate {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const { source, records } = parseArchiveTransferFinalAcceptanceRectificationClosureInput({
    ...input,
    importedAt,
  });
  const recordsByIssueId = new Map<string, EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureRecord>();
  const recordsByProject = new Map<string, EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureRecord>();
  for (const record of records) {
    if (record.issueId) recordsByIssueId.set(rectificationIssueKey(record.issueId), record);
    if (record.projectKey || record.projectName) {
      recordsByProject.set(
        archiveTransferFinalAcceptanceRectificationClosureProjectKey(record.projectKey, record.projectName),
        record,
      );
    }
  }
  const matchedRecords = new Set<EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureRecord>();
  const updateRows: EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureUpdateRow[] = [];
  const updatedRows = aggregation.rows.map(
    (row): EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregationRow => {
      const record =
        recordsByIssueId.get(rectificationIssueKey(row.issueId)) ??
        recordsByProject.get(
          archiveTransferFinalAcceptanceRectificationClosureProjectKey(row.projectKey, row.projectName),
        ) ??
        null;
      if (!record) {
        if (row.closureStatus === "closed") return row;
        updateRows.push({
          updateStatus: "missing_update",
          issueId: row.issueId,
          projectKey: row.projectKey,
          projectName: row.projectName,
          issueType: row.issueType,
          priority: row.priority,
          closureStatus: row.closureStatus,
          closedAt: row.closedAt,
          closedBy: row.closedBy,
          closureNote: row.closureNote,
          externalRecordId: row.closureExternalRecordId,
          sourceRowNumber: null,
          action: "尚未收到该最终接收整改问题的销项回执。",
        });
        return {
          ...row,
          closureSourceStatus: "missing_rectification_receipt",
        };
      }
      matchedRecords.add(record);
      const closedAt = record.closureStatus === "closed" ? record.closedAt ?? importedAt.slice(0, 10) : record.closedAt;
      const nextRow: EngineeringBatchArchiveTransferFinalAcceptanceRectificationAggregationRow = {
        ...row,
        closureStatus: record.closureStatus,
        closedAt,
        closedBy: record.closedBy ?? row.closedBy,
        closureNote: record.closureNote || row.closureNote,
        closureExternalRecordId: record.externalRecordId || row.closureExternalRecordId,
        closureSourceStatus:
          record.closureStatus === "closed"
            ? "closed_by_rectification_receipt"
            : "kept_open_by_rectification_receipt",
      };
      updateRows.push({
        updateStatus: record.closureStatus === "closed" ? "closed" : "kept_open",
        issueId: row.issueId,
        projectKey: row.projectKey,
        projectName: row.projectName,
        issueType: row.issueType,
        priority: row.priority,
        closureStatus: record.closureStatus,
        closedAt: nextRow.closedAt,
        closedBy: nextRow.closedBy,
        closureNote: nextRow.closureNote,
        externalRecordId: nextRow.closureExternalRecordId,
        sourceRowNumber: record.rowNumber,
        action:
          record.closureStatus === "closed"
            ? "销项回执确认该最终接收整改问题已闭环。"
            : "销项回执仍保持打开，请继续跟踪最终接收整改结果。",
      });
      return nextRow;
    },
  );
  for (const record of records) {
    if (matchedRecords.has(record) || (!record.issueId && !record.projectKey && !record.projectName)) continue;
    updateRows.push({
      updateStatus: "unmatched_update",
      issueId: record.issueId,
      projectKey: record.projectKey,
      projectName: record.projectName,
      issueType: "",
      priority: "",
      closureStatus: record.closureStatus,
      closedAt: record.closedAt,
      closedBy: record.closedBy,
      closureNote: record.closureNote,
      externalRecordId: record.externalRecordId,
      sourceRowNumber: record.rowNumber,
      action: "销项回执未匹配当前最终接收整改聚合，请核对 issue_id 或项目名称。",
    });
  }
  const updatedAggregation = buildArchiveTransferFinalAcceptanceRectificationAggregationArtifact({
    generatedAt: aggregation.generatedAt,
    owner: aggregation.owner,
    sourceTrendFingerprint: aggregation.sourceTrendFingerprint,
    sourceBaselineFingerprints: aggregation.sourceBaselineFingerprints,
    rows: updatedRows,
  });
  const csv = archiveTransferFinalAcceptanceRectificationClosureCsv(updateRows);
  const body = {
    schema:
      "railwise.engineering.batch.archiveTransferFinalAcceptanceRectificationClosureUpdate.v1" as const,
    importedAt,
    owner: aggregation.owner,
    source,
    sourceAggregationFingerprint: aggregation.aggregationFingerprint,
    updatedAggregationFingerprint: updatedAggregation.aggregationFingerprint,
    closedCount: updatedAggregation.closedIssueCount,
    stillOpenCount: updatedAggregation.openIssueCount,
    missingUpdateCount: updateRows.filter((row) => row.updateStatus === "missing_update").length,
    unmatchedUpdateCount: updateRows.filter((row) => row.updateStatus === "unmatched_update").length,
    rows: updateRows,
    updatedAggregation,
  };
  const updateFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...body, csv }));
  const withoutArtifacts = {
    ...body,
    updateFingerprint,
  };
  const markdown = archiveTransferFinalAcceptanceRectificationClosureMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveTransferFinalAcceptanceIngestRiskType(
  row: EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureUpdateRow,
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskType {
  if (row.updateStatus === "missing_update") return "missing_closure_receipt";
  if (row.updateStatus === "unmatched_update") return "unmatched_closure_receipt";
  return "open_rectification";
}

function archiveTransferFinalAcceptanceIngestRiskPriority(
  row: EngineeringBatchArchiveTransferFinalAcceptanceRectificationClosureUpdateRow,
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskPriority {
  if (
    row.updateStatus === "missing_update" ||
    row.issueType === "critical_project" ||
    row.issueType === "blocked_project" ||
    row.priority === "P0"
  ) {
    return "critical";
  }
  if (row.updateStatus === "unmatched_update" || row.priority === "P1") return "warning";
  return "notice";
}

function archiveTransferFinalAcceptanceIngestRiskAction(
  row: Pick<
    EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskLedgerRow,
    "riskType" | "projectName" | "issueId" | "sourceRectificationAction"
  >,
): string {
  if (row.riskType === "missing_closure_receipt") {
    return `${row.projectName || row.issueId} 缺少最终接收整改销项回执，入库前需补齐回执或形成人工确认记录。`;
  }
  if (row.riskType === "unmatched_closure_receipt") {
    return `${row.issueId || row.projectName || "未匹配销项"} 未匹配当前最终接收整改聚合，入库前需核对问题编号、项目名称和外部记录号。`;
  }
  return `${row.projectName || row.issueId} 仍有最终接收整改未闭环，需完成整改销项后再放行入库。${row.sourceRectificationAction ? ` 原整改要求：${row.sourceRectificationAction}` : ""}`;
}

