function archiveTransferFinalAcceptanceIngestRiskProjectKey(
  projectKey: string,
  projectName: string,
): string {
  return `${rectificationIssueKey(projectKey)}::${rectificationIssueKey(projectName)}`;
}

export function buildEngineeringBatchArchiveTransferFinalAcceptanceIngestRiskClosureUpdate(
  ledger: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskLedger,
  input: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskClosureInput,
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskClosureUpdate {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const { source, records } = parseArchiveTransferFinalAcceptanceIngestRiskClosureInput({
    ...input,
    importedAt,
  });
  const recordsByRiskId = new Map<string, EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskClosureRecord>();
  const recordsByIssueId = new Map<string, EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskClosureRecord>();
  const recordsByProject = new Map<string, EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskClosureRecord>();
  for (const record of records) {
    if (record.riskId) recordsByRiskId.set(rectificationIssueKey(record.riskId), record);
    if (record.issueId) recordsByIssueId.set(rectificationIssueKey(record.issueId), record);
    if (record.projectKey || record.projectName) {
      recordsByProject.set(
        archiveTransferFinalAcceptanceIngestRiskProjectKey(record.projectKey, record.projectName),
        record,
      );
    }
  }
  const matchedRecords = new Set<EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskClosureRecord>();
  const updateRows: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskClosureUpdateRow[] = [];
  const updatedRows = ledger.rows.map(
    (row): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskLedgerRow => {
      const record =
        recordsByRiskId.get(rectificationIssueKey(row.riskId)) ??
        recordsByIssueId.get(rectificationIssueKey(row.issueId)) ??
        recordsByProject.get(archiveTransferFinalAcceptanceIngestRiskProjectKey(row.projectKey, row.projectName)) ??
        null;
      if (!record) {
        if (row.closureStatus === "closed") return row;
        updateRows.push({
          updateStatus: "missing_update",
          riskId: row.riskId,
          issueId: row.issueId,
          projectKey: row.projectKey,
          projectName: row.projectName,
          riskType: row.riskType,
          riskPriority: row.riskPriority,
          closureStatus: row.closureStatus,
          closedAt: row.closedAt,
          closedBy: row.closedBy,
          closureNote: row.closureNote,
          externalRecordId: row.externalRecordId,
          sourceRowNumber: null,
          action: "尚未收到该最终接收入库风险的销项回执。",
        });
        return {
          ...row,
          closureSourceStatus: "missing_receipt",
        };
      }
      matchedRecords.add(record);
      const closedAt = record.closureStatus === "closed" ? record.closedAt ?? importedAt.slice(0, 10) : record.closedAt;
      const nextRow: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskLedgerRow = {
        ...row,
        closureStatus: record.closureStatus,
        closedAt,
        closedBy: record.closedBy ?? row.closedBy,
        closureNote: record.closureNote || row.closureNote,
        externalRecordId: record.externalRecordId || row.externalRecordId,
        closureSourceStatus: record.closureStatus === "closed" ? "closed_by_receipt" : "kept_open_by_receipt",
      };
      updateRows.push({
        updateStatus: record.closureStatus === "closed" ? "closed" : "kept_open",
        riskId: row.riskId,
        issueId: row.issueId,
        projectKey: row.projectKey,
        projectName: row.projectName,
        riskType: row.riskType,
        riskPriority: row.riskPriority,
        closureStatus: record.closureStatus,
        closedAt: nextRow.closedAt,
        closedBy: nextRow.closedBy,
        closureNote: nextRow.closureNote,
        externalRecordId: nextRow.externalRecordId,
        sourceRowNumber: record.rowNumber,
        action:
          record.closureStatus === "closed"
            ? "销项回执确认该最终接收入库风险已闭环。"
            : "销项回执仍保持打开，请继续跟踪最终接收入库风险。",
      });
      return nextRow;
    },
  );
  for (const record of records) {
    if (
      matchedRecords.has(record) ||
      (!record.riskId && !record.issueId && !record.projectKey && !record.projectName)
    ) {
      continue;
    }
    updateRows.push({
      updateStatus: "unmatched_update",
      riskId: record.riskId,
      issueId: record.issueId,
      projectKey: record.projectKey,
      projectName: record.projectName,
      riskType: "",
      riskPriority: "",
      closureStatus: record.closureStatus,
      closedAt: record.closedAt,
      closedBy: record.closedBy,
      closureNote: record.closureNote,
      externalRecordId: record.externalRecordId,
      sourceRowNumber: record.rowNumber,
      action: "风险销项回执未匹配当前最终接收入库风险台账，请核对 risk_id、issue_id 或项目名称。",
    });
  }
  const updatedRiskLedger = buildArchiveTransferFinalAcceptanceIngestRiskLedgerArtifact({
    generatedAt: ledger.generatedAt,
    owner: ledger.owner,
    sourceRectificationClosureUpdateFingerprint: ledger.sourceRectificationClosureUpdateFingerprint,
    sourceUpdatedAggregationFingerprint: ledger.sourceUpdatedAggregationFingerprint,
    sourceAggregationFingerprint: ledger.sourceAggregationFingerprint,
    rows: updatedRows,
  });
  const csv = archiveTransferFinalAcceptanceIngestRiskClosureCsv(updateRows);
  const body = {
    schema: "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskClosureUpdate.v1" as const,
    importedAt,
    owner: ledger.owner,
    source,
    sourceRiskLedgerFingerprint: ledger.ledgerFingerprint,
    updatedRiskLedgerFingerprint: updatedRiskLedger.ledgerFingerprint,
    closedCount: updatedRiskLedger.closedRiskCount,
    stillOpenCount: updatedRiskLedger.openRiskCount,
    missingUpdateCount: updateRows.filter((row) => row.updateStatus === "missing_update").length,
    unmatchedUpdateCount: updateRows.filter((row) => row.updateStatus === "unmatched_update").length,
    rows: updateRows,
    updatedRiskLedger,
  };
  const updateFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...body, csv }));
  const withoutArtifacts = {
    ...body,
    updateFingerprint,
  };
  const markdown = archiveTransferFinalAcceptanceIngestRiskClosureMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

