export function buildEngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptReview(
  signoff: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalSignoff,
  input: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptReviewInput,
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptReview {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const { source, records } = parseArchiveTransferFinalAcceptanceIngestRiskFinalReceiptInput({
    ...input,
    importedAt,
  });
  const recordsBySignoffId = new Map<string, EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptRecord>();
  const recordsByReceiptId = new Map<string, EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptRecord>();
  for (const record of records) {
    if (record.signoffId) recordsBySignoffId.set(rectificationIssueKey(record.signoffId), record);
    if (record.receiptId) recordsByReceiptId.set(rectificationIssueKey(record.receiptId), record);
  }
  const matchedRecords = new Set<EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptRecord>();
  const rows: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptReviewRow[] = [];
  const expectedRecord =
    recordsBySignoffId.get(rectificationIssueKey(signoff.signoffId)) ??
    recordsByReceiptId.get(rectificationIssueKey(signoff.signedReceipt.receiptId)) ??
    null;
  if (expectedRecord) {
    matchedRecords.add(expectedRecord);
    const reconciliationStatus = expectedRecord.receiptStatus;
    rows.push({
      signoffId: signoff.signoffId,
      receiptId: expectedRecord.receiptId || signoff.signedReceipt.receiptId,
      receiverName: expectedRecord.receiverName || signoff.receiverName,
      receiptStatus: expectedRecord.receiptStatus,
      reconciliationStatus,
      receivedAt: expectedRecord.receivedAt,
      receivedBy: expectedRecord.receivedBy,
      receiptMessage: expectedRecord.receiptMessage,
      externalRecordId: expectedRecord.externalRecordId,
      platformChecksum: expectedRecord.platformChecksum,
      sourceRowNumber: expectedRecord.rowNumber,
      action:
        reconciliationStatus === "accepted"
          ? "外部平台确认入库风险终态签发已入库。"
          : reconciliationStatus === "rejected"
            ? "外部平台拒绝入库风险终态签发，请核对签发索引、风险台账和回执说明后重提。"
            : "外部平台仍在处理入库风险终态签发，请继续跟踪回执状态。",
    });
  } else {
    rows.push({
      signoffId: signoff.signoffId,
      receiptId: signoff.signedReceipt.receiptId,
      receiverName: signoff.receiverName,
      receiptStatus: null,
      reconciliationStatus: "missing_receipt",
      receivedAt: null,
      receivedBy: null,
      receiptMessage: "",
      externalRecordId: "",
      platformChecksum: "",
      sourceRowNumber: null,
      action: "尚未收到该入库风险终态签发的外部入库回执。",
    });
  }
  for (const record of records) {
    if (matchedRecords.has(record) || (!record.signoffId && !record.receiptId)) continue;
    rows.push({
      signoffId: record.signoffId,
      receiptId: record.receiptId,
      receiverName: record.receiverName,
      receiptStatus: record.receiptStatus,
      reconciliationStatus: "unmatched_receipt",
      receivedAt: record.receivedAt,
      receivedBy: record.receivedBy,
      receiptMessage: record.receiptMessage,
      externalRecordId: record.externalRecordId,
      platformChecksum: record.platformChecksum,
      sourceRowNumber: record.rowNumber,
      action: "外部入库回执未匹配当前入库风险终态签发，请核对 signoff_id 或 receipt_id。",
    });
  }
  const acceptedCount = rows.filter((row) => row.reconciliationStatus === "accepted").length;
  const rejectedCount = rows.filter((row) => row.reconciliationStatus === "rejected").length;
  const pendingCount = rows.filter((row) => row.reconciliationStatus === "pending").length;
  const missingReceiptCount = rows.filter((row) => row.reconciliationStatus === "missing_receipt").length;
  const unmatchedReceiptCount = rows.filter((row) => row.reconciliationStatus === "unmatched_receipt").length;
  const reviewStatus: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptReviewStatus =
    missingReceiptCount > 0
      ? "missing_receipt"
      : rejectedCount > 0
        ? "rejected"
        : pendingCount > 0
          ? "pending"
          : acceptedCount > 0
            ? "accepted"
            : "unmatched_receipt";
  const csv = archiveTransferFinalAcceptanceIngestRiskFinalReceiptReviewCsv(rows);
  const body = {
    schema: "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalReceiptReview.v1" as const,
    importedAt,
    signoffId: signoff.signoffId,
    receiverName: signoff.receiverName,
    source,
    sourceSignoffFingerprint: signoff.signoffFingerprint,
    sourceHistoryFingerprint: signoff.sourceHistoryFingerprint,
    finalRiskLedgerFingerprint: signoff.finalRiskLedgerFingerprint,
    reviewStatus,
    acceptedCount,
    rejectedCount,
    pendingCount,
    missingReceiptCount,
    unmatchedReceiptCount,
    rows,
  };
  const reviewFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...body, csv }));
  const withoutArtifacts = {
    ...body,
    reviewFingerprint,
  };
  const markdown = archiveTransferFinalAcceptanceIngestRiskFinalReceiptReviewMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformAction(
  severity: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformSeverity,
  issueTypes: string[],
): string {
  if (severity === "passed") return "各外部入库平台对入库风险终态签发回执一致，可进入跨系统一致性门禁。";
  if (issueTypes.includes("missing_platform")) return "存在要求平台未回传入库回执，需补取平台回执后再判定终态入库。";
  if (issueTypes.includes("missing_receipt")) return "存在平台缺少当前签发的入库回执，需核对 signoff_id、receipt_id 或补传回执。";
  if (issueTypes.includes("status_mismatch")) return "不同平台入库状态不一致，需核对退回原因、平台处理日志和签发索引版本。";
  if (issueTypes.includes("rejected_receipt")) return "存在平台拒绝入库风险终态签发，需按回执说明整改后重新提交。";
  if (issueTypes.includes("pending_receipt")) return "存在平台仍在处理入库风险终态签发，需等待最终回执后再放行。";
  return "存在非阻断差异，需核对平台校验码、外部记录号或接收方名称后保留复核记录。";
}

function archiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformRowStatus(
  issueTypes: string[],
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformRowStatus {
  if (issueTypes.includes("missing_platform")) return "missing_platform";
  if (issueTypes.includes("missing_receipt")) return "missing_receipt";
  if (issueTypes.includes("status_mismatch")) return "status_mismatch";
  if (issueTypes.includes("checksum_mismatch")) return "checksum_mismatch";
  if (issueTypes.includes("external_record_mismatch")) return "external_record_mismatch";
  if (issueTypes.includes("receiver_mismatch")) return "receiver_mismatch";
  return "matched";
}

function archiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformSeverity(
  issueTypes: string[],
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformSeverity {
  if (
    issueTypes.some((issueType) =>
      ["missing_platform", "missing_receipt", "status_mismatch", "rejected_receipt"].includes(issueType),
    )
  ) {
    return "blocking";
  }
  if (
    issueTypes.some((issueType) =>
      ["pending_receipt", "checksum_mismatch", "receiver_mismatch", "external_record_mismatch"].includes(issueType),
    )
  ) {
    return "warning";
  }
  return "passed";
}

