export function buildEngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformReview(
  signoff: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalSignoff,
  receiptReviews: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptReview[],
  options: {
    generatedAt?: string;
    batchName?: string;
    requiredPlatformNames?: string[];
  } = {},
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformReview {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const reviewRows = receiptReviews
    .map((review, index) => {
      const row = review.rows.find(
        (item) =>
          rectificationIssueKey(item.signoffId) === rectificationIssueKey(signoff.signoffId) ||
          rectificationIssueKey(item.receiptId) === rectificationIssueKey(signoff.signedReceipt.receiptId),
      );
      return row
        ? {
            review,
            row,
            sourceName: (review.source.sourceName ?? review.receiverName) || `平台${index + 1}`,
          }
        : null;
    })
    .filter((item): item is NonNullable<typeof item> => Boolean(item));
  const platformNames = reviewRows.map((item) => item.sourceName);
  const requiredPlatformNames = uniqueNonEmptyStrings(options.requiredPlatformNames ?? platformNames);
  const missingPlatformNames = requiredPlatformNames.filter(
    (name) => !platformNames.some((platformName) => rectificationIssueKey(platformName) === rectificationIssueKey(name)),
  );
  const statuses = reviewRows.map((item) => item.row.reconciliationStatus);
  const statusSet = new Set(statuses.filter(Boolean));
  const checksums = reviewRows.map((item) => item.row.platformChecksum).filter((value) => value.trim() !== "");
  const checksumSet = new Set(checksums);
  const receivers = reviewRows.map((item) => item.row.receiverName).filter((value) => value.trim() !== "");
  const receiverSet = new Set(receivers);
  const externalRecordIds = reviewRows.map((item) => item.row.externalRecordId).filter((value) => value.trim() !== "");
  const externalRecordSet = new Set(externalRecordIds);
  const issueTypes: string[] = [];
  if (missingPlatformNames.length > 0) issueTypes.push("missing_platform");
  if (reviewRows.length < receiptReviews.length || reviewRows.length === 0 || statuses.includes("missing_receipt")) {
    issueTypes.push("missing_receipt");
  }
  if (statusSet.size > 1) issueTypes.push("status_mismatch");
  if (statuses.includes("rejected")) issueTypes.push("rejected_receipt");
  if (statuses.includes("pending")) issueTypes.push("pending_receipt");
  if (checksumSet.size > 1) issueTypes.push("checksum_mismatch");
  if (receiverSet.size > 1) issueTypes.push("receiver_mismatch");
  if (externalRecordSet.size > 1) issueTypes.push("external_record_mismatch");
  const uniqueIssueTypes = uniqueNonEmptyStrings(issueTypes);
  const severity = archiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformSeverity(uniqueIssueTypes);
  const rows: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformReviewRow[] = [
    {
      signoffId: signoff.signoffId,
      receiptId: signoff.signedReceipt.receiptId,
      reviewStatus: archiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformRowStatus(uniqueIssueTypes),
      severity,
      issueTypes: uniqueIssueTypes,
      platformStatuses: reviewRows
        .map((item) => `${item.sourceName}:${item.row.reconciliationStatus}`)
        .join("; "),
      platformReceivers: reviewRows
        .map((item) => `${item.sourceName}:${item.row.receiverName || "-"}`)
        .join("; "),
      externalRecordIds: reviewRows
        .map((item) => `${item.sourceName}:${item.row.externalRecordId || "-"}`)
        .join("; "),
      platformChecksums: reviewRows
        .map((item) => `${item.sourceName}:${item.row.platformChecksum || "-"}`)
        .join("; "),
      action: archiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformAction(severity, uniqueIssueTypes),
    },
  ];
  const issueCount = rows.filter((row) => row.issueTypes.length > 0).length;
  const blockingIssueCount = rows.filter((row) => row.severity === "blocking").length;
  const warningIssueCount = rows.filter((row) => row.severity === "warning").length;
  const body = {
    schema:
      "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformReview.v1" as const,
    generatedAt,
    batchName: options.batchName?.trim() || `${signoff.receiverName}多平台入库回执复核`,
    signoffId: signoff.signoffId,
    sourceSignoffFingerprint: signoff.signoffFingerprint,
    sourceHistoryFingerprint: signoff.sourceHistoryFingerprint,
    finalRiskLedgerFingerprint: signoff.finalRiskLedgerFingerprint,
    sourceReceiptReviewFingerprints: receiptReviews.map((review) => review.reviewFingerprint),
    platformCount: receiptReviews.length,
    requiredPlatformCount: requiredPlatformNames.length,
    missingPlatformNames,
    signoffCount: rows.length,
    reviewStatus: issueCount > 0 ? ("needs_review" as const) : ("passed" as const),
    issueCount,
    blockingIssueCount,
    warningIssueCount,
    rows,
  };
  const reviewFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    reviewFingerprint,
  };
  const csv = archiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformCsv(rows);
  const markdown = archiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

