export function buildEngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalConsistencyGate(
  signoff: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalSignoff,
  crossPlatformReview: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformReview,
  options: {
    generatedAt?: string;
    batchName?: string;
    requiredPlatformCount?: number;
    gateOwner?: string;
  } = {},
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalConsistencyGate {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const requiredPlatformCount = Math.max(
    1,
    options.requiredPlatformCount ?? crossPlatformReview.requiredPlatformCount ?? crossPlatformReview.platformCount,
  );
  const criteria = {
    signoff_signed: signoff.signoffStatus === "signed",
    required_platform_receipts:
      crossPlatformReview.platformCount >= requiredPlatformCount &&
      crossPlatformReview.missingPlatformNames.length === 0,
    no_blocking_cross_platform_issues: crossPlatformReview.blockingIssueCount === 0,
    no_warning_cross_platform_issues: crossPlatformReview.warningIssueCount === 0,
  };
  const passedCriteria = Object.entries(criteria)
    .filter(([, passed]) => passed)
    .map(([key]) => key);
  const failedCriteria = Object.entries(criteria)
    .filter(([, passed]) => !passed)
    .map(([key]) => key);
  const blockingFailed = failedCriteria.some((key) =>
    ["signoff_signed", "required_platform_receipts", "no_blocking_cross_platform_issues"].includes(key),
  );
  const gateStatus: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalConsistencyGateStatus = blockingFailed
    ? "blocked"
    : failedCriteria.length > 0
      ? "watch"
      : "passed";
  const readinessStatus: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalConsistencyGateReadinessStatus =
    !criteria.signoff_signed
      ? "blocked_by_signoff"
      : blockingFailed
        ? "blocked_by_platform_receipt"
        : gateStatus === "watch"
          ? "watch_platform_receipt"
          : "ready_for_final_ingest";
  const action =
    gateStatus === "passed"
      ? "跨系统入库状态、平台覆盖和终态签发均满足要求，可放行最终入库证据。"
      : gateStatus === "watch"
        ? "跨系统入库状态无阻断差异，但仍存在提示项，需记录复核意见后谨慎放行。"
        : "暂缓入库终态放行，需补齐缺失平台回执并处理跨平台阻断差异后重新执行门禁。";
  const body = {
    schema: "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalConsistencyGate.v1" as const,
    generatedAt,
    batchName: options.batchName?.trim() || `${crossPlatformReview.batchName}一致性门禁`,
    signoffId: signoff.signoffId,
    gateOwner: options.gateOwner?.trim() || signoff.signedBy || "资料负责人",
    gateStatus,
    readinessStatus,
    sourceSignoffFingerprint: signoff.signoffFingerprint,
    sourceCrossPlatformReviewFingerprint: crossPlatformReview.reviewFingerprint,
    sourceReceiptReviewFingerprints: crossPlatformReview.sourceReceiptReviewFingerprints,
    requiredPlatformCount,
    platformCount: crossPlatformReview.platformCount,
    issueCount: crossPlatformReview.issueCount,
    blockingIssueCount: crossPlatformReview.blockingIssueCount,
    warningIssueCount: crossPlatformReview.warningIssueCount,
    passedCriteria,
    failedCriteria,
    action,
  };
  const gateFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    gateFingerprint,
  };
  const csv = archiveTransferFinalAcceptanceIngestRiskFinalConsistencyGateCsv(withoutArtifacts);
  const markdown = archiveTransferFinalAcceptanceIngestRiskFinalConsistencyGateMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidenceAction(
  row: Pick<
    EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidencePackageRow,
    "reviewStatus" | "platformName" | "sourceName"
  >,
): string {
  if (row.reviewStatus === "accepted") {
    return `${row.platformName} 原始回执 ${row.sourceName} 已作为 accepted 入库证据留存。`;
  }
  if (row.reviewStatus === "rejected") {
    return `${row.platformName} 原始回执 ${row.sourceName} 为 rejected，需连同源文件提交整改复核。`;
  }
  if (row.reviewStatus === "pending") {
    return `${row.platformName} 原始回执 ${row.sourceName} 仍为 pending，需保留源文件并继续跟踪终态。`;
  }
  if (row.reviewStatus === "missing_receipt") {
    return `${row.platformName} 尚缺有效入库回执，证据包仅记录当前缺失状态。`;
  }
  return `${row.platformName} 原始回执 ${row.sourceName} 未匹配当前签发，需核对平台批次或归并到正确签发。`;
}

