export function buildEngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidencePackage(
  signoff: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalSignoff,
  crossPlatformReview: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformReview,
  inputs: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidencePackageInput[],
  options: {
    generatedAt?: string;
    batchName?: string;
    packageOwner?: string;
  } = {},
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidencePackage {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const rows: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidencePackageRow[] = inputs.map(
    (input, index) => {
      const review = input.receiptReview;
      const platformName = input.platformName?.trim() || review.source.sourceName || review.receiverName || `平台${index + 1}`;
      const sourceName = input.sourceName?.trim() || review.source.sourceName || `${platformName}-receipt.${input.format ?? review.source.format}`;
      const format = input.format ?? review.source.format;
      const row: Omit<EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidencePackageRow, "action"> = {
        platformName,
        sourceName,
        format,
        importedAt: review.importedAt,
        rowCount: review.source.rowCount,
        columnNames: review.source.columnNames,
        sourceFingerprint: review.source.sourceFingerprint,
        rawTextFingerprint: fnv1a32Fingerprint(input.sourceText),
        reviewFingerprint: review.reviewFingerprint,
        reviewStatus: review.reviewStatus,
        acceptedCount: review.acceptedCount,
        rejectedCount: review.rejectedCount,
        pendingCount: review.pendingCount,
        missingReceiptCount: review.missingReceiptCount,
        unmatchedReceiptCount: review.unmatchedReceiptCount,
        sourceText: input.sourceText,
      };
      return {
        ...row,
        action: archiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidenceAction(row),
      };
    },
  );
  const body = {
    schema:
      "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidencePackage.v1" as const,
    generatedAt,
    batchName: options.batchName?.trim() || `${crossPlatformReview.batchName}原始回执证据包`,
    signoffId: signoff.signoffId,
    packageOwner: options.packageOwner?.trim() || signoff.signedBy || "资料负责人",
    sourceSignoffFingerprint: signoff.signoffFingerprint,
    sourceCrossPlatformReviewFingerprint: crossPlatformReview.reviewFingerprint,
    sourceReceiptReviewFingerprints: rows.map((row) => row.reviewFingerprint),
    evidenceCount: rows.length,
    rawSourceCount: rows.filter((row) => row.sourceText.trim() !== "").length,
    acceptedCount: rows.reduce((sum, row) => sum + row.acceptedCount, 0),
    rejectedCount: rows.reduce((sum, row) => sum + row.rejectedCount, 0),
    pendingCount: rows.reduce((sum, row) => sum + row.pendingCount, 0),
    missingReceiptCount: rows.reduce((sum, row) => sum + row.missingReceiptCount, 0),
    unmatchedReceiptCount: rows.reduce((sum, row) => sum + row.unmatchedReceiptCount, 0),
    rows,
  };
  const packageFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    packageFingerprint,
  };
  const csv = archiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidenceCsv(rows);
  const markdown = archiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidenceMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

