function archiveTransferFinalAcceptanceIngestRiskFinalProofRowAction(
  row: Pick<
    EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageRow,
    "artifactName" | "handoverStatus"
  >,
): string {
  if (row.handoverStatus === "ready") {
    return `${row.artifactName} 已满足入库证明移交要求，按文件路径和指纹交付。`;
  }
  if (row.handoverStatus === "needs_review") {
    return `${row.artifactName} 可进入人工复核移交，需在证明包中保留复核意见。`;
  }
  return `${row.artifactName} 尚未满足入库证明移交要求，需整改后重新生成证明包。`;
}

function archiveTransferFinalAcceptanceIngestRiskFinalProofEvidenceStatus(
  evidencePackage: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidencePackage,
  requiredPlatformCount: number,
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofHandoverStatus {
  if (
    evidencePackage.evidenceCount < requiredPlatformCount ||
    evidencePackage.rejectedCount > 0 ||
    evidencePackage.missingReceiptCount > 0 ||
    evidencePackage.unmatchedReceiptCount > 0
  ) {
    return "blocked";
  }
  if (evidencePackage.pendingCount > 0) return "needs_review";
  return "ready";
}

export function buildEngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackage(
  signoff: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalSignoff,
  crossPlatformReview: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformReview,
  gate: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalConsistencyGate,
  evidencePackage: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidencePackage,
  options: {
    generatedAt?: string;
    batchName?: string;
    proofOwner?: string;
  } = {},
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackage {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const rowInputs: Array<
    Omit<EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageRow, "action">
  > = [
    {
      artifactKey: "archive_transfer_final_acceptance_ingest_risk_final_signoff",
      artifactName: "资料移交最终接收入库风险终态签发",
      filePath: "batch/archive-transfer-final-acceptance-ingest-risk-final-signoff.json",
      artifactRole: "archive_transfer_final_acceptance_ingest_risk_final_signoff",
      schema: "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalSignoff.v1",
      sourceFingerprint: signoff.signoffFingerprint,
      required: true,
      handoverStatus: signoff.signoffStatus === "signed" ? "ready" : "blocked",
    },
    {
      artifactKey: "archive_transfer_final_acceptance_ingest_risk_final_receipt_cross_platform_review",
      artifactName: "资料移交最终接收入库风险多平台回执差异复核",
      filePath:
        "batch/archive-transfer-final-acceptance-ingest-risk-final-receipt-cross-platform-review.json",
      artifactRole: "archive_transfer_final_acceptance_ingest_risk_final_receipt_cross_platform_review",
      schema:
        "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalReceiptCrossPlatformReview.v1",
      sourceFingerprint: crossPlatformReview.reviewFingerprint,
      required: true,
      handoverStatus:
        crossPlatformReview.blockingIssueCount > 0
          ? "blocked"
          : crossPlatformReview.issueCount > 0
            ? "needs_review"
            : "ready",
    },
    {
      artifactKey: "archive_transfer_final_acceptance_ingest_risk_final_consistency_gate",
      artifactName: "资料移交最终接收入库风险跨系统一致性门禁",
      filePath: "batch/archive-transfer-final-acceptance-ingest-risk-final-consistency-gate.json",
      artifactRole: "archive_transfer_final_acceptance_ingest_risk_final_consistency_gate",
      schema: "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalConsistencyGate.v1",
      sourceFingerprint: gate.gateFingerprint,
      required: true,
      handoverStatus:
        gate.gateStatus === "passed" ? "ready" : gate.gateStatus === "watch" ? "needs_review" : "blocked",
    },
    {
      artifactKey: "archive_transfer_final_acceptance_ingest_risk_final_receipt_evidence_package",
      artifactName: "资料移交最终接收入库风险原始回执证据包",
      filePath:
        "batch/archive-transfer-final-acceptance-ingest-risk-final-receipt-evidence-package.json",
      artifactRole: "archive_transfer_final_acceptance_ingest_risk_final_receipt_evidence_package",
      schema:
        "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalReceiptEvidencePackage.v1",
      sourceFingerprint: evidencePackage.packageFingerprint,
      required: true,
      handoverStatus: archiveTransferFinalAcceptanceIngestRiskFinalProofEvidenceStatus(
        evidencePackage,
        gate.requiredPlatformCount,
      ),
    },
  ];
  const rows = rowInputs.map((row) => ({
    ...row,
    action: archiveTransferFinalAcceptanceIngestRiskFinalProofRowAction(row),
  }));
  const blockedArtifactCount = rows.filter((row) => row.handoverStatus === "blocked").length;
  const needsReviewArtifactCount = rows.filter((row) => row.handoverStatus === "needs_review").length;
  const readyArtifactCount = rows.filter((row) => row.handoverStatus === "ready").length;
  const proofStatus: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofStatus =
    blockedArtifactCount > 0 ? "blocked" : needsReviewArtifactCount > 0 ? "needs_review" : "ready_for_handover";
  const handoverDecision: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofHandoverDecision =
    proofStatus === "ready_for_handover"
      ? "handover_ready"
      : proofStatus === "needs_review"
        ? "handover_with_review"
        : "handover_blocked";
  const action =
    proofStatus === "ready_for_handover"
      ? "终态签发、跨平台回执、跨系统门禁和原始证据包均满足要求，可按移交清单办理最终入库证明移交。"
      : proofStatus === "needs_review"
        ? "存在需人工复核的入库证明构件，需补充复核意见后谨慎移交。"
        : "最终入库证明仍存在阻断构件，需完成整改并重新执行门禁与证明包生成。";
  const body = {
    schema:
      "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalProofPackage.v1" as const,
    generatedAt,
    batchName: options.batchName?.trim() || `${gate.batchName}最终可归档证明`,
    signoffId: signoff.signoffId,
    proofOwner: options.proofOwner?.trim() || gate.gateOwner || signoff.signedBy || "资料负责人",
    proofStatus,
    handoverDecision,
    sourceSignoffFingerprint: signoff.signoffFingerprint,
    sourceCrossPlatformReviewFingerprint: crossPlatformReview.reviewFingerprint,
    sourceGateFingerprint: gate.gateFingerprint,
    sourceReceiptEvidencePackageFingerprint: evidencePackage.packageFingerprint,
    platformCount: gate.platformCount,
    requiredPlatformCount: gate.requiredPlatformCount,
    evidenceCount: evidencePackage.evidenceCount,
    acceptedCount: evidencePackage.acceptedCount,
    rejectedCount: evidencePackage.rejectedCount,
    pendingCount: evidencePackage.pendingCount,
    missingReceiptCount: evidencePackage.missingReceiptCount,
    unmatchedReceiptCount: evidencePackage.unmatchedReceiptCount,
    issueCount: gate.issueCount,
    blockingIssueCount: gate.blockingIssueCount,
    warningIssueCount: gate.warningIssueCount,
    artifactCount: rows.length,
    requiredArtifactCount: rows.filter((row) => row.required).length,
    readyArtifactCount,
    needsReviewArtifactCount,
    blockedArtifactCount,
    rows,
    action,
  };
  const proofFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    proofFingerprint,
  };
  const csv = archiveTransferFinalAcceptanceIngestRiskFinalProofPackageCsv(rows);
  const markdown = archiveTransferFinalAcceptanceIngestRiskFinalProofPackageMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionAction(
  row: Pick<
    EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRow,
    "sendStatus" | "filePath" | "recipientName" | "dueAt"
  >,
): string {
  if (row.sendStatus === "sent") {
    return `${row.filePath} 已向 ${row.recipientName} 分发，等待外部证明回执回写。`;
  }
  if (row.sendStatus === "ready_to_send") {
    return `${row.filePath} 可向 ${row.recipientName} 分发，截止 ${row.dueAt || "未设定"} 前需取得外部证明回执。`;
  }
  if (row.sendStatus === "needs_review") {
    return `${row.filePath} 所属证明包仍需人工复核，分发前应补充复核意见。`;
  }
  return `${row.filePath} 所属证明包存在阻断项，不得对外分发。`;
}

