function archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformName(
  receipt: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReceipt,
  index: number,
): string {
  return receipt.sourceName?.trim() || receipt.source.sourceName?.trim() || `平台${index + 1}`;
}

function archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformRowKey(row: {
  distributionId?: string;
  recipientId?: string;
  filePath?: string;
}): string {
  const distributionId = rectificationIssueKey(row.distributionId ?? "");
  if (distributionId) return `distribution:${distributionId}`;
  return `recipient-file:${rectificationIssueKey(row.recipientId ?? "")}\u0000${rectificationIssueKey(row.filePath ?? "")}`;
}

export function buildEngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionCrossPlatformReview(
  distribution: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistribution,
  receiptReviews: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReceipt[],
  options: {
    generatedAt?: string;
    batchName?: string;
    requiredPlatformNames?: string[];
  } = {},
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionCrossPlatformReview {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const platforms = receiptReviews.map((receipt, index) => ({
    receipt,
    platformName: archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformName(receipt, index),
  }));
  const platformNames = uniqueNonEmptyStrings(platforms.map((platform) => platform.platformName));
  const requiredPlatformNames = uniqueNonEmptyStrings(options.requiredPlatformNames ?? platformNames);
  const missingPlatformNames = requiredPlatformNames.filter(
    (name) => !platformNames.some((platformName) => rectificationIssueKey(platformName) === rectificationIssueKey(name)),
  );
  const distributionRowKeys = new Set(
    distribution.rows.map((row) => archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformRowKey(row)),
  );
  const rows: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionCrossPlatformReviewRow[] =
    distribution.rows.map((distributionRow) => {
      const platformRows = platforms
        .map((platform) => {
          const row =
            platform.receipt.rows.find(
              (receiptRow) =>
                archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformRowKey(receiptRow) ===
                archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformRowKey(distributionRow),
            ) ?? null;
          return row ? { ...platform, row } : null;
        })
        .filter((item): item is NonNullable<typeof item> => Boolean(item));
      const statuses = platformRows.map((item) => item.row.reconciliationStatus).filter(Boolean);
      const statusSet = new Set(statuses);
      const checksums = platformRows.map((item) => item.row.platformChecksum).filter((value) => value.trim() !== "");
      const checksumSet = new Set(checksums);
      const recipients = platformRows.map((item) => item.row.recipientName).filter((value) => value.trim() !== "");
      const recipientSet = new Set(recipients);
      const targetSystems = platformRows.map((item) => item.row.targetSystem).filter((value) => value.trim() !== "");
      const targetSystemSet = new Set(targetSystems);
      const externalRecordIds = platformRows.map((item) => item.row.externalRecordId).filter((value) => value.trim() !== "");
      const externalRecordSet = new Set(externalRecordIds);
      const issueTypes: string[] = [];
      if (missingPlatformNames.length > 0) issueTypes.push("missing_platform");
      if (platformRows.length < platforms.length || statuses.includes("missing_receipt")) issueTypes.push("missing_receipt");
      if (statusSet.size > 1) issueTypes.push("status_mismatch");
      if (statuses.includes("rejected")) issueTypes.push("rejected_receipt");
      if (statuses.includes("pending")) issueTypes.push("pending_receipt");
      if (statuses.includes("skipped")) issueTypes.push("skipped_receipt");
      if (checksumSet.size > 1) issueTypes.push("checksum_mismatch");
      if (recipientSet.size > 1) issueTypes.push("recipient_mismatch");
      if (targetSystemSet.size > 1) issueTypes.push("target_system_mismatch");
      if (externalRecordSet.size > 1) issueTypes.push("external_record_mismatch");
      const uniqueIssueTypes = uniqueNonEmptyStrings(issueTypes);
      const severity =
        archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformSeverity(uniqueIssueTypes);
      return {
        distributionId: distributionRow.distributionId,
        recipientId: distributionRow.recipientId,
        recipientName: distributionRow.recipientName,
        targetSystem: distributionRow.targetSystem,
        filePath: distributionRow.filePath,
        fileType: distributionRow.fileType,
        reviewStatus:
          archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformRowStatus(uniqueIssueTypes),
        severity,
        issueTypes: uniqueIssueTypes,
        platformStatuses: platformRows
          .map((item) => `${item.platformName}:${item.row.reconciliationStatus}`)
          .join("; "),
        platformRecipients: platformRows
          .map((item) => `${item.platformName}:${item.row.recipientName || "-"}`)
          .join("; "),
        platformTargetSystems: platformRows
          .map((item) => `${item.platformName}:${item.row.targetSystem || "-"}`)
          .join("; "),
        externalRecordIds: platformRows
          .map((item) => `${item.platformName}:${item.row.externalRecordId || "-"}`)
          .join("; "),
        platformChecksums: platformRows
          .map((item) => `${item.platformName}:${item.row.platformChecksum || "-"}`)
          .join("; "),
        action: archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformAction(
          severity,
          uniqueIssueTypes,
          distributionRow.filePath,
        ),
      };
    });
  for (const platform of platforms) {
    for (const receiptRow of platform.receipt.rows) {
      const rowKey = archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformRowKey(receiptRow);
      if (distributionRowKeys.has(rowKey) || receiptRow.reconciliationStatus !== "unmatched_receipt") continue;
      const issueTypes = ["unmatched_receipt"];
      const severity =
        archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformSeverity(issueTypes);
      rows.push({
        distributionId: receiptRow.distributionId,
        recipientId: receiptRow.recipientId,
        recipientName: receiptRow.recipientName,
        targetSystem: receiptRow.targetSystem,
        filePath: receiptRow.filePath,
        fileType: receiptRow.fileType,
        reviewStatus:
          archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformRowStatus(issueTypes),
        severity,
        issueTypes,
        platformStatuses: `${platform.platformName}:${receiptRow.reconciliationStatus}`,
        platformRecipients: `${platform.platformName}:${receiptRow.recipientName || "-"}`,
        platformTargetSystems: `${platform.platformName}:${receiptRow.targetSystem || "-"}`,
        externalRecordIds: `${platform.platformName}:${receiptRow.externalRecordId || "-"}`,
        platformChecksums: `${platform.platformName}:${receiptRow.platformChecksum || "-"}`,
        action: archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformAction(
          severity,
          issueTypes,
          receiptRow.filePath,
        ),
      });
    }
  }
  const issueCount = rows.filter((row) => row.issueTypes.length > 0).length;
  const blockingIssueCount = rows.filter((row) => row.severity === "blocking").length;
  const warningIssueCount = rows.filter((row) => row.severity === "warning").length;
  const body = {
    schema:
      "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionCrossPlatformReview.v1" as const,
    generatedAt,
    batchName: options.batchName?.trim() || `${distribution.batchName}多平台回执复核`,
    signoffId: distribution.signoffId,
    sourceDistributionFingerprint: distribution.distributionFingerprint,
    sourceProofFingerprint: distribution.sourceProofFingerprint,
    sourceReceiptFingerprints: receiptReviews.map((receipt) => receipt.receiptFingerprint),
    platformCount: receiptReviews.length,
    requiredPlatformCount: requiredPlatformNames.length,
    missingPlatformNames,
    recipientCount: distribution.recipientCount,
    fileCount: distribution.fileCount,
    rowCount: rows.length,
    reviewStatus: issueCount > 0 ? ("needs_review" as const) : ("passed" as const),
    issueCount,
    blockingIssueCount,
    warningIssueCount,
    missingReceiptIssueCount: rows.filter((row) => row.issueTypes.includes("missing_receipt")).length,
    unmatchedReceiptIssueCount: rows.filter((row) => row.issueTypes.includes("unmatched_receipt")).length,
    statusMismatchCount: rows.filter((row) => row.issueTypes.includes("status_mismatch")).length,
    checksumMismatchCount: rows.filter((row) => row.issueTypes.includes("checksum_mismatch")).length,
    rows,
  };
  const reviewFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    reviewFingerprint,
  };
  const csv = archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformCsv(rows);
  const markdown = archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionCrossPlatformMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

