export function buildEngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGate(
  distribution: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistribution,
  crossPlatformReview: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionCrossPlatformReview,
  options: {
    generatedAt?: string;
    batchName?: string;
    gateOwner?: string;
    requiredPlatformCount?: number;
  } = {},
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGate {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const requiredPlatformCount = Math.max(
    1,
    options.requiredPlatformCount ?? crossPlatformReview.requiredPlatformCount ?? crossPlatformReview.platformCount,
  );
  const criteria = {
    proof_package_distributed:
      distribution.requiredCount > 0 &&
      distribution.sentCount >= distribution.requiredCount &&
      distribution.blockedCount === 0,
    required_platform_receipts:
      crossPlatformReview.platformCount >= requiredPlatformCount &&
      crossPlatformReview.missingPlatformNames.length === 0,
    no_blocking_cross_platform_issues: crossPlatformReview.blockingIssueCount === 0,
    no_warning_cross_platform_issues: crossPlatformReview.warningIssueCount === 0,
  };
  const passedCriteria = Object.entries(criteria)
    .filter(([, passed]) => passed)
    .map(([key]) => key);
  const failedCriteria = Object.entries(criteria)
    .filter(([, passed]) => !passed)
    .map(([key]) => key);
  const distributionBlocked = !criteria.proof_package_distributed;
  const receiptBlocked =
    !criteria.required_platform_receipts || !criteria.no_blocking_cross_platform_issues;
  const gateStatus: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateStatus =
    distributionBlocked || receiptBlocked
      ? "blocked"
      : failedCriteria.length > 0
        ? "watch"
        : "passed";
  const releaseStatus: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseStatus =
    distributionBlocked
      ? "blocked_by_distribution"
      : receiptBlocked
        ? "blocked_by_proof_receipt"
        : gateStatus === "watch"
          ? "watch_proof_receipt"
          : "ready_for_final_archive";
  const action =
    gateStatus === "passed"
      ? "最终证明已完成分发，多平台证明回执覆盖和一致性满足要求，可放行进入正式归档。"
      : gateStatus === "watch"
        ? "最终证明回执无阻断差异，但仍存在提示项，需保留复核意见后谨慎放行。"
        : distributionBlocked
          ? "暂缓最终证明归档放行，需先补齐必发证明文件分发并重新执行门禁。"
          : "暂缓最终证明归档放行，需补齐平台证明回执并处理阻断差异后重新执行门禁。";
  const body = {
    schema:
      "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGate.v1" as const,
    generatedAt,
    batchName: options.batchName?.trim() || `${crossPlatformReview.batchName}放行门禁`,
    signoffId: distribution.signoffId,
    gateOwner: options.gateOwner?.trim() || distribution.distributionOwner || "资料负责人",
    gateStatus,
    releaseStatus,
    sourceDistributionFingerprint: distribution.distributionFingerprint,
    sourceProofFingerprint: distribution.sourceProofFingerprint,
    sourceCrossPlatformReviewFingerprint: crossPlatformReview.reviewFingerprint,
    sourceReceiptFingerprints: crossPlatformReview.sourceReceiptFingerprints,
    requiredPlatformCount,
    platformCount: crossPlatformReview.platformCount,
    distributionRequiredCount: distribution.requiredCount,
    distributionSentCount: distribution.sentCount,
    issueCount: crossPlatformReview.issueCount,
    blockingIssueCount: crossPlatformReview.blockingIssueCount,
    warningIssueCount: crossPlatformReview.warningIssueCount,
    passedCriteria,
    failedCriteria,
    action,
  };
  const gateFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    gateFingerprint,
  };
  const csv = archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReleaseGateCsv(withoutArtifacts);
  const markdown = archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReleaseGateMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReleaseGateBatchSignoffStatus(
  gate: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGate,
  signoff: EngineeringReviewSignoff,
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoffStatus {
  if (gate.gateStatus === "blocked" || signoff.conclusion === "needs_rework") return "blocked";
  if (signoff.conclusion === "pending_review" || !signoff.reviewer) return "pending";
  if (gate.gateStatus === "watch" || signoff.conclusion === "approved_with_comments") {
    return "signed_with_actions";
  }
  return "signed";
}

function archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReleaseGateBatchSignoffRowStatus(
  gate: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGate,
  row: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionCrossPlatformReviewRow,
  signoff: EngineeringReviewSignoff,
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoffStatus {
  if (
    gate.gateStatus === "blocked" ||
    row.severity === "blocking" ||
    signoff.conclusion === "needs_rework"
  ) {
    return "blocked";
  }
  if (signoff.conclusion === "pending_review" || !signoff.reviewer) return "pending";
  if (
    gate.gateStatus === "watch" ||
    row.severity === "warning" ||
    signoff.conclusion === "approved_with_comments"
  ) {
    return "signed_with_actions";
  }
  return "signed";
}

function archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReleaseGateBatchSignoffAction(
  row: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoffRow,
): string {
  if (row.signatureStatus === "blocked") {
    return `阻断签发：${row.filePath} 未满足最终证明分发放行门禁，需补齐证明回执或处理跨平台差异后重签。`;
  }
  if (row.signatureStatus === "pending") return "补充批量签发人、签发日期和签发结论后再归档。";
  if (row.signatureStatus === "signed_with_actions") {
    return `${row.filePath} 可带备注签发，需保留提示项、外部记录号和平台校验码后继续跟踪。`;
  }
  return `${row.filePath} 已满足最终证明分发放行门禁，可批量签发并进入正式归档。`;
}

