function archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReleaseGateBatchSignoffExternalSyncReceiptAction(
  row: Pick<
    EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoffExternalSyncReceiptRow,
    "reconciliationStatus" | "receiptMessage" | "signatureStatus" | "invalidAccepted" | "distributionId" | "filePath"
  >,
): string {
  if (row.invalidAccepted) {
    return `外部系统已接受 ${row.filePath}，但本地放行签发状态为 ${row.signatureStatus}，不得作为最终归档签收完成；需撤回外部记录或重签后重新回传。`;
  }
  if (row.reconciliationStatus === "accepted") return "外部系统已确认最终证明分发放行签发回传完成。";
  if (row.reconciliationStatus === "rejected") {
    return `外部系统拒绝最终证明放行签发回传：${row.receiptMessage || "未提供原因"}`;
  }
  if (row.reconciliationStatus === "pending") return "外部系统仍在处理最终证明放行签发回传，请继续跟踪外部记录号。";
  if (row.reconciliationStatus === "skipped") {
    return `外部系统跳过最终证明放行签发回传：${row.receiptMessage || "未提供原因"}`;
  }
  if (row.reconciliationStatus === "missing_receipt") {
    return `未收到 ${row.distributionId || row.filePath} 的放行签发外部回传回执，请按分发编号和文件路径追踪。`;
  }
  return "放行签发回传回执未匹配当前签发行，请核对 distribution_id、recipient_id 和 file_path。";
}

