export function buildEngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoffExternalSyncReceipt(
  signoff: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoff,
  options: {
    text: string;
    format?: "csv" | "tsv" | "json";
    sourceName?: string;
    importedAt?: string;
  },
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoffExternalSyncReceipt {
  const importedAt = options.importedAt ?? new Date().toISOString();
  const records =
    parseArchiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReleaseGateBatchSignoffExternalSyncReceiptRecords(
      options.text,
      options.format ?? "csv",
    );
  const recordsByDistributionId = new Map<
    string,
    EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoffExternalSyncReceiptRecord
  >();
  const recordsByRecipientAndFile = new Map<
    string,
    EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoffExternalSyncReceiptRecord
  >();
  for (const record of records) {
    if (record.distributionId) recordsByDistributionId.set(rectificationIssueKey(record.distributionId), record);
    if (record.recipientId && record.filePath) {
      recordsByRecipientAndFile.set(
        `${rectificationIssueKey(record.recipientId)}\u0000${rectificationIssueKey(record.filePath)}`,
        record,
      );
    }
  }
  const matchedRecords = new Set<EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoffExternalSyncReceiptRecord>();
  const rows: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoffExternalSyncReceiptRow[] =
    signoff.rows.map((signoffRow) => {
      const record =
        recordsByDistributionId.get(rectificationIssueKey(signoffRow.distributionId)) ??
        recordsByRecipientAndFile.get(
          `${rectificationIssueKey(signoffRow.recipientId)}\u0000${rectificationIssueKey(signoffRow.filePath)}`,
        ) ??
        null;
      if (record) matchedRecords.add(record);
      const reconciliationStatus: EngineeringBatchExternalSystemImportReceiptReconciliationStatus =
        record?.receiptStatus ?? "missing_receipt";
      const invalidAccepted =
        reconciliationStatus === "accepted" &&
        (signoffRow.signatureStatus === "blocked" || signoffRow.signatureStatus === "pending");
      const draft = {
        distributionId: signoffRow.distributionId,
        recipientId: signoffRow.recipientId,
        recipientName: record?.recipientName || signoffRow.recipientName,
        targetSystem: record?.targetSystem || signoffRow.targetSystem,
        filePath: signoffRow.filePath,
        fileType: signoffRow.fileType,
        signatureStatus: signoffRow.signatureStatus,
        gateStatus: signoffRow.gateStatus,
        releaseStatus: signoffRow.releaseStatus,
        receiptStatus: record?.receiptStatus ?? null,
        reconciliationStatus,
        invalidAccepted,
        externalRecordId: record?.externalRecordId || signoffRow.externalRecordIds,
        receiptMessage: record?.receiptMessage ?? "",
        receivedAt: record?.receivedAt ?? "",
        platformChecksum: record?.platformChecksum || signoffRow.platformChecksums,
        syncedReleaseVersion: record?.syncedReleaseVersion ?? "",
        sourceRowNumber: record?.rowNumber ?? null,
      };
      return {
        ...draft,
        action:
          archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReleaseGateBatchSignoffExternalSyncReceiptAction(
            draft,
          ),
      };
    });
  for (const record of records) {
    if (matchedRecords.has(record) || (!record.distributionId && !record.filePath)) continue;
    const draft = {
      distributionId: record.distributionId,
      recipientId: record.recipientId,
      recipientName: record.recipientName,
      targetSystem: record.targetSystem,
      filePath: record.filePath,
      fileType: archiveTransferFinalSignoffExternalSyncReceiptFileType(record.filePath),
      signatureStatus: "pending" as const,
      gateStatus: signoff.gateStatus,
      releaseStatus: signoff.releaseStatus,
      receiptStatus: record.receiptStatus,
      reconciliationStatus: "unmatched_receipt" as const,
      invalidAccepted: false,
      externalRecordId: record.externalRecordId,
      receiptMessage: record.receiptMessage,
      receivedAt: record.receivedAt,
      platformChecksum: record.platformChecksum,
      syncedReleaseVersion: record.syncedReleaseVersion,
      sourceRowNumber: record.rowNumber,
    };
    rows.push({
      ...draft,
      action:
        archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReleaseGateBatchSignoffExternalSyncReceiptAction(
          draft,
        ),
    });
  }
  const acceptedCount = rows.filter((row) => row.reconciliationStatus === "accepted").length;
  const rejectedCount = rows.filter((row) => row.reconciliationStatus === "rejected").length;
  const pendingCount = rows.filter((row) => row.reconciliationStatus === "pending").length;
  const skippedCount = rows.filter((row) => row.reconciliationStatus === "skipped").length;
  const missingReceiptCount = rows.filter((row) => row.reconciliationStatus === "missing_receipt").length;
  const unmatchedReceiptCount = rows.filter((row) => row.reconciliationStatus === "unmatched_receipt").length;
  const invalidAcceptedCount = rows.filter((row) => row.invalidAccepted).length;
  const body = {
    schema:
      "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReleaseGateBatchSignoffExternalSyncReceipt.v1" as const,
    importedAt,
    sourceName: options.sourceName?.trim() || null,
    batchName: signoff.batchName,
    signoffId: signoff.signoffId,
    sourceSignoffFingerprint: signoff.signoffFingerprint,
    sourceReleaseGateFingerprint: signoff.sourceReleaseGateFingerprint,
    sourceDistributionFingerprint: signoff.sourceDistributionFingerprint,
    sourceProofFingerprint: signoff.sourceProofFingerprint,
    sourceCrossPlatformReviewFingerprint: signoff.sourceCrossPlatformReviewFingerprint,
    sourceReceiptFingerprints: signoff.sourceReceiptFingerprints,
    fileCount: signoff.fileCount,
    rowCount: rows.length,
    acceptedCount,
    rejectedCount,
    pendingCount,
    skippedCount,
    missingReceiptCount,
    unmatchedReceiptCount,
    invalidAcceptedCount,
    followUpCount:
      rejectedCount + pendingCount + missingReceiptCount + unmatchedReceiptCount + invalidAcceptedCount,
    rows,
  };
  const receiptFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    receiptFingerprint,
  };
  const csv =
    archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReleaseGateBatchSignoffExternalSyncReceiptCsv(
      rows,
    );
  const markdown =
    archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReleaseGateBatchSignoffExternalSyncReceiptMarkdown(
      withoutArtifacts,
    );
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveTransferFinalAcceptanceIngestRiskFinalProofVersionComparisonChangeStatus(
  previousRow: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageRow | null,
  currentRow: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageRow | null,
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageVersionComparisonChangeStatus {
  if (!previousRow && currentRow) return "added";
  if (previousRow && !currentRow) return "removed";
  if (!previousRow || !currentRow) return "unchanged";
  if (
    previousRow.sourceFingerprint !== currentRow.sourceFingerprint ||
    previousRow.filePath !== currentRow.filePath ||
    previousRow.schema !== currentRow.schema ||
    previousRow.handoverStatus !== currentRow.handoverStatus
  ) {
    return "changed";
  }
  return "unchanged";
}

function archiveTransferFinalAcceptanceIngestRiskFinalProofVersionComparisonRowAction(
  row: Pick<
    EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageVersionComparisonRow,
    "artifactName" | "changeStatus" | "redistributionRequired" | "currentHandoverStatus"
  >,
): string {
  if (row.changeStatus === "unchanged") return `${row.artifactName} 与上一版一致，可沿用当前证明包审计结论。`;
  if (row.changeStatus === "added") return `${row.artifactName} 为新版新增构件，需纳入证明包换版审计。`;
  if (row.changeStatus === "removed") return `${row.artifactName} 已从新版证明包移除，需确认是否影响最终入库证明完整性。`;
  if (row.currentHandoverStatus === "blocked") return `${row.artifactName} 已变更且当前状态阻断，需整改后重新生成证明包。`;
  if (row.redistributionRequired) return `${row.artifactName} 已变更，旧版证明分发和外部回执不可直接复用。`;
  return `${row.artifactName} 已变更，需保留换版复核意见后使用新版证明包。`;
}

function archiveTransferFinalAcceptanceIngestRiskFinalProofVersionComparisonFileAction(
  row: Pick<
    EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageVersionComparisonFileRow,
    "filePath" | "redistributionStatus" | "previousReceiptStatus"
  >,
): string {
  if (row.redistributionStatus === "current_distribution") {
    return `${row.filePath} 已对应当前证明包版本，可沿用当前分发记录继续跟踪回执。`;
  }
  if (row.redistributionStatus === "needs_redistribution") {
    return `${row.filePath} 对应旧版证明包，需重新分发并重新取得外部证明回执。`;
  }
  return `${row.filePath} 暂无上一版分发记录，本次换版对比仅保留文件级占位。`;
}

