function buildArchiveTransferFinalAcceptanceIngestRiskFinalProofDistributionRectificationLedgerArtifact(input: {
  generatedAt: string;
  batchName: string;
  signoffId: string;
  rectificationOwner: string;
  sourceDistributionFingerprint: string;
  sourceReceiptFingerprint: string | null;
  sourceComparisonFingerprint: string | null;
  sourceProofFingerprint: string;
  rows: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationRow[];
}): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationLedger {
  const rows = input.rows;
  const body = {
    schema:
      "railwise.engineering.batch.archiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationLedger.v1" as const,
    generatedAt: input.generatedAt,
    batchName: input.batchName,
    signoffId: input.signoffId,
    rectificationOwner: input.rectificationOwner,
    sourceDistributionFingerprint: input.sourceDistributionFingerprint,
    sourceReceiptFingerprint: input.sourceReceiptFingerprint,
    sourceComparisonFingerprint: input.sourceComparisonFingerprint,
    sourceProofFingerprint: input.sourceProofFingerprint,
    issueCount: rows.length,
    openIssueCount: rows.filter((row) => row.closureStatus === "open").length,
    closedIssueCount: rows.filter((row) => row.closureStatus === "closed").length,
    criticalIssueCount: rows.filter((row) => row.severity === "critical").length,
    warningIssueCount: rows.filter((row) => row.severity === "warning").length,
    noticeIssueCount: rows.filter((row) => row.severity === "notice").length,
    receiptIssueCount: rows.filter((row) =>
      ["rejected_receipt", "pending_receipt", "missing_receipt", "unmatched_receipt"].includes(row.issueType),
    ).length,
    redistributionIssueCount: rows.filter((row) => row.issueType === "needs_redistribution").length,
    blockedDistributionIssueCount: rows.filter((row) =>
      row.issueType === "blocked_distribution" || row.issueType === "review_before_distribution",
    ).length,
    rows,
  };
  const ledgerFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    ledgerFingerprint,
  };
  const csv = archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionRectificationCsv(rows);
  const markdown =
    archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionRectificationMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionRectificationFileType(
  filePath: string,
): "md" | "csv" | "json" | "other" {
  if (filePath.endsWith(".md")) return "md";
  if (filePath.endsWith(".csv")) return "csv";
  if (filePath.endsWith(".json")) return "json";
  return "other";
}

export function buildEngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationLedger(
  distribution: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistribution,
  options: {
    generatedAt?: string;
    batchName?: string;
    rectificationOwner?: string;
    defaultDueDays?: number;
    distributionReceipt?: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReceipt | null;
    versionComparison?: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageVersionComparison | null;
  } = {},
): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationLedger {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const owner = options.rectificationOwner?.trim() || distribution.distributionOwner || "资料负责人";
  const defaultDueDays = options.defaultDueDays ?? 1;
  const receiptRowsByDistributionId = new Map(
    options.distributionReceipt?.rows.map((row) => [rectificationIssueKey(row.distributionId), row]) ?? [],
  );
  const comparisonFileRowsByPath = new Map(
    options.versionComparison?.fileRows.map((row) => [row.filePath, row]) ?? [],
  );
  const comparisonAppliesToDistribution = Boolean(
    options.versionComparison &&
      (options.versionComparison.sourcePreviousDistributionFingerprint === distribution.distributionFingerprint ||
        distribution.sourceProofFingerprint !== options.versionComparison.sourceCurrentProofFingerprint),
  );
  const rows: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationRow[] =
    [];
  const pushIssue = (input: {
    issueType: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationIssueType;
    distributionRow?: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRow | null;
    receiptRow?: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionReceiptRow | null;
    comparisonFileRow?: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageVersionComparisonFileRow | null;
  }) => {
    const distributionRow = input.distributionRow ?? null;
    const receiptRow = input.receiptRow ?? null;
    const comparisonFileRow = input.comparisonFileRow ?? null;
    const filePath = distributionRow?.filePath || receiptRow?.filePath || comparisonFileRow?.filePath || "";
    const dueAt = distributionRow?.dueAt || addDaysIsoDate(generatedAt, defaultDueDays);
    const severity =
      archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionRectificationSeverity(input.issueType);
    rows.push({
      rectificationId: `${distribution.signoffId}-PROOF-DIST-RECT-${String(rows.length + 1).padStart(3, "0")}`,
      issueType: input.issueType,
      severity,
      recipientId: distributionRow?.recipientId || receiptRow?.recipientId || "",
      recipientName: distributionRow?.recipientName || receiptRow?.recipientName || "",
      targetSystem: distributionRow?.targetSystem || receiptRow?.targetSystem || "",
      filePath,
      fileType:
        distributionRow?.fileType ??
        receiptRow?.fileType ??
        comparisonFileRow?.fileType ??
        archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionRectificationFileType(filePath),
      distributionId: distributionRow?.distributionId || receiptRow?.distributionId || comparisonFileRow?.previousDistributionId || "",
      sourceProofFingerprint: distributionRow?.sourceProofFingerprint || distribution.sourceProofFingerprint,
      sourceDistributionFingerprint: distribution.distributionFingerprint,
      sourceReceiptFingerprint: options.distributionReceipt?.receiptFingerprint ?? null,
      sourceComparisonFingerprint: options.versionComparison?.comparisonFingerprint ?? null,
      sendStatus: distributionRow?.sendStatus ?? receiptRow?.sendStatus ?? comparisonFileRow?.previousSendStatus ?? "",
      receiptStatus: receiptRow?.receiptStatus ?? comparisonFileRow?.previousReceiptStatus ?? null,
      reconciliationStatus: receiptRow?.reconciliationStatus ?? null,
      previousReceiptStatus: comparisonFileRow?.previousReceiptStatus ?? receiptRow?.receiptStatus ?? null,
      externalRecordId:
        receiptRow?.externalRecordId ||
        comparisonFileRow?.previousExternalRecordId ||
        distributionRow?.externalRecordId ||
        "",
      platformChecksum: receiptRow?.platformChecksum || comparisonFileRow?.platformChecksum || "",
      dueAt,
      owner,
      closureStatus: "open",
      closedAt: null,
      closedBy: null,
      closureNote: "",
      closureSourceStatus: "generated_open",
      action: archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionRectificationAction(
        input.issueType,
        filePath,
      ),
    });
  };
  for (const distributionRow of distribution.rows) {
    const receiptRow = receiptRowsByDistributionId.get(rectificationIssueKey(distributionRow.distributionId)) ?? null;
    const comparisonFileRow = comparisonFileRowsByPath.get(distributionRow.filePath) ?? null;
    if (distributionRow.sendStatus === "blocked") {
      pushIssue({ issueType: "blocked_distribution", distributionRow, receiptRow, comparisonFileRow });
    } else if (distributionRow.sendStatus === "needs_review") {
      pushIssue({ issueType: "review_before_distribution", distributionRow, receiptRow, comparisonFileRow });
    }
    if (receiptRow?.reconciliationStatus === "rejected") {
      pushIssue({ issueType: "rejected_receipt", distributionRow, receiptRow, comparisonFileRow });
    } else if (receiptRow?.reconciliationStatus === "pending") {
      pushIssue({ issueType: "pending_receipt", distributionRow, receiptRow, comparisonFileRow });
    } else if (receiptRow?.reconciliationStatus === "missing_receipt") {
      pushIssue({ issueType: "missing_receipt", distributionRow, receiptRow, comparisonFileRow });
    } else if (!receiptRow && options.distributionReceipt) {
      pushIssue({ issueType: "missing_receipt", distributionRow, comparisonFileRow });
    }
    if (
      comparisonAppliesToDistribution &&
      comparisonFileRow?.redistributionStatus === "needs_redistribution"
    ) {
      pushIssue({ issueType: "needs_redistribution", distributionRow, receiptRow, comparisonFileRow });
    }
  }
  for (const receiptRow of options.distributionReceipt?.rows ?? []) {
    if (receiptRow.reconciliationStatus !== "unmatched_receipt") continue;
    pushIssue({ issueType: "unmatched_receipt", receiptRow });
  }
  return buildArchiveTransferFinalAcceptanceIngestRiskFinalProofDistributionRectificationLedgerArtifact({
    generatedAt,
    batchName: options.batchName?.trim() || `${distribution.batchName}整改台账`,
    signoffId: distribution.signoffId,
    rectificationOwner: owner,
    sourceDistributionFingerprint: distribution.distributionFingerprint,
    sourceReceiptFingerprint: options.distributionReceipt?.receiptFingerprint ?? null,
    sourceComparisonFingerprint: options.versionComparison?.comparisonFingerprint ?? null,
    sourceProofFingerprint: distribution.sourceProofFingerprint,
    rows,
  });
}

type EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationClosureRecord = {
  rowNumber: number;
  rectificationId: string;
  distributionId: string;
  filePath: string;
  closureStatus: EngineeringProjectArchiveRectificationClosureStatus;
  closedAt: string | null;
  closedBy: string | null;
  closureNote: string;
  externalRecordId: string;
};

function normalizeArchiveTransferFinalAcceptanceIngestRiskFinalProofDistributionRectificationClosureStatus(
  value: string,
): EngineeringProjectArchiveRectificationClosureStatus {
  const normalized = normalizeLedgerStatus(value);
  return normalized === "closed" || normalized === "ok" ? "closed" : "open";
}

function parseArchiveTransferFinalAcceptanceIngestRiskFinalProofDistributionRectificationClosureInput(
  input: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationClosureInput,
): {
  source: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationClosureSource;
  records: EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationClosureRecord[];
} {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const format: "csv" | "tsv" | "json" =
    input.format === "json" || input.format === "tsv" ? input.format : "csv";
  const rows = externalSystemReceiptRowsFromText(input.text, format);
  const columnNames =
    format === "json"
      ? uniqueNonEmptyStrings(rows.flatMap((row) => Object.keys(row)))
      : (parseDelimitedRows(input.text, format === "tsv" ? "\t" : ",")[0] ?? []);
  const records = rows
    .map(
      (
        row,
        index,
      ): EngineeringBatchArchiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationClosureRecord => {
        const closureStatusText =
          archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReceiptValue(row, [
            "closure_status",
            "closureStatus",
            "status",
            "销项状态",
            "闭环状态",
            "处理状态",
          ]);
        return {
          rowNumber: index + 2,
          rectificationId: archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReceiptValue(row, [
            "rectification_id",
            "rectificationId",
            "issue_id",
            "整改编号",
            "销项编号",
          ]),
          distributionId: archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReceiptValue(row, [
            "distribution_id",
            "distributionId",
            "proof_distribution_id",
            "分发编号",
          ]),
          filePath: archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReceiptValue(row, [
            "file_path",
            "filePath",
            "proof_file_path",
            "证明文件",
            "文件路径",
          ]),
          closureStatus:
            normalizeArchiveTransferFinalAcceptanceIngestRiskFinalProofDistributionRectificationClosureStatus(
              closureStatusText,
            ),
          closedAt:
            archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReceiptValue(row, [
              "closed_at",
              "closedAt",
              "completed_at",
              "销项日期",
              "完成时间",
            ]) || null,
          closedBy:
            archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReceiptValue(row, [
              "closed_by",
              "closedBy",
              "completed_by",
              "销项人",
              "完成人",
            ]) || null,
          closureNote: archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReceiptValue(row, [
            "closure_note",
            "closureNote",
            "note",
            "销项说明",
            "整改说明",
            "备注",
          ]),
          externalRecordId: archiveTransferFinalAcceptanceIngestRiskFinalProofDistributionReceiptValue(row, [
            "external_record_id",
            "externalRecordId",
            "record_id",
            "外部记录号",
            "入库单号",
          ]),
        };
      },
    )
    .filter(
      (record) =>
        record.rectificationId ||
        record.distributionId ||
        record.filePath ||
        record.closedAt ||
        record.closedBy ||
        record.closureNote ||
        record.externalRecordId,
    );
  const sourceBody = {
    schema:
      "railwise.engineering.archiveTransferFinalAcceptanceIngestRiskFinalProofPackageDistributionRectificationClosureSource.v1" as const,
    sourceName: input.sourceName?.trim() || null,
    importedAt,
    format,
    rowCount: records.length,
    columnNames,
  };
  return {
    source: {
      ...sourceBody,
      closureSourceFingerprint: fnv1a32Fingerprint(JSON.stringify({ ...sourceBody, records })),
    },
    records,
  };
}

