function buildEngineeringArchiveAcceptanceReview(args: {
  checkedAt: string;
  archivePackageName: string;
  archiveReleaseRecord: EngineeringBatchArchiveReleaseRecord;
  archiveReleaseDeliveryReadiness: EngineeringBatchArchiveReleaseDeliveryReadiness;
  verificationErrors?: string[];
}): EngineeringArchiveAcceptanceReview {
  const verifierErrorRows = (args.verificationErrors ?? []).map(
    (error, index): EngineeringArchiveAcceptanceReviewRow => ({
      gateId: `verifier_error_${String(index + 1).padStart(3, "0")}`,
      gateName: "归档包校验错误",
      evidencePath: args.archivePackageName,
      evidenceStatus: "invalid",
      required: true,
      sourceFingerprint: "",
      remediationPath: "重新生成完整归档 ZIP",
      action: `修复校验错误：${error}`,
    }),
  );
  const readinessRows = args.archiveReleaseDeliveryReadiness.rows.map(
    (row): EngineeringArchiveAcceptanceReviewRow => {
      const evidenceStatus: EngineeringArchiveAcceptanceEvidenceStatus =
        row.readinessStatus === "ready" ? "verified" : row.readinessStatus;
      return {
        gateId: row.checkpointId,
        gateName: row.checkpointName,
        evidencePath: row.artifactPath,
        evidenceStatus,
        required: row.required,
        sourceFingerprint: row.sourceFingerprint,
        remediationPath: evidenceStatus === "verified" ? "" : row.artifactPath || "补齐对应归档成果",
        action: row.action,
      };
    },
  );
  const rows = [...verifierErrorRows, ...readinessRows];
  const invalidIssueCount = rows.filter((row) => row.evidenceStatus === "invalid").length;
  const missingIssueCount = rows.filter((row) => row.evidenceStatus === "missing").length;
  const actionIssueCount = rows.filter((row) => row.evidenceStatus === "action_required").length;
  const verifiedGateCount = rows.filter((row) => row.evidenceStatus === "verified").length;
  const handoverDecision: EngineeringArchiveAcceptanceDecision =
    invalidIssueCount > 0 ||
    missingIssueCount > 0 ||
    args.archiveReleaseDeliveryReadiness.overallStatus === "blocked"
      ? "reject"
      : args.archiveReleaseDeliveryReadiness.overallStatus === "handover_with_actions" || actionIssueCount > 0
        ? "conditional_acceptance"
        : "accept";
  const nextActions: string[] = [];
  if (invalidIssueCount > 0) {
    nextActions.push("归档包存在校验错误，需由提交方重新生成 ZIP 后再验收。");
  }
  if (missingIssueCount > 0) {
    nextActions.push("补齐所有 missing 关口成果，并重新生成归档 ZIP 与校验报告。");
  }
  if (handoverDecision === "conditional_acceptance") {
    nextActions.push("交接单需列明所有 action_required 关口、责任人和补充回执期限。");
    nextActions.push("接收后按补件路径反查原始成果，完成处置后重新运行归档校验。");
  }
  if (nextActions.length === 0) {
    nextActions.push("按发布版本、发布指纹和清单指纹完成归档接收登记。");
  }
  const body = {
    schema: "railwise.engineeringArchive.acceptanceReview.v1" as const,
    checkedAt: args.checkedAt,
    title: "归档接收验收向导" as const,
    archivePath: null,
    archiveName: args.archivePackageName,
    archivePackageName: args.archivePackageName,
    handoverDecision,
    acceptanceStatusLabel: archiveAcceptanceDecisionLabel(handoverDecision),
    releaseVersion: args.archiveReleaseRecord.releaseVersion,
    releaseFingerprint: args.archiveReleaseRecord.releaseFingerprint,
    readinessFingerprint: args.archiveReleaseDeliveryReadiness.readinessFingerprint,
    readinessOverallStatus: args.archiveReleaseDeliveryReadiness.overallStatus,
    verifiedGateCount,
    actionIssueCount,
    missingIssueCount,
    invalidIssueCount,
    blockingIssueCount:
      invalidIssueCount +
      missingIssueCount +
      (args.archiveReleaseDeliveryReadiness.overallStatus === "blocked" ? 1 : 0),
    nextActions,
    rows,
  };
  const acceptanceFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withFingerprint = {
    ...body,
    acceptanceFingerprint,
  };
  const csv = archiveAcceptanceReviewCsv(rows);
  const markdown = archiveAcceptanceReviewMarkdown(withFingerprint);
  return {
    ...withFingerprint,
    markdown,
    csv,
    json: JSON.stringify(withFingerprint, null, 2),
  };
}

function archiveAcceptanceRemediationEvidenceBundlePath(row: EngineeringArchiveAcceptanceReviewRow): string {
  const sourcePath = row.remediationPath || row.evidencePath || row.gateId;
  const lastSegment = sourcePath.split("/").filter(Boolean).at(-1) ?? row.gateId;
  const fileName =
    lastSegment
      .trim()
      .replace(/[\\/:*?"<>|]+/g, "-")
      .replace(/\s+/g, "-")
      .replace(/-+/g, "-")
      .replace(/^-|-$/g, "") || `${row.gateId}.json`;
  return `remediation/${fileName}`;
}

