export function buildEngineeringArchiveAcceptanceRemediationRecheckPackage(
  review: EngineeringArchiveAcceptanceReview,
  options: { generatedAt?: string; archivePath?: string } = {},
): EngineeringArchiveAcceptanceRemediationRecheckPackage {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const archiveTarget = options.archivePath?.trim() || review.archivePath || review.archivePackageName || review.archiveName;
  const recheckCommand = `npm run verify:engineering-archive -- ${archiveZipRecheckCommandPath(archiveTarget)} --require-clean`;
  const rows = review.rows
    .filter((row) => row.evidenceStatus !== "verified")
    .map((row): EngineeringArchiveAcceptanceRemediationRecheckPackageRow => ({
      gateId: row.gateId,
      gateName: row.gateName,
      evidencePath: row.evidencePath,
      evidenceStatus: row.evidenceStatus,
      required: row.required,
      sourceFingerprint: row.sourceFingerprint,
      remediationPath: row.remediationPath,
      evidenceBundlePath: archiveAcceptanceRemediationEvidenceBundlePath(row),
      recheckCommand,
      action: row.action,
    }));
  const actionIssueCount = rows.filter((row) => row.evidenceStatus === "action_required").length;
  const missingIssueCount = rows.filter((row) => row.evidenceStatus === "missing").length;
  const invalidIssueCount = rows.filter((row) => row.evidenceStatus === "invalid").length;
  const requiredArtifacts = uniqueNonEmptyStrings([
    "修复后的归档 ZIP",
    "补件证据包",
    "verify:engineering-archive --require-clean 校验输出",
    "归档 ZIP 导入验收报告",
    ...rows.map((row) => row.evidenceBundlePath),
  ]);
  const body = {
    schema: "railwise.engineeringArchive.acceptanceRemediationRecheckPackage.v1" as const,
    generatedAt,
    archiveName: review.archiveName,
    archivePackageName: review.archivePackageName,
    handoverDecision: review.handoverDecision,
    acceptanceStatusLabel: review.acceptanceStatusLabel,
    releaseVersion: review.releaseVersion,
    acceptanceFingerprint: review.acceptanceFingerprint,
    readinessFingerprint: review.readinessFingerprint,
    issueRowCount: rows.length,
    actionIssueCount,
    missingIssueCount,
    invalidIssueCount,
    blockingIssueCount: missingIssueCount + invalidIssueCount,
    recheckCommand,
    requiredArtifacts,
    rows,
  };
  const packageFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    packageFingerprint,
  };
  const csv = archiveAcceptanceRemediationRecheckPackageCsv(rows);
  const markdown = archiveAcceptanceRemediationRecheckPackageMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveAcceptanceRecheckRowStatus(
  row: EngineeringArchiveAcceptanceReviewRow,
): EngineeringArchiveAcceptanceRemediationRecheckUpdateStatus {
  if (row.evidenceStatus === "verified") return "closed";
  if (row.evidenceStatus === "missing") return "missing_after_recheck";
  if (row.evidenceStatus === "invalid") return "invalid_after_recheck";
  return "still_open";
}

function archiveAcceptanceRecheckUpdateAction(
  status: EngineeringArchiveAcceptanceRemediationRecheckUpdateStatus,
  row: EngineeringArchiveAcceptanceReviewRow,
): string {
  if (status === "closed") return "重验已核验该补件关口，可随接收记录归档闭环。";
  if (status === "missing_after_recheck") return "重验后仍缺少必备成果，需补齐后再次提交归档 ZIP。";
  if (status === "invalid_after_recheck") return "重验后仍存在无效或校验错误，需重新生成成果并复核 checksums。";
  if (status === "new_recheck_issue") return "重验 ZIP 出现原补件包未列明的新问题，需追加补件并更新交接记录。";
  return row.action || "重验后该关口仍需人工处置，请继续跟踪责任人和补件期限。";
}

