function archiveZipRecheckCommandPath(path: string): string {
  return `"${path.replace(/\\/g, "\\\\").replace(/"/g, '\\"')}"`;
}

function archiveZipImportReviewHistoryRecheckActions(
  record: EngineeringArchiveZipImportReviewHistoryRecord,
): string[] {
  const actions: string[] = [];
  if (record.requiredEntriesMissing > 0) {
    actions.push("补齐归档包必备文件，并重新生成 manifest.json、checksums.csv 与归档 ZIP。");
  }
  if (record.manifestMismatchCount > 0) {
    actions.push("重建 manifest.json，确认清单路径、角色、指纹和发布记录与 ZIP 内实际文件一致。");
  }
  if (record.checksumMismatchCount > 0) {
    actions.push("重新计算 checksums.csv，并确认 manifest.json 中记录的 checksum 与 ZIP 内文件字节一致。");
  }
  if (record.errorCount > 0) {
    actions.push("处理导入验收错误，逐条核对验收报告中的错误信息和补件路径。");
  }
  if (record.warningCount > 0) {
    actions.push("复核验收警告并在整改说明中记录保留、替换或豁免依据。");
  }
  actions.push("重新运行归档 ZIP 导入验收，保留新的验收 JSON、CSV 或 HTML 报告。");
  actions.push("将新验收记录导入 ZIP 验收历史台账，确认发布指纹、就绪指纹和报告指纹已更新。");
  return uniqueNonEmptyStrings(actions);
}

export function buildEngineeringArchiveZipImportReviewHistoryRecheckPlan(
  record: EngineeringArchiveZipImportReviewHistoryRecord,
  options: { generatedAt?: string } = {},
): EngineeringArchiveZipImportReviewHistoryRecheckPlan {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const sourcePath = record.sourcePath || record.archiveName;
  const quotedSourcePath = archiveZipRecheckCommandPath(sourcePath);
  const actions = archiveZipImportReviewHistoryRecheckActions(record);
  const requiredArtifacts = uniqueNonEmptyStrings([
    "修复后的归档 ZIP",
    "verify:engineering-archive --require-clean 校验输出",
    "归档 ZIP 导入验收报告",
    "补件或整改说明",
    record.releaseFingerprint ? "归档包版本发布记录" : "",
    record.readinessFingerprint ? "归档发布交付就绪清单" : "",
  ]);
  const commands = [
    `npm run verify:engineering-archive -- ${quotedSourcePath} --require-clean`,
    `npm run verify:engineering-archive -- ${quotedSourcePath} --json --require-clean > archive-recheck-report.json`,
  ];
  const body = {
    schema: "railwise.engineeringArchive.importReviewHistoryRecheckPlan.v1" as const,
    generatedAt,
    recordId: record.recordId,
    title: `${record.archiveName} 重验计划`,
    sourcePath,
    acceptanceDecision: record.acceptanceDecision,
    acceptanceStatusLabel: record.acceptanceStatusLabel,
    actions,
    requiredArtifacts,
    commands,
  };
  const planFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const markdown = [
    "# ZIP 验收历史重验计划",
    "",
    `生成时间：${generatedAt}`,
    `归档文件：${record.archiveName}`,
    `来源路径：${sourcePath}`,
    `验收结论：${record.acceptanceStatusLabel}`,
    `验收人：${record.operator || "未填验收人"}`,
    `记录时间：${record.recordedAt}`,
    `验收时间：${record.checkedAt}`,
    `报告指纹：${record.reportFingerprint}`,
    `发布指纹：${record.releaseFingerprint || "未记录"}`,
    `验收就绪指纹：${record.readinessFingerprint || "未记录"}`,
    `计划指纹：${planFingerprint}`,
    "",
    "## 异常概况",
    "",
    `- 缺项：${record.requiredEntriesMissing}`,
    `- Manifest 异常：${record.manifestMismatchCount}`,
    `- Checksum 异常：${record.checksumMismatchCount}`,
    `- 错误：${record.errorCount}`,
    `- 警告：${record.warningCount}`,
    `- 问题摘要：${record.issueSummary || "无"}`,
    "",
    "## 重验动作",
    "",
    ...actions.map((action, index) => `${index + 1}. ${action}`),
    "",
    "## 需归档证据",
    "",
    ...requiredArtifacts.map((artifact) => `- ${artifact}`),
    "",
    "## 命令模板",
    "",
    ...commands.map((command) => `- \`${command}\``),
  ].join("\n");
  return {
    ...body,
    markdown,
    planFingerprint,
  };
}

function writeSavedEngineeringArchiveZipImportReviewHistory(
  history: EngineeringArchiveZipImportReviewHistory,
): boolean {
  try {
    engineeringLocalStorage()?.setItem(
      ARCHIVE_ZIP_IMPORT_REVIEW_HISTORY_STORAGE_KEY,
      JSON.stringify({
        schema: history.schema,
        generatedAt: history.generatedAt,
        records: history.records,
        historyFingerprint: history.historyFingerprint,
      }),
    );
    return true;
  } catch {
    return false;
  }
}

export function readSavedEngineeringArchiveZipImportReviewHistory():
  | EngineeringArchiveZipImportReviewHistory
  | null {
  try {
    const raw = engineeringLocalStorage()?.getItem(ARCHIVE_ZIP_IMPORT_REVIEW_HISTORY_STORAGE_KEY);
    if (!raw) return null;
    const parsed = objectFrom(JSON.parse(raw));
    const records = arrayFrom(parsed.records)
      .map(cleanArchiveZipImportReviewHistoryRecord)
      .filter((record): record is EngineeringArchiveZipImportReviewHistoryRecord => Boolean(record));
    return records.length > 0
      ? buildEngineeringArchiveZipImportReviewHistory(records, {
          generatedAt: textFrom(parsed.generatedAt, "") || undefined,
        })
      : null;
  } catch {
    return null;
  }
}

export function appendSavedEngineeringArchiveZipImportReviewHistory(
  review: EngineeringArchiveZipImportReview,
  options: { operator?: string; sourcePath?: string; recordedAt?: string } = {},
): EngineeringArchiveZipImportReviewHistory {
  const current = readSavedEngineeringArchiveZipImportReviewHistory();
  const nextRecord = archiveZipImportReviewHistoryRecord(review, options);
  const history = buildEngineeringArchiveZipImportReviewHistory([nextRecord, ...(current?.records ?? [])], {
    generatedAt: nextRecord.recordedAt,
  });
  writeSavedEngineeringArchiveZipImportReviewHistory(history);
  return history;
}

export function buildEngineeringArchiveZipImportReviewHistoryExport(
  history: EngineeringArchiveZipImportReviewHistory,
  options: { generatedAt?: string } = {},
): EngineeringArchiveZipImportReviewHistory {
  return buildEngineeringArchiveZipImportReviewHistory(history.records, {
    generatedAt: options.generatedAt ?? history.generatedAt,
  });
}

export function applyEngineeringArchiveZipImportReviewHistoryJson(
  text: string,
  options: { importedAt?: string; sourceName?: string } = {},
): EngineeringArchiveZipImportReviewHistoryImportReport {
  const importedAt = options.importedAt ?? new Date().toISOString();
  const parsed = objectFrom(JSON.parse(text));
  if (textFrom(parsed.schema, "") !== "railwise.engineeringArchive.importReviewHistory.v1") {
    throw new Error("不是 Railwise ZIP 验收历史台账 JSON");
  }
  const importedRecords = arrayFrom(parsed.records)
    .map(cleanArchiveZipImportReviewHistoryRecord)
    .filter((record): record is EngineeringArchiveZipImportReviewHistoryRecord => Boolean(record));
  const importedHistory = buildEngineeringArchiveZipImportReviewHistory(importedRecords, {
    generatedAt: textFrom(parsed.generatedAt, "") || importedAt,
  });
  const current = readSavedEngineeringArchiveZipImportReviewHistory();
  const currentByFingerprint = new Map((current?.records ?? []).map((record) => [record.reportFingerprint, record]));
  const auditRows: EngineeringArchiveZipImportReviewHistoryImportAuditRow[] = importedHistory.records.map((record) => {
    const matchedExistingRecord = currentByFingerprint.get(record.reportFingerprint) ?? null;
    return matchedExistingRecord
      ? {
          disposition: "duplicate",
          record,
          matchedExistingRecord,
          reason: "reportFingerprint 已存在于本机历史，跳过重复记录。",
        }
      : {
          disposition: "added",
          record,
          matchedExistingRecord: null,
          reason: "外部验收记录不存在于本机历史，已合并入库。",
        };
  });
  const addedRecords = auditRows.filter((row) => row.disposition === "added").map((row) => row.record);
  const duplicateRecordCount = importedHistory.records.length - addedRecords.length;
  const updatedHistory = buildEngineeringArchiveZipImportReviewHistory(
    [...addedRecords, ...(current?.records ?? [])],
    { generatedAt: importedAt },
  );
  const historyApplied = writeSavedEngineeringArchiveZipImportReviewHistory(updatedHistory);
  const warnings = [
    duplicateRecordCount > 0 ? `已跳过 ${duplicateRecordCount} 条重复验收历史记录` : "",
    historyApplied ? "" : "ZIP 验收历史合并后保存失败",
  ].filter(Boolean);
  return {
    schema: "railwise.engineeringArchive.importReviewHistoryImport.v1",
    importedAt,
    sourceName: options.sourceName?.trim() || null,
    importedRecordCount: importedHistory.recordCount,
    previousRecordCount: current?.recordCount ?? 0,
    addedRecordCount: addedRecords.length,
    duplicateRecordCount,
    mergedRecordCount: updatedHistory.recordCount,
    historyApplied,
    previousHistoryFingerprint: current?.historyFingerprint ?? null,
    importedHistoryFingerprint: importedHistory.historyFingerprint,
    updatedHistoryFingerprint: updatedHistory.historyFingerprint,
    updatedHistory,
    auditRows,
    warnings,
  };
}

