function archiveZipImportAuditRowValue(
  record: EngineeringArchiveZipImportReviewHistoryRecord | null,
  field: string,
): string {
  if (!record) return "本机无匹配记录";
  switch (field) {
    case "archiveName":
      return record.archiveName;
    case "recordedAt":
      return record.recordedAt;
    case "checkedAt":
      return record.checkedAt;
    case "operator":
      return record.operator || "未填验收人";
    case "sourcePath":
      return record.sourcePath || "未记录";
    case "acceptanceStatusLabel":
      return record.acceptanceStatusLabel;
    case "entryCount":
      return String(record.entryCount);
    case "requiredEntriesMissing":
      return String(record.requiredEntriesMissing);
    case "manifestMismatchCount":
      return String(record.manifestMismatchCount);
    case "checksumMismatchCount":
      return String(record.checksumMismatchCount);
    case "errorCount":
      return String(record.errorCount);
    case "warningCount":
      return String(record.warningCount);
    case "releaseFingerprint":
      return record.releaseFingerprint || "未记录";
    case "readinessFingerprint":
      return record.readinessFingerprint || "未记录";
    case "reportFingerprint":
      return record.reportFingerprint;
    case "issueSummary":
      return record.issueSummary || "无";
    default:
      return "";
  }
}

function archiveZipImportAuditRowDifferences(
  row: EngineeringArchiveZipImportReviewHistoryImportAuditRow,
): EngineeringArchiveZipImportReviewHistoryImportAuditRowDifference[] {
  const fields = [
    ["archiveName", "归档文件"],
    ["recordedAt", "记录时间"],
    ["checkedAt", "验收时间"],
    ["operator", "验收人"],
    ["sourcePath", "来源路径"],
    ["acceptanceStatusLabel", "验收结论"],
    ["entryCount", "条目数"],
    ["requiredEntriesMissing", "缺项"],
    ["manifestMismatchCount", "Manifest 异常"],
    ["checksumMismatchCount", "Checksum 异常"],
    ["errorCount", "错误"],
    ["warningCount", "警告"],
    ["releaseFingerprint", "发布指纹"],
    ["readinessFingerprint", "验收就绪指纹"],
    ["reportFingerprint", "报告指纹"],
    ["issueSummary", "问题摘要"],
  ] as const;
  return fields.map(([field, label]) => {
    const importedValue = archiveZipImportAuditRowValue(row.record, field);
    const existingValue = archiveZipImportAuditRowValue(row.matchedExistingRecord, field);
    return {
      field,
      label,
      importedValue,
      existingValue,
      status: row.matchedExistingRecord ? (importedValue === existingValue ? "same" : "changed") : "added",
    };
  });
}

function archiveZipImportAuditRowDetailMarkdown(
  detail: Omit<EngineeringArchiveZipImportReviewHistoryImportAuditRowDetail, "markdown" | "trackingText">,
): string {
  const rows = detail.differences
    .map((difference) =>
      [
        difference.label,
        difference.importedValue,
        difference.existingValue,
        difference.status === "same" ? "一致" : difference.status === "changed" ? "不一致" : "新增",
      ].map(markdownTableCell).join(" | "),
    )
    .map((row) => `| ${row} |`);
  return [
    "# ZIP 验收历史导入审计行详情",
    "",
    `生成时间：${detail.generatedAt}`,
    `归档文件：${detail.title}`,
    `处置：${detail.disposition === "added" ? "新增" : "重复"}`,
    `摘要：${detail.summary}`,
    "",
    "## 导入记录",
    "",
    detail.recordDetail.trackingText,
    "",
    "## 重复记录差异",
    "",
    "| 字段 | 导入值 | 本机值 | 状态 |",
    "| --- | --- | --- | --- |",
    ...rows,
  ].join("\n");
}

export function buildEngineeringArchiveZipImportReviewHistoryImportAuditRowDetail(
  row: EngineeringArchiveZipImportReviewHistoryImportAuditRow,
  options: { generatedAt?: string } = {},
): EngineeringArchiveZipImportReviewHistoryImportAuditRowDetail {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const recordDetail = buildEngineeringArchiveZipImportReviewHistoryRecordDetail(row.record);
  const differences = archiveZipImportAuditRowDifferences(row);
  const duplicateDifferenceCount = row.matchedExistingRecord
    ? differences.filter((difference) => difference.status === "changed").length
    : 0;
  const summary =
    row.disposition === "added"
      ? `新增记录 · ${row.record.acceptanceStatusLabel} · ${row.reason}`
      : `重复记录 · 差异 ${duplicateDifferenceCount} 项 · ${row.reason}`;
  const body = {
    schema: "railwise.engineeringArchive.importReviewHistoryImportAuditRowDetail.v1" as const,
    generatedAt,
    disposition: row.disposition,
    recordId: row.record.recordId,
    title: row.record.archiveName,
    summary,
    duplicateDifferenceCount,
    recordDetail,
    differences,
  };
  const trackingText = [
    `归档文件：${row.record.archiveName}`,
    `处置：${row.disposition === "added" ? "新增" : "重复"}`,
    `原因：${row.reason}`,
    `摘要：${summary}`,
    "",
    "导入记录",
    recordDetail.trackingText,
    "",
    "重复记录差异",
    ...differences
      .filter((difference) => difference.status !== "same")
      .map((difference) => `${difference.label}：导入=${difference.importedValue}；本机=${difference.existingValue}`),
  ].join("\n");
  const markdown = archiveZipImportAuditRowDetailMarkdown(body);
  return {
    ...body,
    trackingText,
    markdown,
  };
}

function archiveZipImportIssueHandoverAction(
  record: EngineeringArchiveZipImportReviewHistoryRecord,
): string {
  if (record.acceptanceDecision === "reject") {
    return "新增拒收记录需按重验计划完成补件、重算校验和重新导入验收历史。";
  }
  if (record.requiredEntriesMissing > 0 || record.manifestMismatchCount > 0 || record.checksumMismatchCount > 0) {
    return "新增异常记录需复核归档清单、checksum 和补件证据，确认后再转入接收或条件接收。";
  }
  return "新增带警告记录需补充复核说明，确认不影响归档接收后再关闭。";
}

