function archiveZipImportIssueRectificationDispatchPriority(
  row: EngineeringArchiveZipImportReviewHistoryImportIssueHandoverRow,
): EngineeringProjectArchiveRectificationPriority {
  if (
    row.acceptanceDecision === "reject" ||
    row.requiredEntriesMissing > 0 ||
    row.manifestMismatchCount > 0 ||
    row.checksumMismatchCount > 0 ||
    row.errorCount > 0
  ) {
    return "high";
  }
  if (row.warningCount > 0) return "normal";
  return "low";
}

function archiveZipImportIssueRectificationRequiredEvidence(
  row: EngineeringArchiveZipImportReviewHistoryImportIssueHandoverRow,
): string {
  if (row.acceptanceDecision === "reject") {
    return "补件包或重新打包 ZIP、更新后的 manifest/checksum、复验报告和验收历史导入截图。";
  }
  if (
    row.requiredEntriesMissing > 0 ||
    row.manifestMismatchCount > 0 ||
    row.checksumMismatchCount > 0 ||
    row.errorCount > 0
  ) {
    return "问题项修复说明、更新后的 manifest/checksum、重验命令输出和复核人签字。";
  }
  return "警告复核说明、风险接受依据和复核人签字。";
}

function archiveZipImportIssueRectificationAction(
  row: EngineeringArchiveZipImportReviewHistoryImportIssueHandoverRow,
): string {
  return `${row.action} 完成后重新导入 ZIP 验收历史，并核对报告指纹 ${row.reportFingerprint}。`;
}

function archiveZipImportIssueRectificationDispatchMarkdown(
  dispatch: Omit<
    EngineeringArchiveZipImportReviewHistoryImportIssueRectificationDispatch,
    "markdown" | "csv" | "json"
  >,
): string {
  const rows = dispatch.rows
    .map((row) =>
      [
        row.issueId,
        row.archiveName,
        row.owner,
        row.dueAt,
        row.priority,
        row.status,
        row.requiredEvidence,
        row.verifyCommand,
        row.action,
      ].map(markdownTableCell).join(" | "),
    )
    .map((row) => `| ${row} |`);
  return [
    "# ZIP 验收历史新增异常整改派单",
    "",
    `来源：${dispatch.sourceName || "未命名 JSON"}`,
    `导入时间：${dispatch.importedAt}`,
    `生成时间：${dispatch.generatedAt}`,
    `派单记录：${dispatch.issueRecordCount} 条`,
    `未关闭：${dispatch.openCount} 条`,
    `高优先级：${dispatch.highPriorityCount} 条；普通：${dispatch.normalPriorityCount} 条；低：${dispatch.lowPriorityCount} 条`,
    `联动筛选命中：${dispatch.filterResult.matchedRecordCount}/${dispatch.filterResult.totalRecordCount}`,
    `来源台账指纹：${dispatch.sourceLedgerFingerprint}`,
    `派单指纹：${dispatch.dispatchFingerprint}`,
    "",
    "| 派单编号 | 归档文件 | 责任人 | 截止日期 | 优先级 | 状态 | 必备证据 | 复验命令 | 整改动作 |",
    "| --- | --- | --- | --- | --- | --- | --- | --- | --- |",
    ...(rows.length > 0
      ? rows
      : ["| 无新增异常 | - | - | - | low | closed | 无需补充证据。 | - | 本次导入未新增异常记录。 |"]),
    "",
    "## 复核要求",
    "",
    ...(dispatch.rows.length > 0
      ? dispatch.rows.map(
          (row) =>
            `- ${row.archiveName}：执行 \`${row.verifyCommand}\`，通过后重新导入验收历史并核对重验计划 ${row.recheckPlanFingerprint}。`,
        )
      : ["- 无需复核。"]),
  ].join("\n");
}

