function buildArchiveZipImportIssueRectificationDispatchArtifact(input: {
  schema: "railwise.engineeringArchive.importReviewHistoryImportIssueRectificationDispatch.v1";
  generatedAt: string;
  fileBaseName: string;
  sourceName: string | null;
  importedAt: string;
  sourceLedgerFingerprint: string;
  filter: { recordIds: string[]; issueOnly: true };
  filterResult: EngineeringArchiveZipImportReviewHistoryFilterResult;
  rows: EngineeringArchiveZipImportReviewHistoryImportIssueRectificationDispatchRow[];
}): EngineeringArchiveZipImportReviewHistoryImportIssueRectificationDispatch {
  const csv = archiveZipImportIssueRectificationDispatchCsv(input.rows);
  const bodyWithoutFingerprint = {
    ...input,
    issueRecordCount: input.rows.length,
    openCount: input.rows.filter((row) => row.status === "open").length,
    highPriorityCount: input.rows.filter((row) => row.priority === "high").length,
    normalPriorityCount: input.rows.filter((row) => row.priority === "normal").length,
    lowPriorityCount: input.rows.filter((row) => row.priority === "low").length,
  };
  const dispatchFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...bodyWithoutFingerprint, csv }));
  const body = {
    ...bodyWithoutFingerprint,
    dispatchFingerprint,
  };
  const markdown = archiveZipImportIssueRectificationDispatchMarkdown(body);
  return {
    ...body,
    markdown,
    csv,
    json: JSON.stringify({ ...body, markdown, csv }, null, 2),
  };
}

export function buildEngineeringArchiveZipImportReviewHistoryImportIssueRectificationDispatch(
  report: EngineeringArchiveZipImportReviewHistoryImportReport,
  options: { generatedAt?: string; owner?: string; dueAt?: string; defaultDueDays?: number } = {},
): EngineeringArchiveZipImportReviewHistoryImportIssueRectificationDispatch {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const dueAt = options.dueAt ?? addDaysIsoDate(generatedAt, options.defaultDueDays ?? 3);
  const ledger = buildEngineeringArchiveZipImportReviewHistoryImportIssueLedger(report, { generatedAt });
  const schema = "railwise.engineeringArchive.importReviewHistoryImportIssueRectificationDispatch.v1" as const;
  const fileBaseName = `railwise-engineering-archive-import-history-issue-rectification-dispatch-${generatedAt.slice(
    0,
    10,
  )}`;
  const rows: EngineeringArchiveZipImportReviewHistoryImportIssueRectificationDispatchRow[] = ledger.rows.map(
    (row, index) => {
      const priority = archiveZipImportIssueRectificationDispatchPriority(row);
      return {
        issueId: `${row.recordId}-RECTIFY-${String(index + 1).padStart(3, "0")}`,
        recordId: row.recordId,
        archiveName: row.archiveName,
        acceptanceDecision: row.acceptanceDecision,
        acceptanceStatusLabel: row.acceptanceStatusLabel,
        owner: options.owner?.trim() || row.operator || "资料员",
        dueAt,
        priority,
        status: "open",
        operator: row.operator,
        sourcePath: row.sourcePath,
        recordedAt: row.recordedAt,
        checkedAt: row.checkedAt,
        requiredEntriesMissing: row.requiredEntriesMissing,
        manifestMismatchCount: row.manifestMismatchCount,
        checksumMismatchCount: row.checksumMismatchCount,
        errorCount: row.errorCount,
        warningCount: row.warningCount,
        issueSummary: row.issueSummary,
        reportFingerprint: row.reportFingerprint,
        recheckPlanFingerprint: row.recheckPlanFingerprint,
        verifyCommand: row.verifyCommand,
        requiredEvidence: archiveZipImportIssueRectificationRequiredEvidence(row),
        action: archiveZipImportIssueRectificationAction(row),
        closedAt: null,
        closedBy: null,
        closureNote: "",
        closureExternalRecordId: "",
        closureSourceStatus: "generated_open",
      };
    },
  );
  return buildArchiveZipImportIssueRectificationDispatchArtifact({
    schema,
    generatedAt,
    fileBaseName,
    sourceName: report.sourceName,
    importedAt: report.importedAt,
    sourceLedgerFingerprint: ledger.ledgerFingerprint,
    filter: ledger.filter,
    filterResult: ledger.filterResult,
    rows,
  });
}

type EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureRecord = {
  rowNumber: number;
  issueId: string;
  recordId: string;
  archiveName: string;
  sourcePath: string;
  closureStatus: EngineeringProjectArchiveRectificationClosureStatus;
  closedAt: string | null;
  closedBy: string | null;
  closureNote: string;
  externalRecordId: string;
};

function archiveZipImportIssueRectificationClosureFormat(
  input: EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureInput,
): EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureFormat {
  if (input.format === "json" || input.format === "tsv" || input.format === "csv") return input.format;
  const detected = inferEngineeringInputFormat(input.sourceName ?? "", input.text);
  if (detected === "json") return "json";
  if (detected === "tsv") return "tsv";
  return "csv";
}

function normalizeArchiveZipImportIssueRectificationClosureStatus(
  value: string,
): EngineeringProjectArchiveRectificationClosureStatus {
  const normalized = normalizeLedgerStatus(value);
  return normalized === "closed" || normalized === "ok" ? "closed" : "open";
}

function parseArchiveZipImportIssueRectificationClosureInput(
  input: EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureInput,
): {
  source: EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureSource;
  records: EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureRecord[];
} {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const format = archiveZipImportIssueRectificationClosureFormat(input);
  const rows = externalSystemReceiptRowsFromText(input.text, format);
  const columnNames =
    format === "json"
      ? uniqueNonEmptyStrings(rows.flatMap((row) => Object.keys(row)))
      : (parseDelimitedRows(input.text, format === "tsv" ? "\t" : ",")[0] ?? []);
  const records = rows
    .map((row, index): EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureRecord => {
      const closureStatusText = finalReceiptValue(row, ["closure_status", "status", "closed_status", "销项状态", "闭环状态"]);
      return {
        rowNumber: index + 2,
        issueId: finalReceiptValue(row, ["issue_id", "issueId", "派单编号", "问题编号"]),
        recordId: finalReceiptValue(row, ["record_id", "recordId", "验收记录编号"]),
        archiveName: finalReceiptValue(row, ["archive_name", "archiveName", "归档文件"]),
        sourcePath: finalReceiptValue(row, ["source_path", "sourcePath", "来源路径"]),
        closureStatus: normalizeArchiveZipImportIssueRectificationClosureStatus(closureStatusText),
        closedAt: finalReceiptValue(row, ["closed_at", "closedAt", "完成时间", "销项时间"]) || null,
        closedBy: finalReceiptValue(row, ["closed_by", "closedBy", "完成人", "销项人"]) || null,
        closureNote: finalReceiptValue(row, ["closure_note", "closureNote", "note", "remarks", "说明", "备注"]),
        externalRecordId: finalReceiptValue(row, ["external_record_id", "externalRecordId", "外部记录编号"]),
      };
    })
    .filter(
      (record) =>
        record.issueId ||
        record.recordId ||
        record.archiveName ||
        record.sourcePath ||
        record.closedAt ||
        record.closedBy ||
        record.closureNote ||
        record.externalRecordId,
    );
  const sourceBody = {
    schema: "railwise.engineeringArchive.importReviewHistoryImportIssueRectificationClosureSource.v1" as const,
    sourceName: input.sourceName ?? null,
    importedAt,
    format,
    rowCount: records.length,
    columnNames,
  };
  return {
    source: {
      ...sourceBody,
      closureSourceFingerprint: fnv1a32Fingerprint(JSON.stringify({ ...sourceBody, records })),
    },
    records,
  };
}

