function archiveZipImportIssueRectificationRecordKey(value: string): string {
  return rectificationIssueKey(value);
}

export function buildEngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureUpdate(
  dispatch: EngineeringArchiveZipImportReviewHistoryImportIssueRectificationDispatch,
  input: EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureInput,
): EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureUpdate {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const { source, records } = parseArchiveZipImportIssueRectificationClosureInput({ ...input, importedAt });
  const recordsByIssueId = new Map<string, EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureRecord>();
  const recordsByRecordId = new Map<string, EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureRecord>();
  const recordsByArchiveName = new Map<string, EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureRecord>();
  const recordsBySourcePath = new Map<string, EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureRecord>();
  for (const record of records) {
    if (record.issueId) recordsByIssueId.set(archiveZipImportIssueRectificationRecordKey(record.issueId), record);
    if (record.recordId) recordsByRecordId.set(archiveZipImportIssueRectificationRecordKey(record.recordId), record);
    if (record.archiveName) recordsByArchiveName.set(archiveZipImportIssueRectificationRecordKey(record.archiveName), record);
    if (record.sourcePath) recordsBySourcePath.set(archiveZipImportIssueRectificationRecordKey(record.sourcePath), record);
  }
  const matchedRecords = new Set<EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureRecord>();
  const updateRows: EngineeringArchiveZipImportReviewHistoryImportIssueRectificationClosureUpdateRow[] = [];
  const updatedRows = dispatch.rows.map((row): EngineeringArchiveZipImportReviewHistoryImportIssueRectificationDispatchRow => {
    const record =
      recordsByIssueId.get(archiveZipImportIssueRectificationRecordKey(row.issueId)) ??
      recordsByRecordId.get(archiveZipImportIssueRectificationRecordKey(row.recordId)) ??
      recordsByArchiveName.get(archiveZipImportIssueRectificationRecordKey(row.archiveName)) ??
      recordsBySourcePath.get(archiveZipImportIssueRectificationRecordKey(row.sourcePath)) ??
      null;
    if (!record) {
      updateRows.push({
        updateStatus: "missing_update",
        issueId: row.issueId,
        recordId: row.recordId,
        archiveName: row.archiveName,
        owner: row.owner,
        sourcePath: row.sourcePath,
        closureStatus: row.status,
        closedAt: row.closedAt,
        closedBy: row.closedBy,
        closureNote: row.closureNote,
        externalRecordId: row.closureExternalRecordId,
        sourceRowNumber: null,
        action: "尚未收到该 ZIP 新增异常整改派单的销项回执。",
      });
      return {
        ...row,
        closureSourceStatus: row.status === "closed" ? row.closureSourceStatus : "missing_rectification_receipt",
      };
    }
    matchedRecords.add(record);
    const closedAt = record.closureStatus === "closed" ? record.closedAt ?? importedAt.slice(0, 10) : record.closedAt;
    const nextRow: EngineeringArchiveZipImportReviewHistoryImportIssueRectificationDispatchRow = {
      ...row,
      status: record.closureStatus,
      closedAt,
      closedBy: record.closedBy ?? row.closedBy,
      closureNote: record.closureNote || row.closureNote,
      closureExternalRecordId: record.externalRecordId || row.closureExternalRecordId,
      closureSourceStatus:
        record.closureStatus === "closed"
          ? "closed_by_rectification_receipt"
          : "kept_open_by_rectification_receipt",
    };
    updateRows.push({
      updateStatus: record.closureStatus === "closed" ? "closed" : "kept_open",
      issueId: row.issueId,
      recordId: row.recordId,
      archiveName: row.archiveName,
      owner: row.owner,
      sourcePath: row.sourcePath,
      closureStatus: record.closureStatus,
      closedAt: nextRow.closedAt,
      closedBy: nextRow.closedBy,
      closureNote: nextRow.closureNote,
      externalRecordId: nextRow.closureExternalRecordId,
      sourceRowNumber: record.rowNumber,
      action:
        record.closureStatus === "closed"
          ? "销项回执确认该 ZIP 新增异常整改派单已闭环。"
          : "销项回执仍保持打开，请继续跟踪重验和归档补件。",
    });
    return nextRow;
  });
  for (const record of records) {
    if (matchedRecords.has(record) || (!record.issueId && !record.recordId && !record.archiveName && !record.sourcePath)) {
      continue;
    }
    updateRows.push({
      updateStatus: "unmatched_update",
      issueId: record.issueId,
      recordId: record.recordId,
      archiveName: record.archiveName,
      owner: "",
      sourcePath: record.sourcePath,
      closureStatus: record.closureStatus,
      closedAt: record.closedAt,
      closedBy: record.closedBy,
      closureNote: record.closureNote,
      externalRecordId: record.externalRecordId,
      sourceRowNumber: record.rowNumber,
      action: "销项回执未匹配当前 ZIP 新增异常整改派单，请核对 issue_id、record_id、archive_name 或 source_path。",
    });
  }
  const updatedDispatch = buildArchiveZipImportIssueRectificationDispatchArtifact({
    schema: dispatch.schema,
    generatedAt: dispatch.generatedAt,
    fileBaseName: dispatch.fileBaseName,
    sourceName: dispatch.sourceName,
    importedAt: dispatch.importedAt,
    sourceLedgerFingerprint: dispatch.sourceLedgerFingerprint,
    filter: dispatch.filter,
    filterResult: dispatch.filterResult,
    rows: updatedRows,
  });
  const csv = archiveZipImportIssueRectificationClosureCsv(updateRows);
  const body = {
    schema: "railwise.engineeringArchive.importReviewHistoryImportIssueRectificationClosureUpdate.v1" as const,
    importedAt,
    source,
    sourceDispatchFingerprint: dispatch.dispatchFingerprint,
    updatedDispatchFingerprint: updatedDispatch.dispatchFingerprint,
    closedCount: updatedDispatch.rows.filter((row) => row.status === "closed").length,
    stillOpenCount: updatedDispatch.openCount,
    missingUpdateCount: updateRows.filter((row) => row.updateStatus === "missing_update").length,
    unmatchedUpdateCount: updateRows.filter((row) => row.updateStatus === "unmatched_update").length,
    rows: updateRows,
    updatedDispatch,
  };
  const updateFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...body, csv }));
  const withoutArtifacts = {
    ...body,
    updateFingerprint,
  };
  const markdown = archiveZipImportIssueRectificationClosureMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

