function archiveReleaseTrendSlaHtml(
  report: Omit<EngineeringBatchArchiveReleaseTrendSlaReport, "html" | "json" | "trendCsv" | "adapterSlaCsv">,
): string {
  const maxChanged = Math.max(1, ...report.versionTrendRows.map((row) => row.changedArtifactCount));
  const maxFollowUp = Math.max(1, ...report.versionTrendRows.map((row) => row.followUpCount));
  const chartRows = report.versionTrendRows
    .map((row, index) => {
      const y = 58 + index * 56;
      const changedWidth = Math.round((row.changedArtifactCount / maxChanged) * 260);
      const followUpWidth = Math.round((row.followUpCount / maxFollowUp) * 180);
      return [
        `<text x="24" y="${y}" class="label">${htmlEscape(row.releaseVersion)}</text>`,
        `<rect x="210" y="${y - 18}" width="${changedWidth}" height="18" class="changed" />`,
        `<rect x="210" y="${y + 6}" width="${followUpWidth}" height="18" class="${row.overdueFollowUpCount > 0 ? "overdue" : "followup"}" />`,
        `<text x="480" y="${y - 5}" class="value">变化 ${htmlEscape(row.changedArtifactCount)}</text>`,
        `<text x="480" y="${y + 19}" class="value">未闭环 ${htmlEscape(row.followUpCount)} / 超期 ${htmlEscape(row.overdueFollowUpCount)}</text>`,
      ].join("");
    })
    .join("");
  const svgHeight = Math.max(160, 78 + report.versionTrendRows.length * 56);
  const overdueRows = report.adapterSlaRows
    .filter((row) => row.resolutionStatus === "overdue")
    .slice(0, 12)
    .map(
      (row) =>
        `<tr><td>${htmlEscape(row.releaseVersion)}</td><td>${htmlEscape(row.targetSystem || row.adapterId)}</td><td>${htmlEscape(row.reconciliationStatus)}</td><td>${htmlEscape(row.elapsedHours)}</td><td>${htmlEscape(row.action)}</td></tr>`,
    )
    .join("");
  return [
    "<!doctype html>",
    '<html lang="zh-CN">',
    "<head>",
    '<meta charset="utf-8" />',
    "<title>发布版本趋势与外部回执 SLA</title>",
    "<style>",
    "body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif;margin:32px;color:#172033;background:#f7f9fb}",
    ".card{background:#fff;border:1px solid #d9e1ea;border-radius:8px;padding:18px;margin:16px 0}",
    ".meta{color:#5e6b7a}.grid{display:grid;grid-template-columns:repeat(4,minmax(0,1fr));gap:12px}",
    ".metric{background:#eef4f8;border-radius:6px;padding:12px}.metric span{display:block;color:#617086;font-size:12px}.metric strong{font-size:22px}",
    "svg{width:100%;height:auto;background:#fff}.label{font-size:12px;fill:#263447}.value{font-size:12px;fill:#5a6777}.changed{fill:#2f6fed}.followup{fill:#7a8899}.overdue{fill:#c2410c}",
    "table{width:100%;border-collapse:collapse}th,td{border-bottom:1px solid #e5ebf0;padding:8px;text-align:left;font-size:13px}th{color:#46586f}",
    "</style>",
    "</head>",
    "<body>",
    "<h1>发布版本趋势与外部回执 SLA</h1>",
    `<p class="meta">生成时间：${htmlEscape(report.generatedAt)} · SLA：${htmlEscape(report.slaHours)} 小时 · 指纹：${htmlEscape(report.reportFingerprint)}</p>`,
    '<div class="grid">',
    `<div class="metric"><span>版本数</span><strong>${htmlEscape(report.releaseCount)}</strong></div>`,
    `<div class="metric"><span>外部系统数</span><strong>${htmlEscape(report.adapterCount)}</strong></div>`,
    `<div class="metric"><span>未闭环</span><strong>${htmlEscape(report.openFollowUpCount)}</strong></div>`,
    `<div class="metric"><span>超期</span><strong>${htmlEscape(report.overdueFollowUpCount)}</strong></div>`,
    "</div>",
    '<div class="card">',
    "<h2>版本趋势图</h2>",
    `<svg viewBox="0 0 720 ${svgHeight}" role="img" aria-label="发布版本变化与未闭环趋势">`,
    '<text x="210" y="24" class="value">构件变化</text><text x="390" y="24" class="value">未闭环/超期</text>',
    chartRows,
    "</svg>",
    "</div>",
    '<div class="card">',
    "<h2>超期外部系统</h2>",
    "<table><thead><tr><th>版本</th><th>外部系统</th><th>状态</th><th>耗时小时</th><th>处理动作</th></tr></thead>",
    `<tbody>${overdueRows || '<tr><td colspan="5">暂无超期外部系统。</td></tr>'}</tbody></table>`,
    "</div>",
    "</body>",
    "</html>",
  ].join("");
}

export function buildEngineeringBatchArchiveReleaseTrendSlaReport(
  dashboard: EngineeringBatchArchiveReleasePortfolioDashboard,
  options: {
    generatedAt?: string;
    slaHours?: number;
    slaRuleTemplate?: EngineeringBatchArchiveReleaseSlaRuleTemplate | null;
  } = {},
): EngineeringBatchArchiveReleaseTrendSlaReport {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const slaHours = archiveReleaseSlaHours(options.slaRuleTemplate?.defaultSlaHours ?? options.slaHours, 24);
  const slaRulesByAdapterId = new Map((options.slaRuleTemplate?.rows ?? []).map((row) => [row.adapterId, row]));
  const timelineByVersion = new Map(dashboard.timelineRows.map((row) => [row.releaseVersion, row]));
  const adapterSlaRows: EngineeringBatchArchiveReleaseTrendSlaAdapterRow[] = dashboard.adapterRows.map((row) => {
    const release = timelineByVersion.get(row.releaseVersion);
    const isClosed = row.reconciliationStatus === "accepted" || row.reconciliationStatus === "skipped";
    const endAt = isClosed && row.receivedAt ? row.receivedAt : generatedAt;
    const elapsedHours = hoursBetween(release?.releasedAt ?? dashboard.generatedAt, endAt);
    const rule = slaRulesByAdapterId.get(row.adapterId);
    const rowSlaHours = archiveReleaseSlaHours(rule?.slaHours, slaHours);
    const overdue = elapsedHours > rowSlaHours;
    const escalationRole = rule?.escalationRole || "资料负责人";
    const overdueSeverity = rule?.overdueSeverity ?? "warning";
    const actionTemplate =
      rule?.actionTemplate || `${row.targetSystem || row.adapterId} 超过 ${rowSlaHours} 小时未闭环时升级资料负责人。`;
    const draftRow: EngineeringBatchArchiveReleaseTrendSlaAdapterRow = {
      releaseVersion: row.releaseVersion,
      adapterId: row.adapterId,
      targetSystem: row.targetSystem,
      externalRecordId: row.externalRecordId,
      reconciliationStatus: row.reconciliationStatus,
      receivedAt: row.receivedAt,
      elapsedHours,
      slaHours: rowSlaHours,
      overdue,
      escalationRole,
      overdueSeverity,
      actionTemplate,
      resolutionStatus: archiveReleaseTrendSlaResolutionStatus(row, overdue),
      action: "",
    };
    return {
      ...draftRow,
      action: archiveReleaseTrendSlaAction(draftRow),
    };
  });
  let cumulativeChangedArtifactCount = 0;
  const versionTrendRows: EngineeringBatchArchiveReleaseTrendSlaVersionRow[] = dashboard.timelineRows.map((row) => {
    cumulativeChangedArtifactCount += row.changedArtifactCount;
    const overdueFollowUpCount = adapterSlaRows.filter(
      (adapterRow) => adapterRow.releaseVersion === row.releaseVersion && adapterRow.resolutionStatus === "overdue",
    ).length;
    return {
      releaseVersion: row.releaseVersion,
      releasedAt: row.releasedAt,
      changedArtifactCount: row.changedArtifactCount,
      followUpCount: row.followUpCount,
      overdueFollowUpCount,
      closureStatus: row.closureStatus,
      cumulativeChangedArtifactCount,
      action:
        overdueFollowUpCount > 0
          ? `该版本有 ${overdueFollowUpCount} 项外部系统回执超过 SLA，应优先处理。`
          : row.action,
    };
  });
  const adapterCount = new Set(adapterSlaRows.map((row) => row.adapterId)).size;
  const body = {
    schema: "railwise.engineering.batch.archiveReleaseTrendSlaReport.v1" as const,
    generatedAt,
    slaHours,
    sourceDashboardFingerprint: dashboard.dashboardFingerprint,
    slaRuleTemplateFingerprint: options.slaRuleTemplate?.templateFingerprint ?? null,
    releaseCount: dashboard.releaseCount,
    adapterCount,
    openFollowUpCount: dashboard.openFollowUpCount,
    overdueFollowUpCount: adapterSlaRows.filter((row) => row.resolutionStatus === "overdue").length,
    latestClosureStatus: dashboard.latestClosureStatus,
    versionTrendRows,
    adapterSlaRows,
  };
  const reportFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withFingerprint = {
    ...body,
    reportFingerprint,
  };
  return {
    ...withFingerprint,
    trendCsv: archiveReleaseTrendCsv(versionTrendRows),
    adapterSlaCsv: archiveReleaseTrendSlaAdapterCsv(adapterSlaRows),
    html: archiveReleaseTrendSlaHtml(withFingerprint),
    json: JSON.stringify(withFingerprint, null, 2),
  };
}

