function buildArchiveReleaseSlaRectificationLedgerArtifact(input: {
  generatedAt: string;
  sourceReportFingerprint: string;
  rows: EngineeringBatchArchiveReleaseSlaRectificationRow[];
}): EngineeringBatchArchiveReleaseSlaRectificationLedger {
  const openRows = input.rows.filter((row) => row.closureStatus === "open");
  const body = {
    schema: "railwise.engineering.batch.archiveReleaseSlaRectificationLedger.v1" as const,
    generatedAt: input.generatedAt,
    sourceReportFingerprint: input.sourceReportFingerprint,
    rowCount: input.rows.length,
    openCount: openRows.length,
    blockingCount: openRows.filter((row) => row.overdueSeverity === "blocking").length,
    warningCount: openRows.filter((row) => row.overdueSeverity === "warning").length,
    noticeCount: openRows.filter((row) => row.overdueSeverity === "notice").length,
    rows: input.rows,
  };
  const ledgerFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    ledgerFingerprint,
  };
  const csv = archiveReleaseSlaRectificationCsv(input.rows);
  const closureTemplateCsv = archiveReleaseSlaRectificationClosureTemplateCsv(input.rows);
  const markdown = archiveReleaseSlaRectificationMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    closureTemplateCsv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv, closureTemplateCsv }, null, 2),
  };
}

export function buildEngineeringBatchArchiveReleaseSlaRectificationLedger(
  report: EngineeringBatchArchiveReleaseTrendSlaReport,
  options: { generatedAt?: string; defaultDueHours?: number } = {},
): EngineeringBatchArchiveReleaseSlaRectificationLedger {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const dueAt = addHoursIso(generatedAt, options.defaultDueHours ?? 24);
  const rows: EngineeringBatchArchiveReleaseSlaRectificationRow[] = report.adapterSlaRows
    .filter((row) => row.resolutionStatus === "overdue")
    .map((row, index) => ({
      issueId: `${row.releaseVersion}-SLA-${String(index + 1).padStart(3, "0")}`,
      releaseVersion: row.releaseVersion,
      adapterId: row.adapterId,
      targetSystem: row.targetSystem,
      issueType: "sla_overdue" as const,
      overdueSeverity: row.overdueSeverity,
      escalationRole: row.escalationRole,
      elapsedHours: row.elapsedHours,
      slaHours: row.slaHours,
      dueAt,
      closureStatus: "open" as const,
      externalRecordId: row.externalRecordId,
      reconciliationStatus: row.reconciliationStatus,
      action: row.actionTemplate || row.action,
      closedAt: null,
      closedBy: null,
      closureNote: "",
      closureSourceStatus: "generated_open" as const,
    }));
  return buildArchiveReleaseSlaRectificationLedgerArtifact({
    generatedAt,
    sourceReportFingerprint: report.reportFingerprint,
    rows,
  });
}

type EngineeringBatchArchiveReleaseSlaRectificationClosureRecord = {
  rowNumber: number;
  issueId: string;
  releaseVersion: string;
  adapterId: string;
  closureStatus: EngineeringProjectArchiveRectificationClosureStatus;
  closedAt: string | null;
  closedBy: string | null;
  closureNote: string;
  externalRecordId: string;
};

function archiveReleaseSlaRectificationClosureFormat(
  input: EngineeringBatchArchiveReleaseSlaRectificationClosureInput,
): EngineeringBatchArchiveReleaseSlaRectificationClosureFormat {
  if (input.format === "json" || input.format === "tsv") return input.format;
  return "csv";
}

function archiveReleaseSlaRectificationClosureValue(row: Record<string, string>, aliases: string[]): string {
  for (const alias of aliases) {
    const direct = row[alias];
    if (direct !== undefined) return direct.trim();
    const normalizedAlias = normalizeHeader(alias);
    const normalized = row[normalizedAlias];
    if (normalized !== undefined) return normalized.trim();
    for (const [key, value] of Object.entries(row)) {
      if (normalizeHeader(key) === normalizedAlias) return value.trim();
    }
  }
  return "";
}

function normalizeArchiveReleaseSlaRectificationClosureStatus(
  value: string,
): EngineeringProjectArchiveRectificationClosureStatus {
  const normalized = normalizeLedgerStatus(value);
  return normalized === "closed" || normalized === "ok" ? "closed" : "open";
}

function archiveReleaseSlaRectificationClosureTemplateForInput(
  input: EngineeringBatchArchiveReleaseSlaRectificationClosureInput,
): {
  rows: EngineeringBatchArchiveReleaseSlaRectificationClosureTemplateRow[];
  templateFingerprint: string | null;
} {
  if (input.fieldTemplate) {
    return {
      rows: input.fieldTemplate.rows,
      templateFingerprint: input.fieldTemplate.templateFingerprint,
    };
  }
  const saved = readSavedEngineeringBatchArchiveReleaseSlaRectificationClosureTemplate();
  if (saved) {
    return {
      rows: saved.rows,
      templateFingerprint: saved.templateFingerprint || null,
    };
  }
  const defaults = buildEngineeringBatchArchiveReleaseSlaRectificationClosureTemplate({
    exportedAt: "railwise-system-default",
  });
  return {
    rows: defaults.rows,
    templateFingerprint: defaults.templateFingerprint,
  };
}

function archiveReleaseSlaRectificationClosureAliases(
  rows: EngineeringBatchArchiveReleaseSlaRectificationClosureTemplateRow[],
  fieldKey: EngineeringBatchArchiveReleaseSlaRectificationClosureField,
): string[] {
  return rows.find((row) => row.fieldKey === fieldKey)?.aliases ?? archiveReleaseSlaRectificationClosureTemplateDefaultRow(fieldKey).aliases;
}

function archiveReleaseSlaClosureCompositeKey(releaseVersion: string, adapterId: string): string {
  return `${rectificationIssueKey(releaseVersion)}::${rectificationIssueKey(adapterId)}`;
}

function parseArchiveReleaseSlaRectificationClosureInput(
  input: EngineeringBatchArchiveReleaseSlaRectificationClosureInput,
): {
  source: EngineeringBatchArchiveReleaseSlaRectificationClosureSource;
  records: EngineeringBatchArchiveReleaseSlaRectificationClosureRecord[];
} {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const format = archiveReleaseSlaRectificationClosureFormat(input);
  const rows = externalSystemReceiptRowsFromText(input.text, format);
  const columnNames = uniqueNonEmptyStrings(rows.flatMap((row) => Object.keys(row)));
  const fieldTemplate = archiveReleaseSlaRectificationClosureTemplateForInput(input);
  const records = rows
    .map((row, index): EngineeringBatchArchiveReleaseSlaRectificationClosureRecord => {
      const issueId = archiveReleaseSlaRectificationClosureValue(
        row,
        archiveReleaseSlaRectificationClosureAliases(fieldTemplate.rows, "issueId"),
      );
      const releaseVersion = archiveReleaseSlaRectificationClosureValue(
        row,
        archiveReleaseSlaRectificationClosureAliases(fieldTemplate.rows, "releaseVersion"),
      );
      const adapterId = archiveReleaseSlaRectificationClosureValue(
        row,
        archiveReleaseSlaRectificationClosureAliases(fieldTemplate.rows, "adapterId"),
      );
      const closureStatus = normalizeArchiveReleaseSlaRectificationClosureStatus(
        archiveReleaseSlaRectificationClosureValue(
          row,
          archiveReleaseSlaRectificationClosureAliases(fieldTemplate.rows, "closureStatus"),
        ),
      );
      return {
        rowNumber: index + 2,
        issueId,
        releaseVersion,
        adapterId,
        closureStatus,
        closedAt:
          archiveReleaseSlaRectificationClosureValue(
            row,
            archiveReleaseSlaRectificationClosureAliases(fieldTemplate.rows, "closedAt"),
          ) || null,
        closedBy:
          archiveReleaseSlaRectificationClosureValue(
            row,
            archiveReleaseSlaRectificationClosureAliases(fieldTemplate.rows, "closedBy"),
          ) || null,
        closureNote: archiveReleaseSlaRectificationClosureValue(
          row,
          archiveReleaseSlaRectificationClosureAliases(fieldTemplate.rows, "closureNote"),
        ),
        externalRecordId: archiveReleaseSlaRectificationClosureValue(
          row,
          archiveReleaseSlaRectificationClosureAliases(fieldTemplate.rows, "externalRecordId"),
        ),
      };
    })
    .filter(
      (record) =>
        record.issueId ||
        record.releaseVersion ||
        record.adapterId ||
        record.closedAt ||
        record.closedBy ||
        record.closureNote ||
        record.externalRecordId,
    );
  const sourceBody = {
    sourceName: input.sourceName ?? null,
    importedAt,
    format,
    columnNames,
    fieldTemplateFingerprint: fieldTemplate.templateFingerprint,
    records,
  };
  return {
    source: {
      schema: "railwise.engineering.archiveReleaseSlaRectificationClosureSource.v1",
      sourceName: input.sourceName ?? null,
      importedAt,
      format,
      rowCount: records.length,
      columnNames,
      fieldTemplateFingerprint: fieldTemplate.templateFingerprint,
      closureSourceFingerprint: fnv1a32Fingerprint(JSON.stringify(sourceBody)),
    },
    records,
  };
}

