export function buildEngineeringBatchArchiveReleaseSlaReminderSchedule(
  reminderReport: EngineeringBatchArchiveReleaseSlaAuditReminderReport,
  options: {
    generatedAt?: string;
    scheduleTemplate?: EngineeringBatchArchiveReleaseSlaReminderScheduleTemplate | null;
    policyName?: string;
    timezone?: string;
    startAt?: string;
    horizonDays?: number;
    dailySendHour?: number;
    includeWeekends?: boolean;
    maxOccurrencesPerReminder?: number;
    criticalRepeatHours?: number;
    warningRepeatHours?: number;
    noticeRepeatHours?: number;
    channels?: string[] | null;
  } = {},
): EngineeringBatchArchiveReleaseSlaReminderSchedule {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const template = options.scheduleTemplate ?? null;
  const clean = cleanArchiveReleaseSlaReminderScheduleTemplateOptions({
    policyName: options.policyName ?? template?.policyName,
    timezone: options.timezone ?? template?.timezone,
    horizonDays: options.horizonDays ?? template?.horizonDays,
    dailySendHour: options.dailySendHour ?? template?.dailySendHour,
    includeWeekends: options.includeWeekends ?? template?.includeWeekends,
    maxOccurrencesPerReminder: options.maxOccurrencesPerReminder ?? template?.maxOccurrencesPerReminder,
    criticalRepeatHours: options.criticalRepeatHours ?? template?.criticalRepeatHours,
    warningRepeatHours: options.warningRepeatHours ?? template?.warningRepeatHours,
    noticeRepeatHours: options.noticeRepeatHours ?? template?.noticeRepeatHours,
    channels: options.channels ?? template?.channels,
  });
  const policyName = clean.policyName;
  const timezone = clean.timezone;
  const dailySendHour = clean.dailySendHour;
  const startAt = archiveReleaseSlaReminderScheduleStartAt(options.startAt ?? generatedAt, dailySendHour);
  const horizonDays = clean.horizonDays;
  const includeWeekends = clean.includeWeekends;
  const maxOccurrencesPerReminder = clean.maxOccurrencesPerReminder;
  const channels = clean.channels;
  const startMs = Date.parse(startAt);
  const safeStartMs = Number.isFinite(startMs) ? startMs : Date.now();
  const horizonEndMs = safeStartMs + horizonDays * 24 * 3600000;
  const rows: EngineeringBatchArchiveReleaseSlaReminderScheduleRow[] = [];
  reminderReport.rows.forEach((reminderRow, reminderIndex) => {
    const repeatIntervalHours = archiveReleaseSlaReminderScheduleIntervalHours(reminderRow.reminderSeverity, clean);
    let occurrenceMs = safeStartMs;
    let occurrenceIndex = 0;
    let safety = 0;
    while (occurrenceMs < horizonEndMs && occurrenceIndex < maxOccurrencesPerReminder && safety < 500) {
      const date = new Date(occurrenceMs);
      const weekend = date.getUTCDay() === 0 || date.getUTCDay() === 6;
      if (includeWeekends || !weekend) {
        const occurrenceAt = date.toISOString();
        const escalationWindow = archiveReleaseSlaReminderScheduleEscalationWindow(reminderRow, occurrenceAt);
        const overdueHoursAtOccurrence =
          reminderRow.sourceStatus === "unmatched_rectification_receipt" ? 0 : hoursBetween(reminderRow.dueAt, occurrenceAt);
        const scheduleSeverity = archiveReleaseSlaReminderScheduleSeverity(reminderRow, escalationWindow);
        rows.push({
          occurrenceId: `SLA-SCHEDULE-${String(reminderIndex + 1).padStart(3, "0")}-${String(occurrenceIndex + 1).padStart(2, "0")}`,
          reminderId: reminderRow.reminderId,
          occurrenceAt,
          policyName,
          reminderSeverity: reminderRow.reminderSeverity,
          scheduleSeverity,
          repeatIntervalHours,
          channels,
          sourceStatus: reminderRow.sourceStatus,
          issueId: reminderRow.issueId,
          releaseVersion: reminderRow.releaseVersion,
          adapterId: reminderRow.adapterId,
          targetSystem: reminderRow.targetSystem,
          escalationRole: reminderRow.escalationRole,
          dueAt: reminderRow.dueAt,
          overdueHoursAtOccurrence,
          escalationWindow,
          action: archiveReleaseSlaReminderScheduleAction(reminderRow, occurrenceAt, channels, escalationWindow),
        });
        occurrenceIndex += 1;
      }
      occurrenceMs += repeatIntervalHours * 3600000;
      safety += 1;
    }
  });
  rows.sort((left, right) =>
    left.occurrenceAt === right.occurrenceAt
      ? left.occurrenceId.localeCompare(right.occurrenceId)
      : left.occurrenceAt.localeCompare(right.occurrenceAt),
  );
  const body = {
    schema: "railwise.engineering.batch.archiveReleaseSlaReminderSchedule.v1" as const,
    generatedAt,
    policyName,
    timezone,
    startAt,
    horizonDays,
    dailySendHour,
    includeWeekends,
    maxOccurrencesPerReminder,
    channels,
    sourceReminderFingerprint: reminderReport.reminderFingerprint,
    sourceLedgerFingerprint: reminderReport.sourceLedgerFingerprint,
    sourceClosureFingerprint: reminderReport.sourceClosureFingerprint,
    scheduleTemplateFingerprint: template?.templateFingerprint ?? null,
    occurrenceCount: rows.length,
    criticalOccurrenceCount: rows.filter((row) => row.scheduleSeverity === "critical").length,
    warningOccurrenceCount: rows.filter((row) => row.scheduleSeverity === "warning").length,
    noticeOccurrenceCount: rows.filter((row) => row.scheduleSeverity === "notice").length,
    rows,
  };
  const scheduleFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    scheduleFingerprint,
  };
  const csv = archiveReleaseSlaReminderScheduleCsv(rows);
  const markdown = archiveReleaseSlaReminderScheduleMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveReleaseSlaNotificationExecutionStatus(
  value: unknown,
): EngineeringBatchArchiveReleaseSlaNotificationExecutionStatus {
  const status = textFrom(value, "pending").toLowerCase();
  if (["sent", "delivered", "accepted", "success", "ok", "成功", "已发送", "已送达"].includes(status)) return "sent";
  if (["failed", "rejected", "error", "failure", "失败", "发送失败", "退回"].includes(status)) return "failed";
  if (["skipped", "ignored", "skip", "跳过", "已跳过"].includes(status)) return "skipped";
  return "pending";
}

function archiveReleaseSlaNotificationAckStatus(
  value: unknown,
  executionStatus: EngineeringBatchArchiveReleaseSlaNotificationExecutionStatus,
): EngineeringBatchArchiveReleaseSlaNotificationAckStatus {
  const status = textFrom(value, "").toLowerCase();
  if (["acknowledged", "confirmed", "accepted", "success", "ok", "已确认", "确认", "成功"].includes(status)) return "acknowledged";
  if (["rejected", "failed", "error", "failure", "拒绝", "退回", "失败"].includes(status)) return "rejected";
  if (["not_required", "notrequired", "none", "skip", "skipped", "无需确认", "不需要", "不适用"].includes(status)) return "not_required";
  if (["pending_ack", "pending", "waiting", "待确认", "处理中"].includes(status)) return "pending_ack";
  if (executionStatus === "sent") return "pending_ack";
  if (executionStatus === "failed" || executionStatus === "skipped") return "not_required";
  return "pending_ack";
}

function archiveReleaseSlaNotificationExecutionKey(occurrenceId: string, channel: string): string {
  return `${occurrenceId.trim().toLowerCase()}::${channel.trim().toLowerCase()}`;
}

function archiveReleaseSlaNotificationAction(row: {
  executionStatus: EngineeringBatchArchiveReleaseSlaNotificationExecutionStatus;
  ackStatus: EngineeringBatchArchiveReleaseSlaNotificationAckStatus;
  channel: string;
  externalMessageId: string;
  failureReason: string;
}): string {
  if (row.executionStatus === "failed") {
    return `通知发送失败，请核对${row.channel}渠道并重发：${row.failureReason || "未记录失败原因"}。`;
  }
  if (row.executionStatus === "skipped") {
    return `通知已跳过，请确认${row.channel}渠道是否不适用。`;
  }
  if (row.ackStatus === "acknowledged") {
    return `通知已确认，归档外部消息号 ${row.externalMessageId || "-"}。`;
  }
  if (row.ackStatus === "rejected") {
    return `通知已被退回，请核对${row.channel}渠道确认意见并重新处理。`;
  }
  if (row.executionStatus === "sent") {
    return `通知已发送，等待${row.channel}渠道确认。`;
  }
  return `按排班通过${row.channel}发送通知，并记录外部消息号和确认状态。`;
}

