export function buildEngineeringBatchArchiveReleaseSlaNotificationExecutionAudit(
  schedule: EngineeringBatchArchiveReleaseSlaReminderSchedule,
  options: {
    generatedAt?: string;
    executedBy?: string | null;
    executionRows?: EngineeringBatchArchiveReleaseSlaNotificationExecutionInputRow[] | null;
  } = {},
): EngineeringBatchArchiveReleaseSlaNotificationExecutionAudit {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const executedBy = textFrom(options.executedBy, "") || null;
  const inputRows = new Map<string, EngineeringBatchArchiveReleaseSlaNotificationExecutionInputRow>();
  for (const row of options.executionRows ?? []) {
    inputRows.set(archiveReleaseSlaNotificationExecutionKey(row.occurrenceId, row.channel), row);
  }
  const rows: EngineeringBatchArchiveReleaseSlaNotificationExecutionRow[] = [];
  schedule.rows.forEach((occurrence, occurrenceIndex) => {
    const channels = occurrence.channels.length > 0 ? occurrence.channels : schedule.channels;
    channels.forEach((channel, channelIndex) => {
      const input = inputRows.get(archiveReleaseSlaNotificationExecutionKey(occurrence.occurrenceId, channel));
      const executionStatus = archiveReleaseSlaNotificationExecutionStatus(input?.executionStatus);
      const ackStatus = archiveReleaseSlaNotificationAckStatus(input?.ackStatus, executionStatus);
      const externalMessageId = textFrom(input?.externalMessageId, "");
      const failureReason = textFrom(input?.failureReason, "");
      const messageTitle = `SLA ${occurrence.scheduleSeverity.toUpperCase()} ${occurrence.targetSystem || occurrence.adapterId || occurrence.issueId}`;
      const messageBody = [
        `排班：${occurrence.occurrenceId}`,
        `版本：${occurrence.releaseVersion || "-"}`,
        `问题：${occurrence.issueId || "-"}`,
        `责任角色：${occurrence.escalationRole || "-"}`,
        `处理要求：${occurrence.action}`,
      ].join("\n");
      const action = archiveReleaseSlaNotificationAction({
        executionStatus,
        ackStatus,
        channel,
        externalMessageId,
        failureReason,
      });
      rows.push({
        executionId: `SLA-NOTIFY-${String(occurrenceIndex + 1).padStart(3, "0")}-${String(channelIndex + 1).padStart(2, "0")}`,
        occurrenceId: occurrence.occurrenceId,
        reminderId: occurrence.reminderId,
        occurrenceAt: occurrence.occurrenceAt,
        channel,
        executionStatus,
        ackStatus,
        executedAt: textFrom(input?.executedAt, "") || null,
        executedBy: textFrom(input?.executedBy, "") || executedBy,
        externalMessageId,
        failureReason,
        acknowledgedAt: textFrom(input?.acknowledgedAt, "") || null,
        scheduleSeverity: occurrence.scheduleSeverity,
        releaseVersion: occurrence.releaseVersion,
        adapterId: occurrence.adapterId,
        targetSystem: occurrence.targetSystem,
        issueId: occurrence.issueId,
        escalationRole: occurrence.escalationRole,
        messageTitle,
        messageBody,
        action,
      });
    });
  });
  const body = {
    schema: "railwise.engineering.batch.archiveReleaseSlaNotificationExecutionAudit.v1" as const,
    generatedAt,
    executedBy,
    sourceScheduleFingerprint: schedule.scheduleFingerprint,
    sourceReminderFingerprint: schedule.sourceReminderFingerprint,
    sourceLedgerFingerprint: schedule.sourceLedgerFingerprint,
    scheduleTemplateFingerprint: schedule.scheduleTemplateFingerprint,
    rowCount: rows.length,
    pendingCount: rows.filter((row) => row.executionStatus === "pending").length,
    sentCount: rows.filter((row) => row.executionStatus === "sent").length,
    failedCount: rows.filter((row) => row.executionStatus === "failed").length,
    skippedCount: rows.filter((row) => row.executionStatus === "skipped").length,
    acknowledgedCount: rows.filter((row) => row.ackStatus === "acknowledged").length,
    unacknowledgedCount: rows.filter(
      (row) => row.executionStatus === "sent" && row.ackStatus !== "acknowledged",
    ).length,
    rows,
  };
  const auditFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    auditFingerprint,
  };
  const csv = archiveReleaseSlaNotificationExecutionCsv(rows);
  const markdown = archiveReleaseSlaNotificationExecutionMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveReleaseSlaNotificationReceiptFormat(
  input: EngineeringBatchArchiveReleaseSlaNotificationExecutionReceiptInput,
): EngineeringBatchArchiveReleaseSlaNotificationExecutionReceiptFormat {
  if (input.format === "json" || input.format === "tsv") return input.format;
  return input.text.trim().startsWith("{") || input.text.trim().startsWith("[") ? "json" : "csv";
}

function archiveReleaseSlaNotificationReceiptValue(row: Record<string, string>, ...keys: string[]): string {
  const normalized = new Map(Object.entries(row).map(([key, value]) => [key.trim().toLowerCase(), value]));
  for (const key of keys) {
    const value = normalized.get(key.trim().toLowerCase());
    if (value !== undefined && value.trim()) return value.trim();
  }
  return "";
}

type ArchiveReleaseSlaNotificationReceiptRecord = {
  executionId: string;
  occurrenceId: string;
  channel: string;
  executionStatus: EngineeringBatchArchiveReleaseSlaNotificationExecutionStatus;
  ackStatus: EngineeringBatchArchiveReleaseSlaNotificationAckStatus;
  executedAt: string | null;
  executedBy: string | null;
  externalMessageId: string;
  failureReason: string;
  acknowledgedAt: string | null;
  sourceRowNumber: number;
};

function parseArchiveReleaseSlaNotificationReceiptInput(
  input: EngineeringBatchArchiveReleaseSlaNotificationExecutionReceiptInput,
): {
  source: EngineeringBatchArchiveReleaseSlaNotificationExecutionReceiptSource;
  records: ArchiveReleaseSlaNotificationReceiptRecord[];
} {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const format = archiveReleaseSlaNotificationReceiptFormat(input);
  const rows = externalSystemReceiptRowsFromText(input.text, format);
  const columnNames = rows.length > 0 ? Object.keys(rows[0]!) : [];
  const records = rows
    .map((row, index) => {
      const executionStatus = archiveReleaseSlaNotificationExecutionStatus(
        archiveReleaseSlaNotificationReceiptValue(row, "execution_status", "executionStatus", "发送状态", "执行状态"),
      );
      const ackStatus = archiveReleaseSlaNotificationAckStatus(
        archiveReleaseSlaNotificationReceiptValue(row, "ack_status", "ackStatus", "确认状态", "回执状态"),
        executionStatus,
      );
      return {
        executionId: archiveReleaseSlaNotificationReceiptValue(row, "execution_id", "executionId", "通知执行编号"),
        occurrenceId: archiveReleaseSlaNotificationReceiptValue(row, "occurrence_id", "occurrenceId", "排班编号"),
        channel: archiveReleaseSlaNotificationReceiptValue(row, "channel", "通知渠道", "渠道"),
        executionStatus,
        ackStatus,
        executedAt:
          archiveReleaseSlaNotificationReceiptValue(row, "executed_at", "executedAt", "发送时间", "执行时间") || null,
        executedBy:
          archiveReleaseSlaNotificationReceiptValue(row, "executed_by", "executedBy", "发送人", "执行人") || null,
        externalMessageId: archiveReleaseSlaNotificationReceiptValue(
          row,
          "external_message_id",
          "externalMessageId",
          "外部消息号",
          "消息编号",
        ),
        failureReason: archiveReleaseSlaNotificationReceiptValue(
          row,
          "failure_reason",
          "failureReason",
          "失败原因",
          "退回原因",
        ),
        acknowledgedAt:
          archiveReleaseSlaNotificationReceiptValue(row, "acknowledged_at", "acknowledgedAt", "确认时间") || null,
        sourceRowNumber: index + 2,
      };
    })
    .filter((record) => record.executionId || (record.occurrenceId && record.channel));
  const sourceBody = {
    schema: "railwise.engineering.archiveReleaseSlaNotificationExecutionReceiptSource.v1" as const,
    importedAt,
    sourceName: input.sourceName ?? null,
    format,
    rowCount: records.length,
    columnNames,
  };
  const receiptSourceFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...sourceBody, records }));
  return {
    source: {
      ...sourceBody,
      receiptSourceFingerprint,
    },
    records,
  };
}

function archiveReleaseSlaNotificationExecutionAuditFromRows(
  baseAudit: EngineeringBatchArchiveReleaseSlaNotificationExecutionAudit,
  rows: EngineeringBatchArchiveReleaseSlaNotificationExecutionRow[],
  generatedAt: string,
): EngineeringBatchArchiveReleaseSlaNotificationExecutionAudit {
  const body = {
    schema: "railwise.engineering.batch.archiveReleaseSlaNotificationExecutionAudit.v1" as const,
    generatedAt,
    executedBy: baseAudit.executedBy,
    sourceScheduleFingerprint: baseAudit.sourceScheduleFingerprint,
    sourceReminderFingerprint: baseAudit.sourceReminderFingerprint,
    sourceLedgerFingerprint: baseAudit.sourceLedgerFingerprint,
    scheduleTemplateFingerprint: baseAudit.scheduleTemplateFingerprint,
    rowCount: rows.length,
    pendingCount: rows.filter((row) => row.executionStatus === "pending").length,
    sentCount: rows.filter((row) => row.executionStatus === "sent").length,
    failedCount: rows.filter((row) => row.executionStatus === "failed").length,
    skippedCount: rows.filter((row) => row.executionStatus === "skipped").length,
    acknowledgedCount: rows.filter((row) => row.ackStatus === "acknowledged").length,
    unacknowledgedCount: rows.filter(
      (row) => row.executionStatus === "sent" && row.ackStatus !== "acknowledged",
    ).length,
    rows,
  };
  const auditFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    auditFingerprint,
  };
  const csv = archiveReleaseSlaNotificationExecutionCsv(rows);
  const markdown = archiveReleaseSlaNotificationExecutionMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

