function archiveReleaseSlaNotificationReceiptUpdateMarkdown(
  update: Omit<EngineeringBatchArchiveReleaseSlaNotificationExecutionReceiptUpdate, "markdown" | "csv" | "json">,
): string {
  return [
    "# 发布回执 SLA 通知执行回执更新",
    "",
    `- 导入时间：${update.importedAt}`,
    `- 回执：${update.source.sourceName ?? "未命名通知回执"}`,
    `- 已更新：${update.updatedCount}`,
    `- 缺回执：${update.missingReceiptCount}`,
    `- 未匹配：${update.unmatchedReceiptCount}`,
    `- 已发送：${update.sentCount}`,
    `- 失败：${update.failedCount}`,
    `- 已确认：${update.acknowledgedCount}`,
    `- 来源审计指纹：${update.sourceAuditFingerprint}`,
    `- 更新后审计指纹：${update.updatedAuditFingerprint}`,
    "",
    "| 状态 | 执行 | 排班 | 渠道 | 发送 | 确认 | 外部消息 | 行号 | 处理要求 |",
    "| --- | --- | --- | --- | --- | --- | --- | --- | --- |",
    ...update.rows.map(
      (row) =>
        `| ${row.updateStatus} | ${row.executionId || "-"} | ${row.occurrenceId || "-"} | ${row.channel || "-"} | ${row.executionStatus} | ${row.ackStatus} | ${row.externalMessageId || "-"} | ${row.sourceRowNumber ?? "-"} | ${row.action} |`,
    ),
    "",
  ].join("\n");
}

export function buildEngineeringBatchArchiveReleaseSlaNotificationExecutionReceiptUpdate(
  audit: EngineeringBatchArchiveReleaseSlaNotificationExecutionAudit,
  input: EngineeringBatchArchiveReleaseSlaNotificationExecutionReceiptInput,
): EngineeringBatchArchiveReleaseSlaNotificationExecutionReceiptUpdate {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const { source, records } = parseArchiveReleaseSlaNotificationReceiptInput({ ...input, importedAt });
  const recordsByExecutionId = new Map<string, ArchiveReleaseSlaNotificationReceiptRecord>();
  const recordsByOccurrenceChannel = new Map<string, ArchiveReleaseSlaNotificationReceiptRecord>();
  for (const record of records) {
    if (record.executionId) recordsByExecutionId.set(record.executionId.trim().toLowerCase(), record);
    if (record.occurrenceId && record.channel) {
      recordsByOccurrenceChannel.set(
        archiveReleaseSlaNotificationExecutionKey(record.occurrenceId, record.channel),
        record,
      );
    }
  }
  const matchedRecords = new Set<ArchiveReleaseSlaNotificationReceiptRecord>();
  const updateRows: EngineeringBatchArchiveReleaseSlaNotificationExecutionReceiptUpdateRow[] = [];
  const updatedAuditRows = audit.rows.map((row) => {
    const record =
      recordsByExecutionId.get(row.executionId.trim().toLowerCase()) ??
      recordsByOccurrenceChannel.get(archiveReleaseSlaNotificationExecutionKey(row.occurrenceId, row.channel)) ??
      null;
    if (!record) {
      updateRows.push({
        updateStatus: "missing_receipt",
        executionId: row.executionId,
        occurrenceId: row.occurrenceId,
        channel: row.channel,
        executionStatus: row.executionStatus,
        ackStatus: row.ackStatus,
        executedAt: row.executedAt,
        executedBy: row.executedBy,
        externalMessageId: row.externalMessageId,
        failureReason: row.failureReason,
        acknowledgedAt: row.acknowledgedAt,
        sourceRowNumber: null,
        action: `尚未收到 ${row.channel} 对 ${row.executionId} 的通知执行回执。`,
      });
      return row;
    }
    matchedRecords.add(record);
    const merged = {
      ...row,
      executionStatus: record.executionStatus,
      ackStatus: record.ackStatus,
      executedAt: record.executedAt ?? row.executedAt,
      executedBy: record.executedBy ?? row.executedBy,
      externalMessageId: record.externalMessageId || row.externalMessageId,
      failureReason: record.failureReason || row.failureReason,
      acknowledgedAt: record.acknowledgedAt ?? row.acknowledgedAt,
    };
    const action = archiveReleaseSlaNotificationAction(merged);
    const updatedRow = {
      ...merged,
      action,
    };
    updateRows.push({
      updateStatus: "updated",
      executionId: row.executionId,
      occurrenceId: row.occurrenceId,
      channel: row.channel,
      executionStatus: updatedRow.executionStatus,
      ackStatus: updatedRow.ackStatus,
      executedAt: updatedRow.executedAt,
      executedBy: updatedRow.executedBy,
      externalMessageId: updatedRow.externalMessageId,
      failureReason: updatedRow.failureReason,
      acknowledgedAt: updatedRow.acknowledgedAt,
      sourceRowNumber: record.sourceRowNumber,
      action,
    });
    return updatedRow;
  });
  for (const record of records) {
    if (matchedRecords.has(record)) continue;
    updateRows.push({
      updateStatus: "unmatched_receipt",
      executionId: record.executionId,
      occurrenceId: record.occurrenceId,
      channel: record.channel,
      executionStatus: record.executionStatus,
      ackStatus: record.ackStatus,
      executedAt: record.executedAt,
      executedBy: record.executedBy,
      externalMessageId: record.externalMessageId,
      failureReason: record.failureReason,
      acknowledgedAt: record.acknowledgedAt,
      sourceRowNumber: record.sourceRowNumber,
      action: `通知执行回执未匹配当前审计台账，请核对 execution_id 或 occurrence_id + channel：${record.executionId || `${record.occurrenceId}/${record.channel}`}.`,
    });
  }
  const updatedAudit = archiveReleaseSlaNotificationExecutionAuditFromRows(audit, updatedAuditRows, importedAt);
  const body = {
    schema: "railwise.engineering.batch.archiveReleaseSlaNotificationExecutionReceiptUpdate.v1" as const,
    importedAt,
    source,
    sourceAuditFingerprint: audit.auditFingerprint,
    updatedAuditFingerprint: updatedAudit.auditFingerprint,
    updatedCount: updateRows.filter((row) => row.updateStatus === "updated").length,
    missingReceiptCount: updateRows.filter((row) => row.updateStatus === "missing_receipt").length,
    unmatchedReceiptCount: updateRows.filter((row) => row.updateStatus === "unmatched_receipt").length,
    sentCount: updateRows.filter((row) => row.updateStatus === "updated" && row.executionStatus === "sent").length,
    failedCount: updateRows.filter((row) => row.updateStatus === "updated" && row.executionStatus === "failed").length,
    acknowledgedCount: updateRows.filter(
      (row) => row.updateStatus === "updated" && row.ackStatus === "acknowledged",
    ).length,
    rows: updateRows,
    updatedAudit,
  };
  const csv = archiveReleaseSlaNotificationReceiptUpdateCsv(updateRows);
  const updateFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...body, csv }));
  const withoutArtifacts = {
    ...body,
    updateFingerprint,
  };
  const markdown = archiveReleaseSlaNotificationReceiptUpdateMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

