type SavedEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate = Omit<
  EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate,
  "schema" | "exportedAt" | "templateStorageKey" | "json"
>;

function readSavedEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate():
  | SavedEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate
  | null {
  try {
    const raw = engineeringLocalStorage()?.getItem(
      ARCHIVE_RELEASE_SLA_NOTIFICATION_HTTP_DELIVERY_FIELD_TEMPLATE_STORAGE_KEY,
    );
    if (!raw) return null;
    const parsed = objectFrom(JSON.parse(raw));
    const clean = cleanArchiveReleaseSlaNotificationHttpDeliveryFieldTemplateOptions({
      adapterMode: textFrom(parsed.adapterMode, "generic_webhook") as EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryMode,
      payloadFieldNames: parsed.payloadFieldNames as Partial<EngineeringBatchArchiveReleaseSlaNotificationHttpPayloadFieldNames>,
      responseAliases: parsed.responseAliases as Partial<EngineeringBatchArchiveReleaseSlaNotificationHttpResponseAliases>,
    });
    const templateFingerprint = textFrom(parsed.templateFingerprint, "") || fnv1a32Fingerprint(JSON.stringify(clean));
    return {
      projectName: textFrom(parsed.projectName, "") || null,
      ...clean,
      templateFingerprint,
    };
  } catch {
    return null;
  }
}

function writeSavedEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate(
  template: EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate,
): boolean {
  try {
    engineeringLocalStorage()?.setItem(
      ARCHIVE_RELEASE_SLA_NOTIFICATION_HTTP_DELIVERY_FIELD_TEMPLATE_STORAGE_KEY,
      JSON.stringify({
        schema: "railwise.engineering.batch.archiveReleaseSlaNotificationHttpDeliveryFieldTemplate.v1",
        projectName: template.projectName,
        adapterMode: template.adapterMode,
        payloadFieldNames: template.payloadFieldNames,
        responseAliases: template.responseAliases,
        payloadFieldCount: template.payloadFieldCount,
        responseAliasCount: template.responseAliasCount,
        templateFingerprint: template.templateFingerprint,
      }),
    );
    return true;
  } catch {
    return false;
  }
}

export function clearSavedEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate(): boolean {
  try {
    engineeringLocalStorage()?.removeItem(ARCHIVE_RELEASE_SLA_NOTIFICATION_HTTP_DELIVERY_FIELD_TEMPLATE_STORAGE_KEY);
    return true;
  } catch {
    return false;
  }
}

export function buildSavedEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate(
  options: Omit<
    EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplateOptions,
    "payloadFieldNames" | "responseAliases" | "adapterMode"
  > = {},
): EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate {
  const saved = readSavedEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate();
  return buildEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate({
    ...options,
    adapterMode: saved?.adapterMode ?? "generic_webhook",
    payloadFieldNames: saved?.payloadFieldNames,
    responseAliases: saved?.responseAliases,
  });
}

export function applyEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplateJson(
  text: string,
  options: { importedAt?: string } = {},
): EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplateImportReport {
  const importedAt = options.importedAt ?? new Date().toISOString();
  const parsed = objectFrom(JSON.parse(text));
  const schema = textFrom(parsed.schema, "");
  if (schema !== "railwise.engineering.batch.archiveReleaseSlaNotificationHttpDeliveryFieldTemplate.v1") {
    throw new Error("不是 Railwise SLA 通知 HTTP 字段模板文件");
  }
  const template = buildEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate({
    projectName: textFrom(parsed.projectName, "") || undefined,
    exportedAt: textFrom(parsed.exportedAt, "") || importedAt,
    adapterMode: textFrom(parsed.adapterMode, "generic_webhook") as EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryMode,
    payloadFieldNames: parsed.payloadFieldNames as Partial<EngineeringBatchArchiveReleaseSlaNotificationHttpPayloadFieldNames>,
    responseAliases: parsed.responseAliases as Partial<EngineeringBatchArchiveReleaseSlaNotificationHttpResponseAliases>,
  });
  const templateApplied = writeSavedEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate(template);
  const warnings = templateApplied ? [] : ["SLA 通知 HTTP 字段模板保存失败"];
  return {
    schema: "railwise.engineering.batch.archiveReleaseSlaNotificationHttpDeliveryFieldTemplateImport.v1",
    importedAt,
    projectName: template.projectName,
    adapterMode: template.adapterMode,
    templateFingerprint: textFrom(parsed.templateFingerprint, "") || template.templateFingerprint,
    templateApplied,
    payloadFieldCount: template.payloadFieldCount,
    responseAliasCount: template.responseAliasCount,
    warnings,
  };
}

function archiveReleaseSlaNotificationHttpEndpoint(value: unknown): string {
  const endpoint = textFrom(value, "").replace(/\/+$/g, "");
  if (!endpoint) throw new Error("SLA 通知 HTTP 发送需要填写 Endpoint");
  return endpoint;
}

function archiveReleaseSlaNotificationHttpAdapterMode(
  value: unknown,
): EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryMode {
  const mode = textFrom(value, "generic_webhook");
  if (mode === "wecom_robot" || mode === "email_gateway") return mode;
  return "generic_webhook";
}

function archiveReleaseSlaNotificationHttpPayload(
  row: EngineeringBatchArchiveReleaseSlaNotificationExecutionRow,
  audit: EngineeringBatchArchiveReleaseSlaNotificationExecutionAudit,
  mode: EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryMode,
  deliveryFieldTemplate?: EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate | null,
): Record<string, unknown> {
  const fieldNames =
    deliveryFieldTemplate?.payloadFieldNames ?? DEFAULT_ARCHIVE_RELEASE_SLA_NOTIFICATION_HTTP_PAYLOAD_FIELD_NAMES;
  const values: Record<EngineeringBatchArchiveReleaseSlaNotificationHttpPayloadFieldKey, string> = {
    executionId: row.executionId,
    occurrenceId: row.occurrenceId,
    reminderId: row.reminderId,
    occurrenceAt: row.occurrenceAt,
    channel: row.channel,
    severity: row.scheduleSeverity,
    releaseVersion: row.releaseVersion,
    adapterId: row.adapterId,
    targetSystem: row.targetSystem,
    issueId: row.issueId,
    escalationRole: row.escalationRole,
    title: row.messageTitle,
    body: row.messageBody,
    action: row.action,
    sourceAuditFingerprint: audit.auditFingerprint,
    sourceScheduleFingerprint: audit.sourceScheduleFingerprint,
  };
  const base = Object.fromEntries(
    ARCHIVE_RELEASE_SLA_NOTIFICATION_HTTP_PAYLOAD_FIELD_KEYS.map((key) => [fieldNames[key], values[key]]),
  );
  if (mode === "wecom_robot") {
    return {
      msgtype: "markdown",
      markdown: {
        content: `### ${row.messageTitle}\n\n${row.messageBody}\n\n处理要求：${row.action}`,
      },
      railwise: base,
    };
  }
  if (mode === "email_gateway") {
    return {
      subject: row.messageTitle,
      text: `${row.messageBody}\n\n处理要求：${row.action}`,
      to_role: row.escalationRole,
      channel: row.channel,
      railwise: base,
    };
  }
  return base;
}

