export function buildEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryPlan(
  audit: EngineeringBatchArchiveReleaseSlaNotificationExecutionAudit,
  options: {
    generatedAt?: string;
    endpointBaseUrl: string;
    adapterMode?: EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryMode;
    includeProcessed?: boolean;
    deliveryFieldTemplate?: EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate | null;
  },
): EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryPlan {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const endpointBaseUrl = archiveReleaseSlaNotificationHttpEndpoint(options.endpointBaseUrl);
  const adapterMode = archiveReleaseSlaNotificationHttpAdapterMode(options.adapterMode);
  const deliveryFieldTemplate = options.deliveryFieldTemplate ?? null;
  const candidateRows = audit.rows.filter((row) => options.includeProcessed || row.executionStatus === "pending");
  const requests = candidateRows.map((row, index) => {
    const requestBody = {
      requestId: `SLA-NOTIFY-HTTP-${String(index + 1).padStart(3, "0")}`,
      executionId: row.executionId,
      occurrenceId: row.occurrenceId,
      reminderId: row.reminderId,
      occurrenceAt: row.occurrenceAt,
      channel: row.channel,
      method: "POST" as const,
      endpointUrl: endpointBaseUrl,
      adapterMode,
      scheduleSeverity: row.scheduleSeverity,
      releaseVersion: row.releaseVersion,
      adapterId: row.adapterId,
      targetSystem: row.targetSystem,
      issueId: row.issueId,
      escalationRole: row.escalationRole,
      messageTitle: row.messageTitle,
      messageBody: row.messageBody,
      payload: archiveReleaseSlaNotificationHttpPayload(row, audit, adapterMode, deliveryFieldTemplate),
    };
    return {
      ...requestBody,
      requestFingerprint: fnv1a32Fingerprint(JSON.stringify(requestBody)),
    };
  });
  const body = {
    schema: "railwise.engineering.batch.archiveReleaseSlaNotificationHttpDeliveryPlan.v1" as const,
    generatedAt,
    endpointBaseUrl,
    adapterMode,
    sourceAuditFingerprint: audit.auditFingerprint,
    sourceScheduleFingerprint: audit.sourceScheduleFingerprint,
    sourceReminderFingerprint: audit.sourceReminderFingerprint,
    sourceLedgerFingerprint: audit.sourceLedgerFingerprint,
    scheduleTemplateFingerprint: audit.scheduleTemplateFingerprint,
    fieldTemplateFingerprint: deliveryFieldTemplate?.templateFingerprint ?? null,
    requestCount: requests.length,
    pendingExecutionCount: audit.rows.filter((row) => row.executionStatus === "pending").length,
    includedProcessedCount: requests.filter((row) => {
      const source = audit.rows.find((auditRow) => auditRow.executionId === row.executionId);
      return source ? source.executionStatus !== "pending" : false;
    }).length,
    requests,
  };
  const planFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const csv = archiveReleaseSlaNotificationHttpDeliveryPlanCsv(requests);
  return {
    ...body,
    planFingerprint,
    csv,
    json: JSON.stringify({ ...body, planFingerprint, csv }, null, 2),
  };
}

function archiveReleaseSlaNotificationHttpResponseValue(
  response: Record<string, unknown>,
  aliases: string[],
): string {
  return externalSystemHttpResponseValue(response, aliases);
}

function archiveReleaseSlaNotificationHttpResponseAliases(
  key: EngineeringBatchArchiveReleaseSlaNotificationHttpResponseFieldKey,
  deliveryFieldTemplate?: EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate | null,
): string[] {
  return uniqueNonEmptyStrings([
    ...(deliveryFieldTemplate?.responseAliases[key] ?? []),
    ...DEFAULT_ARCHIVE_RELEASE_SLA_NOTIFICATION_HTTP_RESPONSE_ALIASES[key],
  ]);
}

function archiveReleaseSlaNotificationHttpExecutionStatus(input: {
  attempt: EngineeringBatchExternalSystemHttpSubmissionAttemptInput | undefined;
  statusCode: number | null;
  httpOk: boolean;
  response: Record<string, unknown>;
  deliveryFieldTemplate?: EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate | null;
}): EngineeringBatchArchiveReleaseSlaNotificationExecutionStatus {
  const explicit = archiveReleaseSlaNotificationHttpResponseValue(
    input.response,
    archiveReleaseSlaNotificationHttpResponseAliases("executionStatus", input.deliveryFieldTemplate),
  );
  const normalized = explicit.trim().toLowerCase();
  if (normalized === "sent" || normalized === "delivered" || normalized === "accepted" || normalized === "success") return "sent";
  if (normalized === "failed" || normalized === "rejected" || normalized === "error") return "failed";
  if (normalized === "skipped" || normalized === "ignored") return "skipped";
  if (!input.attempt) return "pending";
  if (input.attempt.errorMessage || input.statusCode === null || !input.httpOk || input.statusCode >= 400) return "failed";
  return "sent";
}

function archiveReleaseSlaNotificationHttpDeliveryStatus(input: {
  attempt: EngineeringBatchExternalSystemHttpSubmissionAttemptInput | undefined;
  statusCode: number | null;
  httpOk: boolean;
  executionStatus: EngineeringBatchArchiveReleaseSlaNotificationExecutionStatus;
}): EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryStatus {
  if (!input.attempt) return "missing_attempt";
  if (input.attempt.errorMessage || input.statusCode === null) return "network_error";
  if (!input.httpOk || input.statusCode >= 400) return "http_error";
  if (input.executionStatus === "skipped") return "skipped";
  if (input.executionStatus === "failed") return "failed";
  if (input.executionStatus === "sent") return "sent";
  return "pending";
}

function archiveReleaseSlaNotificationHttpResponseMessage(
  attempt: EngineeringBatchExternalSystemHttpSubmissionAttemptInput | undefined,
  response: Record<string, unknown>,
  deliveryFieldTemplate?: EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryFieldTemplate | null,
): string {
  if (!attempt) return "未执行 HTTP 通知发送";
  if (attempt.errorMessage) return attempt.errorMessage;
  const message = archiveReleaseSlaNotificationHttpResponseValue(
    response,
    archiveReleaseSlaNotificationHttpResponseAliases("responseMessage", deliveryFieldTemplate),
  );
  if (message) return message;
  if (attempt.statusCode && attempt.statusCode >= 400) return `HTTP ${attempt.statusCode} 通知发送失败`;
  return "通知网关已接收";
}

function archiveReleaseSlaNotificationHttpFailureReason(input: {
  attempt: EngineeringBatchExternalSystemHttpSubmissionAttemptInput | undefined;
  statusCode: number | null;
  deliveryStatus: EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryStatus;
  responseMessage: string;
}): string {
  if (input.deliveryStatus === "network_error") return input.responseMessage || "网络或连接失败";
  if (input.deliveryStatus === "http_error") {
    return input.statusCode ? `HTTP ${input.statusCode}: ${input.responseMessage}` : input.responseMessage;
  }
  if (input.deliveryStatus === "failed") return input.responseMessage;
  return "";
}

