function engineeringImportFileStem(file: EngineeringImportFilePayload): string {
  const name = file.file_name || file.path.split(/[\\/]/).pop() || file.path;
  return name.replace(/\.[^.]+$/u, "").trim() || name;
}

function externalSystemImportEndpointUrl(
  adapterId: string,
  recordType: EngineeringBatchExternalSystemUploadRecordType,
  baseUrl: string | null,
): string {
  const suffix = `${adapterId}/${recordType}`;
  if (!baseUrl) return `offline://${suffix}`;
  return `${baseUrl.replace(/\/+$/g, "")}/${suffix}`;
}

function externalSystemImportRequestId(
  adapterId: string,
  recordType: EngineeringBatchExternalSystemUploadRecordType,
  filePath: string,
  index: number,
): string {
  const pathSegment = filePath ? archivePathSegment(filePath, "file") : "archive";
  return `${adapterId}-${recordType}-${index + 1}-${pathSegment}`.slice(0, 120);
}

function buildEngineeringBatchExternalSystemImportPlanFromPayload(
  payload: EngineeringBatchArchivePayload,
  context: EngineeringBatchArchiveZipExportContext = {},
  rowFilter?: (row: EngineeringBatchExternalSystemUploadRow) => boolean,
  adapterIdsOverride?: EngineeringBatchExternalSystemUploadAdapterId[],
): EngineeringBatchExternalSystemImportPlan {
  const importMode = context.externalSystemImportMode ?? "offline_csv";
  const endpointBaseUrl = normalizeExternalSystemEndpointBaseUrl(context.externalSystemEndpointBaseUrl) || null;
  const uploadRows = rowFilter
    ? payload.externalSystemUploadAdapters.rows.filter(rowFilter)
    : payload.externalSystemUploadAdapters.rows;
  const groups = new Map<
    string,
    {
      adapterId: string;
      targetSystem: string;
      recordType: EngineeringBatchExternalSystemUploadRecordType;
      filePath: string;
      fields: EngineeringBatchExternalSystemUploadRow[];
    }
  >();
  for (const row of uploadRows) {
    const key = `${row.adapterId}\u0000${row.recordType}\u0000${row.filePath}`;
    const current =
      groups.get(key) ??
      {
        adapterId: row.adapterId,
        targetSystem: row.targetSystem,
        recordType: row.recordType,
        filePath: row.filePath,
        fields: [],
      };
    current.fields.push(row);
    groups.set(key, current);
  }
  const requests: EngineeringBatchExternalSystemImportPlanRequest[] = Array.from(groups.values()).map((group, index) => {
    const payloadFields = Object.fromEntries(group.fields.map((field) => [field.externalFieldKey, field.value]));
    const requestBody = {
      requestId: externalSystemImportRequestId(group.adapterId, group.recordType, group.filePath, index),
      adapterId: group.adapterId,
      targetSystem: group.targetSystem,
      recordType: group.recordType,
      filePath: group.filePath,
      method: "POST" as const,
      endpointUrl: externalSystemImportEndpointUrl(group.adapterId, group.recordType, endpointBaseUrl),
      payload: payloadFields,
      fieldCount: group.fields.length,
      requiredFieldCount: group.fields.filter((field) => field.required).length,
    };
    return {
      ...requestBody,
      requestFingerprint: fnv1a32Fingerprint(JSON.stringify(requestBody)),
    };
  });
  const adapterIds =
    adapterIdsOverride ??
    (uniqueNonEmptyStrings(
      requests.map((request) => request.adapterId),
    ) as EngineeringBatchExternalSystemUploadAdapterId[]);
  const body = {
    schema: "railwise.engineering.batch.externalSystemImportPlan.v1" as const,
    generatedAt: payload.exportedAt,
    batchName: payload.batchName,
    archiveFolderName: payload.externalUploadManifest.archiveFolderName,
    archivePackageName: payload.archivePackageName,
    importMode,
    endpointBaseUrl,
    adapterIds,
    adapterCount: adapterIds.length,
    requestCount: requests.length,
    requests,
  };
  const planFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withFingerprint = {
    ...body,
    planFingerprint,
  };
  const csv = csvFromRows(
    [
      "request_id",
      "adapter_id",
      "target_system",
      "record_type",
      "file_path",
      "method",
      "endpoint_url",
      "field_count",
      "required_field_count",
      "payload_json",
      "request_fingerprint",
    ],
    requests.map((request) => ({
      request_id: request.requestId,
      adapter_id: request.adapterId,
      target_system: request.targetSystem,
      record_type: request.recordType,
      file_path: request.filePath,
      method: request.method,
      endpoint_url: request.endpointUrl,
      field_count: request.fieldCount,
      required_field_count: request.requiredFieldCount,
      payload_json: JSON.stringify(request.payload),
      request_fingerprint: request.requestFingerprint,
    })),
  );
  const receiptTemplateCsv = csvFromRows(
    [
      "request_id",
      "adapter_id",
      "record_type",
      "file_path",
      "external_record_id",
      "receipt_status",
      "receipt_message",
      "received_at",
    ],
    requests.map((request) => ({
      request_id: request.requestId,
      adapter_id: request.adapterId,
      record_type: request.recordType,
      file_path: request.filePath,
      external_record_id: "",
      receipt_status: "",
      receipt_message: "",
      received_at: "",
    })),
  );
  return {
    ...withFingerprint,
    csv,
    receiptTemplateCsv,
    json: JSON.stringify(withFingerprint, null, 2),
  };
}

