const ARCHIVE_RELEASE_SLA_REMINDER_ARCHIVE_INGEST_IMPORT_FILE_PATHS = new Set([
  "batch/archive-release-sla-reminder-ingest.md",
  "batch/archive-release-sla-reminder-ingest.csv",
  "batch/archive-release-sla-reminder-ingest.json",
]);

export function buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemImportPlan(
  items: EngineeringBatchPackageItem[],
  context: EngineeringBatchArchiveZipExportContext = {},
): EngineeringBatchExternalSystemImportPlan {
  const payload = buildEngineeringBatchArchivePayload(items, context);
  return buildEngineeringBatchExternalSystemImportPlanFromPayload(
    payload,
    context,
    (row) =>
      row.recordType === "file" && ARCHIVE_RELEASE_SLA_REMINDER_ARCHIVE_INGEST_IMPORT_FILE_PATHS.has(row.filePath),
  );
}

function archiveReleaseSlaReminderExternalImportFileType(filePath: string): "md" | "csv" | "json" {
  if (filePath.endsWith(".md")) return "md";
  if (filePath.endsWith(".csv")) return "csv";
  return "json";
}

function archiveReleaseSlaReminderExternalImportStatus(input: {
  requestCount: number;
  acceptedCount: number;
  rejectedCount: number;
  pendingCount: number;
  skippedCount: number;
  missingReceiptCount: number;
}): EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportStatus {
  if (input.requestCount === 0 || input.missingReceiptCount === input.requestCount) return "missing_receipt";
  if (input.rejectedCount > 0) return "rejected";
  if (input.pendingCount > 0 || input.skippedCount > 0 || input.missingReceiptCount > 0) return "pending";
  if (input.acceptedCount === input.requestCount) return "accepted";
  return "mixed";
}

function archiveReleaseSlaReminderExternalImportAggregateStatus(
  rows: EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportReceiptUpdateRow[],
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportStatus {
  if (rows.length === 0) return "missing_receipt";
  if (rows.some((row) => row.externalImportStatus === "rejected")) return "rejected";
  if (rows.some((row) => row.externalImportStatus === "pending")) return "pending";
  if (rows.some((row) => row.externalImportStatus === "missing_receipt")) return "missing_receipt";
  if (rows.every((row) => row.externalImportStatus === "accepted")) return "accepted";
  return "mixed";
}

function archiveReleaseSlaReminderExternalImportAction(
  status: EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportStatus,
): string {
  if (status === "accepted") return "SLA 提醒入库证据已在全部目标系统确认入库，可归档外部回执。";
  if (status === "rejected") return "存在外部系统拒绝入库，请按回执原因修正字段、权限或资料版本后重新提交。";
  if (status === "pending") return "存在异步处理、跳过或部分缺回执，请保留 request_id 继续追踪最终入库状态。";
  if (status === "missing_receipt") return "缺少外部系统回执，请按专项回执模板补齐 request_id 对应结果。";
  return "外部入库状态不一致，请按文件和 adapter 拆分复核。";
}

