export function buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemImportReceiptUpdate(
  ingest: EngineeringBatchArchiveReleaseSlaReminderArchiveIngest,
  plan: EngineeringBatchExternalSystemImportPlan,
  reconciliation: EngineeringBatchExternalSystemImportReceiptReconciliation,
  options: { generatedAt?: string } = {},
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportReceiptUpdate {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const targetFilePaths = Array.from(ARCHIVE_RELEASE_SLA_REMINDER_ARCHIVE_INGEST_IMPORT_FILE_PATHS);
  const rows = targetFilePaths.map((filePath): EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportReceiptUpdateRow => {
    const related = reconciliation.rows.filter(
      (row) => row.filePath === filePath && row.reconciliationStatus !== "unmatched_receipt",
    );
    const requestCount = plan.requests.filter((request) => request.filePath === filePath).length || related.length;
    const acceptedCount = related.filter((row) => row.reconciliationStatus === "accepted").length;
    const rejectedCount = related.filter((row) => row.reconciliationStatus === "rejected").length;
    const pendingCount = related.filter((row) => row.reconciliationStatus === "pending").length;
    const skippedCount = related.filter((row) => row.reconciliationStatus === "skipped").length;
    const missingReceiptCount = Math.max(
      related.filter((row) => row.reconciliationStatus === "missing_receipt").length,
      requestCount - related.length,
    );
    const externalImportStatus = archiveReleaseSlaReminderExternalImportStatus({
      requestCount,
      acceptedCount,
      rejectedCount,
      pendingCount,
      skippedCount,
      missingReceiptCount,
    });
    return {
      filePath,
      fileType: archiveReleaseSlaReminderExternalImportFileType(filePath),
      requestCount,
      adapterIds: uniqueNonEmptyStrings(related.map((row) => row.adapterId)) as EngineeringBatchExternalSystemUploadAdapterId[],
      acceptedCount,
      rejectedCount,
      pendingCount,
      skippedCount,
      missingReceiptCount,
      externalRecordIds: uniqueNonEmptyStrings(related.map((row) => row.externalRecordId)),
      receiptMessages: uniqueNonEmptyStrings(related.map((row) => row.receiptMessage)),
      externalImportStatus,
      action: archiveReleaseSlaReminderExternalImportAction(externalImportStatus),
    };
  });
  const acceptedCount = rows.reduce((sum, row) => sum + row.acceptedCount, 0);
  const rejectedCount = rows.reduce((sum, row) => sum + row.rejectedCount, 0);
  const pendingCount = rows.reduce((sum, row) => sum + row.pendingCount, 0);
  const skippedCount = rows.reduce((sum, row) => sum + row.skippedCount, 0);
  const missingReceiptCount = rows.reduce((sum, row) => sum + row.missingReceiptCount, 0);
  const externalImportStatus = archiveReleaseSlaReminderExternalImportAggregateStatus(rows);
  const { markdown: _markdown, csv: _csv, json: _json, ingestFingerprint: sourceIngestFingerprint, ...ingestBase } = ingest;
  const updatedIngestBody = {
    ...ingestBase,
    externalImportUpdatedAt: generatedAt,
    externalImportPlanFingerprint: plan.planFingerprint,
    externalImportReconciliationFingerprint: reconciliation.reconciliationFingerprint,
    externalImportStatus,
    externalImportRequestCount: plan.requestCount,
    externalImportAcceptedCount: acceptedCount,
    externalImportRejectedCount: rejectedCount,
    externalImportPendingCount: pendingCount,
    externalImportSkippedCount: skippedCount,
    externalImportMissingReceiptCount: missingReceiptCount,
    externalImportUnmatchedReceiptCount: reconciliation.unmatchedReceiptCount,
    externalImportRows: rows,
  };
  const updatedIngestFingerprint = fnv1a32Fingerprint(JSON.stringify(updatedIngestBody));
  const updatedIngestWithoutArtifacts = {
    ...updatedIngestBody,
    ingestFingerprint: updatedIngestFingerprint,
  };
  const updatedIngestCsv = archiveReleaseSlaReminderArchiveIngestCsv(updatedIngestWithoutArtifacts);
  const updatedIngestMarkdown = archiveReleaseSlaReminderArchiveIngestMarkdown(updatedIngestWithoutArtifacts);
  const updatedArchiveIngest: EngineeringBatchArchiveReleaseSlaReminderArchiveIngest = {
    ...updatedIngestWithoutArtifacts,
    markdown: updatedIngestMarkdown,
    csv: updatedIngestCsv,
    json: JSON.stringify({ ...updatedIngestWithoutArtifacts, markdown: updatedIngestMarkdown, csv: updatedIngestCsv }, null, 2),
  };
  const body = {
    schema: "railwise.engineering.batch.archiveReleaseSlaReminderExternalSystemImportReceiptUpdate.v1" as const,
    generatedAt,
    batchName: ingest.batchName,
    sourceIngestFingerprint,
    planFingerprint: plan.planFingerprint,
    sourceReconciliationFingerprint: reconciliation.reconciliationFingerprint,
    fileCount: rows.length,
    requestCount: plan.requestCount,
    acceptedCount,
    rejectedCount,
    pendingCount,
    skippedCount,
    missingReceiptCount,
    unmatchedReceiptCount: reconciliation.unmatchedReceiptCount,
    externalImportStatus,
    rows,
    updatedArchiveIngest,
  };
  const updateFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    updateFingerprint,
  };
  const csv = archiveReleaseSlaReminderExternalImportReceiptUpdateCsv(rows);
  const markdown = archiveReleaseSlaReminderExternalImportReceiptUpdateMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveReleaseSlaReminderExternalImportRectificationType(
  status: EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportStatus,
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationType | null {
  if (status === "accepted") return null;
  if (status === "rejected") return "rejected";
  if (status === "pending") return "pending";
  if (status === "missing_receipt") return "missing_receipt";
  return "mixed";
}

function archiveReleaseSlaReminderExternalImportRectificationPriority(
  type: EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationType,
): EngineeringProjectArchiveRectificationPriority {
  return type === "rejected" || type === "mixed" ? "high" : "normal";
}

function archiveReleaseSlaReminderExternalImportRectificationAction(
  type: EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationType,
): string {
  if (type === "rejected") return "按专项回执拒绝原因修正 SLA 提醒入库清单字段、权限或资料版本后重新提交。";
  if (type === "pending") return "外部系统仍在处理 SLA 提醒入库清单，保留 request_id 并在截止日前补充最终回执。";
  if (type === "missing_receipt") return "缺少 SLA 提醒入库清单外部回执，请联系平台或接口管理员按文件补齐结果。";
  return "SLA 提醒入库清单外部状态不一致，请按文件和 adapter 拆分复核后重新回执。";
}

