export function buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationClosureUpdate(
  ledger: EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationLedger,
  input: EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationClosureInput,
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationClosureUpdate {
  const importedAt = input.importedAt ?? new Date().toISOString();
  const { source, records } = parseArchiveReleaseSlaReminderExternalImportRectificationClosureInput({
    ...input,
    importedAt,
  });
  const recordsByIssueId = new Map<string, EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationClosureRecord>();
  const recordsByFilePath = new Map<string, EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationClosureRecord>();
  for (const record of records) {
    if (record.issueId) recordsByIssueId.set(rectificationIssueKey(record.issueId), record);
    if (record.filePath) recordsByFilePath.set(rectificationIssueKey(record.filePath), record);
  }
  const matchedRecords = new Set<EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationClosureRecord>();
  const updateRows: EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationClosureUpdateRow[] = [];
  const updatedRows = ledger.rows.map((row): EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationRow => {
    const record =
      recordsByIssueId.get(rectificationIssueKey(row.issueId)) ??
      recordsByFilePath.get(rectificationIssueKey(row.filePath)) ??
      null;
    if (!record) {
      updateRows.push({
        updateStatus: "missing_update",
        issueId: row.issueId,
        filePath: row.filePath,
        closureStatus: row.closureStatus,
        closedAt: row.closedAt ?? null,
        closedBy: row.closedBy ?? null,
        closureNote: row.closureNote ?? "",
        externalRecordId: row.externalRecordIds.join(";"),
        sourceRowNumber: null,
      });
      return {
        ...row,
        closureSourceStatus: row.closureStatus === "closed" ? row.closureSourceStatus : "missing_rectification_receipt",
      };
    }
    matchedRecords.add(record);
    const closedAt = record.closureStatus === "closed" ? record.closedAt ?? importedAt.slice(0, 10) : record.closedAt;
    const nextRow: EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationRow = {
      ...row,
      closureStatus: record.closureStatus,
      closedAt,
      closedBy: record.closedBy ?? row.closedBy ?? null,
      closureNote: record.closureNote || row.closureNote || "",
      externalRecordIds: uniqueNonEmptyStrings([...row.externalRecordIds, record.externalRecordId]),
      closureSourceStatus:
        record.closureStatus === "closed"
          ? "closed_by_rectification_receipt"
          : "kept_open_by_rectification_receipt",
    };
    updateRows.push({
      updateStatus: record.closureStatus === "closed" ? "closed" : "kept_open",
      issueId: row.issueId,
      filePath: row.filePath,
      closureStatus: record.closureStatus,
      closedAt: nextRow.closedAt ?? null,
      closedBy: nextRow.closedBy ?? null,
      closureNote: nextRow.closureNote ?? "",
      externalRecordId: record.externalRecordId,
      sourceRowNumber: record.rowNumber,
    });
    return nextRow;
  });
  for (const record of records) {
    if (matchedRecords.has(record) || (!record.issueId && !record.filePath)) continue;
    updateRows.push({
      updateStatus: "unknown_issue",
      issueId: record.issueId,
      filePath: record.filePath,
      closureStatus: record.closureStatus,
      closedAt: record.closedAt,
      closedBy: record.closedBy,
      closureNote: record.closureNote,
      externalRecordId: record.externalRecordId,
      sourceRowNumber: record.rowNumber,
    });
  }
  const updatedLedger = buildArchiveReleaseSlaReminderExternalImportRectificationLedgerArtifact({
    generatedAt: ledger.generatedAt,
    batchName: ledger.batchName,
    sourceReceiptUpdateFingerprint: ledger.sourceReceiptUpdateFingerprint,
    sourceIngestFingerprint: ledger.sourceIngestFingerprint,
    updatedIngestFingerprint: ledger.updatedIngestFingerprint,
    rows: updatedRows,
  });
  const csv = archiveReleaseSlaReminderExternalImportRectificationClosureCsv(updateRows);
  const body = {
    schema: "railwise.engineering.batch.archiveReleaseSlaReminderExternalSystemImportRectificationClosureUpdate.v1" as const,
    importedAt,
    batchName: ledger.batchName,
    source,
    sourceLedgerFingerprint: ledger.rectificationFingerprint,
    updatedLedgerFingerprint: updatedLedger.rectificationFingerprint,
    closedCount: updatedLedger.rows.filter((row) => row.closureStatus === "closed").length,
    stillOpenCount: updatedLedger.rows.filter((row) => row.closureStatus === "open").length,
    missingUpdateCount: updateRows.filter((row) => row.updateStatus === "missing_update").length,
    unmatchedUpdateCount: updateRows.filter((row) => row.updateStatus === "unknown_issue").length,
    rows: updateRows,
    updatedLedger,
  };
  const closureFingerprint = fnv1a32Fingerprint(JSON.stringify({ ...body, csv }));
  const withoutArtifacts = {
    ...body,
    closureFingerprint,
  };
  const markdown = archiveReleaseSlaReminderExternalImportRectificationClosureMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function isEngineeringBatchArchiveReleaseSlaReminderExternalSystemImportPlan(
  plan: EngineeringBatchExternalSystemImportPlan,
): boolean {
  return (
    plan.requestCount > 0 &&
    plan.requests.length > 0 &&
    plan.requests.every(
      (request) =>
        request.recordType === "file" && ARCHIVE_RELEASE_SLA_REMINDER_ARCHIVE_INGEST_IMPORT_FILE_PATHS.has(request.filePath),
    )
  );
}

export function buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemHttpReplayUpdate(
  ingest: EngineeringBatchArchiveReleaseSlaReminderArchiveIngest,
  plan: EngineeringBatchExternalSystemImportPlan,
  baseAudit: EngineeringBatchExternalSystemHttpSubmissionAudit,
  replayAudit: EngineeringBatchExternalSystemHttpSubmissionAudit,
  options: { generatedAt?: string } = {},
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemHttpReplayUpdateResult {
  if (!isEngineeringBatchArchiveReleaseSlaReminderExternalSystemImportPlan(plan)) {
    throw new Error("SLA 提醒专项 HTTP 重放更新只支持提醒入库清单三文件的专项入库计划");
  }
  const generatedAt = options.generatedAt ?? replayAudit.completedAt;
  const mergedAudit = mergeEngineeringBatchExternalSystemHttpReplayAudit(baseAudit, replayAudit, {
    mergedAt: generatedAt,
  });
  const reconciliation = buildEngineeringBatchExternalSystemImportReceiptReconciliation(plan, {
    text: mergedAudit.receiptCsv,
    format: "csv",
    sourceName: "SLA 提醒专项 HTTP 重放合并回执.csv",
    importedAt: generatedAt,
  });
  const replayQueue = buildEngineeringBatchExternalSystemHttpReplayQueue(plan, mergedAudit, {
    generatedAt,
  });
  const receiptUpdate = buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemImportReceiptUpdate(
    ingest,
    plan,
    reconciliation,
    { generatedAt },
  );
  return {
    mergedAudit,
    reconciliation,
    replayQueue,
    receiptUpdate,
  };
}

