export function buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptConfirmation(
  receiptUpdate: EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportReceiptUpdate,
  plan: EngineeringBatchExternalSystemImportPlan,
  input: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptInput,
  options: {
    replayHistory?: EngineeringBatchArchiveReleaseSlaReminderExternalSystemHttpReplayHistory | null;
    closureUpdate?: EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationClosureUpdate | null;
  } = {},
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptConfirmation {
  if (!isEngineeringBatchArchiveReleaseSlaReminderExternalSystemImportPlan(plan)) {
    throw new Error("SLA 提醒专项最终回执二次确认只支持提醒入库清单三文件的专项入库计划");
  }
  const { source, records } = parseArchiveReleaseSlaReminderFinalReceiptInput(input);
  const recordsByRequestId = new Map(records.filter((record) => record.requestId).map((record) => [record.requestId, record]));
  const recordsByAdapterFile = new Map(
    records
      .filter((record) => record.adapterId && record.filePath)
      .map((record) => [`${record.adapterId}\u0000${record.filePath}`, record]),
  );
  const matchedRecords = new Set<EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptRecord>();
  const previousFileStatusByPath = new Map(
    receiptUpdate.rows.map((row) => [row.filePath, row.externalImportStatus] as const),
  );
  const rows: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptConfirmationRow[] = plan.requests.map((request) => {
    const record =
      recordsByRequestId.get(request.requestId) ??
      recordsByAdapterFile.get(`${request.adapterId}\u0000${request.filePath}`) ??
      null;
    if (record) matchedRecords.add(record);
    const confirmationStatus = archiveReleaseSlaReminderFinalConfirmationStatus(record?.finalReceiptStatus ?? null);
    return {
      requestId: request.requestId,
      adapterId: request.adapterId,
      targetSystem: request.targetSystem,
      filePath: request.filePath,
      previousFileStatus: previousFileStatusByPath.get(request.filePath) ?? null,
      finalReceiptStatus: record?.finalReceiptStatus ?? null,
      confirmationStatus,
      externalRecordId: record?.externalRecordId ?? "",
      confirmedAt: record?.confirmedAt ?? null,
      confirmedBy: record?.confirmedBy ?? null,
      confirmationNote: record?.confirmationNote ?? "",
      platformChecksum: record?.platformChecksum ?? "",
      sourceRowNumber: record?.rowNumber ?? null,
    };
  });
  for (const record of records) {
    if (matchedRecords.has(record)) continue;
    rows.push({
      requestId: record.requestId,
      adapterId: record.adapterId,
      targetSystem: "",
      filePath: record.filePath,
      previousFileStatus: null,
      finalReceiptStatus: record.finalReceiptStatus,
      confirmationStatus: "unmatched_confirmation",
      externalRecordId: record.externalRecordId,
      confirmedAt: record.confirmedAt,
      confirmedBy: record.confirmedBy,
      confirmationNote: record.confirmationNote,
      platformChecksum: record.platformChecksum,
      sourceRowNumber: record.rowNumber,
    });
  }
  const planRows = rows.filter((row) => row.confirmationStatus !== "unmatched_confirmation");
  const confirmedCount = planRows.filter((row) => row.confirmationStatus === "confirmed").length;
  const rejectedCount = planRows.filter((row) => row.confirmationStatus === "rejected").length;
  const pendingCount = planRows.filter((row) => row.confirmationStatus === "kept_pending").length;
  const missingConfirmationCount = planRows.filter((row) => row.confirmationStatus === "missing_confirmation").length;
  const unmatchedConfirmationCount = rows.filter((row) => row.confirmationStatus === "unmatched_confirmation").length;
  const finalExternalImportStatus = archiveReleaseSlaReminderFinalConfirmationAggregateStatus({
    requestCount: plan.requestCount,
    confirmedCount,
    rejectedCount,
    pendingCount,
    missingConfirmationCount,
    unmatchedConfirmationCount,
  });
  const fileRows = Array.from(ARCHIVE_RELEASE_SLA_REMINDER_ARCHIVE_INGEST_IMPORT_FILE_PATHS).map(
    (filePath): EngineeringBatchArchiveReleaseSlaReminderExternalSystemImportReceiptUpdateRow => {
      const related = planRows.filter((row) => row.filePath === filePath);
      const requestCount = plan.requests.filter((request) => request.filePath === filePath).length;
      const acceptedCount = related.filter((row) => row.confirmationStatus === "confirmed").length;
      const rejectedForFile = related.filter((row) => row.confirmationStatus === "rejected").length;
      const pendingForFile = related.filter((row) => row.confirmationStatus === "kept_pending").length;
      const missingForFile = Math.max(
        related.filter((row) => row.confirmationStatus === "missing_confirmation").length,
        requestCount - related.length,
      );
      const externalImportStatus = archiveReleaseSlaReminderExternalImportStatus({
        requestCount,
        acceptedCount,
        rejectedCount: rejectedForFile,
        pendingCount: pendingForFile,
        skippedCount: 0,
        missingReceiptCount: missingForFile,
      });
      return {
        filePath,
        fileType: archiveReleaseSlaReminderExternalImportFileType(filePath),
        requestCount,
        adapterIds: uniqueNonEmptyStrings(related.map((row) => row.adapterId)) as EngineeringBatchExternalSystemUploadAdapterId[],
        acceptedCount,
        rejectedCount: rejectedForFile,
        pendingCount: pendingForFile,
        skippedCount: 0,
        missingReceiptCount: missingForFile,
        externalRecordIds: uniqueNonEmptyStrings(related.map((row) => row.externalRecordId)),
        receiptMessages: uniqueNonEmptyStrings(related.map((row) => row.confirmationNote)),
        externalImportStatus,
        action: archiveReleaseSlaReminderExternalImportAction(externalImportStatus),
      };
    },
  );
  const preFingerprintBody = {
    schema: "railwise.engineering.batch.archiveReleaseSlaReminderExternalSystemFinalReceiptConfirmation.v1" as const,
    importedAt: source.importedAt,
    batchName: receiptUpdate.batchName,
    source,
    planFingerprint: plan.planFingerprint,
    sourceReceiptUpdateFingerprint: receiptUpdate.updateFingerprint,
    sourceReplayHistoryFingerprint: options.replayHistory?.historyFingerprint ?? null,
    sourceClosureFingerprint: options.closureUpdate?.closureFingerprint ?? null,
    requestCount: plan.requestCount,
    fileCount: fileRows.length,
    confirmedCount,
    rejectedCount,
    pendingCount,
    missingConfirmationCount,
    unmatchedConfirmationCount,
    finalExternalImportStatus,
    rows,
    fileRows,
  };
  const confirmationFingerprint = fnv1a32Fingerprint(JSON.stringify(preFingerprintBody));
  const { markdown: _markdown, csv: _csv, json: _json, ingestFingerprint: _ingestFingerprint, ...ingestBase } =
    receiptUpdate.updatedArchiveIngest;
  const updatedIngestBody = {
    ...ingestBase,
    externalImportUpdatedAt: source.importedAt,
    externalImportPlanFingerprint: plan.planFingerprint,
    externalImportReconciliationFingerprint: confirmationFingerprint,
    externalImportStatus: finalExternalImportStatus,
    externalImportRequestCount: plan.requestCount,
    externalImportAcceptedCount: confirmedCount,
    externalImportRejectedCount: rejectedCount,
    externalImportPendingCount: pendingCount,
    externalImportSkippedCount: 0,
    externalImportMissingReceiptCount: missingConfirmationCount,
    externalImportUnmatchedReceiptCount: unmatchedConfirmationCount,
    externalImportRows: fileRows,
  };
  const ingestFingerprint = fnv1a32Fingerprint(JSON.stringify(updatedIngestBody));
  const updatedIngestWithoutArtifacts = {
    ...updatedIngestBody,
    ingestFingerprint,
  };
  const updatedIngestCsv = archiveReleaseSlaReminderArchiveIngestCsv(updatedIngestWithoutArtifacts);
  const updatedIngestMarkdown = archiveReleaseSlaReminderArchiveIngestMarkdown(updatedIngestWithoutArtifacts);
  const updatedArchiveIngest: EngineeringBatchArchiveReleaseSlaReminderArchiveIngest = {
    ...updatedIngestWithoutArtifacts,
    markdown: updatedIngestMarkdown,
    csv: updatedIngestCsv,
    json: JSON.stringify({ ...updatedIngestWithoutArtifacts, markdown: updatedIngestMarkdown, csv: updatedIngestCsv }, null, 2),
  };
  const withoutArtifacts = {
    ...preFingerprintBody,
    updatedArchiveIngest,
    confirmationFingerprint,
  };
  const csv = archiveReleaseSlaReminderFinalConfirmationCsv(rows);
  const markdown = archiveReleaseSlaReminderFinalConfirmationMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveReleaseSlaReminderFinalReceiptCrossPlatformReviewStatus(
  issueTypes: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformIssueType[],
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformReviewStatus {
  const withoutRecordWarnings = issueTypes.filter((type) => type !== "external_record_mismatch");
  if (withoutRecordWarnings.length === 0 && issueTypes.length === 0) return "consistent";
  if (withoutRecordWarnings.length === 1) return withoutRecordWarnings[0];
  if (withoutRecordWarnings.length === 0 && issueTypes.length === 1) return issueTypes[0];
  return "mixed";
}

function archiveReleaseSlaReminderFinalReceiptCrossPlatformSeverity(
  issueTypes: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformIssueType[],
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformSeverity {
  if (
    issueTypes.includes("status_mismatch") ||
    issueTypes.includes("checksum_mismatch") ||
    issueTypes.includes("missing_confirmation")
  ) {
    return "blocking";
  }
  if (issueTypes.length > 0) return "warning";
  return "ok";
}

function archiveReleaseSlaReminderFinalReceiptCrossPlatformAction(
  row: Pick<
    EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformRow,
    "reviewStatus" | "issueTypes" | "filePath" | "missingConfirmationCount"
  >,
): string {
  if (row.issueTypes.includes("missing_confirmation")) {
    return `补齐 ${row.filePath} 在所有外部平台的最终回执后再签发。`;
  }
  if (row.issueTypes.includes("status_mismatch")) {
    return `${row.filePath} 跨平台最终状态不一致，应回到外部平台核对 accepted/rejected/pending 终态。`;
  }
  if (row.issueTypes.includes("checksum_mismatch")) {
    return `${row.filePath} 跨平台校验码不一致，应复核上传文件版本和平台保存文件。`;
  }
  if (row.issueTypes.includes("external_record_mismatch")) {
    return `${row.filePath} 外部记录号存在差异，签发前应确认各平台档案号是否均属同一资料版本。`;
  }
  return `${row.filePath} 跨平台最终回执一致，可进入最终确认签发。`;
}

