export function buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformReview(
  confirmation: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptConfirmation,
  options: { generatedAt?: string } = {},
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformReview {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const requestRows = confirmation.rows.filter((row) => row.confirmationStatus !== "unmatched_confirmation");
  const expectedAdapterIds = uniqueNonEmptyStrings(requestRows.map((row) => row.adapterId));
  const filePaths = uniqueNonEmptyStrings([
    ...Array.from(ARCHIVE_RELEASE_SLA_REMINDER_ARCHIVE_INGEST_IMPORT_FILE_PATHS),
    ...requestRows.map((row) => row.filePath),
  ]);
  const rows = filePaths.map((filePath): EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformRow => {
    const related = requestRows.filter((row) => row.filePath === filePath);
    const adapterIds = uniqueNonEmptyStrings(related.map((row) => row.adapterId));
    const expectedAdapterCount = expectedAdapterIds.length;
    const finalStatuses = uniqueNonEmptyStrings(related.map((row) => row.finalReceiptStatus ?? ""));
    const externalRecordIds = uniqueNonEmptyStrings(related.map((row) => row.externalRecordId));
    const platformChecksums = uniqueNonEmptyStrings(related.map((row) => row.platformChecksum));
    const confirmedAdapterCount = related.filter((row) => row.confirmationStatus === "confirmed").length;
    const pendingAdapterCount = related.filter((row) => row.confirmationStatus === "kept_pending").length;
    const rejectedAdapterCount = related.filter((row) => row.confirmationStatus === "rejected").length;
    const missingConfirmationCount =
      related.filter((row) => row.confirmationStatus === "missing_confirmation").length +
      Math.max(0, expectedAdapterCount - adapterIds.length);
    const issueTypes = uniqueNonEmptyStrings([
      missingConfirmationCount > 0 ? "missing_confirmation" : "",
      finalStatuses.length > 1 ? "status_mismatch" : "",
      platformChecksums.length > 1 ? "checksum_mismatch" : "",
    ]) as EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformIssueType[];
    const reviewStatus = archiveReleaseSlaReminderFinalReceiptCrossPlatformReviewStatus(issueTypes);
    const severity = archiveReleaseSlaReminderFinalReceiptCrossPlatformSeverity(issueTypes);
    const draft = {
      filePath,
      fileType: archiveReleaseSlaReminderExternalImportFileType(filePath),
      expectedAdapterCount,
      adapterCount: adapterIds.length,
      confirmedAdapterCount,
      pendingAdapterCount,
      rejectedAdapterCount,
      missingConfirmationCount,
      finalStatuses,
      externalRecordIds,
      platformChecksums,
      adapterSummaries: related.map(
        (row) =>
          `${row.adapterId}:${row.finalReceiptStatus ?? "-"}:${row.confirmationStatus}:${row.externalRecordId || "-"}:${row.platformChecksum || "-"}`,
      ),
      issueTypes,
      reviewStatus,
      severity,
      action: "",
    };
    return {
      ...draft,
      action: archiveReleaseSlaReminderFinalReceiptCrossPlatformAction(draft),
    };
  });
  const blockingIssueCount = rows.filter((row) => row.severity === "blocking").length;
  const warningIssueCount = rows.filter((row) => row.severity === "warning").length;
  const body = {
    schema:
      "railwise.engineering.batch.archiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformReview.v1" as const,
    generatedAt,
    batchName: confirmation.batchName,
    sourceConfirmationFingerprint: confirmation.confirmationFingerprint,
    sourceReceiptUpdateFingerprint: confirmation.sourceReceiptUpdateFingerprint,
    sourceReplayHistoryFingerprint: confirmation.sourceReplayHistoryFingerprint,
    fileCount: rows.length,
    adapterCount: expectedAdapterIds.length,
    issueFileCount: rows.filter((row) => row.severity !== "ok").length,
    blockingIssueCount,
    warningIssueCount,
    reviewStatus: blockingIssueCount + warningIssueCount > 0 ? ("needs_review" as const) : ("passed" as const),
    rows,
  };
  const reviewFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    reviewFingerprint,
  };
  const csv = archiveReleaseSlaReminderFinalReceiptCrossPlatformCsv(rows);
  const markdown = archiveReleaseSlaReminderFinalReceiptCrossPlatformMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveReleaseSlaReminderFinalReceiptBatchSignoffStatus(
  signoff: EngineeringReviewSignoff,
  review: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformReview,
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptBatchSignoffStatus {
  if (review.blockingIssueCount > 0 || review.reviewStatus !== "passed" || signoff.conclusion === "needs_rework") {
    return "blocked";
  }
  if (signoff.conclusion === "pending_review" || !signoff.reviewer) return "pending";
  if (signoff.conclusion === "approved_with_comments" || review.warningIssueCount > 0) return "signed_with_actions";
  return "signed";
}

function archiveReleaseSlaReminderFinalReceiptBatchSignoffRowStatus(
  signoff: EngineeringReviewSignoff,
  row: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformRow,
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptBatchSignoffStatus {
  if (row.severity === "blocking" || signoff.conclusion === "needs_rework") return "blocked";
  if (signoff.conclusion === "pending_review" || !signoff.reviewer) return "pending";
  if (row.severity === "warning" || signoff.conclusion === "approved_with_comments") return "signed_with_actions";
  return "signed";
}

function archiveReleaseSlaReminderFinalReceiptBatchSignoffAction(
  row: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptBatchSignoffRow,
): string {
  if (row.signatureStatus === "blocked") return `阻断签发：${row.action || "需先完成终态复核整改。"}`;
  if (row.signatureStatus === "pending") return "补充最终确认签发人、签发日期和签发结论后再发布。";
  if (row.signatureStatus === "signed_with_actions") {
    return `${row.filePath} 可带备注签发，签发后需保留外部记录号、校验码和备注闭环证据。`;
  }
  return `${row.filePath} 跨平台终态一致，准予最终确认批量签发。`;
}

