export function buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptBatchSignoff(
  confirmation: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptConfirmation,
  review: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformReview,
  options: {
    generatedAt?: string;
    batchName?: string;
    signoff?: EngineeringReviewSignoffInput;
  } = {},
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptBatchSignoff {
  if (review.sourceConfirmationFingerprint !== confirmation.confirmationFingerprint) {
    throw new Error("SLA 提醒专项最终确认批量签发的复核来源与最终回执不一致");
  }
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const signoff = buildEngineeringReviewSignoff(options.signoff, generatedAt);
  const rows = review.rows.map((reviewRow): EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptBatchSignoffRow => {
    const draft = {
      filePath: reviewRow.filePath,
      fileType: reviewRow.fileType,
      signatureStatus: archiveReleaseSlaReminderFinalReceiptBatchSignoffRowStatus(signoff, reviewRow),
      reviewStatus: reviewRow.reviewStatus,
      severity: reviewRow.severity,
      issueTypes: reviewRow.issueTypes,
      adapterCount: reviewRow.adapterCount,
      expectedAdapterCount: reviewRow.expectedAdapterCount,
      finalStatuses: reviewRow.finalStatuses,
      externalRecordIds: reviewRow.externalRecordIds,
      platformChecksums: reviewRow.platformChecksums,
      signedAt: signoff.signedAt,
      signedBy: signoff.reviewer,
      action: reviewRow.action,
    };
    return {
      ...draft,
      action: archiveReleaseSlaReminderFinalReceiptBatchSignoffAction(draft),
    };
  });
  const body = {
    schema: "railwise.engineering.batch.archiveReleaseSlaReminderExternalSystemFinalReceiptBatchSignoff.v1" as const,
    generatedAt,
    batchName: options.batchName?.trim() || confirmation.batchName,
    sourceConfirmationFingerprint: confirmation.confirmationFingerprint,
    sourceCrossPlatformReviewFingerprint: review.reviewFingerprint,
    sourceReceiptUpdateFingerprint: confirmation.sourceReceiptUpdateFingerprint,
    sourceReplayHistoryFingerprint: confirmation.sourceReplayHistoryFingerprint,
    signoff,
    signatureStatus: archiveReleaseSlaReminderFinalReceiptBatchSignoffStatus(signoff, review),
    fileCount: rows.length,
    signedFileCount: rows.filter((row) => row.signatureStatus === "signed").length,
    actionFileCount: rows.filter((row) => row.signatureStatus === "signed_with_actions").length,
    blockingFileCount: rows.filter((row) => row.signatureStatus === "blocked").length,
    rows,
  };
  const signoffFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    signoffFingerprint,
  };
  const csv = archiveReleaseSlaReminderFinalReceiptBatchSignoffCsv(rows);
  const markdown = archiveReleaseSlaReminderFinalReceiptBatchSignoffMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function archiveReleaseSlaReminderFinalReceiptSignoffExternalSyncReceiptAction(
  status: EngineeringBatchExternalSystemImportReceiptReconciliationStatus,
  message: string,
): string {
  if (status === "accepted") return "外部系统已确认最终签发回传完成。";
  if (status === "rejected") return `外部系统拒绝最终签发回传：${message || "未提供原因"}`;
  if (status === "pending") return "外部系统仍在处理最终签发回传，请继续追踪。";
  if (status === "skipped") return `外部系统跳过最终签发回传：${message || "未提供原因"}`;
  if (status === "missing_receipt") return "未收到该最终签发文件的外部回传回执，请按 file_path 追踪。";
  return "回传回执未匹配当前最终签发文件，请核对 file_path。";
}

function archiveReleaseSlaReminderFinalReceiptSignoffExternalSyncReceiptCsv(
  rows: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptSignoffExternalSyncReceiptRow[],
): string {
  return csvFromRows(
    [
      "file_path",
      "file_type",
      "signature_status",
      "external_record_id",
      "receipt_status",
      "receipt_message",
      "received_at",
      "synced_release_version",
      "reconciliation_status",
      "action",
    ],
    rows.map((row) => ({
      file_path: row.filePath,
      file_type: row.fileType,
      signature_status: row.signatureStatus,
      external_record_id: row.externalRecordId,
      receipt_status: row.receiptStatus ?? "",
      receipt_message: row.receiptMessage,
      received_at: row.receivedAt,
      synced_release_version: row.syncedReleaseVersion,
      reconciliation_status: row.reconciliationStatus,
      action: row.action,
    })),
  );
}

function archiveReleaseSlaReminderFinalReceiptSignoffExternalSyncReceiptMarkdown(
  receipt: Omit<
    EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptSignoffExternalSyncReceipt,
    "markdown" | "csv" | "json"
  >,
): string {
  return [
    "# SLA 提醒专项最终签发外部回传回执",
    "",
    `- 批次：${receipt.batchName}`,
    `- 导入时间：${receipt.importedAt}`,
    `- 来源文件：${receipt.sourceName ?? "未命名回执"}`,
    `- 来源最终签发：${receipt.sourceSignoffFingerprint}`,
    `- 签发文件：${receipt.fileCount}`,
    `- 已回传：${receipt.acceptedCount}`,
    `- 拒绝：${receipt.rejectedCount}`,
    `- 待处理：${receipt.pendingCount}`,
    `- 缺回执：${receipt.missingReceiptCount}`,
    `- 未匹配：${receipt.unmatchedReceiptCount}`,
    `- 需跟踪：${receipt.followUpCount}`,
    "",
    "| 文件 | 签发状态 | 回传状态 | 外部记录号 | 版本 | 处理要求 |",
    "| --- | --- | --- | --- | --- | --- |",
    ...receipt.rows.map(
      (row) =>
        `| ${row.filePath} | ${row.signatureStatus} | ${row.reconciliationStatus} | ${row.externalRecordId || "-"} | ${row.syncedReleaseVersion || "-"} | ${row.action} |`,
    ),
    "",
    `receiptFingerprint：${receipt.receiptFingerprint}`,
    "",
  ].join("\n");
}

export function buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptSignoffExternalSyncReceipt(
  signoff: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptBatchSignoff,
  options: {
    text: string;
    format?: "csv" | "tsv" | "json";
    sourceName?: string;
    importedAt?: string;
  },
): EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptSignoffExternalSyncReceipt {
  const importedAt = options.importedAt ?? new Date().toISOString();
  const receiptRows = externalSystemReceiptRowsFromText(options.text, options.format ?? "csv");
  const receiptsByFilePath = new Map<string, Record<string, string>>();
  for (const row of receiptRows) {
    const filePath = textFrom(row.file_path ?? row.signoff_file_path, "");
    if (filePath) receiptsByFilePath.set(filePath, row);
  }
  const signoffFilePaths = new Set(signoff.rows.map((row) => row.filePath));
  const rows: EngineeringBatchArchiveReleaseSlaReminderExternalSystemFinalReceiptSignoffExternalSyncReceiptRow[] =
    signoff.rows.map((signoffRow) => {
      const receipt = receiptsByFilePath.get(signoffRow.filePath);
      const receiptStatus = receipt ? externalSystemReceiptStatus(textFrom(receipt.receipt_status, "")) : null;
      const reconciliationStatus: EngineeringBatchExternalSystemImportReceiptReconciliationStatus =
        receiptStatus ?? "missing_receipt";
      const receiptMessage = receipt ? textFrom(receipt.receipt_message, "") : "";
      return {
        filePath: signoffRow.filePath,
        fileType: signoffRow.fileType,
        signatureStatus: signoffRow.signatureStatus,
        externalRecordId: receipt ? textFrom(receipt.external_record_id, "") : "",
        receiptStatus,
        receiptMessage,
        receivedAt: receipt ? textFrom(receipt.received_at, "") : "",
        syncedReleaseVersion: receipt
          ? textFrom(receipt.synced_release_version ?? receipt.release_version ?? receipt.current_release_version, "")
          : "",
        reconciliationStatus,
        action: archiveReleaseSlaReminderFinalReceiptSignoffExternalSyncReceiptAction(reconciliationStatus, receiptMessage),
      };
    });
  for (const receipt of receiptRows) {
    const filePath = textFrom(receipt.file_path ?? receipt.signoff_file_path, "");
    if (!filePath || signoffFilePaths.has(filePath)) continue;
    const receiptStatus = externalSystemReceiptStatus(textFrom(receipt.receipt_status, ""));
    const receiptMessage = textFrom(receipt.receipt_message, "");
    rows.push({
      filePath,
      fileType: archiveReleaseSlaReminderExternalImportFileType(filePath),
      signatureStatus: "pending",
      externalRecordId: textFrom(receipt.external_record_id, ""),
      receiptStatus,
      receiptMessage,
      receivedAt: textFrom(receipt.received_at, ""),
      syncedReleaseVersion: textFrom(receipt.synced_release_version ?? receipt.release_version ?? receipt.current_release_version, ""),
      reconciliationStatus: "unmatched_receipt",
      action: archiveReleaseSlaReminderFinalReceiptSignoffExternalSyncReceiptAction("unmatched_receipt", receiptMessage),
    });
  }
  const acceptedCount = rows.filter((row) => row.reconciliationStatus === "accepted").length;
  const rejectedCount = rows.filter((row) => row.reconciliationStatus === "rejected").length;
  const pendingCount = rows.filter((row) => row.reconciliationStatus === "pending").length;
  const skippedCount = rows.filter((row) => row.reconciliationStatus === "skipped").length;
  const missingReceiptCount = rows.filter((row) => row.reconciliationStatus === "missing_receipt").length;
  const unmatchedReceiptCount = rows.filter((row) => row.reconciliationStatus === "unmatched_receipt").length;
  const body = {
    schema:
      "railwise.engineering.batch.archiveReleaseSlaReminderExternalSystemFinalReceiptSignoffExternalSyncReceipt.v1" as const,
    importedAt,
    sourceName: options.sourceName?.trim() || null,
    batchName: signoff.batchName,
    sourceSignoffFingerprint: signoff.signoffFingerprint,
    sourceConfirmationFingerprint: signoff.sourceConfirmationFingerprint,
    sourceCrossPlatformReviewFingerprint: signoff.sourceCrossPlatformReviewFingerprint,
    fileCount: signoff.fileCount,
    rowCount: rows.length,
    acceptedCount,
    rejectedCount,
    pendingCount,
    skippedCount,
    missingReceiptCount,
    unmatchedReceiptCount,
    followUpCount: rejectedCount + pendingCount + missingReceiptCount + unmatchedReceiptCount,
    rows,
  };
  const receiptFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    receiptFingerprint,
  };
  const csv = archiveReleaseSlaReminderFinalReceiptSignoffExternalSyncReceiptCsv(rows);
  const markdown = archiveReleaseSlaReminderFinalReceiptSignoffExternalSyncReceiptMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function externalSystemAvailableSourceFields(
  manifest: EngineeringBatchExternalUploadManifest,
  recordType: EngineeringBatchExternalSystemUploadRecordType,
): Set<string> {
  if (recordType === "archive") {
    return new Set([
      ...manifest.uploadFields.map((field) => field.fieldKey),
      "archiveFolderName",
      "archivePackageName",
      "approvalStatusLabel",
      "auditFingerprint",
      "batchFingerprint",
    ]);
  }
  const fields = new Set<string>();
  for (const file of manifest.files) {
    for (const key of Object.keys(file)) fields.add(key);
  }
  return fields;
}

export function buildEngineeringBatchExternalSystemAdapterPreflightReport(
  items: EngineeringBatchPackageItem[],
  context: EngineeringBatchArchiveZipExportContext = {},
): EngineeringBatchExternalSystemAdapterPreflightReport {
  const payload = buildEngineeringBatchArchivePayload(items, context);
  const rows: EngineeringBatchExternalSystemAdapterPreflightRow[] = payload.externalSystemUploadAdapters.adapters.flatMap(
    (adapter) =>
      adapter.fieldMappings.map((mapping) => {
        const availableFields = externalSystemAvailableSourceFields(payload.externalUploadManifest, mapping.recordType);
        const matchingUploadRows = payload.externalSystemUploadAdapters.rows.filter(
          (row) =>
            row.adapterId === adapter.adapterId &&
            row.recordType === mapping.recordType &&
            row.externalFieldKey === mapping.externalFieldKey &&
            row.sourceFieldKey === mapping.sourceFieldKey,
        );
        const sourceExists = availableFields.has(mapping.sourceFieldKey);
        const emptyRequiredValue =
          sourceExists && mapping.required && matchingUploadRows.every((row) => row.value.trim().length === 0);
        const status: EngineeringBatchExternalSystemAdapterPreflightStatus = !sourceExists
          ? "missing_source"
          : emptyRequiredValue
            ? "empty_required_value"
            : "ready";
        const evidence =
          status === "missing_source"
            ? `来源字段 ${mapping.sourceFieldKey} 不在 ${mapping.recordType === "archive" ? "归档包级字段" : "文件级字段"} 中`
            : status === "empty_required_value"
              ? `来源字段 ${mapping.sourceFieldKey} 已存在，但必填值为空`
              : `来源字段 ${mapping.sourceFieldKey} 可映射 ${matchingUploadRows.length} 条上传值`;
        return {
          adapterId: adapter.adapterId,
          targetSystem: adapter.targetSystem,
          recordType: mapping.recordType,
          externalFieldKey: mapping.externalFieldKey,
          externalFieldLabel: mapping.externalFieldLabel,
          sourceFieldKey: mapping.sourceFieldKey,
          required: mapping.required,
          status,
          evidence,
        };
      }),
  );
  const readyFieldCount = rows.filter((row) => row.status === "ready").length;
  const missingSourceFieldCount = rows.filter((row) => row.status === "missing_source").length;
  const emptyRequiredValueCount = rows.filter((row) => row.status === "empty_required_value").length;
  const body = {
    schema: "railwise.engineering.batch.externalSystemAdapterPreflight.v1" as const,
    generatedAt: payload.exportedAt,
    batchName: payload.batchName,
    archivePackageName: payload.archivePackageName,
    adapterIds: payload.externalSystemUploadAdapters.adapterIds,
    adapterCount: payload.externalSystemUploadAdapters.adapterIds.length,
    fieldMappingCount: rows.length,
    readyFieldCount,
    missingSourceFieldCount,
    emptyRequiredValueCount,
    blockingIssueCount: missingSourceFieldCount + emptyRequiredValueCount,
    rows,
  };
  const preflightFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withFingerprint = {
    ...body,
    preflightFingerprint,
  };
  const csv = csvFromRows(
    [
      "adapter_id",
      "target_system",
      "record_type",
      "external_field_key",
      "external_field_label",
      "source_field_key",
      "required",
      "status",
      "evidence",
    ],
    rows.map((row) => ({
      adapter_id: row.adapterId,
      target_system: row.targetSystem,
      record_type: row.recordType,
      external_field_key: row.externalFieldKey,
      external_field_label: row.externalFieldLabel,
      source_field_key: row.sourceFieldKey,
      required: row.required,
      status: row.status,
      evidence: row.evidence,
    })),
  );
  return {
    ...withFingerprint,
    csv,
    json: JSON.stringify(withFingerprint, null, 2),
  };
}

function externalSystemReceiptStatus(value: string): EngineeringBatchExternalSystemImportReceiptStatus | null {
  const normalized = value.trim().toLowerCase();
  if (["accepted", "success", "succeeded", "ok", "已入库", "成功"].includes(normalized)) return "accepted";
  if (["rejected", "failed", "error", "失败", "拒绝"].includes(normalized)) return "rejected";
  if (["pending", "processing", "wait", "待处理", "处理中"].includes(normalized)) return "pending";
  if (["skipped", "ignored", "跳过"].includes(normalized)) return "skipped";
  return null;
}

const EXTERNAL_SYSTEM_HTTP_RETRY_STATUS_CODES = [429, 500, 502, 503, 504];

function cleanExternalSystemHttpExecutionConfig(
  input?: Partial<EngineeringBatchExternalSystemHttpExecutionConfig>,
): EngineeringBatchExternalSystemHttpExecutionConfig {
  const authMode: EngineeringBatchExternalSystemHttpAuthMode =
    input?.authMode === "bearer" || input?.authMode === "api_key_header" ? input.authMode : "none";
  const authHeaderName =
    authMode === "bearer"
      ? "Authorization"
      : authMode === "api_key_header"
        ? input?.authHeaderName?.trim() || "X-API-Key"
        : null;
  const timeoutMs =
    typeof input?.timeoutMs === "number" && Number.isFinite(input.timeoutMs) && input.timeoutMs > 0
      ? Math.round(input.timeoutMs)
      : null;
  const maxRetries =
    typeof input?.maxRetries === "number" && Number.isFinite(input.maxRetries) && input.maxRetries > 0
      ? Math.min(5, Math.round(input.maxRetries))
      : 0;
  const retryStatusCodes = uniqueNonEmptyStrings(
    (input?.retryStatusCodes?.length ? input.retryStatusCodes : EXTERNAL_SYSTEM_HTTP_RETRY_STATUS_CODES).map((code) =>
      String(Math.round(code)),
    ),
  )
    .map((code) => Number(code))
    .filter((code) => Number.isFinite(code) && code >= 400 && code <= 599);
  return {
    authMode,
    authConfigured: authMode !== "none" && input?.authConfigured === true,
    authHeaderName,
    timeoutMs,
    maxRetries,
    retryStatusCodes,
  };
}

function externalSystemHttpResponseObject(responseText: string | undefined): Record<string, unknown> {
  if (!responseText?.trim()) return {};
  try {
    const parsed = JSON.parse(responseText) as unknown;
    const root = objectFrom(parsed);
    const nested = objectFrom(root.data ?? root.result ?? root.response);
    return Object.keys(nested).length > 0 ? { ...root, ...nested } : root;
  } catch {
    return {};
  }
}

function externalSystemHttpResponseValue(row: Record<string, unknown>, aliases: string[]): string {
  for (const alias of aliases) {
    const direct = row[alias];
    if (direct !== undefined && direct !== null) return String(direct).trim();
    const normalizedAlias = normalizeHeader(alias);
    for (const [key, value] of Object.entries(row)) {
      if (normalizeHeader(key) === normalizedAlias && value !== undefined && value !== null) return String(value).trim();
    }
  }
  return "";
}

function externalSystemHttpAttemptStatusCode(
  attempt: EngineeringBatchExternalSystemHttpSubmissionAttemptInput | undefined,
): number | null {
  return typeof attempt?.statusCode === "number" && Number.isFinite(attempt.statusCode) ? attempt.statusCode : null;
}

function externalSystemHttpAttemptOk(
  attempt: EngineeringBatchExternalSystemHttpSubmissionAttemptInput | undefined,
  statusCode: number | null,
): boolean {
  if (!attempt) return false;
  if (typeof attempt.ok === "boolean") return attempt.ok;
  return statusCode !== null && statusCode >= 200 && statusCode < 300;
}

function externalSystemHttpReceiptStatus(input: {
  attempt: EngineeringBatchExternalSystemHttpSubmissionAttemptInput | undefined;
  statusCode: number | null;
  httpOk: boolean;
  response: Record<string, unknown>;
}): EngineeringBatchExternalSystemImportReceiptStatus {
  const explicit = externalSystemReceiptStatus(
    externalSystemHttpResponseValue(input.response, [
      "receipt_status",
      "receiptStatus",
      "status",
      "state",
      "result",
      "code",
      "处理状态",
      "入库状态",
    ]),
  );
  if (explicit) return explicit;
  if (!input.attempt || input.attempt.errorMessage) return "rejected";
  if (input.statusCode === 202) return "pending";
  if (!input.httpOk || (input.statusCode !== null && input.statusCode >= 400)) return "rejected";
  return "accepted";
}

function externalSystemHttpSubmissionStatus(input: {
  attempt: EngineeringBatchExternalSystemHttpSubmissionAttemptInput | undefined;
  statusCode: number | null;
  httpOk: boolean;
  receiptStatus: EngineeringBatchExternalSystemImportReceiptStatus;
}): EngineeringBatchExternalSystemHttpSubmissionStatus {
  if (!input.attempt) return "missing_attempt";
  if (input.attempt.errorMessage || input.statusCode === null) return "network_error";
  if (!input.httpOk || input.statusCode >= 400) return "http_error";
  return input.receiptStatus;
}

function externalSystemHttpReceiptMessage(input: {
  attempt: EngineeringBatchExternalSystemHttpSubmissionAttemptInput | undefined;
  statusCode: number | null;
  receiptStatus: EngineeringBatchExternalSystemImportReceiptStatus;
  response: Record<string, unknown>;
}): string {
  if (!input.attempt) return "未执行 HTTP 提交";
  if (input.attempt.errorMessage) return input.attempt.errorMessage;
  const message = externalSystemHttpResponseValue(input.response, [
    "receipt_message",
    "receiptMessage",
    "message",
    "msg",
    "error",
    "errorMessage",
    "处理说明",
    "回执说明",
  ]);
  if (message) return message;
  if (input.statusCode !== null && input.statusCode >= 400) return `HTTP ${input.statusCode} 提交失败`;
  if (input.receiptStatus === "pending") return "外部系统已接收，等待异步处理完成";
  if (input.receiptStatus === "skipped") return "外部系统跳过该记录";
  if (input.receiptStatus === "rejected") return "外部系统拒绝入库";
  return "外部系统已确认入库";
}

function externalSystemHttpAttemptResponseFingerprint(
  attempt: EngineeringBatchExternalSystemHttpSubmissionAttemptInput | undefined,
  statusCode: number | null,
  httpOk: boolean,
): string {
  return fnv1a32Fingerprint(
    JSON.stringify({
      statusCode,
      ok: httpOk,
      responseText: attempt?.responseText ?? "",
      errorMessage: attempt?.errorMessage ?? "",
    }),
  );
}

function externalSystemHttpRetryReason(
  attempt: EngineeringBatchExternalSystemHttpSubmissionAttemptInput,
  statusCode: number | null,
): string {
  if (attempt.errorMessage) {
    const normalized = attempt.errorMessage.toLowerCase();
    if (normalized.includes("timeout")) return "timeout";
    return "network_error";
  }
  if (statusCode !== null && statusCode >= 400) return `HTTP ${statusCode}`;
  return "";
}

function externalSystemHttpSubmissionAction(status: EngineeringBatchExternalSystemHttpSubmissionStatus): string {
  if (status === "accepted") return "HTTP 提交已入库，可回写归档入库台账。";
  if (status === "pending") return "HTTP 提交进入异步处理，保留 request_id 继续追踪最终回执。";
  if (status === "skipped") return "外部系统跳过该记录，需核对接口规则或业务状态。";
  if (status === "http_error") return "HTTP 返回错误状态码，检查 endpoint、鉴权、payload 字段和平台错误信息后重试。";
  if (status === "network_error") return "网络或连接失败，检查内网/VPN/证书/代理后重试。";
  if (status === "missing_attempt") return "当前请求未执行提交，需重新发起 HTTP 入库。";
  return "外部系统业务拒绝入库，按回执原因生成整改任务。";
}

