function externalSystemHttpSubmissionAttemptCsv(
  rows: EngineeringBatchExternalSystemHttpSubmissionAttemptAuditRow[],
): string {
  return csvFromRows(
    [
      "request_id",
      "attempt_index",
      "submitted_at",
      "completed_at",
      "duration_ms",
      "status_code",
      "http_ok",
      "error_message",
      "response_fingerprint",
      "retry_planned",
      "retry_reason",
    ],
    rows.map((row) => ({
      request_id: row.requestId,
      attempt_index: row.attemptIndex,
      submitted_at: row.submittedAt,
      completed_at: row.completedAt,
      duration_ms: row.durationMs,
      status_code: row.statusCode,
      http_ok: row.httpOk,
      error_message: row.errorMessage,
      response_fingerprint: row.responseFingerprint,
      retry_planned: row.retryPlanned,
      retry_reason: row.retryReason,
    })),
  );
}

function externalSystemHttpSubmissionMarkdown(
  audit: Omit<EngineeringBatchExternalSystemHttpSubmissionAudit, "receiptCsv" | "csv" | "attemptCsv" | "markdown" | "json">,
): string {
  return [
    "# 外部系统 HTTP 入库提交审计",
    "",
    `- 批次：${audit.batchName}`,
    `- 提交时间：${audit.submittedAt}`,
    `- 完成时间：${audit.completedAt}`,
    `- 请求数：${audit.requestCount}`,
    `- 已入库：${audit.acceptedCount}`,
    `- 待处理：${audit.pendingCount}`,
    `- 业务拒绝：${audit.rejectedCount}`,
    `- HTTP 错误：${audit.httpErrorCount}`,
    `- 网络错误：${audit.networkErrorCount}`,
    `- 鉴权：${audit.executionConfig.authMode}${audit.executionConfig.authConfigured ? "（已配置，已脱敏）" : "（未配置）"}`,
    `- 超时：${audit.executionConfig.timeoutMs ? `${audit.executionConfig.timeoutMs}ms` : "未设置"}`,
    `- 最大重试：${audit.executionConfig.maxRetries}`,
    `- 实际尝试：${audit.attemptCount}`,
    `- 实际重试：${audit.retryCount}`,
    ...(audit.replaySourceFingerprint
      ? [`- 重放来源：${audit.replaySourceFingerprint}`, `- 重放合并：${audit.replayMergedAt ?? "-"}`]
      : []),
    `- 计划指纹：${audit.planFingerprint}`,
    `- 提交指纹：${audit.submissionFingerprint}`,
    "",
    "| 请求 | Adapter | 类型 | HTTP | 提交状态 | 回执状态 | 外部记录 | 处理要求 |",
    "| --- | --- | --- | --- | --- | --- | --- | --- |",
    ...audit.rows.map(
      (row) =>
        `| ${row.requestId} | ${row.adapterId} | ${row.recordType} | ${row.statusCode ?? "-"} | ${row.submissionStatus} | ${row.receiptStatus} | ${row.externalRecordId || "-"} | ${row.action} |`,
    ),
    "",
  ].join("\n");
}

function buildExternalSystemHttpSubmissionAuditArtifact(
  body: Omit<
    EngineeringBatchExternalSystemHttpSubmissionAudit,
    "submissionFingerprint" | "receiptCsv" | "csv" | "attemptCsv" | "markdown" | "json"
  >,
): EngineeringBatchExternalSystemHttpSubmissionAudit {
  const submissionFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    submissionFingerprint,
  };
  const receiptCsv = externalSystemHttpSubmissionReceiptCsv(body.rows);
  const csv = externalSystemHttpSubmissionCsv(body.rows);
  const attemptCsv = externalSystemHttpSubmissionAttemptCsv(body.attemptRows);
  const markdown = externalSystemHttpSubmissionMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    receiptCsv,
    csv,
    attemptCsv,
    markdown,
    json: JSON.stringify({ ...withoutArtifacts, receiptCsv, csv, attemptCsv, markdown }, null, 2),
  };
}

export function buildEngineeringBatchExternalSystemHttpSubmissionAudit(
  plan: EngineeringBatchExternalSystemImportPlan,
  options: {
    attempts: EngineeringBatchExternalSystemHttpSubmissionAttemptInput[];
    executionConfig?: Partial<EngineeringBatchExternalSystemHttpExecutionConfig>;
    submittedAt?: string;
    completedAt?: string;
  },
): EngineeringBatchExternalSystemHttpSubmissionAudit {
  const submittedAt = options.submittedAt ?? new Date().toISOString();
  const completedAt = options.completedAt ?? submittedAt;
  const executionConfig = cleanExternalSystemHttpExecutionConfig(options.executionConfig);
  const attemptsByRequestId = new Map<string, EngineeringBatchExternalSystemHttpSubmissionAttemptInput[]>();
  for (const attempt of options.attempts) {
    const current = attemptsByRequestId.get(attempt.requestId) ?? [];
    current.push(attempt);
    attemptsByRequestId.set(attempt.requestId, current);
  }
  const attemptRows: EngineeringBatchExternalSystemHttpSubmissionAttemptAuditRow[] = [];
  const rows = plan.requests.map((request): EngineeringBatchExternalSystemHttpSubmissionAuditRow => {
    const attempts = attemptsByRequestId.get(request.requestId) ?? [];
    const attempt = attempts.at(-1);
    const response = externalSystemHttpResponseObject(attempt?.responseText);
    const statusCode = externalSystemHttpAttemptStatusCode(attempt);
    const httpOk = externalSystemHttpAttemptOk(attempt, statusCode);
    const receiptStatus = externalSystemHttpReceiptStatus({ attempt, statusCode, httpOk, response });
    const submissionStatus = externalSystemHttpSubmissionStatus({ attempt, statusCode, httpOk, receiptStatus });
    const externalRecordId = externalSystemHttpResponseValue(response, [
      "external_record_id",
      "externalRecordId",
      "recordId",
      "record_id",
      "archiveId",
      "archive_id",
      "id",
      "外部记录号",
      "外部档案号",
      "入库编号",
    ]);
    const receiptMessage = externalSystemHttpReceiptMessage({ attempt, statusCode, receiptStatus, response });
    const responseFingerprint = externalSystemHttpAttemptResponseFingerprint(attempt, statusCode, httpOk);
    attempts.forEach((currentAttempt, index) => {
      const currentStatusCode = externalSystemHttpAttemptStatusCode(currentAttempt);
      const currentHttpOk = externalSystemHttpAttemptOk(currentAttempt, currentStatusCode);
      const retryReason = externalSystemHttpRetryReason(currentAttempt, currentStatusCode);
      attemptRows.push({
        requestId: request.requestId,
        attemptIndex: index + 1,
        submittedAt: currentAttempt.submittedAt ?? submittedAt,
        completedAt: currentAttempt.completedAt ?? completedAt,
        durationMs: currentAttempt.durationMs ?? null,
        statusCode: currentStatusCode,
        httpOk: currentHttpOk,
        errorMessage: currentAttempt.errorMessage ?? "",
        responseFingerprint: externalSystemHttpAttemptResponseFingerprint(currentAttempt, currentStatusCode, currentHttpOk),
        retryPlanned: index < attempts.length - 1,
        retryReason: index < attempts.length - 1 ? retryReason || "manual_retry" : "",
      });
    });
    const retryReasons = attemptRows
      .filter((row) => row.requestId === request.requestId && row.retryPlanned)
      .map((row) => row.retryReason);
    return {
      requestId: request.requestId,
      adapterId: request.adapterId,
      targetSystem: request.targetSystem,
      recordType: request.recordType,
      filePath: request.filePath,
      method: request.method,
      endpointUrl: request.endpointUrl,
      statusCode,
      httpOk,
      submissionStatus,
      receiptStatus,
      externalRecordId,
      receiptMessage,
      submittedAt: attempt?.submittedAt ?? submittedAt,
      completedAt: attempt?.completedAt ?? completedAt,
      durationMs: attempt?.durationMs ?? null,
      attemptCount: attempts.length,
      retryCount: Math.max(0, attempts.length - 1),
      finalAttemptIndex: attempts.length > 0 ? attempts.length : null,
      retrySummary: retryReasons.join(" -> "),
      requestFingerprint: request.requestFingerprint,
      responseFingerprint,
      action: externalSystemHttpSubmissionAction(submissionStatus),
    };
  });
  const body = {
    schema: "railwise.engineering.batch.externalSystemHttpSubmissionAudit.v1" as const,
    submittedAt,
    completedAt,
    batchName: plan.batchName,
    archivePackageName: plan.archivePackageName,
    planFingerprint: plan.planFingerprint,
    executionConfig,
    requestCount: plan.requestCount,
    submittedCount: rows.filter((row) => row.submissionStatus !== "missing_attempt").length,
    attemptCount: attemptRows.length,
    retryCount: rows.reduce((sum, row) => sum + row.retryCount, 0),
    acceptedCount: rows.filter((row) => row.submissionStatus === "accepted").length,
    rejectedCount: rows.filter((row) => row.submissionStatus === "rejected").length,
    pendingCount: rows.filter((row) => row.submissionStatus === "pending").length,
    skippedCount: rows.filter((row) => row.submissionStatus === "skipped").length,
    httpErrorCount: rows.filter((row) => row.submissionStatus === "http_error").length,
    networkErrorCount: rows.filter((row) => row.submissionStatus === "network_error").length,
    missingAttemptCount: rows.filter((row) => row.submissionStatus === "missing_attempt").length,
    rows,
    attemptRows,
    replaySourceFingerprint: null,
    replayMergedAt: null,
  };
  return buildExternalSystemHttpSubmissionAuditArtifact(body);
}

function externalSystemHttpReplayReason(
  status: EngineeringBatchExternalSystemHttpSubmissionStatus,
): EngineeringBatchExternalSystemHttpReplayReason | null {
  if (status === "pending") return "pending";
  if (status === "rejected") return "rejected";
  if (status === "http_error") return "http_error";
  if (status === "network_error") return "network_error";
  if (status === "missing_attempt") return "missing_attempt";
  return null;
}

function externalSystemHttpReplayPriority(
  reason: EngineeringBatchExternalSystemHttpReplayReason,
): EngineeringProjectArchiveRectificationPriority {
  return reason === "http_error" || reason === "network_error" || reason === "rejected" ? "high" : "normal";
}

function externalSystemHttpReplayQueueCsv(rows: EngineeringBatchExternalSystemHttpReplayQueueRow[]): string {
  return csvFromRows(
    [
      "request_id",
      "adapter_id",
      "target_system",
      "record_type",
      "file_path",
      "endpoint_url",
      "previous_submission_status",
      "previous_receipt_status",
      "previous_receipt_message",
      "previous_attempt_count",
      "replay_reason",
      "priority",
      "request_fingerprint",
    ],
    rows.map((row) => ({
      request_id: row.requestId,
      adapter_id: row.adapterId,
      target_system: row.targetSystem,
      record_type: row.recordType,
      file_path: row.filePath,
      endpoint_url: row.endpointUrl,
      previous_submission_status: row.previousSubmissionStatus,
      previous_receipt_status: row.previousReceiptStatus,
      previous_receipt_message: row.previousReceiptMessage,
      previous_attempt_count: row.previousAttemptCount,
      replay_reason: row.replayReason,
      priority: row.priority,
      request_fingerprint: row.requestFingerprint,
    })),
  );
}

function externalSystemHttpReplayQueueMarkdown(
  queue: Omit<EngineeringBatchExternalSystemHttpReplayQueue, "markdown" | "csv" | "json">,
): string {
  return [
    "# 外部系统 HTTP 入库失败重放队列",
    "",
    `- 批次：${queue.batchName}`,
    `- 生成时间：${queue.generatedAt}`,
    `- 待重放：${queue.requestCount}`,
    `- 待处理：${queue.pendingCount}`,
    `- 业务拒绝：${queue.rejectedCount}`,
    `- HTTP 错误：${queue.httpErrorCount}`,
    `- 网络错误：${queue.networkErrorCount}`,
    `- 来源提交指纹：${queue.sourceSubmissionFingerprint}`,
    "",
    "| 请求 | Adapter | 类型 | 原状态 | 原回执 | 原因 | 优先级 | 文件 |",
    "| --- | --- | --- | --- | --- | --- | --- | --- |",
    ...queue.rows.map(
      (row) =>
        `| ${row.requestId} | ${row.adapterId} | ${row.recordType} | ${row.previousSubmissionStatus} | ${row.previousReceiptStatus} | ${row.replayReason} | ${row.priority} | ${row.filePath || "-"} |`,
    ),
    "",
  ].join("\n");
}

export function buildEngineeringBatchExternalSystemHttpReplayQueue(
  plan: EngineeringBatchExternalSystemImportPlan,
  audit: EngineeringBatchExternalSystemHttpSubmissionAudit,
  options: { generatedAt?: string } = {},
): EngineeringBatchExternalSystemHttpReplayQueue {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const requestsById = new Map(plan.requests.map((request) => [request.requestId, request]));
  const rows: EngineeringBatchExternalSystemHttpReplayQueueRow[] = audit.rows.flatMap((row) => {
    const replayReason = externalSystemHttpReplayReason(row.submissionStatus);
    const request = requestsById.get(row.requestId);
    if (!replayReason || !request) return [];
    return [
      {
        requestId: row.requestId,
        adapterId: row.adapterId,
        targetSystem: row.targetSystem,
        recordType: row.recordType,
        filePath: row.filePath,
        endpointUrl: row.endpointUrl,
        previousSubmissionStatus: row.submissionStatus,
        previousReceiptStatus: row.receiptStatus,
        previousReceiptMessage: row.receiptMessage,
        previousAttemptCount: row.attemptCount,
        replayReason,
        priority: externalSystemHttpReplayPriority(replayReason),
        requestFingerprint: request.requestFingerprint,
      },
    ];
  });
  const body = {
    schema: "railwise.engineering.batch.externalSystemHttpReplayQueue.v1" as const,
    generatedAt,
    batchName: audit.batchName,
    planFingerprint: plan.planFingerprint,
    sourceSubmissionFingerprint: audit.submissionFingerprint,
    requestCount: rows.length,
    pendingCount: rows.filter((row) => row.replayReason === "pending").length,
    rejectedCount: rows.filter((row) => row.replayReason === "rejected").length,
    httpErrorCount: rows.filter((row) => row.replayReason === "http_error").length,
    networkErrorCount: rows.filter((row) => row.replayReason === "network_error").length,
    missingAttemptCount: rows.filter((row) => row.replayReason === "missing_attempt").length,
    highPriorityCount: rows.filter((row) => row.priority === "high").length,
    rows,
  };
  const replayQueueFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    replayQueueFingerprint,
  };
  const csv = externalSystemHttpReplayQueueCsv(rows);
  const markdown = externalSystemHttpReplayQueueMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

export function mergeEngineeringBatchExternalSystemHttpReplayAudit(
  baseAudit: EngineeringBatchExternalSystemHttpSubmissionAudit,
  replayAudit: EngineeringBatchExternalSystemHttpSubmissionAudit,
  options: { mergedAt?: string } = {},
): EngineeringBatchExternalSystemHttpSubmissionAudit {
  const mergedAt = options.mergedAt ?? replayAudit.completedAt;
  const replayRowsById = new Map(replayAudit.rows.map((row) => [row.requestId, row]));
  const baseAttemptRowsById = new Map<string, EngineeringBatchExternalSystemHttpSubmissionAttemptAuditRow[]>();
  for (const row of baseAudit.attemptRows) {
    const current = baseAttemptRowsById.get(row.requestId) ?? [];
    current.push(row);
    baseAttemptRowsById.set(row.requestId, current);
  }
  const replayAttemptRowsById = new Map<string, EngineeringBatchExternalSystemHttpSubmissionAttemptAuditRow[]>();
  for (const row of replayAudit.attemptRows) {
    const current = replayAttemptRowsById.get(row.requestId) ?? [];
    current.push(row);
    replayAttemptRowsById.set(row.requestId, current);
  }
  const mergedAttemptRows: EngineeringBatchExternalSystemHttpSubmissionAttemptAuditRow[] = [];
  const rows = baseAudit.rows.map((row): EngineeringBatchExternalSystemHttpSubmissionAuditRow => {
    const replayRow = replayRowsById.get(row.requestId);
    const baseAttempts = baseAttemptRowsById.get(row.requestId) ?? [];
    const replayAttempts = replayAttemptRowsById.get(row.requestId) ?? [];
    if (!replayRow) {
      mergedAttemptRows.push(...baseAttempts);
      return row;
    }
    const combinedAttempts = [
      ...baseAttempts,
      ...replayAttempts.map((attempt, index) => ({
        ...attempt,
        attemptIndex: baseAttempts.length + index + 1,
      })),
    ];
    mergedAttemptRows.push(...combinedAttempts);
    const retrySummary = combinedAttempts
      .filter((attempt) => attempt.retryPlanned || attempt.attemptIndex < combinedAttempts.length)
      .map((attempt) => attempt.retryReason || (attempt.attemptIndex <= baseAttempts.length ? "base_attempt" : "replay_attempt"))
      .join(" -> ");
    return {
      ...replayRow,
      submittedAt: row.submittedAt,
      attemptCount: combinedAttempts.length,
      retryCount: Math.max(0, combinedAttempts.length - 1),
      finalAttemptIndex: combinedAttempts.length > 0 ? combinedAttempts.length : null,
      retrySummary,
    };
  });
  const body = {
    schema: "railwise.engineering.batch.externalSystemHttpSubmissionAudit.v1" as const,
    submittedAt: baseAudit.submittedAt,
    completedAt: replayAudit.completedAt,
    batchName: baseAudit.batchName,
    archivePackageName: baseAudit.archivePackageName,
    planFingerprint: baseAudit.planFingerprint,
    executionConfig: replayAudit.executionConfig,
    requestCount: baseAudit.requestCount,
    submittedCount: rows.filter((row) => row.submissionStatus !== "missing_attempt").length,
    attemptCount: mergedAttemptRows.length,
    retryCount: rows.reduce((sum, row) => sum + row.retryCount, 0),
    acceptedCount: rows.filter((row) => row.submissionStatus === "accepted").length,
    rejectedCount: rows.filter((row) => row.submissionStatus === "rejected").length,
    pendingCount: rows.filter((row) => row.submissionStatus === "pending").length,
    skippedCount: rows.filter((row) => row.submissionStatus === "skipped").length,
    httpErrorCount: rows.filter((row) => row.submissionStatus === "http_error").length,
    networkErrorCount: rows.filter((row) => row.submissionStatus === "network_error").length,
    missingAttemptCount: rows.filter((row) => row.submissionStatus === "missing_attempt").length,
    rows,
    attemptRows: mergedAttemptRows,
    replaySourceFingerprint: replayAudit.submissionFingerprint,
    replayMergedAt: mergedAt,
  };
  return buildExternalSystemHttpSubmissionAuditArtifact(body);
}

function externalSystemReceiptRowsFromText(
  text: string,
  format: "csv" | "tsv" | "json",
): Array<Record<string, string>> {
  if (format === "json") {
    const parsed = JSON.parse(text) as unknown;
    const source = Array.isArray(parsed) ? parsed : arrayFrom(objectFrom(parsed).rows);
    return source.map((row) =>
      Object.fromEntries(Object.entries(objectFrom(row)).map(([key, value]) => [key, value === null || value === undefined ? "" : String(value)])),
    );
  }
  const rows = parseDelimitedRows(text, format === "tsv" ? "\t" : ",");
  const headers = rows[0] ?? [];
  return rows.slice(1).map((row) =>
    Object.fromEntries(headers.map((header, index) => [header, row[index] ?? ""])),
  );
}

function externalSystemImportReceiptAction(
  status: EngineeringBatchExternalSystemImportReceiptReconciliationStatus,
  message: string,
): string {
  if (status === "accepted") return "外部系统已确认入库";
  if (status === "rejected") return `外部系统拒绝入库：${message || "未提供原因"}`;
  if (status === "pending") return "外部系统仍在处理，请保留 request_id 继续追踪。";
  if (status === "skipped") return `外部系统跳过该记录：${message || "未提供原因"}`;
  if (status === "missing_receipt") return "未收到外部系统回执，请按 request_id 追踪导入状态。";
  return "回执未匹配当前导入计划，请核对 request_id 或批次版本。";
}

export function buildEngineeringBatchExternalSystemImportReceiptReconciliation(
  plan: EngineeringBatchExternalSystemImportPlan,
  options: {
    text: string;
    format?: "csv" | "tsv" | "json";
    sourceName?: string;
    importedAt?: string;
  },
): EngineeringBatchExternalSystemImportReceiptReconciliation {
  const importedAt = options.importedAt ?? new Date().toISOString();
  const receiptRows = externalSystemReceiptRowsFromText(options.text, options.format ?? "csv");
  const receiptsByRequestId = new Map(receiptRows.map((row) => [textFrom(row.request_id, ""), row]));
  const planRequestIds = new Set(plan.requests.map((request) => request.requestId));
  const rows: EngineeringBatchExternalSystemImportReceiptReconciliationRow[] = plan.requests.map((request) => {
    const receipt = receiptsByRequestId.get(request.requestId);
    const receiptStatus = receipt ? externalSystemReceiptStatus(textFrom(receipt.receipt_status, "")) : null;
    const reconciliationStatus: EngineeringBatchExternalSystemImportReceiptReconciliationStatus =
      receiptStatus ?? "missing_receipt";
    const receiptMessage = receipt ? textFrom(receipt.receipt_message, "") : "";
    return {
      requestId: request.requestId,
      adapterId: request.adapterId,
      targetSystem: request.targetSystem,
      recordType: request.recordType,
      filePath: request.filePath,
      externalRecordId: receipt ? textFrom(receipt.external_record_id, "") : "",
      receiptStatus,
      receiptMessage,
      receivedAt: receipt ? textFrom(receipt.received_at, "") : "",
      reconciliationStatus,
      action: externalSystemImportReceiptAction(reconciliationStatus, receiptMessage),
    };
  });
  for (const receipt of receiptRows) {
    const requestId = textFrom(receipt.request_id, "");
    if (!requestId || planRequestIds.has(requestId)) continue;
    const receiptStatus = externalSystemReceiptStatus(textFrom(receipt.receipt_status, ""));
    const recordTypeText = textFrom(receipt.record_type, "file");
    const recordType: EngineeringBatchExternalSystemUploadRecordType = recordTypeText === "archive" ? "archive" : "file";
    rows.push({
      requestId,
      adapterId: textFrom(receipt.adapter_id, ""),
      targetSystem: "",
      recordType,
      filePath: textFrom(receipt.file_path, ""),
      externalRecordId: textFrom(receipt.external_record_id, ""),
      receiptStatus,
      receiptMessage: textFrom(receipt.receipt_message, ""),
      receivedAt: textFrom(receipt.received_at, ""),
      reconciliationStatus: "unmatched_receipt",
      action: externalSystemImportReceiptAction("unmatched_receipt", textFrom(receipt.receipt_message, "")),
    });
  }
  const acceptedCount = rows.filter((row) => row.reconciliationStatus === "accepted").length;
  const rejectedCount = rows.filter((row) => row.reconciliationStatus === "rejected").length;
  const pendingCount = rows.filter((row) => row.reconciliationStatus === "pending").length;
  const skippedCount = rows.filter((row) => row.reconciliationStatus === "skipped").length;
  const missingReceiptCount = rows.filter((row) => row.reconciliationStatus === "missing_receipt").length;
  const unmatchedReceiptCount = rows.filter((row) => row.reconciliationStatus === "unmatched_receipt").length;
  const body = {
    schema: "railwise.engineering.batch.externalSystemImportReceiptReconciliation.v1" as const,
    importedAt,
    sourceName: options.sourceName?.trim() || null,
    batchName: plan.batchName,
    planFingerprint: plan.planFingerprint,
    requestCount: plan.requestCount,
    acceptedCount,
    rejectedCount,
    pendingCount,
    skippedCount,
    missingReceiptCount,
    unmatchedReceiptCount,
    rows,
  };
  const reconciliationFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withFingerprint = {
    ...body,
    reconciliationFingerprint,
  };
  const csv = csvFromRows(
    [
      "request_id",
      "adapter_id",
      "target_system",
      "record_type",
      "file_path",
      "external_record_id",
      "receipt_status",
      "receipt_message",
      "received_at",
      "reconciliation_status",
      "action",
    ],
    rows.map((row) => ({
      request_id: row.requestId,
      adapter_id: row.adapterId,
      target_system: row.targetSystem,
      record_type: row.recordType,
      file_path: row.filePath,
      external_record_id: row.externalRecordId,
      receipt_status: row.receiptStatus ?? "",
      receipt_message: row.receiptMessage,
      received_at: row.receivedAt,
      reconciliation_status: row.reconciliationStatus,
      action: row.action,
    })),
  );
  return {
    ...withFingerprint,
    csv,
    json: JSON.stringify(withFingerprint, null, 2),
  };
}

const EXTERNAL_SYSTEM_SIGNOFF_UPLOAD_PATHS = [
  "audit/archive-inspection-signoff.html",
  "audit/archive-inspection-signoff.json",
  "audit/archive-inspection-signoff.csv",
] as const;

function externalSystemSignoffFileType(path: string): EngineeringBatchExternalSystemSignoffFileType | null {
  if (path.endsWith(".html")) return "html";
  if (path.endsWith(".json")) return "json";
  if (path.endsWith(".csv")) return "csv";
  return null;
}

function externalSystemSignoffReceiptCsv(
  rows: EngineeringBatchExternalSystemSignoffReceiptReconciliationRow[],
): string {
  return csvFromRows(
    [
      "request_id",
      "adapter_id",
      "target_system",
      "signoff_file_path",
      "signoff_file_type",
      "endpoint_url",
      "external_record_id",
      "receipt_status",
      "receipt_message",
      "received_at",
      "reconciliation_status",
      "request_fingerprint",
      "action",
    ],
    rows.map((row) => ({
      request_id: row.requestId,
      adapter_id: row.adapterId,
      target_system: row.targetSystem,
      signoff_file_path: row.signoffFilePath,
      signoff_file_type: row.signoffFileType,
      endpoint_url: row.endpointUrl,
      external_record_id: row.externalRecordId,
      receipt_status: row.receiptStatus ?? "",
      receipt_message: row.receiptMessage,
      received_at: row.receivedAt,
      reconciliation_status: row.reconciliationStatus,
      request_fingerprint: row.requestFingerprint,
      action: row.action,
    })),
  );
}

function externalSystemSignoffReceiptMarkdown(
  receipt: Omit<EngineeringBatchExternalSystemSignoffReceiptReconciliation, "markdown" | "csv" | "json">,
): string {
  return [
    "# 归档抽检签发文件外部入库回执",
    "",
    `- 批次：${receipt.batchName}`,
    `- 生成时间：${receipt.generatedAt}`,
    `- 签发请求：${receipt.signoffRequestCount}`,
    `- 已入库：${receipt.acceptedCount}`,
    `- 拒绝：${receipt.rejectedCount}`,
    `- 待处理：${receipt.pendingCount}`,
    `- 缺回执：${receipt.missingReceiptCount}`,
    `- 需跟踪：${receipt.followUpCount}`,
    `- 来源回执指纹：${receipt.sourceReconciliationFingerprint}`,
    "",
    "| 请求 | Adapter | 签发文件 | 类型 | 状态 | 外部记录号 | 处理要求 |",
    "| --- | --- | --- | --- | --- | --- | --- |",
    ...receipt.rows.map(
      (row) =>
        `| ${row.requestId} | ${row.adapterId} | ${row.signoffFilePath} | ${row.signoffFileType} | ${row.reconciliationStatus} | ${row.externalRecordId || "-"} | ${row.action} |`,
    ),
    "",
  ].join("\n");
}

export function buildEngineeringBatchExternalSystemSignoffReceiptReconciliation(
  plan: EngineeringBatchExternalSystemImportPlan,
  reconciliation: EngineeringBatchExternalSystemImportReceiptReconciliation,
  options: { generatedAt?: string } = {},
): EngineeringBatchExternalSystemSignoffReceiptReconciliation {
  const generatedAt = options.generatedAt ?? reconciliation.importedAt;
  const requestsById = new Map(plan.requests.map((request) => [request.requestId, request]));
  const reconciliationRowsById = new Map(reconciliation.rows.map((row) => [row.requestId, row]));
  const signoffRequests = plan.requests.filter((request) =>
    EXTERNAL_SYSTEM_SIGNOFF_UPLOAD_PATHS.includes(request.filePath as (typeof EXTERNAL_SYSTEM_SIGNOFF_UPLOAD_PATHS)[number]),
  );
  const rows: EngineeringBatchExternalSystemSignoffReceiptReconciliationRow[] = signoffRequests.map((request) => {
    const source = reconciliationRowsById.get(request.requestId);
    const signoffFileType = externalSystemSignoffFileType(request.filePath) ?? "json";
    return {
      requestId: request.requestId,
      adapterId: request.adapterId,
      targetSystem: request.targetSystem,
      signoffFilePath: request.filePath,
      signoffFileType,
      endpointUrl: request.endpointUrl,
      externalRecordId: source?.externalRecordId ?? "",
      receiptStatus: source?.receiptStatus ?? null,
      receiptMessage: source?.receiptMessage ?? "",
      receivedAt: source?.receivedAt ?? "",
      reconciliationStatus: source?.reconciliationStatus ?? "missing_receipt",
      requestFingerprint: request.requestFingerprint,
      action: source?.action ?? externalSystemImportReceiptAction("missing_receipt", ""),
    };
  });
  for (const row of reconciliation.rows) {
    if (requestsById.has(row.requestId)) continue;
    const signoffFileType = externalSystemSignoffFileType(row.filePath);
    if (!signoffFileType || !EXTERNAL_SYSTEM_SIGNOFF_UPLOAD_PATHS.includes(row.filePath as (typeof EXTERNAL_SYSTEM_SIGNOFF_UPLOAD_PATHS)[number])) {
      continue;
    }
    rows.push({
      requestId: row.requestId,
      adapterId: row.adapterId,
      targetSystem: row.targetSystem,
      signoffFilePath: row.filePath,
      signoffFileType,
      endpointUrl: "",
      externalRecordId: row.externalRecordId,
      receiptStatus: row.receiptStatus,
      receiptMessage: row.receiptMessage,
      receivedAt: row.receivedAt,
      reconciliationStatus: "unmatched_receipt",
      requestFingerprint: "",
      action: row.action,
    });
  }
  const acceptedCount = rows.filter((row) => row.reconciliationStatus === "accepted").length;
  const rejectedCount = rows.filter((row) => row.reconciliationStatus === "rejected").length;
  const pendingCount = rows.filter((row) => row.reconciliationStatus === "pending").length;
  const skippedCount = rows.filter((row) => row.reconciliationStatus === "skipped").length;
  const missingReceiptCount = rows.filter((row) => row.reconciliationStatus === "missing_receipt").length;
  const unmatchedReceiptCount = rows.filter((row) => row.reconciliationStatus === "unmatched_receipt").length;
  const followUpCount = rejectedCount + pendingCount + missingReceiptCount + unmatchedReceiptCount;
  const body = {
    schema: "railwise.engineering.batch.externalSystemSignoffReceiptReconciliation.v1" as const,
    generatedAt,
    batchName: plan.batchName,
    planFingerprint: plan.planFingerprint,
    sourceReconciliationFingerprint: reconciliation.reconciliationFingerprint,
    signoffRequestCount: signoffRequests.length,
    acceptedCount,
    rejectedCount,
    pendingCount,
    skippedCount,
    missingReceiptCount,
    unmatchedReceiptCount,
    followUpCount,
    rows,
  };
  const signoffReceiptFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withoutArtifacts = {
    ...body,
    signoffReceiptFingerprint,
  };
  const csv = externalSystemSignoffReceiptCsv(rows);
  const markdown = externalSystemSignoffReceiptMarkdown(withoutArtifacts);
  return {
    ...withoutArtifacts,
    markdown,
    csv,
    json: JSON.stringify({ ...withoutArtifacts, markdown, csv }, null, 2),
  };
}

function externalSystemImportLedgerStatus(
  status: EngineeringBatchExternalSystemImportReceiptReconciliationStatus,
): EngineeringBatchExternalSystemImportLedgerStatus {
  if (status === "accepted") return "imported";
  if (status === "rejected") return "blocked";
  if (status === "pending") return "pending";
  if (status === "skipped") return "skipped";
  if (status === "unmatched_receipt") return "unmatched_receipt";
  return "missing_receipt";
}

export function buildEngineeringBatchExternalSystemImportLedgerUpdate(
  reconciliation: EngineeringBatchExternalSystemImportReceiptReconciliation,
  options: { generatedAt?: string } = {},
): EngineeringBatchExternalSystemImportLedgerUpdate {
  const generatedAt = options.generatedAt ?? new Date().toISOString();
  const rows: EngineeringBatchExternalSystemImportLedgerUpdateRow[] = reconciliation.rows.map((row) => ({
    requestId: row.requestId,
    adapterId: row.adapterId,
    targetSystem: row.targetSystem,
    recordType: row.recordType,
    filePath: row.filePath,
    archiveLedgerStatus: externalSystemImportLedgerStatus(row.reconciliationStatus),
    externalRecordId: row.externalRecordId,
    receiptStatus: row.receiptStatus,
    receiptMessage: row.receiptMessage,
    receivedAt: row.receivedAt,
    action: row.action,
  }));
  const importedCount = rows.filter((row) => row.archiveLedgerStatus === "imported").length;
  const blockedCount = rows.filter((row) => row.archiveLedgerStatus === "blocked").length;
  const pendingCount = rows.filter((row) => row.archiveLedgerStatus === "pending").length;
  const skippedCount = rows.filter((row) => row.archiveLedgerStatus === "skipped").length;
  const missingReceiptCount = rows.filter((row) => row.archiveLedgerStatus === "missing_receipt").length;
  const unmatchedReceiptCount = rows.filter((row) => row.archiveLedgerStatus === "unmatched_receipt").length;
  const body = {
    schema: "railwise.engineering.batch.externalSystemImportLedgerUpdate.v1" as const,
    generatedAt,
    batchName: reconciliation.batchName,
    planFingerprint: reconciliation.planFingerprint,
    reconciliationFingerprint: reconciliation.reconciliationFingerprint,
    rowCount: rows.length,
    importedCount,
    blockedCount,
    pendingCount,
    skippedCount,
    missingReceiptCount,
    unmatchedReceiptCount,
    rows,
  };
  const ledgerFingerprint = fnv1a32Fingerprint(JSON.stringify(body));
  const withFingerprint = {
    ...body,
    ledgerFingerprint,
  };
  const csv = csvFromRows(
    [
      "request_id",
      "adapter_id",
      "target_system",
      "record_type",
      "file_path",
      "archive_ledger_status",
      "external_record_id",
      "receipt_status",
      "receipt_message",
      "received_at",
      "action",
    ],
    rows.map((row) => ({
      request_id: row.requestId,
      adapter_id: row.adapterId,
      target_system: row.targetSystem,
      record_type: row.recordType,
      file_path: row.filePath,
      archive_ledger_status: row.archiveLedgerStatus,
      external_record_id: row.externalRecordId,
      receipt_status: row.receiptStatus ?? "",
      receipt_message: row.receiptMessage,
      received_at: row.receivedAt,
      action: row.action,
    })),
  );
  return {
    ...withFingerprint,
    csv,
    json: JSON.stringify(withFingerprint, null, 2),
  };
}

function externalSystemImportRectificationType(
  status: EngineeringBatchExternalSystemImportReceiptReconciliationStatus,
): EngineeringBatchExternalSystemImportRectificationType | null {
  if (status === "rejected") return "rejected";
  if (status === "pending") return "pending";
  if (status === "missing_receipt") return "missing_receipt";
  if (status === "unmatched_receipt") return "unmatched_receipt";
  return null;
}

function externalSystemImportRectificationPriority(
  type: EngineeringBatchExternalSystemImportRectificationType,
): EngineeringProjectArchiveRectificationPriority {
  if (type === "rejected") return "high";
  return "normal";
}

function externalSystemImportRectificationAction(
  type: EngineeringBatchExternalSystemImportRectificationType,
): string {
  if (type === "rejected") {
    return "按外部系统拒绝原因整改后重新提交该文件，并在回执中回填新的 external_record_id。";
  }
  if (type === "pending") return "外部系统仍在处理，跟踪处理状态并在截止日前补充最终回执。";
  if (type === "missing_receipt") {
    return "未收到外部系统回执，按 request_id 联系平台或接口管理员确认导入结果。";
  }
  return "回执未匹配当前导入计划，核对 request_id、批次版本和外部记录来源。";
}

