  const run = useCallback(() => {
    try {
      const parsed = parseEngineeringInputText(
        activeId,
        inputText,
        inputFormat,
        inputFormat === "json" ? undefined : fieldMapping,
      );
      setInputError(null);
      setImportWarnings(parsed.warnings);
      setImportSummary(parsed);
      setExportNotice(null);
      const scenarioRun = buildSelectedScenarioRun(activeId, parsed.input);
      setScenarioTemplateApplication(scenarioRun.application);
      if (isIndoorAdjustmentToolId(activeId)) {
        const sampleSize = indoorAdjustmentInputSampleSize(activeId, scenarioRun.input);
        if (sampleSize >= ASYNC_INDOOR_ADJUSTMENT_SAMPLE_SIZE) {
          scheduleIndoorAdjustmentCalculation(activeId, scenarioRun.input, sampleSize);
          return;
        }
      }
      clearScheduledCalculation();
      setCalculationProgress(null);
      setResult(runCalculationWithPerformanceAcceptance(activeId, scenarioRun.input));
      void applySurveyAdjustmentIpcResult(
        activeId,
        scenarioRun.input,
        "本地 survey-mcp 平差计算完成",
        "本地离线平差计算完成",
      );
    } catch (error) {
      setInputError(error instanceof Error ? error.message : String(error));
    }
  }, [
    activeId,
    applySurveyAdjustmentIpcResult,
    buildSelectedScenarioRun,
    fieldMapping,
    inputFormat,
    inputText,
    runCalculationWithPerformanceAcceptance,
    scheduleIndoorAdjustmentCalculation,
    clearScheduledCalculation,
  ]);

  const applyAdjustmentResultToDeformation = useCallback(() => {
    if (!isIndoorAdjustmentToolId(result.toolId)) return;
    const toolTitle = TOOL_BY_ID.get(result.toolId)?.title ?? result.title;
    if (!deformationBaselineAdjustment || deformationBaselineAdjustment.toolId !== result.toolId) {
      setDeformationBaselineAdjustment(result);
      setExportNotice(`${toolTitle}已设为变形分析初始值`);
      return;
    }

    const deformationInput = buildEngineeringDeformationInputFromAdjustmentResults(deformationBaselineAdjustment, result, {
      baselineDate: "初始值",
      currentDate: "本期复测",
    });
    if (arrayFrom(deformationInput.points).length === 0) {
      setExportNotice("当前平差成果没有可转入变形分析的同名点。");
      return;
    }

    const scenarioRun = buildSelectedScenarioRun("deformation_trend", deformationInput);
    const nextText = JSON.stringify(scenarioRun.input, null, 2);
    const parsed = parseEngineeringInputText("deformation_trend", nextText, "json");
    clearScheduledCalculation();
    setCalculationProgress(null);
    setActiveId("deformation_trend");
    setInputFormat("json");
    setInputText(nextText);
    setInputError(null);
    setImportWarnings(parsed.warnings);
    setImportSummary({ ...parsed, sourceName: "平差成果转入变形分析" });
    setFieldMapping({ fields: {} });
    setScenarioTemplateApplication(scenarioRun.application);
    setResult(runCalculationWithPerformanceAcceptance("deformation_trend", scenarioRun.input));
    setExportNotice("平差成果已转入变形分析");
  }, [
    buildSelectedScenarioRun,
    clearScheduledCalculation,
    deformationBaselineAdjustment,
    result,
    runCalculationWithPerformanceAcceptance,
  ]);

