  const generateIndoorAiReportWithDeepSeek = useCallback(async () => {
    if (!indoorAiReportDraft || !isIndoorAdjustmentToolId(result.toolId)) return;
    setIndoorAiReportGenerating(true);
    try {
      const { invoke } = await import("@tauri-apps/api/core");
      const payload = await invoke<unknown>("generate_indoor_adjustment_ai_report", {
        request: {
          sourceToolId: result.toolId,
          sourceToolTitle: result.title,
          projectContext: normalizeEngineeringWorkbenchProjectContext(projectContext),
          prompt: indoorAiReportDraft.prompt,
          draftMarkdown: indoorAiReportDraft.reportMarkdown,
          highlights: indoorAiReportDraft.highlights,
          algorithmEvidence: indoorAiReportDraft.algorithmEvidence,
        },
      });
      const body = objectFrom(payload);
      const reportMarkdown = textFrom(body.reportMarkdown, "");
      if (!reportMarkdown.trim()) throw new Error("DeepSeek 未返回报告正文");
      const generated = buildIndoorAdjustmentAiReportGenerationEvidence({
        draft: indoorAiReportDraft,
        result,
        provider: "deepseek_chat_completions",
        status: "generated",
        generatedAt: textFrom(body.generatedAt, new Date().toISOString()),
        reportMarkdown,
        model: textFrom(body.model, "deepseek-v4-flash"),
        reportFingerprint: textFrom(body.reportFingerprint, ""),
        promptFingerprint: textFrom(body.promptFingerprint, ""),
      });
      setIndoorAiReportGeneration(generated);
      setExportNotice("DeepSeek AI 平差报告已生成");
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      const fallback = buildIndoorAdjustmentAiReportGenerationEvidence({
        draft: indoorAiReportDraft,
        result,
        provider: "local_fallback",
        status: "fallback",
        model: null,
        errorMessage: message,
      });
      setIndoorAiReportGeneration(fallback);
      setExportNotice("DeepSeek 报告生成失败，已保留本地草稿");
    } finally {
      setIndoorAiReportGenerating(false);
    }
  }, [indoorAiReportDraft, projectContext, result]);

