  const importArchiveZipForAcceptanceReview = useCallback(async () => {
    try {
      const [{ open }, { invoke }] = await Promise.all([
        import("@tauri-apps/plugin-dialog"),
        import("@tauri-apps/api/core"),
      ]);
      const selected = await open({
        multiple: false,
        filters: [{ name: "Railwise 工程归档 ZIP", extensions: ["zip"] }],
      });
      const path = Array.isArray(selected) ? selected[0] : selected;
      if (!path) return;
      const bytes = await invoke<number[]>("read_binary_file", { path });
      const archiveName = path.split(/[\\/]/).pop() || "imported-archive.zip";
      const review = verifyEngineeringArchiveZipImport(new Uint8Array(bytes), {
        archiveName,
        checkedAt: new Date().toISOString(),
      });
      setArchiveZipImportReview(review);
      setArchiveZipImportReviewSourcePath(path);
      setArchiveAcceptanceRemediationRecheckUpdate(null);
      setArchiveAcceptanceFinalRegistration(null);
      setArchiveAcceptanceReview(review.acceptanceReview);
      setArchiveReleaseDeliveryReadiness(review.archiveReleaseDeliveryReadiness);
      const history = appendSavedEngineeringArchiveZipImportReviewHistory(review, {
        operator: batchPreparedBy,
        sourcePath: path,
        recordedAt: new Date().toISOString(),
      });
      setArchiveZipImportHistory(history);
      setArchiveZipImportHistoryImportReport(null);
      setExportNotice(
        `归档 ZIP 验收：${review.acceptanceReview.acceptanceStatusLabel}，条目 ${review.summary.entryCount}，缺项 ${review.summary.requiredEntriesMissing}，错误 ${review.summary.errors}，历史 ${history.recordCount} 条`,
      );
    } catch (error) {
      setInputError(error instanceof Error ? error.message : String(error));
    }
  }, [batchPreparedBy]);

