  const buildExternalSystemHttpExecutionOptions = useCallback(() => {
    const timeoutMs = Number.parseInt(externalSystemHttpTimeoutMs, 10);
    const boundedTimeoutMs =
      Number.isFinite(timeoutMs) && timeoutMs > 0 ? Math.min(120000, Math.max(1000, timeoutMs)) : null;
    const maxRetries = Number.parseInt(externalSystemHttpMaxRetries, 10);
    const boundedMaxRetries = Number.isFinite(maxRetries) && maxRetries > 0 ? Math.min(5, Math.max(0, maxRetries)) : 0;
    const retryStatusCodes = EXTERNAL_SYSTEM_HTTP_RETRY_STATUS_CODES;
    const authHeaderName =
      externalSystemHttpAuthMode === "bearer"
        ? "Authorization"
        : externalSystemHttpAuthMode === "api_key_header"
          ? externalSystemHttpApiKeyHeader.trim() || "X-API-Key"
          : null;
    const authValue =
      externalSystemHttpAuthMode === "bearer"
        ? externalSystemHttpBearerToken.trim()
          ? `Bearer ${externalSystemHttpBearerToken.trim()}`
          : ""
        : externalSystemHttpAuthMode === "api_key_header"
          ? externalSystemHttpApiKeyValue.trim()
          : "";
    return {
      authHeaderName,
      authValue,
      executionConfig: {
        authMode: externalSystemHttpAuthMode,
        authConfigured: externalSystemHttpAuthMode !== "none" && Boolean(authValue),
        authHeaderName,
        timeoutMs: boundedTimeoutMs,
        maxRetries: boundedMaxRetries,
        retryStatusCodes,
      } satisfies EngineeringBatchExternalSystemHttpExecutionConfig,
    };
  }, [
    externalSystemHttpApiKeyHeader,
    externalSystemHttpApiKeyValue,
    externalSystemHttpAuthMode,
    externalSystemHttpBearerToken,
    externalSystemHttpMaxRetries,
    externalSystemHttpTimeoutMs,
  ]);

