  const runExternalSystemHttpPlanRequests = useCallback(
    async (plan: EngineeringBatchExternalSystemImportPlan) => {
      const { authHeaderName, authValue, executionConfig } = buildExternalSystemHttpExecutionOptions();
      const attempts: EngineeringBatchExternalSystemHttpSubmissionAttemptInput[] = [];
      for (const request of plan.requests) {
        for (let attemptIndex = 0; attemptIndex <= executionConfig.maxRetries; attemptIndex++) {
          const requestStartedAt = new Date().toISOString();
          const startedMs = Date.now();
          const controller = executionConfig.timeoutMs ? new AbortController() : null;
          let timedOut = false;
          const timeoutId =
            controller && executionConfig.timeoutMs
              ? window.setTimeout(() => {
                  timedOut = true;
                  controller.abort();
                }, executionConfig.timeoutMs)
              : null;
          try {
            const headers: Record<string, string> = {
              "Content-Type": "application/json",
              Accept: "application/json, text/plain;q=0.9, */*;q=0.8",
            };
            if (authHeaderName && authValue) headers[authHeaderName] = authValue;
            const response = await fetch(request.endpointUrl, {
              method: request.method,
              headers,
              body: JSON.stringify({ request_id: request.requestId, ...request.payload }),
              signal: controller?.signal,
            });
            const responseText = await response.text();
            attempts.push({
              requestId: request.requestId,
              submittedAt: requestStartedAt,
              completedAt: new Date().toISOString(),
              durationMs: Date.now() - startedMs,
              statusCode: response.status,
              ok: response.ok,
              responseText,
            });
            const shouldRetry =
              attemptIndex < executionConfig.maxRetries &&
              !response.ok &&
              executionConfig.retryStatusCodes.includes(response.status);
            if (!shouldRetry) break;
          } catch (error) {
            attempts.push({
              requestId: request.requestId,
              submittedAt: requestStartedAt,
              completedAt: new Date().toISOString(),
              durationMs: Date.now() - startedMs,
              statusCode: null,
              ok: false,
              errorMessage: timedOut
                ? `timeout after ${executionConfig.timeoutMs}ms`
                : error instanceof Error
                  ? error.message
                  : String(error),
            });
            if (attemptIndex >= executionConfig.maxRetries) break;
          } finally {
            if (timeoutId !== null) window.clearTimeout(timeoutId);
          }
        }
      }
      return { attempts, executionConfig };
    },
    [buildExternalSystemHttpExecutionOptions],
  );

