  const replayBatchArchiveReleaseSlaNotificationHttpFailures = useCallback(async () => {
    if (
      !archiveReleaseSlaNotificationHttpDeliveryPlan ||
      !archiveReleaseSlaNotificationHttpDeliveryAudit ||
      !archiveReleaseSlaNotificationHttpReplayQueue
    ) {
      setExportNotice("尚未生成 SLA 通知 HTTP 重放队列");
      return;
    }
    if (archiveReleaseSlaNotificationHttpReplayQueue.requestCount === 0) {
      setExportNotice("当前没有需要重放的 SLA 通知 HTTP 请求");
      return;
    }
    const replayRequestIds = new Set(archiveReleaseSlaNotificationHttpReplayQueue.rows.map((row) => row.requestId));
    const replayRequests = archiveReleaseSlaNotificationHttpDeliveryPlan.requests.filter((request) =>
      replayRequestIds.has(request.requestId),
    );
    if (replayRequests.length === 0) {
      setExportNotice("SLA 通知重放队列未匹配到当前发送计划");
      return;
    }
    const submittedAt = new Date().toISOString();
    const replayPlan: EngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryPlan = {
      ...archiveReleaseSlaNotificationHttpDeliveryPlan,
      generatedAt: submittedAt,
      requestCount: replayRequests.length,
      requests: replayRequests,
    };
    setExportNotice(`正在重放 SLA 通知 HTTP 发送：${replayRequests.length} 条请求`);
    const { attempts, executionConfig } = await runArchiveReleaseSlaNotificationHttpDeliveryRequests(replayPlan);
    const completedAt = new Date().toISOString();
    const replayAudit = buildEngineeringBatchArchiveReleaseSlaNotificationHttpDeliveryAudit(
      archiveReleaseSlaNotificationHttpDeliveryAudit.updatedAudit,
      replayPlan,
      {
        attempts,
        executionConfig,
        submittedAt,
        completedAt,
        executedBy: batchPreparedBy || null,
        deliveryFieldTemplate: archiveReleaseSlaNotificationHttpDeliveryFieldTemplate,
      },
    );
    const mergedAudit = mergeEngineeringBatchArchiveReleaseSlaNotificationHttpReplayAudit(
      archiveReleaseSlaNotificationHttpDeliveryAudit,
      replayAudit,
      { mergedAt: completedAt },
    );
    const replayQueue = buildEngineeringBatchArchiveReleaseSlaNotificationHttpReplayQueue(
      archiveReleaseSlaNotificationHttpDeliveryPlan,
      mergedAudit,
      { generatedAt: completedAt },
    );
    setArchiveReleaseSlaNotificationHttpDeliveryAudit(mergedAudit);
    setArchiveReleaseSlaNotificationHttpReplayQueue(replayQueue);
    setArchiveReleaseSlaNotificationExecutionAudit(mergedAudit.updatedAudit);
    setArchiveReleaseSlaNotificationExecutionReceiptUpdate(null);
    setArchiveReleaseSlaReminderArchiveIngest(null);
    setArchiveReleaseSlaReminderExternalSystemImportReceiptUpdate(null);
    setArchiveReleaseSlaReminderExternalSystemImportRectificationLedger(null);
    setArchiveReleaseSlaReminderExternalSystemImportRectificationClosureUpdate(null);
    setExportNotice(
      `SLA 通知重放完成：已发送 ${mergedAudit.sentCount}，失败 ${mergedAudit.failedCount}，HTTP 错误 ${mergedAudit.httpErrorCount}，网络错误 ${mergedAudit.networkErrorCount}，剩余重放 ${replayQueue.requestCount}`,
    );
  }, [
    archiveReleaseSlaNotificationHttpDeliveryAudit,
    archiveReleaseSlaNotificationHttpDeliveryFieldTemplate,
    archiveReleaseSlaNotificationHttpDeliveryPlan,
    archiveReleaseSlaNotificationHttpReplayQueue,
    batchPreparedBy,
    runArchiveReleaseSlaNotificationHttpDeliveryRequests,
  ]);

