  const submitBatchExternalSystemHttpImport = useCallback(async () => {
    if (batchQueue.length === 0) {
      setExportNotice("批处理队列为空");
      return;
    }
    if (externalSystemImportMode !== "http_json") {
      setExportNotice("请先将入库模式切换为 HTTP");
      return;
    }
    if (!externalSystemEndpointBaseUrl.trim()) {
      setExportNotice("HTTP 入库需要填写 Endpoint");
      return;
    }
    const submittedAt = new Date().toISOString();
    const context = buildBatchArchiveExportContext(submittedAt);
    const preflight = buildEngineeringBatchExternalSystemAdapterPreflightReport(batchQueue, context);
    if (preflight.blockingIssueCount > 0) {
      setExportNotice(`外部适配预检存在 ${preflight.blockingIssueCount} 个阻断问题，请先导出预检 CSV 修正字段模板`);
      return;
    }
    const plan = buildEngineeringBatchExternalSystemImportPlan(batchQueue, context);
    setExportNotice(`正在提交外部系统 HTTP 入库：${plan.requestCount} 条请求`);
    const { attempts, executionConfig } = await runExternalSystemHttpPlanRequests(plan);
    const completedAt = new Date().toISOString();
    const audit = buildEngineeringBatchExternalSystemHttpSubmissionAudit(plan, {
      attempts,
      executionConfig,
      submittedAt,
      completedAt,
    });
    const reconciliation = buildEngineeringBatchExternalSystemImportReceiptReconciliation(plan, {
      text: audit.receiptCsv,
      format: "csv",
      sourceName: "HTTP 提交审计回执.csv",
      importedAt: completedAt,
    });
    const signoffReceipt = buildEngineeringBatchExternalSystemSignoffReceiptReconciliation(plan, reconciliation, {
      generatedAt: completedAt,
    });
    const ledgerUpdate = buildEngineeringBatchExternalSystemImportLedgerUpdate(reconciliation, {
      generatedAt: completedAt,
    });
    const rectificationLedger = buildEngineeringBatchExternalSystemImportRectificationLedger(reconciliation, {
      generatedAt: completedAt,
    });
    const replayQueue = buildEngineeringBatchExternalSystemHttpReplayQueue(plan, audit, {
      generatedAt: completedAt,
    });
    setExternalSystemHttpSubmissionPlan(plan);
    setExternalSystemHttpSubmissionAudit(audit);
    setExternalSystemHttpReplayQueue(replayQueue);
    setArchiveReleaseSlaReminderExternalSystemHttpReplayQueue(null);
    setExternalSystemImportReceiptReconciliation(reconciliation);
    setExternalSystemSignoffReceiptReconciliation(signoffReceipt);
    setExternalSystemImportLedgerUpdate(ledgerUpdate);
    setExternalSystemImportRectificationLedger(rectificationLedger);
    setExternalSystemImportRectificationClosureUpdate(null);
    setExportNotice(
      `HTTP 入库提交完成：已入库 ${audit.acceptedCount}，待处理 ${audit.pendingCount}，业务拒绝 ${audit.rejectedCount}，HTTP 错误 ${audit.httpErrorCount}，网络错误 ${audit.networkErrorCount}，整改 ${rectificationLedger.openCount}`,
    );
  }, [
    batchQueue,
    buildBatchArchiveExportContext,
    externalSystemEndpointBaseUrl,
    externalSystemImportMode,
    runExternalSystemHttpPlanRequests,
  ]);

  const replayBatchExternalSystemHttpFailures = useCallback(async () => {
    if (!externalSystemHttpSubmissionPlan || !externalSystemHttpSubmissionAudit || !externalSystemHttpReplayQueue) {
      setExportNotice("尚未生成 HTTP 重放队列");
      return;
    }
    if (externalSystemHttpReplayQueue.requestCount === 0) {
      setExportNotice("当前没有需要重放的 HTTP 请求");
      return;
    }
    const replayRequestIds = new Set(externalSystemHttpReplayQueue.rows.map((row) => row.requestId));
    const replayRequests = externalSystemHttpSubmissionPlan.requests.filter((request) =>
      replayRequestIds.has(request.requestId),
    );
    if (replayRequests.length === 0) {
      setExportNotice("重放队列未匹配到当前 HTTP 入库计划");
      return;
    }
    setExportNotice(`正在重放外部系统 HTTP 入库：${replayRequests.length} 条请求`);
    const submittedAt = new Date().toISOString();
    const replayPlan: EngineeringBatchExternalSystemImportPlan = {
      ...externalSystemHttpSubmissionPlan,
      generatedAt: submittedAt,
      requestCount: replayRequests.length,
      requests: replayRequests,
      adapterIds: uniqueNonEmptyStrings(replayRequests.map((request) => request.adapterId)),
      adapterCount: uniqueNonEmptyStrings(replayRequests.map((request) => request.adapterId)).length,
    };
    const { attempts, executionConfig } = await runExternalSystemHttpPlanRequests(replayPlan);
    const completedAt = new Date().toISOString();
    const replayAudit = buildEngineeringBatchExternalSystemHttpSubmissionAudit(replayPlan, {
      attempts,
      executionConfig,
      submittedAt,
      completedAt,
    });
    const dedicatedReplayUpdate =
      archiveReleaseSlaReminderArchiveIngest &&
      isEngineeringBatchArchiveReleaseSlaReminderExternalSystemImportPlan(externalSystemHttpSubmissionPlan)
        ? buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemHttpReplayUpdate(
            archiveReleaseSlaReminderArchiveIngest,
            externalSystemHttpSubmissionPlan,
            externalSystemHttpSubmissionAudit,
            replayAudit,
            { generatedAt: completedAt },
          )
        : null;
    if (dedicatedReplayUpdate) {
      const rectificationLedger =
        buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemImportRectificationLedger(
          dedicatedReplayUpdate.receiptUpdate,
          { generatedAt: completedAt },
        );
      const initialIngestForHistory =
        archiveReleaseSlaReminderExternalSystemInitialArchiveIngest ?? archiveReleaseSlaReminderArchiveIngest;
      const initialAuditForHistory =
        archiveReleaseSlaReminderExternalSystemInitialHttpAudit ?? externalSystemHttpSubmissionAudit;
      const initialReceiptUpdateForHistory =
        archiveReleaseSlaReminderExternalSystemInitialReceiptUpdate ?? archiveReleaseSlaReminderExternalSystemImportReceiptUpdate;
      if (!initialIngestForHistory) {
        setExportNotice("SLA 提醒专项 HTTP 重放历史缺少初始入库清单，请重新提交专项 HTTP");
        return;
      }
      const nextHistoryRounds: EngineeringBatchArchiveReleaseSlaReminderExternalSystemHttpReplayHistoryRoundInput[] = [
        ...archiveReleaseSlaReminderExternalSystemHttpReplayHistoryRounds,
        {
          roundNo: archiveReleaseSlaReminderExternalSystemHttpReplayHistoryRounds.length + 1,
          replayStartedAt: submittedAt,
          replayCompletedAt: completedAt,
          beforeQueue: externalSystemHttpReplayQueue,
          replayAudit,
          update: dedicatedReplayUpdate,
          rectificationLedger: rectificationLedger.rowCount > 0 ? rectificationLedger : null,
        },
      ];
      const replayHistory = buildEngineeringBatchArchiveReleaseSlaReminderExternalSystemHttpReplayHistory({
        generatedAt: completedAt,
        batchName: dedicatedReplayUpdate.receiptUpdate.batchName,
        plan: externalSystemHttpSubmissionPlan,
        initialIngest: initialIngestForHistory,
        initialAudit: initialAuditForHistory,
        initialReceiptUpdate: initialReceiptUpdateForHistory,
        rounds: nextHistoryRounds,
      });
      setExternalSystemHttpSubmissionAudit(dedicatedReplayUpdate.mergedAudit);
      setExternalSystemHttpReplayQueue(dedicatedReplayUpdate.replayQueue);
      setArchiveReleaseSlaReminderExternalSystemHttpReplayQueue(dedicatedReplayUpdate.replayQueue);
      setArchiveReleaseSlaReminderExternalSystemInitialArchiveIngest(initialIngestForHistory);
      setArchiveReleaseSlaReminderExternalSystemInitialHttpAudit(initialAuditForHistory);
      setArchiveReleaseSlaReminderExternalSystemInitialReceiptUpdate(initialReceiptUpdateForHistory);
      setArchiveReleaseSlaReminderExternalSystemHttpReplayHistoryRounds(nextHistoryRounds);
      setArchiveReleaseSlaReminderExternalSystemHttpReplayHistory(replayHistory);
      setArchiveReleaseSlaReminderExternalSystemFinalReceiptConfirmation(null);
      setArchiveReleaseSlaReminderExternalSystemFinalReceiptCrossPlatformReview(null);
      setArchiveReleaseSlaReminderExternalSystemFinalReceiptBatchSignoff(null);
      setArchiveReleaseSlaReminderExternalSystemFinalReceiptSignoffExternalSyncReceipt(null);
      setExternalSystemImportReceiptReconciliation(dedicatedReplayUpdate.reconciliation);
      setArchiveReleaseSlaReminderArchiveIngest(dedicatedReplayUpdate.receiptUpdate.updatedArchiveIngest);
      setArchiveReleaseSlaReminderExternalSystemImportReceiptUpdate(dedicatedReplayUpdate.receiptUpdate);
      setArchiveReleaseSlaReminderExternalSystemImportRectificationLedger(
        rectificationLedger.rowCount > 0 ? rectificationLedger : null,
      );
      setArchiveReleaseSlaReminderExternalSystemImportRectificationClosureUpdate(null);
      setExternalSystemSignoffReceiptReconciliation(null);
      setExternalSystemImportLedgerUpdate(null);
      setExternalSystemImportRectificationLedger(null);
      setExternalSystemImportRectificationClosureUpdate(null);
      setExportNotice(
        `SLA 提醒专项 HTTP 重放完成：第 ${replayHistory.roundCount} 轮，已入库 ${dedicatedReplayUpdate.mergedAudit.acceptedCount}，待处理 ${dedicatedReplayUpdate.mergedAudit.pendingCount}，业务拒绝 ${dedicatedReplayUpdate.mergedAudit.rejectedCount}，HTTP 错误 ${dedicatedReplayUpdate.mergedAudit.httpErrorCount}，网络错误 ${dedicatedReplayUpdate.mergedAudit.networkErrorCount}，剩余重放 ${dedicatedReplayUpdate.replayQueue.requestCount}`,
      );
      return;
    }
    const mergedAudit = mergeEngineeringBatchExternalSystemHttpReplayAudit(
      externalSystemHttpSubmissionAudit,
      replayAudit,
      { mergedAt: completedAt },
    );
    const reconciliation = buildEngineeringBatchExternalSystemImportReceiptReconciliation(externalSystemHttpSubmissionPlan, {
      text: mergedAudit.receiptCsv,
      format: "csv",
      sourceName: "HTTP 重放合并回执.csv",
      importedAt: completedAt,
    });
    const signoffReceipt = buildEngineeringBatchExternalSystemSignoffReceiptReconciliation(
      externalSystemHttpSubmissionPlan,
      reconciliation,
      { generatedAt: completedAt },
    );
    const ledgerUpdate = buildEngineeringBatchExternalSystemImportLedgerUpdate(reconciliation, {
      generatedAt: completedAt,
    });
    const rectificationLedger = buildEngineeringBatchExternalSystemImportRectificationLedger(reconciliation, {
      generatedAt: completedAt,
    });
    const replayQueue = buildEngineeringBatchExternalSystemHttpReplayQueue(externalSystemHttpSubmissionPlan, mergedAudit, {
      generatedAt: completedAt,
    });
    setExternalSystemHttpSubmissionAudit(mergedAudit);
    setExternalSystemHttpReplayQueue(replayQueue);
    setArchiveReleaseSlaReminderExternalSystemHttpReplayQueue(null);
    setArchiveReleaseSlaReminderExternalSystemHttpReplayHistory(null);
    setArchiveReleaseSlaReminderExternalSystemHttpReplayHistoryRounds([]);
    setArchiveReleaseSlaReminderExternalSystemImportRectificationLedger(null);
    setArchiveReleaseSlaReminderExternalSystemImportRectificationClosureUpdate(null);
    setExternalSystemImportReceiptReconciliation(reconciliation);
    setExternalSystemSignoffReceiptReconciliation(signoffReceipt);
    setExternalSystemImportLedgerUpdate(ledgerUpdate);
    setExternalSystemImportRectificationLedger(rectificationLedger);
    setExternalSystemImportRectificationClosureUpdate(null);
    setExportNotice(
      `HTTP 重放完成：已入库 ${mergedAudit.acceptedCount}，待处理 ${mergedAudit.pendingCount}，业务拒绝 ${mergedAudit.rejectedCount}，HTTP 错误 ${mergedAudit.httpErrorCount}，网络错误 ${mergedAudit.networkErrorCount}，剩余重放 ${replayQueue.requestCount}`,
    );
  }, [
    archiveReleaseSlaReminderArchiveIngest,
    archiveReleaseSlaReminderExternalSystemHttpReplayHistoryRounds,
    archiveReleaseSlaReminderExternalSystemImportReceiptUpdate,
    archiveReleaseSlaReminderExternalSystemInitialArchiveIngest,
    archiveReleaseSlaReminderExternalSystemInitialHttpAudit,
    archiveReleaseSlaReminderExternalSystemInitialReceiptUpdate,
    externalSystemHttpReplayQueue,
    externalSystemHttpSubmissionAudit,
    externalSystemHttpSubmissionPlan,
    runExternalSystemHttpPlanRequests,
  ]);

