  const importBatchExternalSystemImportReceiptFile = useCallback(async () => {
    if (batchQueue.length === 0) {
      setExportNotice("批处理队列为空");
      return;
    }
    try {
      const [{ open }, { invoke }] = await Promise.all([
        import("@tauri-apps/plugin-dialog"),
        import("@tauri-apps/api/core"),
      ]);
      const selected = await open({
        multiple: false,
        filters: [{ name: "外部系统入库回执", extensions: ["csv", "tsv", "json"] }],
      });
      const path = Array.isArray(selected) ? selected[0] : selected;
      if (!path) return;
      const file = await invoke<EngineeringImportFilePayload>("read_engineering_import_file", { path });
      const importedAt = new Date().toISOString();
      const plan = buildEngineeringBatchExternalSystemImportPlan(
        batchQueue,
        buildBatchArchiveExportContext(importedAt),
      );
      const detected = inferEngineeringInputFormat(file.file_name || file.path, file.content);
      const format = detected === "tsv" ? "tsv" : detected === "json" ? "json" : "csv";
      const reconciliation = buildEngineeringBatchExternalSystemImportReceiptReconciliation(plan, {
        text: file.content,
        format,
        sourceName: file.file_name || file.path,
        importedAt,
      });
      const signoffReceipt = buildEngineeringBatchExternalSystemSignoffReceiptReconciliation(plan, reconciliation, {
        generatedAt: importedAt,
      });
      const ledgerUpdate = buildEngineeringBatchExternalSystemImportLedgerUpdate(reconciliation, {
        generatedAt: importedAt,
      });
      const rectificationLedger = buildEngineeringBatchExternalSystemImportRectificationLedger(reconciliation, {
        generatedAt: importedAt,
      });
      setExternalSystemHttpSubmissionPlan(null);
      setExternalSystemHttpSubmissionAudit(null);
      setExternalSystemHttpReplayQueue(null);
      setExternalSystemImportReceiptReconciliation(reconciliation);
      setExternalSystemSignoffReceiptReconciliation(signoffReceipt);
      setExternalSystemImportLedgerUpdate(ledgerUpdate);
      setExternalSystemImportRectificationLedger(rectificationLedger);
      setExternalSystemImportRectificationClosureUpdate(null);
      setExportNotice(
        `外部入库回执已合并：成功 ${reconciliation.acceptedCount}，拒绝 ${reconciliation.rejectedCount}，待处理 ${reconciliation.pendingCount}，缺回执 ${reconciliation.missingReceiptCount}，未匹配 ${reconciliation.unmatchedReceiptCount}，整改 ${rectificationLedger.openCount}`,
      );
    } catch (error) {
      setInputError(error instanceof Error ? error.message : String(error));
    }
  }, [batchQueue, buildBatchArchiveExportContext]);

