  const importBatchExternalSystemImportRectificationClosureFile = useCallback(async () => {
    if (!externalSystemImportRectificationLedger) {
      setExportNotice("尚未生成外部入库整改台账");
      return;
    }
    try {
      const [{ open }, { invoke }] = await Promise.all([
        import("@tauri-apps/plugin-dialog"),
        import("@tauri-apps/api/core"),
      ]);
      const selected = await open({
        multiple: false,
        filters: [{ name: "外部入库整改销项回执", extensions: ["csv", "tsv", "json"] }],
      });
      const path = Array.isArray(selected) ? selected[0] : selected;
      if (!path) return;
      const file = await invoke<EngineeringImportFilePayload>("read_engineering_import_file", { path });
      const importedAt = new Date().toISOString();
      const detected = inferEngineeringInputFormat(file.file_name || file.path, file.content);
      const format = detected === "tsv" ? "tsv" : detected === "json" ? "json" : "csv";
      const closureUpdate = buildEngineeringBatchExternalSystemImportRectificationClosureUpdate(
        externalSystemImportRectificationLedger,
        {
          text: file.content,
          format,
          sourceName: file.file_name || file.path,
          importedAt,
        },
      );
      setExternalSystemImportRectificationClosureUpdate(closureUpdate);
      setExternalSystemImportRectificationLedger(closureUpdate.updatedLedger);
      setExportNotice(
        `外部入库整改销项已导入：已闭环 ${closureUpdate.closedCount}，待闭环 ${closureUpdate.stillOpenCount}，未回执 ${closureUpdate.missingUpdateCount}，未匹配 ${closureUpdate.unmatchedUpdateCount}`,
      );
    } catch (error) {
      setInputError(error instanceof Error ? error.message : String(error));
    }
  }, [externalSystemImportRectificationLedger]);

